# Dump of table actions
# ------------------------------------------------------------

DROP TABLE IF EXISTS `actions`;

CREATE TABLE `actions` (
  `record_id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'ID записи',
  `name` varchar(64) DEFAULT '' COMMENT 'Название акции',
  `descr` varchar(1000) DEFAULT NULL COMMENT 'Описание акции',
