  `dtfrom_end` date NOT NULL DEFAULT '0000-00-00' COMMENT 'Дата, с которой клиенту назначается акция, не может быть больше этой даты',
  `dtto` date NOT NULL DEFAULT '0000-00-00' COMMENT 'Дата безусловного окончания срока действия акции для всех клиентов',
  `day_count` int(11) NOT NULL DEFAULT '0' COMMENT 'Срок действия акции (дней) после назначения клиенту',
  `type` tinyint(1) DEFAULT '0' COMMENT 'Тип участия в акции: 1 - условное, 2 - безусловное, 3 - комбинированное',
  `object` tinyint(1) DEFAULT '0' COMMENT 'Акция распространяется на: 0 - пользователя, 1 - договор, 2 - у.з.',
  `archive` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Запись удалена (флаг)',
  `for_corporation` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Акция для юр. лиц (флаг)',
  `for_individual` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Акция для физ. лиц (флаг)',
  `modify_rent` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Участие в акции модифицирует величину а/п (флаг)',
  `modify_above` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Участие в акции модифицирует стоимость превышения (флаг)',
  `modify_shape` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Участие в акции модифицирует скорость доступа (флаг)',
  `positive_balance` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Для подключения к акции необходим положительный текущий баланс',
  `not_blocked_1` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Для подключения к акции необходимо отсутствие финансовой блокировки на 1 число',
  `uuid` varchar(40) DEFAULT NULL COMMENT 'Уникальный код акции',
  `available` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Возможность назначать/отменять акцию из клиентского интерфейса',
  `script` varchar(255) NOT NULL DEFAULT '' COMMENT 'Скрипт, запускаемый при назначении акции. На вход скрипта передается action_staff.record_id',
  `link` varchar(255) NOT NULL DEFAULT '' COMMENT 'Ссылка на подробное описание',
  PRIMARY KEY (`record_id`),
  UNIQUE KEY `actions_uniq_uuid` (`uuid`),
  KEY `archive` (`archive`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='Маркетинговые акции';



