DELIMITER ;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION" */;;
/*!50003 CREATE */ /*!50017 DEFINER=`billing`@`127.0.0.1` */ /*!50003 TRIGGER `applications_insert` BEFORE INSERT ON `applications` FOR EACH ROW BEGIN
	IF @LB_DISABLE_TRIGGERS IS NULL OR @LB_DISABLE_TRIGGERS = 0 THEN
		IF NEW.`execute_final` IS NOT NULL THEN
			SET @WDAYRESTR = 0;
			SELECT APP_RESTRICTIONS(NEW.`execute_final`, NEW.`type_id`) INTO @WDAYRESTR;
			IF @WDAYRESTR = 1 THEN
				CALL WEEK_DAY_RESTRICTIONS_ERROR();
			END IF;
		END IF;
        set @ACC_ADDR = NULL;
        
    SET @USERNAME = NULL;
    SET @AUTH_NAME = NULL;
		SELECT `address` INTO @ACC_ADDR FROM `accounts_addr` WHERE `uid` = NEW.`uid` AND `type` = 2;
		IF @ACC_ADDR IS NOT NULL THEN
			SET NEW.`address` = @ACC_ADDR;
		END IF;
		IF NEW.`uid` IS NOT NULL AND NEW.`uid` > 0 THEN
			SELECT `name` INTO @USERNAME FROM `accounts` WHERE `uid` = NEW.`uid`;
			SET NEW.`username` = @USERNAME;
		END IF;
		SELECT `fio` INTO @AUTH_NAME FROM `managers` WHERE `person_id` = NEW.`author_id`;
		IF @AUTH_NAME IS NOT NULL THEN
			SET NEW.`author_name` = @AUTH_NAME;
		END IF;
		IF NEW.`responsible_id` > 0 THEN
			SET @AUTH_NAME = NULL;
			SELECT `fio` INTO @AUTH_NAME FROM `managers` WHERE `person_id` = NEW.`responsible_id`;
			IF @AUTH_NAME IS NOT NULL THEN
				SET NEW.`responsible` = @AUTH_NAME;
			END IF;
		END IF;
		IF NEW.`executor_id` > 0 THEN
			SET @AUTH_NAME = NULL;
			SELECT `fio` INTO @AUTH_NAME FROM `managers` WHERE `person_id` = NEW.`executor_id`;
			IF @AUTH_NAME IS NOT NULL THEN
				SET NEW.`executor` = @AUTH_NAME;
			END IF;
		END IF;
	END IF;
END */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION" */;;
/*!50003 CREATE */ /*!50017 DEFINER=`billing`@`127.0.0.1` */ /*!50003 TRIGGER `applications_update` BEFORE UPDATE ON `applications` FOR EACH ROW BEGIN
	IF @LB_DISABLE_TRIGGERS IS NULL OR @LB_DISABLE_TRIGGERS = 0 THEN
		IF NEW.`execute_final` IS NOT NULL THEN
			IF DATE(OLD.`execute_final`) <> DATE(NEW.`execute_final`) THEN
				SET @WDAYRESTR = 0;
				SELECT APP_RESTRICTIONS(NEW.`execute_final`, NEW.`type_id`) INTO @WDAYRESTR;
				IF @WDAYRESTR = 1 THEN
					CALL WEEK_DAY_RESTRICTIONS_ERROR();
				END IF;
			END IF;
		END IF;
		IF OLD.`uid` > 0 THEN
			IF OLD.`uid` <> NEW.`uid` OR NEW.`uid` IS NULL THEN
				SELECT `template` INTO @UID_ISTEMPL FROM `accounts` WHERE `uid` = OLD.`uid` AND `template` = 2;
				IF @UID_ISTEMPL = 2 THEN
					DELETE FROM `vgroups` WHERE `uid` = OLD.`uid`;
					DELETE FROM `agreements` WHERE `uid` = OLD.`uid`;
					DELETE FROM `accounts` WHERE `uid` = OLD.`uid`;
				END IF;
			END IF;
		END IF;
		IF NEW.`uid` > 0 THEN
			SELECT `name` INTO @UID_NAME FROM `accounts` WHERE `uid` = NEW.`uid`;
			SET NEW.`username` = @UID_NAME;
		END IF;
		SET @COMMENTS = '';
		IF OLD.`username` <> NEW.`username` THEN
			SELECT CONCAT(@COMMENTS, '[%username%]:[%', OLD.`username`, '%]:[%', NEW.`username`, '%]
') INTO @COMMENTS;
		END IF;
		IF OLD.`responsible` <> NEW.`responsible` THEN
			SELECT CONCAT(@COMMENTS, '[%responsible%]:[%', OLD.`responsible`, '%]:[%', NEW.`responsible`, '%]
') INTO @COMMENTS;
		END IF;
		IF OLD.`status_id` <> NEW.`status_id` THEN
			SELECT CONCAT(@COMMENTS, '[%status%]:[%') INTO @COMMENTS;
			SELECT CONCAT(@COMMENTS, `descr`) INTO @COMMENTS FROM `sbss_statuses` WHERE `group` = 1 AND `id` = OLD.`status_id`;
			SELECT CONCAT(@COMMENTS, '%]:[%') INTO @COMMENTS;
			SELECT CONCAT(@COMMENTS, `descr`) INTO @COMMENTS FROM `sbss_statuses` WHERE `group` = 1 AND `id` = NEW.`status_id`;
			SELECT CONCAT(@COMMENTS, '%]
') INTO @COMMENTS;
		END IF;
		IF OLD.`execute_start` <> NEW.`execute_start` THEN
			SELECT CONCAT(@COMMENTS, '[%execute_start%]:[%', OLD.`execute_start`, '%]:[%', NEW.`execute_start`, '%]
') INTO @COMMENTS;
		END IF;
		IF OLD.`execute_final` <> NEW.`execute_final` THEN
			SELECT CONCAT(@COMMENTS, '[%execute_final%]:[%', OLD.`execute_final`, '%]:[%', NEW.`execute_final`, '%]
') INTO @COMMENTS;
		END IF;
		IF OLD.`execute_time` <> NEW.`execute_time` THEN
			SELECT CONCAT(@COMMENTS, '[%execute_time%]:[%', OLD.`execute_time`, '%]:[%', NEW.`execute_time`, '%]
') INTO @COMMENTS;
		END IF;
		IF OLD.`already_done` <> NEW.`already_done` THEN
			SELECT CONCAT(@COMMENTS, '[%already_done%]:[%', OLD.`already_done`, '%]:[%', NEW.`already_done`, '%]
') INTO @COMMENTS;
		END IF;
		IF OLD.`address` <> NEW.`address` THEN
			SELECT CONCAT(@COMMENTS, '[%address%]:[%', OLD.`address`, '%]:[%', NEW.`address`, '%]
') INTO @COMMENTS;
			IF NEW.`address` = 'address' THEN
				SELECT `address` INTO @ACC_ADDR FROM `accounts_addr` WHERE `uid` = NEW.`uid` AND `type` = 2;
				IF @ACC_ADDR IS NOT NULL THEN
					SET NEW.`address` = @ACC_ADDR;
				END IF;
			END IF;
		END IF;
		IF OLD.`task` <> NEW.`task` THEN
			SELECT CONCAT(@COMMENTS, '[%task%]:[%', OLD.`task`, '%]:[%', NEW.`task`, '%]
') INTO @COMMENTS;
		END IF;
		IF LENGTH(@COMMENTS) > 0 THEN
			INSERT INTO `app_comments`(`app_id`, `author_id`, `author_name`, `comments`)
			VALUES(NEW.`record_id`, @logged_person_id, '', @COMMENTS);
		END IF;
	END IF;
END */;;
DELIMITER ;
/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;


