DELIMITER ;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION" */;;
/*!50003 CREATE */ /*!50017 DEFINER=`root`@`localhost` */ /*!50003 TRIGGER `check_catalog` BEFORE UPDATE ON `catalog` FOR EACH ROW BEGIN
	DECLARE used boolean;
	DECLARE CONTINUE HANDLER FOR 1329 SET used = FALSE;
	IF @LB_DISABLE_TRIGGERS IS NULL OR @LB_DISABLE_TRIGGERS = 0 THEN
		SELECT TRUE INTO used
		FROM `tel_cat` `c`
		JOIN `tel_cat_idx` `x` USING(`zone_id`)
		JOIN `categories` `t` USING(`tar_id`, `cat_idx`)
		WHERE `c`.`cat_id` = NEW.`cat_id` AND `t`.`oper_id` <> NEW.`oper_id`
		LIMIT 1;
		IF used THEN
			CALL ERROR_INCONSISTENT_RECORD();
		END IF;
	END IF;
END */;;
DELIMITER ;
/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;


