  `dis_prior` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Приоритет применения скидок: 0-min стоимость, 1-по объему, 2-по времени, 3-max стоимость',
  `descr` varchar(255) NOT NULL DEFAULT '' COMMENT 'Описание категории',
