  `round_seconds` int(11) NOT NULL DEFAULT '1' COMMENT 'Округлять с точностью до... (сек)',
  `min_charge_dur` int(11) NOT NULL DEFAULT '0' COMMENT 'Минимальная длительность звонка после округления (сек)',
  `enabled` tinyint(1) NOT NULL DEFAULT '1' COMMENT 'Сервис, описываемый категорией, включен в подписку по умолчанию',
  `available` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Возможность назначать/отменять подписку на сервис из клиентского интерфейса',
  `archive` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Категория удалена (флаг)',
  `script` varchar(255) NOT NULL DEFAULT '' COMMENT 'Скрипт, выполняемый при назначении услуги (cmd:scriptname или mysql:scriptname), на вход скрипта подается serv_id',
  `sale_dictionary_id` int(11) DEFAULT NULL COMMENT 'Идентификатор услуги, связанной с категорией',
  `code_okei` int(3) DEFAULT NULL COMMENT 'Единица измерения услуги из справочника ОКАИ',
  `keep_turned_on` tinyint(1) DEFAULT '0' COMMENT 'Флаг отключения пакета ЦТВ: 0 - отключать, 1 - удерживать включенным',
  `auto_assign` tinyint(1) DEFAULT '0' COMMENT 'Флаг автоматического назначения услуги при смене тарифа (только при условии авто-назначения всех категорий с тарифа): 0 - не назначать, 1 - назначать',
  `serv_func_id` int(11) DEFAULT NULL COMMENT 'Идентификатор (ссылка) на сервисную функцию, управляющую данной услугой',
  `descr_full` text COMMENT 'Подробное описание услуги',
  `link` varchar(255) NOT NULL DEFAULT '' COMMENT 'Ссылка на подробное описание услуги',
  `script_off` varchar(255) NOT NULL DEFAULT '' COMMENT 'Скрипт, выполняемый при отключении услуги (cmd:scriptname или mysql:scriptname), на вход скрипта подается serv_id',
  `dtv_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Тип услуги ЦТВ: 0-N/A, 1 - ChannelsPackage, 2 - Channel, 3 - VAS, 4 - VOD, 5 - PPVEvent, 6 - PPVBlock, 7 - PPVBundle, 8 - Advert',
  `owner` int(11) DEFAULT NULL,
