DELIMITER ;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION" */;;
/*!50003 CREATE */ /*!50017 DEFINER=`root`@`localhost` */ /*!50003 TRIGGER `charges_after_insert` AFTER INSERT ON `charges` FOR EACH ROW BEGIN
	IF @LB_DISABLE_TRIGGERS IS NULL OR @LB_DISABLE_TRIGGERS = 0 THEN
		CALL CHARGE_IMPL(NEW.`vg_id`, NEW.`agrm_id`, NEW.`period`, LAST_DAY(NEW.`period`) + interval 1 day - interval 1 month, NEW.`amount`);
	END IF;
END */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION" */;;
/*!50003 CREATE */ /*!50017 DEFINER=`root`@`localhost` */ /*!50003 TRIGGER `charges_before_update` BEFORE UPDATE ON `charges` FOR EACH ROW BEGIN
	IF @LB_DISABLE_TRIGGERS IS NULL OR @LB_DISABLE_TRIGGERS = 0 THEN
		CALL CHARGE_IMPL(NEW.`vg_id`, NEW.`agrm_id`, NEW.`period`, LAST_DAY(NEW.`period`) + interval 1 day - interval 1 month, NEW.`amount` - OLD.`amount`);
	END IF;
END */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION" */;;
/*!50003 CREATE */ /*!50017 DEFINER=`root`@`localhost` */ /*!50003 TRIGGER `charges_before_delete` BEFORE DELETE ON `charges` FOR EACH ROW BEGIN
	IF @LB_DISABLE_TRIGGERS IS NULL OR @LB_DISABLE_TRIGGERS = 0 THEN
		CALL CHARGE_IMPL(OLD.`vg_id`, OLD.`agrm_id`, OLD.`period`, LAST_DAY(OLD.`period`) + interval 1 day - interval 1 month, -OLD.`amount`);
	END IF;
END */;;
