  `cntout` int(11) NOT NULL DEFAULT '0' COMMENT 'Количество исходящих вызовов для учетной записи за день',
  `additional` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Трафик прошлого периода, загруженный в текущем (флаг)',
