# Dump of table documents
# ------------------------------------------------------------

DROP TABLE IF EXISTS `documents`;

CREATE TABLE `documents` (
  `doc_id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'Идентификатор шаблона',
  `name` varchar(128) DEFAULT NULL COMMENT 'Имя шаблона',
  `cur_id` int(11) NOT NULL DEFAULT '1' COMMENT 'Валюта документа',
  `nds_above` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'В сумму документа включен НДС (флаг)',
  `template` varchar(255) DEFAULT NULL COMMENT 'Имя файла шаблона на диске',
  `save_path` varchar(255) DEFAULT NULL COMMENT 'Путь к папке для сохранения сгенерированных по шаблону документов',
  `group_path` varchar(255) DEFAULT NULL COMMENT 'Путь к папке для сохранения сгруппированных документов',
  `usergroup_id` int(11) DEFAULT NULL COMMENT 'Идентификатор группы пользователей для автоматической генерации документов',
  `group_id` int(11) DEFAULT NULL COMMENT 'Идентификатор объединения для автоматической генерации документов',
  `payable` tinyint(1) DEFAULT '0' COMMENT 'Документ оплачивается 0-без оплаты, 1-постоплата, 2-предоплата, 3-предоплата с учетом услуг',
  `client_allowed` tinyint(1) DEFAULT '0' COMMENT 'Сгенерированные документы доступны из кабинета клиента',
  `upload_ext` varchar(64) DEFAULT NULL COMMENT 'Тип MIME для сгенерированных файлов',
  `hidden` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Скрыть шаблон из списков при генерации (флаг)',
  `onfly` tinyint(11) NOT NULL DEFAULT '0' COMMENT 'Категория документа:0-счет,1-договор,2-отчет,3-квитанция,4-Заявка,5-уведомление о признании должником,6-документ у.з.,7-отчет по платежам,8-выгрузка',
  `detail` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Не использовать агрегированные данные из таблиц reportYYYYMM (Флаг)',
  `file_naming` int(11) NOT NULL DEFAULT '0' COMMENT 'Именование файлов на диске: 0-orders.order_id, 1-accounts_addr.address (почтовый индекс), 2-agreements.number',
  `penalty_cost` decimal(20,6) NOT NULL DEFAULT '0.000000' COMMENT 'Стоимость просрочки в процентах от стоимости документа в единицу времени',
  `penalty_interval` varchar(64) NOT NULL DEFAULT '' COMMENT 'Срок оплаты основного счета (1 month, 45 day etc)',
  `penalty_limit` decimal(20,6) NOT NULL DEFAULT '0.000000' COMMENT 'Ограничение суммы штрафа по документу (в валюте документа)',
  `penalty_period` enum('D','M') NOT NULL DEFAULT 'D' COMMENT 'Период начисления штрафов (день, месяц)',
  `document_period` tinyint(1) DEFAULT '0' COMMENT 'Период формирования отчета: 0-месяц, 1-период, 2-день',
  `gen_for_subscribers` tinyint(1) DEFAULT '0' COMMENT 'Доставка счетов по email только подписчикам',
  `total_summ` tinyint(1) DEFAULT '0' COMMENT 'Определение суммы счета или квитанции: 0-По умолчанию,1-Первичные списания,2-По шаблону,3-Документы о начислениях',
  PRIMARY KEY (`doc_id`),
  KEY `hidden` (`hidden`),
  KEY `onfly` (`onfly`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='Шаблоны документов';



