  `fio` varchar(240) NOT NULL DEFAULT '' COMMENT 'Полное имя',
  `email` varchar(255) NOT NULL DEFAULT '' COMMENT 'Email',
  `descr` varchar(500) DEFAULT NULL COMMENT 'Описание',
  `office` varchar(32) NOT NULL DEFAULT '' COMMENT 'Номер или описание офиса',
  `external_id` varchar(64) DEFAULT NULL COMMENT 'Идентификатор менеджера во внешней системе',
  `cash_register_folder` varchar(255) DEFAULT NULL COMMENT 'Папка на локальной машине менеджера для сохранения данных ККМ',
