  `payments` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Внешняя Платежная Система (флаг)',
  `template` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Шаблон ли это? Шаблон - учетная запись менеджера без возможности логина',
  `parent_template` int(11) DEFAULT NULL COMMENT 'Ссылка на шаблон данного менеджера',
  `archive` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Запись удалена (флаг)',
