  `use_advance` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Разрешить проведение авансовых платежей внешней платежной системе',
  PRIMARY KEY (`person_id`),
  UNIQUE KEY `login` (`login`),
  KEY `archive` (`archive`),
  KEY `arch_pay` (`payments`,`archive`),
  KEY `managers_ibfk_1` (`pay_class_id`),
  CONSTRAINT `managers_ibfk_1` FOREIGN KEY (`pay_class_id`) REFERENCES `pay_classes` (`class_id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='Менеджеры АСР и их привилегии';


