  `name` varchar(255) NOT NULL DEFAULT '' COMMENT 'Имя атрибута',
  `radius_type` smallint(5) unsigned NOT NULL DEFAULT '0' COMMENT 'Номер атрибута или номер VSA, если vendor > 0',
  `vendor` int(10) unsigned NOT NULL DEFAULT '0' COMMENT 'Номер вендора',
  `value_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Тип значения: 0-integer, 1-string, 2-AVPair, 3-IP, 4-timestamp, 5-URL, 6-octets, 7-sublist',
  `replace_id` int(11) DEFAULT NULL COMMENT 'Идентификатор записи подменяемого атрибута',
  `tagged` int(11) DEFAULT '0' COMMENT 'Тегированный атрибут (флаг)',
  `to_history` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Сохранять ли значение атрибута в таблице auth_history_attrs (флаг)',
  `default` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Атрибут создается из create / update',
  PRIMARY KEY (`record_id`),
  UNIQUE KEY `dict` (`nas_id`,`name`),
  UNIQUE KEY `repl` (`replace_id`,`nas_id`),
  KEY `vendor` (`vendor`),
  KEY `to_history` (`to_history`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='Словарь RADIUS атрибутов';



