  `re_summ` decimal(20,6) NOT NULL DEFAULT '0.000000' COMMENT 'Общая сумма документа в валюте лицевого счета',
  `curr_summ` decimal(20,6) NOT NULL DEFAULT '0.000000' COMMENT 'Общая сумма документа в валюте лицевого счета',
