  KEY `agrm_id` (`agrm_id`),
  KEY `grouped_order_id` (`grouped_order_id`),
  CONSTRAINT `orders_ibfk_1` FOREIGN KEY (`agrm_id`) REFERENCES `agreements` (`agrm_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `orders_ibfk_2` FOREIGN KEY (`oper_id`) REFERENCES `accounts` (`uid`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `orders_ibfk_3` FOREIGN KEY (`grouped_order_id`) REFERENCES `grouped_orders` (`order_id`) ON DELETE SET NULL ON UPDATE CASCADE
