# Dump of table payments_history
# ------------------------------------------------------------

DROP TABLE IF EXISTS `payments_history`;

CREATE TABLE `payments_history` (
  `record_id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'Идентификатор версии платежа',
  `origin_record_id` int(11) NOT NULL COMMENT 'Идентификатор платежа, к которому относится данное исправление',
  `agrm_id` int(11) NOT NULL COMMENT 'Идентификатор лицевого счета зачисления платежа',
  `agrm_id_new` int(11) NOT NULL COMMENT 'Идентификатор нового лицевого счёта зачисления платежа',
  `amount` decimal(20,6) NOT NULL COMMENT 'Сумма платежа в валюте лицевого счета, пересчитанная на дату платежа',
  `amount_new` decimal(20,6) NOT NULL COMMENT 'Новая сумма платежа в валюте лицевого счета, пересчитанная на дату платежа',
  `comment` varchar(500) NOT NULL COMMENT 'Комментарий к платежу',
  `comment_new` varchar(500) NOT NULL COMMENT 'Новый комментарий к платежу',
  `receipt` varchar(128) DEFAULT NULL COMMENT 'Идентификатор документа, подтверждающего платёж',
  `pay_date` datetime NOT NULL COMMENT 'Дата платежа (пересчёты сумм(разностей сумм) из одной валюты в другую выполняются на эту дату)',
  `local_date` datetime NOT NULL COMMENT 'Дата создания/изменения платежа по часам АСР',
  `local_date_new` datetime NOT NULL COMMENT 'Новая дата создания/изменения платежа по часам АСР',
  `cancel_date` datetime DEFAULT NULL COMMENT 'Дата аннулирования платежа',
  `cancel_date_new` datetime DEFAULT NULL COMMENT 'Новая дата аннулирования платежа',
  `period_date` date DEFAULT NULL COMMENT 'Период бух.учета, к которому относится платёж',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Статус платежа: 0-платеж проведен, 1-проведен и подтвержден сверкой (при загрузке файла сверки), 2-платеж аннулирован',
  `status_new` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Новый статус платежа',
  `mod_person` int(11) NOT NULL COMMENT 'Идентификатор менеджера создавшего/изменившего платёж',
  `mod_person_new` int(11) NOT NULL COMMENT 'Идентификатор менеджера создавшего/изменившего новый платёж',
  `order_id` int(11) DEFAULT NULL COMMENT 'Идентификатор оплачиваемого счёта',
  `order_id_new` int(11) DEFAULT NULL COMMENT 'Идентификатор нового оплачиваемого счёта',
  `class_id` int(11) NOT NULL COMMENT 'Идентификатор категории платежа',
  `agrm_number` varchar(64) DEFAULT NULL COMMENT 'Номер договора авансового платежа',
  `amount_cur` decimal(20,6) NOT NULL COMMENT 'Сумма платежа в валюте платежа',
  `amount_cur_new` decimal(20,6) NOT NULL COMMENT 'Новая сумма платежа в валюте платежа',
  `amount_cur_id` int(11) NOT NULL COMMENT 'Валюта платежа',
  `from_agrm_id` int(11) DEFAULT NULL COMMENT 'Идентификатор лицевого счёта, с которого поступил платёж',
  `bso_id` int(11) DEFAULT NULL COMMENT 'Идентификатор бланка строгой отчетности',
  `uuid` varchar(40) DEFAULT NULL COMMENT 'Идентификатор платежа для интеграции с внешними системами',
  `check_sum` varchar(32) DEFAULT NULL COMMENT 'Контрольная сумма',
  PRIMARY KEY (`record_id`),
  KEY `origin_record_id` (`origin_record_id`,`local_date_new`),
  KEY `agrm_id_local_date` (`agrm_id`,`local_date`),
  KEY `pay_date` (`pay_date`),
  KEY `local_date` (`local_date`),
  KEY `local_date_new` (`local_date_new`),
  KEY `period_date` (`period_date`,`pay_date`),
  KEY `agrm_id` (`agrm_id`),
  KEY `agrm_id_new` (`agrm_id_new`),
  KEY `from_agrm_id` (`from_agrm_id`),
  KEY `uuid` (`uuid`),
  KEY `payments_history_ibfk_4` (`class_id`),
  KEY `payments_history_ibfk_5` (`amount_cur_id`),
  KEY `payments_history_ibfk_6` (`bso_id`),
  CONSTRAINT `payments_history_ibfk_1` FOREIGN KEY (`origin_record_id`) REFERENCES `payments` (`record_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `payments_history_ibfk_2` FOREIGN KEY (`agrm_id`) REFERENCES `agreements` (`agrm_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `payments_history_ibfk_3` FOREIGN KEY (`agrm_id_new`) REFERENCES `agreements` (`agrm_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `payments_history_ibfk_4` FOREIGN KEY (`class_id`) REFERENCES `pay_classes` (`class_id`) ON UPDATE CASCADE,
  CONSTRAINT `payments_history_ibfk_5` FOREIGN KEY (`amount_cur_id`) REFERENCES `currency` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `payments_history_ibfk_6` FOREIGN KEY (`bso_id`) REFERENCES `bso_doc` (`record_id`) ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='История исправлений платежей';



