CREATE TABLE `pre_payments` (
  `record_id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'Идентификатор предварительного платежа',
  `number` varchar(256) NOT NULL COMMENT 'Идентификатор авторизации абонента',
