  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Статус платежа:0-запрос на проведение платежа,1-проведен и подтвержден сверкой,2-платеж аннулирован',
  `manager_id` int(11) DEFAULT NULL COMMENT 'Идентификатор менеджера (ВПС) через которого произведен платёж',
