  CONSTRAINT `pre_payments_ibfk_3` FOREIGN KEY (`payment_id`) REFERENCES `payments` (`record_id`) ON UPDATE CASCADE,
  CONSTRAINT `pre_payments_ibfk_4` FOREIGN KEY (`agrm_id`) REFERENCES `agreements` (`agrm_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='Платежи для подтверждения со стороны третьей системы';



