  `pay_id` int(11) NOT NULL COMMENT 'Идентификатор платежа из `payments` при погашении обещания или -1, если платеж просрочен и предоставленный кредит аннулирован',
  `mod_person` int(11) DEFAULT NULL COMMENT 'Идентификатор менеджера, совершившего платеж, или NULL, если платеж инициирован абонентом',
