# Dump of table radius_stat_cache
# ------------------------------------------------------------

DROP TABLE IF EXISTS `radius_stat_cache`;

CREATE TABLE `radius_stat_cache` (
  `record_id` bigint(20) unsigned NOT NULL AUTO_INCREMENT COMMENT 'Идентификатор записи',
  `agent_id` int(11) unsigned DEFAULT NULL COMMENT 'Идентификатор агента, которому принадлежит трафик',
  `ip` binary(16) DEFAULT NULL COMMENT 'IP адрес из подучетных сегменов, которому принадлежит трафик',
  `remote` binary(16) DEFAULT NULL COMMENT 'Идентификатор удаленного ресурса (пока не используется)',
  `cin` bigint(20) unsigned DEFAULT NULL COMMENT 'Входящий трафик (байт)',
  `cout` bigint(20) unsigned DEFAULT NULL COMMENT 'Исходящий трафик (байт)',
  `tm` int(11) unsigned DEFAULT NULL COMMENT 'Потребленный трафик в секундах',
  `timefrom` datetime DEFAULT NULL COMMENT 'Время начала агрегирования трафика (по часам агента)',
  `timeto` datetime DEFAULT NULL COMMENT 'Время сброса статистики в БД',
  `ani` varchar(255) DEFAULT NULL COMMENT 'Транспортный адрес клиента (Calling-Station-Id)',
  `dnis` varchar(255) DEFAULT NULL COMMENT 'Транспортный адрес сервера доступа (Called-Station-Id)',
  `uuid` varchar(255) DEFAULT NULL COMMENT 'Код для связки с внешней системой',
  `vg_id` int(11) unsigned DEFAULT NULL COMMENT 'Идентификатор учетной записи, которой принадлежит трафик',
  `agrm_id` int(11) unsigned DEFAULT NULL COMMENT 'Идентификатор лицевого счета, с которого производилось списание',
  `amount` decimal(20,6) DEFAULT NULL COMMENT 'Размер списания',
  `tar_id` int(11) unsigned DEFAULT NULL COMMENT 'Идентификатор тарифа',
  `cat_idx` int(11) unsigned DEFAULT NULL COMMENT 'Идентификатор категории тарифа',
  `size_discount` int(11) unsigned DEFAULT NULL COMMENT 'Идентификатор скидки по объему (0, если скидки нет)',
  `time_discount` int(11) unsigned DEFAULT NULL COMMENT 'Идентификатор скидки по времени (0, если скидки нет)',
  `rent` smallint(5) unsigned DEFAULT NULL COMMENT 'Флаг включения трафик в абонентскую плату:0-подсчет по превышению,1-часть трафика включена в тариф, -1-трафик NETFLOW',
  `service` varchar(255) DEFAULT NULL COMMENT 'Название сервиса',
  `session_id` varchar(255) DEFAULT NULL COMMENT 'Идентификатор сессии',
  `nas` binary(16) DEFAULT NULL COMMENT 'IP адрес сервера доступа',
  `parent_session_id` varchar(255) DEFAULT NULL COMMENT 'Идентификатор родительской сессии',
  `need_calc` smallint(5) DEFAULT NULL COMMENT 'Состояние записи: 0 - запись рассчитана',
  `cause` smallint(5) DEFAULT NULL COMMENT 'Причина завершения сессии: -1 - завершена агентом по таймауту, 0 - сессия активна, ...',
  `qin` bigint(20) unsigned DEFAULT NULL COMMENT 'Непротарифицированный входящий трафик (байт)',
  `qout` bigint(20) unsigned DEFAULT NULL COMMENT 'Непротарифицированный исходящий трафик (байт)',
  `is_guest` tinyint(1) unsigned NOT NULL DEFAULT '0' COMMENT 'Является ли сессия гостевой:0-нет, 1-является',
  `table_name` varchar(16) DEFAULT NULL COMMENT 'Название таблицы, в которую необходимо положить трафик',
  `group_by_hour` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'группировка по часам',
  PRIMARY KEY (`record_id`),
  KEY `t_index_key` (`group_by_hour`,`nas`,`session_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='Буфер для данных о трафике для агентов Radius';



