# ------------------------------------------------------------

DROP TABLE IF EXISTS `rnas`;

CREATE TABLE `rnas` (
  `nas_id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'Идентификатор NASа',
  `id` int(11) NOT NULL COMMENT 'Идентификатор агента, с которым работает NAS',
  `rnas` binary(16) NOT NULL COMMENT 'адрес NASа в бинарном формате',
  `rsharedsec` varchar(32) DEFAULT 'secret' COMMENT 'Разделяемый секрет',
  `device_id` int(11) DEFAULT NULL COMMENT 'Ссылка на устройство',
  `type` varchar(32) DEFAULT 'generic' COMMENT 'Тип NAS - generic, cisco_isg, redback',
  `auth_method` varchar(128) DEFAULT 'AUTO' COMMENT 'Метод авторизации. Для VOIP:AUTO,PASSWORD,ANI,DIGEST,CHAP,H323. Для ШПД:AUTO,MAC,LOGIN,OPT82,ANI,CARD,IP,VLANS,CARD_OPT82',
  `dae_server` varchar(64) DEFAULT NULL COMMENT 'Сервер для отправки CoA- и POD-пакетов',
  `dae_port` int(11) unsigned DEFAULT NULL COMMENT 'Порт для отправки CoA- и POD-пакетов',
  `descr` varchar(255) NOT NULL DEFAULT '' COMMENT 'Описание',
  `timezone` decimal(6,2) NOT NULL DEFAULT '0.00' COMMENT 'Временная зона',
  PRIMARY KEY (`nas_id`),
  UNIQUE KEY `rnas_id_unique_key` (`id`,`rnas`),
  KEY `id` (`id`,`nas_id`),
  KEY `device_id` (`device_id`),
  CONSTRAINT `rnas_ibfk_1` FOREIGN KEY (`id`) REFERENCES `settings` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `rnas_ibfk_2` FOREIGN KEY (`device_id`) REFERENCES `devices` (`device_id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='Серверы доступа (NAS)';


