    INSERT INTO tm_rnas SET tm_mark = unix_timestamp(), nas_id = NEW.nas_id ON DUPLICATE KEY UPDATE tm_mark = unix_timestamp();
END */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION" */;;
/*!50003 CREATE */ /*!50017 DEFINER=`root`@`localhost` */ /*!50003 TRIGGER `rnas_update_tm` AFTER UPDATE ON `rnas` FOR EACH ROW BEGIN
    INSERT INTO tm_rnas SET tm_mark = unix_timestamp(), nas_id = NEW.nas_id ON DUPLICATE KEY UPDATE tm_mark = unix_timestamp();
END */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION" */;;
/*!50003 CREATE */ /*!50017 DEFINER=`root`@`localhost` */ /*!50003 TRIGGER `rnas_delete_tm` AFTER DELETE ON `rnas` FOR EACH ROW BEGIN
    INSERT INTO tm_rnas SET tm_mark = unix_timestamp(), nas_id = OLD.nas_id ON DUPLICATE KEY UPDATE tm_mark = unix_timestamp();
