  `count` decimal(20,6) NOT NULL COMMENT 'Количество единиц оказанной услуги в единицах из справочника услуг',
  `price_cur` decimal(20,6) NOT NULL COMMENT 'Цена за единицу услуги с НДС в валюте документа',
  `amount_cur` decimal(20,6) NOT NULL COMMENT 'Стоимость услуги с НДС в валюте документа',
  `amount_cur_vat` decimal(20,6) NOT NULL COMMENT 'Сумма НДС в валюте документа',
  `price` decimal(20,6) NOT NULL COMMENT 'Цена за единицу услуги с НДС в валюте договора',
  `amount` decimal(20,6) NOT NULL COMMENT 'Стоимость услуги с НДС в валюте договора',
  `amount_vat` decimal(20,6) NOT NULL COMMENT 'Сумма НДС в валюте договора',
  `record_id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'идентификатор детальных данных о продажах',
  `vg_id` int(11) DEFAULT NULL COMMENT 'reserved for future use ссылка на учетную запись',
