  CONSTRAINT `sale_details_ibfk_3` FOREIGN KEY (`vg_id`) REFERENCES `vgroups` (`vg_id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='Детализация документов о начислениях';



# Dump of table sale_dictionary
# ------------------------------------------------------------

DROP TABLE IF EXISTS `sale_dictionary`;

CREATE TABLE `sale_dictionary` (
  `record_id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'Идентификатор услуги',
  `gaap` int(11) NOT NULL COMMENT 'Код GAAP (код вида услуги)',
  `name` text NOT NULL COMMENT 'Наименование услуги',
  `unit` varchar(6) DEFAULT NULL COMMENT 'Единица измерения услуги',
  `unit_mult` decimal(20,6) DEFAULT NULL COMMENT 'Коэффициент пересчёта количества услуги из единиц учёта в единицы измерения',
  `mod_person` int(11) DEFAULT NULL COMMENT 'Идентификатор менеджера, внёсшего/исправившего данную услугу (опционально)',
  `code_okei` int(11) DEFAULT NULL COMMENT 'Единица измерения услуги из справочника ОКЕИ',
  `serv_type` int(11) NOT NULL DEFAULT '0' COMMENT 'Тип услуги 0 - услуга, 1 - продажа, 2 - аренда',
  `last_mod_date` timestamp NOT NULL DEFAULT '0000-00-00 00:00:00' ON UPDATE CURRENT_TIMESTAMP COMMENT 'Метка времени последней модификации',
  `uuid` varchar(40) DEFAULT NULL COMMENT 'Код для связки с внешней системой',
  `protected` tinyint(1) DEFAULT '0' COMMENT 'Запись не м.б. удалена (флаг)',
  `level_1_1C` varchar(255) DEFAULT '' COMMENT 'Уровень 1 номенклатуры 1С',
  `level_2_1C` varchar(255) DEFAULT '' COMMENT 'Уровень 2 номенклатуры 1С',
  `level_3_1C` varchar(255) DEFAULT '' COMMENT 'Уровень 3 номенклатуры 1С',
  PRIMARY KEY (`record_id`),
  UNIQUE KEY `sale_dictionary_ubk_1` (`uuid`),
  KEY `sale_dictionary_ibfk_1` (`code_okei`),
  CONSTRAINT `sale_dictionary_ibfk_1` FOREIGN KEY (`code_okei`) REFERENCES `dict_okei` (`record_id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='Справочник кодов услуг';


DELIMITER ;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION" */;;
/*!50003 CREATE */ /*!50017 DEFINER=`root`@`localhost` */ /*!50003 TRIGGER `sale_dictionary_delete` BEFORE DELETE ON `sale_dictionary` FOR EACH ROW BEGIN
	IF @LB_DISABLE_TRIGGERS IS NULL OR @LB_DISABLE_TRIGGERS = 0 THEN
		IF old.protected THEN
            CALL ERORR_CANT_DELETE_PROTECTED_RECORD();
        END IF;
	END IF;
END */;;
DELIMITER ;
/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;


