  `amount_vat` decimal(20,6) NOT NULL COMMENT 'Сумма НДС по документу в валюте лицевого счета (пересчитанная на дату платежа)',
  `receipt_seq` int(11) NOT NULL COMMENT 'Внутренний номер акта/счёта фактуры',
  `receipt` varchar(64) NOT NULL COMMENT 'Номер акта/счёта-фактуры',
  `sale_date` datetime NOT NULL COMMENT 'Дата документа (Все пересчёты сумм(разностей сумм) из одной валюты в другую выполняются на эту дату)',
  `local_date` datetime NOT NULL COMMENT 'Дата последнего изменения документа по часам АСР',
  `cancel_date` datetime DEFAULT NULL COMMENT 'Дата аннулирования документа',
  `period_date` date DEFAULT NULL COMMENT 'Период бух.учета, к которому относится последняя версия документа',
  `bdate` date NOT NULL COMMENT 'Начало периода, за который рассчитаны услуги (Услуги за эту дату включены в документ)',
  `edate` date NOT NULL COMMENT 'Конец периода, за который рассчитаны услуги (Услуги за эту дату НЕ включены в документ)',
  `comment` varchar(255) NOT NULL COMMENT 'Комментарий к последней версии документа',
  `mod_person` int(11) NOT NULL COMMENT 'Идентификатор менеджера, создавшего последнюю версию документа',
  `pay_date` date DEFAULT NULL COMMENT 'Дата оплаты документа. Выставляется автоматически при покрытии документа платежом',
  `delta` decimal(20,6) DEFAULT '0.000000' COMMENT 'Остаток округления суммы списаний при формировании документа',
  PRIMARY KEY (`sale_id`),
  KEY `receipt_seq` (`sale_date`,`oper_id`,`receipt_seq`),
  KEY `agrm_id` (`agrm_id`),
  KEY `receipt` (`receipt`),
  KEY `sale_date` (`sale_date`),
  KEY `local_date` (`local_date`),
  KEY `period_date` (`agrm_id`,`period_date`),
  KEY `agrm_id_localdate` (`agrm_id`,`local_date`),
  KEY `bedate` (`bdate`,`edate`),
  KEY `paydate` (`pay_date`),
  KEY `mod_person` (`mod_person`),
  KEY `sales_ibfk_2` (`oper_id`),
  KEY `sales_ibfk_3` (`amount_cur_id`),
  KEY `sales_ibfk_4` (`owner_id`),
  CONSTRAINT `sales_ibfk_1` FOREIGN KEY (`agrm_id`) REFERENCES `agreements` (`agrm_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `sales_ibfk_2` FOREIGN KEY (`oper_id`) REFERENCES `accounts` (`uid`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `sales_ibfk_3` FOREIGN KEY (`amount_cur_id`) REFERENCES `currency` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `sales_ibfk_4` FOREIGN KEY (`owner_id`) REFERENCES `accounts` (`uid`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='Документы о начислениях';



