  `na_pass` varchar(64) NOT NULL DEFAULT 'billing' COMMENT 'Пароль для доступа к БД агента',
  `nfhost` binary(16) DEFAULT NULL COMMENT 'Прослушиваемый адрес для агентов Netflow(IPv4)',
  `nfhost6` binary(16) DEFAULT NULL COMMENT 'Прослушиваемый адрес для агентов Netflow(IPv6)',
  `nfport` int(11) NOT NULL DEFAULT '0' COMMENT 'Прослушиваемый порт для агентов Netflow',
  `local_as_num` int(11) unsigned NOT NULL DEFAULT '0' COMMENT 'Номер локальной AS (для Netflow)',
  `use_rtime` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Использовать временную метку из датаграммы при записи трафика (для Netflow)',
  `day` date NOT NULL DEFAULT '0000-00-00' COMMENT 'Последние сутки, выгруженные в табл. `day`',
  `raccport` int(11) NOT NULL DEFAULT '0' COMMENT 'Порт RADIUS аккаунтинга',
  `rauthport` int(11) NOT NULL DEFAULT '0' COMMENT 'Порт RADIUS аутентификации',
  `remulate_on_naid` int(11) NOT NULL DEFAULT '0' COMMENT 'Идентификатор кабельного агента для режима эмуляции агента RADIUS/DialUP',
  `raddrpool` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Выдавать адреса динамически из пула (флаг)',
  `save_stat_addr` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Сохранять статическое распределение адресов в режиме работы с пулом (флаг)',
  `eapcertpassword` varchar(64) NOT NULL DEFAULT '' COMMENT 'Пароль к EAP сертификату',
  `rad_stop_expired` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Запускать script_stop для зависших RADIUS сессий (флаг)',
  `max_radius_timeout` int(11) NOT NULL DEFAULT '86400' COMMENT 'Максимальная продолжительность RADIUS сессии',
  `session_lifetime` int(11) NOT NULL DEFAULT '86400' COMMENT 'Время жизни RADIUS сессии, по истечении которого с момента последнего Accounting пакета сессия считается зависшей',
  `restart_shape` tinyint(1) DEFAULT '1' COMMENT 'Запускать script_stop при изменении текущей скорости (флаг)',
  `ignorelocal` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Игнорировать локальный трафик (флаг). Локальный трафик - трафик между IP, входящими в сегменты агента. Для USBox - назначать услуги тарифа измененного по расписанию',
  `multiply` int(11) NOT NULL DEFAULT '1024' COMMENT 'Число байт в 1Кб (параметр для возможности введения поправки на размер заголовков канального уровня)',
  `lastcontact` datetime NOT NULL DEFAULT '0000-00-00 00:00:00' COMMENT 'Время последней активности агента',
  `adm_notify` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Контроль уведомлений администратора о неактивности агента (флаг). При отсылке уведомления флаг устанавливается в 1, после проявления активности агента - сбрасывается в 0',
  `tel_direction_mode` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Алгоритм определения направления: 0-по умолчанию, 1-по абонентской базе',
  `failed_calls` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Для тел. агентов - заносить в БД записи о неудавшихся вызовах, для агентов платформы интернет - не учитывать трафик заблокированных у.з.',
  `voip_card_user` varchar(128) NOT NULL DEFAULT '' COMMENT 'Значение атрибута User-Name, используемое для авторизации карты без серийного номера (только по PIN)',
  `recalc_stat` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Запрос на перерасчет детальной статистики: -2-зарезервировано для UCD-тарификатора, -1-удаление статистики с откатом баланса, 1-перерасчет с повторным определением владельца трафика, 2-перерасчет с сохранением владельца трафика, 3-сохранение владельца и тарифа на момент списания',
  `recalc_rent` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Запрос на перерасчет абон. платы: -1-удаление статистики с откатом баланса, 1 - перерасчет по текущему тарифу, 2 - перерасчет с сохранением тарифа на момент списания',
  `recalc_date` date NOT NULL DEFAULT '0000-00-00' COMMENT 'Перерасчет, начиная с указанной даты',
  `recalc_group` int(11) NOT NULL DEFAULT '0' COMMENT 'Идентификатор объединения, для которого затребован перерасчет (0 - для всех учетных записей)',
  `recalc_current` date NOT NULL DEFAULT '0000-00-00' COMMENT 'Дата последних протарифицированных суток',
  `oper_cat` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Определять оператора по каталогу направлений (флаг, 0 - по признаку оператора);Авторизовывать несуществующих пользователей в гостевой сети',
  `keepdetail` int(11) NOT NULL DEFAULT '0' COMMENT 'Хранить детальную статистику (дней). 0 - бессрочно.',
  `rid` varbinary(16) DEFAULT NULL COMMENT 'Уникальный идентификатор записи в рамках БД',
  `last_mod_date` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'Метка времени последней модификации записи',
  `archive` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Запись удалена (флаг)',
  PRIMARY KEY (`id`),
  KEY `remulate_on_naid` (`remulate_on_naid`),
  KEY `settings_ibfk_2` (`type`),
  CONSTRAINT `settings_ibfk_2` FOREIGN KEY (`type`) REFERENCES `agent_types` (`record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='Сетевые агенты';


