  `record_id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'Идентификатор записи',
  `vg_id` int(11) DEFAULT NULL COMMENT 'Идентификатор учетной записи',
  `equip_id` int(11) DEFAULT NULL COMMENT 'Идентификатор абонентского устройства',
  `segment` binary(16) NOT NULL COMMENT 'IP подсеть (либо AS), назначенная учетной записи',
  `mask` binary(16) NOT NULL COMMENT 'Маска подсети',
  `type` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Тип поля segment: 0-IP подсеть, 1-IP подсеть с привязкой к порту, 2-номер AS',
  `segment_id` int(11) DEFAULT NULL COMMENT 'Идентификатор сегмента, из которого выдана подсеть',
  `rid` varbinary(16) DEFAULT NULL COMMENT 'Уникальный идентификатор записи в рамках БД',
  `last_mod_date` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'Метка времени последней модификации записи',
  `archive` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Запись удалена (флаг)',
  PRIMARY KEY (`record_id`),
  KEY `vg_id` (`vg_id`),
  KEY `equip_id` (`equip_id`),
  KEY `type` (`type`),
  KEY `segment` (`segment`),
  KEY `segment_id` (`segment_id`),
  CONSTRAINT `staff_ibfk_1` FOREIGN KEY (`vg_id`) REFERENCES `vgroups` (`vg_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `staff_ibfk_2` FOREIGN KEY (`segment_id`) REFERENCES `segments` (`record_id`) ON UPDATE CASCADE,
  CONSTRAINT `staff_ibfk_3` FOREIGN KEY (`equip_id`) REFERENCES `equipment` (`equip_id`) ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='Сетевые сегменты, назначенные учетным записям';


DELIMITER ;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION" */;;
/*!50003 CREATE */ /*!50017 DEFINER=`root`@`localhost` */ /*!50003 TRIGGER `staff_insert` AFTER INSERT ON `staff` FOR EACH ROW BEGIN
	IF @LB_DISABLE_TRIGGERS IS NULL OR @LB_DISABLE_TRIGGERS = 0 THEN
		INSERT INTO `staff_history` (`record_id`, `vg_id`, `equip_id`, `segment`, `mask`, `type`, `segment_id`, `timefrom`, `timeto`)
		VALUES (NEW.`record_id`, NEW.`vg_id`, NEW.`equip_id`, NEW.`segment`, NEW.`mask`, NEW.`type`, NEW.`segment_id`, now(), 0);

    
    INSERT INTO tm_staff SET tm_mark = unix_timestamp(), record_id = NEW.record_id ON DUPLICATE KEY UPDATE tm_mark = unix_timestamp();
	END IF;
END */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION" */;;
/*!50003 CREATE */ /*!50017 DEFINER=`root`@`localhost` */ /*!50003 TRIGGER `staff_update_tm` AFTER UPDATE ON `staff` FOR EACH ROW BEGIN
    INSERT INTO tm_staff SET tm_mark = unix_timestamp(), record_id = NEW.record_id ON DUPLICATE KEY UPDATE tm_mark = unix_timestamp();
END */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION" */;;
/*!50003 CREATE */ /*!50017 DEFINER=`root`@`localhost` */ /*!50003 TRIGGER `staff_delete` BEFORE DELETE ON `staff` FOR EACH ROW BEGIN
	IF @LB_DISABLE_TRIGGERS IS NULL OR @LB_DISABLE_TRIGGERS = 0 THEN
		UPDATE staff_history SET timeto = NOW() WHERE `record_id` = OLD.`record_id`;
	END IF;
END */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION" */;;
/*!50003 CREATE */ /*!50017 DEFINER=`root`@`localhost` */ /*!50003 TRIGGER `staff_delete_tm` AFTER DELETE ON `staff` FOR EACH ROW BEGIN
    INSERT INTO tm_staff SET tm_mark = unix_timestamp(), record_id = OLD.record_id ON DUPLICATE KEY UPDATE tm_mark = unix_timestamp();
END */;;
