  `tar_id` int(11) DEFAULT NULL COMMENT 'Идентификатор тарифа',
  `serv_id` int(11) DEFAULT NULL COMMENT 'Идентификатор сервиса из usbox_services',
  `vg_id` int(11) DEFAULT NULL COMMENT 'Идентификатор у.з.',
  `timefrom` datetime DEFAULT NULL COMMENT 'начало действия модификатора',
