  `block_rent` decimal(20,6) DEFAULT NULL COMMENT 'новая а/п при блокировке (абсолютное значение)',
  `rate` decimal(20,6) DEFAULT NULL COMMENT 'процент скидки. если not null, то используем его, иначе абс. значения',
  `discount` decimal(20,6) DEFAULT NULL COMMENT 'Величина скидки от а/п. Используется, если rent и rate is null',
  `block_discount` decimal(20,6) DEFAULT NULL COMMENT 'Величина скидки от а/п при блокировке. Используется, если block_rent и rate is null',
  `block_state` int(11) DEFAULT '4094' COMMENT 'Побитовая маска из 11 значений для учета блокировок,младший бит определяет группу,далее по возрастающей значения блокировок от 0 до 10 включительно',
  `user_packet_id` int(11) DEFAULT NULL COMMENT 'Идентификатор экземпляра пакета, если УЗ входит в пакет, в противном случае NULL',
  `action_staff_id` int(11) DEFAULT NULL COMMENT 'Идентификатор участника акции если модификатор был назначен в связи с подключением к акции, в противном случае NULL',
  `service_id` int(11) DEFAULT NULL COMMENT 'Идентификатор услуги из services',
  `tarifs_rasp_id` int(11) DEFAULT NULL COMMENT 'Идентификатор строки из расписания тарифов',
  `keep_modifier` tinyint(1) DEFAULT '1' COMMENT 'Сохранить модификатор при смене тарифа',
  `parent_record_id` int(11) DEFAULT NULL COMMENT 'Идентификатор родительской записи',
  PRIMARY KEY (`record_id`),
  KEY `vg_id` (`vg_id`),
  KEY `name` (`name`),
  KEY `tar_id` (`tar_id`),
  KEY `times` (`timefrom`,`timeto`),
  KEY `tariff_modifiers_ibfk_2` (`serv_id`),
  KEY `tariff_modifiers_ibfk_3` (`action_staff_id`),
  KEY `tariff_modifiers_ibfk_4` (`user_packet_id`),
  KEY `tariff_modifiers_ibfk_5` (`service_id`),
  CONSTRAINT `tariff_modifiers_ibfk_1` FOREIGN KEY (`vg_id`) REFERENCES `vgroups` (`vg_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `tariff_modifiers_ibfk_2` FOREIGN KEY (`serv_id`) REFERENCES `usbox_services` (`serv_id`) ON UPDATE CASCADE,
  CONSTRAINT `tariff_modifiers_ibfk_3` FOREIGN KEY (`action_staff_id`) REFERENCES `action_staff` (`record_id`) ON UPDATE CASCADE,
  CONSTRAINT `tariff_modifiers_ibfk_4` FOREIGN KEY (`user_packet_id`) REFERENCES `user_packets` (`user_packet_id`) ON UPDATE CASCADE,
  CONSTRAINT `tariff_modifiers_ibfk_5` FOREIGN KEY (`service_id`) REFERENCES `services` (`service_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='Модификаторы тарифов';



