# Dump of table telNNNYYYYmmdd
# ------------------------------------------------------------

DROP TABLE IF EXISTS `telNNNYYYYmmdd`;

CREATE TABLE `telNNNYYYYmmdd` (
  `record_id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'Идентификатор записи',
  `parent_id` int(11) NOT NULL DEFAULT '0' COMMENT 'Идентификатор родительской записи, если тарифицируются несколько участников',
  `numfrom` varchar(32) NOT NULL DEFAULT '' COMMENT 'Номер абонента (номер А, если vg_id=0)',
  `numto` varchar(32) NOT NULL DEFAULT '' COMMENT 'Внешний номер (номер Б, если vg_id=0)',
  `trunk_in` varchar(255) NOT NULL DEFAULT '' COMMENT 'Признак оператора на входящей линии',
  `trunk_out` varchar(255) NOT NULL DEFAULT '' COMMENT 'Признак оператора на исходящей линии',
  `timefrom` datetime DEFAULT NULL COMMENT 'Время начала вызова',
  `duration` int(11) NOT NULL DEFAULT '0' COMMENT 'Продолжительность разговора (сек)',
  `vg_id` int(11) NOT NULL DEFAULT '0' COMMENT 'Идентификатор учетной записи',
  `uid` int(11) NOT NULL DEFAULT '0' COMMENT 'Идентификатор пользователя, которому принадлежит уч. запись',
  `agrm_id` int(11) NOT NULL DEFAULT '0' COMMENT 'Идентификатор лицевого счета',
  `c_date` date NOT NULL DEFAULT '0000-00-00' COMMENT 'Начало отчетного периода, в рамках которого тарифицировалась запись',
  `direction` tinyint(1) NOT NULL DEFAULT '1' COMMENT 'Направление вызова: 0-входящий, 1-исходящий',
  `amount` decimal(20,6) NOT NULL DEFAULT '0.000000' COMMENT 'Размер списаний в валюте тарифа',
  `incall` decimal(20,6) DEFAULT NULL COMMENT 'Информация о звонке содержит стоимость, если NOT NULL',
  `duration_round` int(11) NOT NULL DEFAULT '0' COMMENT 'Продолжительность разговора после округления (сек)',
  `tar_id` int(11) NOT NULL DEFAULT '0' COMMENT 'Идентификатор тарифа',
  `cat_idx` int(11) NOT NULL DEFAULT '0' COMMENT 'Идентификатор категории тарифа',
  `zone_id` int(11) NOT NULL DEFAULT '0' COMMENT 'Идентификатор направления по каталогу',
  `oper_id` int(11) NOT NULL DEFAULT '0' COMMENT 'Идентификатор оператора',
  `rent` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Вызов полностью или частично включен в абон. плату (флаг)',
  `time_discount` int(11) NOT NULL DEFAULT '0' COMMENT 'Идентификатор скидки по времени, если вызов полностью или частично попал под действие скидки',
  `size_discount` int(11) NOT NULL DEFAULT '0' COMMENT 'Идентификатор скидки по объему, если вызов полностью или частично попал под действие скидки',
  `need_calc` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Необходимость перерасчета записи:0-посчитано,1-пересчитать стоимость,2-определить тариф и стоимость,3-пересчитать всё,6-стоимость уже в CDR,42-откат',
  `session_id` varchar(256) DEFAULT NULL COMMENT 'Идентификатор вызова/сессии (VoIP)',
  `original_numfrom` varchar(32) NOT NULL DEFAULT '' COMMENT 'Номер А до применения правил замены номеров',
  `original_numto` varchar(32) NOT NULL DEFAULT '' COMMENT 'Номер Б до применения правил замены номеров',
  `original_direction` tinyint(1) unsigned NOT NULL DEFAULT '1' COMMENT 'Направление вызова, установленное источником CDR',
  `original_vg_id` int(11) NOT NULL DEFAULT '0' COMMENT 'Идентификатор учетной записи, определенный на этапе формирования CDR (VoIP)',
  `cin` int(10) unsigned NOT NULL DEFAULT '0' COMMENT 'Входящий трафик в байтах (VoIP)',
  `cout` int(10) unsigned NOT NULL DEFAULT '0' COMMENT 'Исходящий трафик в байтах (VoIP)',
  `source` varchar(255) DEFAULT NULL COMMENT 'Источник CDR',
  `cause` int(11) unsigned NOT NULL DEFAULT '0' COMMENT 'Причина завершения вызова согласно значениям Cisco-Disconnect-Cause (0 - информация недоступна)',
  `hash` char(32) DEFAULT '0' COMMENT 'Уникальный идентификатор телефонного вызова, вычисляется как md5(concat(original_numfrom,original_numto,duration,timefrom))',
  `phone_station_id` int(11) DEFAULT NULL COMMENT 'Идентификатор парсера',
  `additional` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Трафик прошлого периода, загруженный в текущем (флаг)',
  `num_redirect` varchar(32) NOT NULL DEFAULT '' COMMENT 'Признак того, что звонок переадресован на другого абонента с значением номера куда звонок уходит',
  `bonus_seconds` int(11) unsigned NOT NULL DEFAULT '0' COMMENT 'Количество бонусных секунд, входящих в пакет',
  `bonus_minute_packets_id` int(11) DEFAULT NULL COMMENT 'Идентификатор бонусного пакета',
  `remain_seconds` int(11) unsigned NOT NULL DEFAULT '0' COMMENT 'Остаток `включенных в тариф` секунд после совершенного звонка',
  PRIMARY KEY (`record_id`),
  KEY `vg_id` (`vg_id`),
  KEY `uid` (`uid`),
  KEY `hash` (`hash`),
  KEY `session_id` (`session_id`(8)),
  KEY `timefrom` (`timefrom`),
  KEY `need_calc` (`need_calc`)
) ENGINE=MyISAM DEFAULT CHARSET=utf8 COMMENT='Статистика агента телефонии';



