) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='История тарификации периодических и разовых услуг';


DELIMITER ;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION" */;;
/*!50003 CREATE */ /*!50017 DEFINER=`root`@`localhost` */ /*!50003 TRIGGER `usbox_charge_insert` AFTER INSERT ON `usbox_charge` FOR EACH ROW BEGIN
	DECLARE l_vg_id int;
	IF @LB_DISABLE_TRIGGERS IS NULL OR @LB_DISABLE_TRIGGERS = 0 THEN
		SELECT `vg_id` INTO l_vg_id FROM `usbox_services` WHERE `serv_id` = NEW.`serv_id`;
		CALL CHARGE_IMPL(l_vg_id, NEW.`agrm_id`, NEW.`period`, NEW.`c_date`, NEW.`amount`);
	END IF;
END */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION" */;;
