CREATE TABLE `usbox_services` (
  `serv_id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'Идентификатор записи',
  `vg_id` int(11) NOT NULL COMMENT 'Идентификатор учетной записи',
  `tar_id` int(11) NOT NULL COMMENT 'Идентификатор тарифа USBox типа',
  `cat_idx` int(11) NOT NULL COMMENT 'Идентификатор категории тарифа (услуги)',
  `mul` decimal(20,6) NOT NULL DEFAULT '1.000000' COMMENT 'В каком количестве оказана услуга (множитель для стоимости услуги из тарифа)',
  `person_id` int(11) DEFAULT NULL COMMENT 'Идентификатор менеджера, назначившего услугу. NULL - услуга назначена самим абонентом.',
  `comment` varchar(255) NOT NULL DEFAULT '' COMMENT 'Комментарий',
  `created` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Дата назначения услуги (создания записи)',
  `timefrom` datetime NOT NULL DEFAULT '0000-00-00 00:00:00' COMMENT 'Дата начала оказания услуги',
  `timeto` datetime NOT NULL DEFAULT '9999-12-31 23:59:59' COMMENT 'Дата завершения оказания услуги',
  `need_calc` tinyint(1) NOT NULL DEFAULT '1' COMMENT 'Необходимость тарификации записи (флаг): 1-тарифицировать запись, 0-не тарифицировать, -1-удалить запись и аннулировать списания',
  `external_data` varchar(500) NOT NULL DEFAULT '' COMMENT 'Для хранения абстрактных данных внешних приложений',
  `state` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Текущее состояние услуги 0-отключена,не активирована;1-включена,не активирована;2-выключена,активирована;3-включена,активирована',
  `activated` datetime NOT NULL DEFAULT '0000-00-00 00:00:00' COMMENT 'Дата начала тарификации услуги',
  PRIMARY KEY (`serv_id`),
  KEY `vg_id` (`vg_id`),
  KEY `tar_id` (`tar_id`,`cat_idx`),
  KEY `person_id` (`person_id`),
  KEY `need_calc` (`need_calc`),
  KEY `serv_id` (`serv_id`,`vg_id`),
  KEY `state` (`state`),
  CONSTRAINT `usbox_services_ibfk_1` FOREIGN KEY (`vg_id`) REFERENCES `vgroups` (`vg_id`) ON UPDATE CASCADE,
  CONSTRAINT `usbox_services_ibfk_2` FOREIGN KEY (`tar_id`, `cat_idx`) REFERENCES `categories` (`tar_id`, `cat_idx`) ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='Назначенные периодические и разовые услуги';


DELIMITER ;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION" */;;
/*!50003 CREATE */ /*!50017 DEFINER=`root`@`localhost` */ /*!50003 TRIGGER `usbox_services_update` BEFORE UPDATE ON `usbox_services` FOR EACH ROW BEGIN
	DECLARE locked_period DATE;
	IF @LB_DISABLE_TRIGGERS IS NULL OR @LB_DISABLE_TRIGGERS = 0 THEN
		IF NEW.timeto <> OLD.timeto OR NEW.timefrom <> OLD.timefrom OR NEW.mul <> OLD.mul OR NEW.tar_id <> OLD.tar_id OR NEW.cat_idx <> OLD.cat_idx THEN
			SELECT IFNULL(DATE(value), DATE('0000-00-00')) INTO locked_period FROM options WHERE name = 'lock_period';
			
			DELETE FROM usbox_charge WHERE serv_id = NEW.serv_id AND period >= GREATEST(DATE(DATE_FORMAT(DATE(NEW.timeto), '%Y-%m-01')), locked_period);
			
			DELETE FROM usbox_charge WHERE serv_id = NEW.serv_id AND period < DATE(DATE_FORMAT(DATE(NEW.timefrom), '%Y-%m-01')) AND period >= locked_period;

			SET NEW.need_calc = 1;
		END IF;
	END IF;
END */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION" */;;
/*!50003 CREATE */ /*!50017 DEFINER=`root`@`localhost` */ /*!50003 TRIGGER `usbox_services_delete` BEFORE DELETE ON `usbox_services` FOR EACH ROW BEGIN
	IF @LB_DISABLE_TRIGGERS IS NULL OR @LB_DISABLE_TRIGGERS = 0 THEN
		DELETE FROM `usbox_charge` where `serv_id` = OLD.`serv_id`;
	END IF;
END */;;
DELIMITER ;
/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;


