DELIMITER ;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION" */;;
/*!50003 CREATE */ /*!50017 DEFINER=`root`@`localhost` */ /*!50003 TRIGGER `check_block` BEFORE INSERT ON `vg_blocks` FOR EACH ROW BEGIN
    DECLARE tf datetime;
    IF @LB_DISABLE_TRIGGERS IS NULL OR @LB_DISABLE_TRIGGERS = 0 THEN
        SET tf = NULL;
        SELECT `timefrom` INTO tf
        FROM `vg_blocks`
        WHERE `vg_id` = NEW.`vg_id`
        AND `timeto` > NEW.`timefrom`
        AND `timefrom` < NEW.`timeto`
        AND `timefrom` <> `timeto` LIMIT 1;
        IF tf IS NOT NULL THEN
            CALL ERROR_BLOCK_PERIODS_ARE_OVERLAPPED();
        END IF;
    END IF;
END */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION" */;;
/*!50003 CREATE */ /*!50017 DEFINER=`root`@`localhost` */ /*!50003 TRIGGER `vg_blocks_insert_tm` AFTER INSERT ON `vg_blocks` FOR EACH ROW BEGIN
    INSERT INTO tm_vg_blocks SET tm_mark = unix_timestamp(), record_id = NEW.record_id ON DUPLICATE KEY UPDATE tm_mark = unix_timestamp();
END */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION" */;;
/*!50003 CREATE */ /*!50017 DEFINER=`root`@`localhost` */ /*!50003 TRIGGER `vg_blocks_update_tm` AFTER UPDATE ON `vg_blocks` FOR EACH ROW BEGIN
    INSERT INTO tm_vg_blocks SET tm_mark = unix_timestamp(), record_id = NEW.record_id ON DUPLICATE KEY UPDATE tm_mark = unix_timestamp();
END */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION" */;;
/*!50003 CREATE */ /*!50017 DEFINER=`root`@`localhost` */ /*!50003 TRIGGER `vg_blocks_delete_tm` AFTER DELETE ON `vg_blocks` FOR EACH ROW BEGIN
    INSERT INTO tm_vg_blocks SET tm_mark = unix_timestamp(), record_id = OLD.record_id ON DUPLICATE KEY UPDATE tm_mark = unix_timestamp();
END */;;
