  `creation_date` datetime DEFAULT NULL COMMENT 'Метка времени создания учетной записи',
  `dirty` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Актуальность списаний по периодическим услугам или аренде (флаг)',
