  `connected_from` int(11) DEFAULT NULL COMMENT 'Идентификатор пользователя через которого произведено подключение (индекс)',
  `user_packet_id` int(11) DEFAULT NULL COMMENT 'Идентификатор экземпляра пакета, если УЗ входит в пакет, в противном случае NULL',
  `rid` varbinary(16) DEFAULT NULL COMMENT 'Уникальный идентификатор записи в рамках БД',
  `last_mod_date` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'Метка времени последней модификации записи',
  `auth_method` varchar(128) DEFAULT NULL COMMENT 'Метод авторизации:NULL-не задано,0-AUTO,1-PASSWORD,2-ANI,3-DIGEST,4-CHAP,5-H323',
  `set_id` int(11) DEFAULT NULL COMMENT 'Идентификатор набора карт, на основании которого создана у.з.',
  `activation_code` varchar(14) DEFAULT NULL COMMENT 'Код активации для внешних систем',
  PRIMARY KEY (`vg_id`),
  UNIQUE KEY `login` (`login`,`id`),
  UNIQUE KEY `cu_id` (`cu_id`,`id`),
  KEY `id` (`id`),
  KEY `parent_vg_id` (`parent_vg_id`),
  KEY `tar_id` (`tar_id`),
  KEY `c_date` (`c_date`),
  KEY `agrm_id` (`agrm_id`),
  KEY `blocked` (`blocked`),
  KEY `blk_req` (`blk_req`),
  KEY `changed` (`changed`),
  KEY `archive` (`archive`),
  KEY `acc_ondate` (`acc_ondate`),
  KEY `acc_offdate` (`acc_offdate`),
  KEY `uid` (`uid`),
  KEY `darchagrm` (`dirty`,`archive`,`agrm_id`),
  KEY `vgroups_ibfk_6` (`user_packet_id`),
  KEY `vgroups_ibfk_7` (`set_id`),
  CONSTRAINT `vgroups_ibfk_1` FOREIGN KEY (`parent_vg_id`) REFERENCES `vgroups` (`vg_id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `vgroups_ibfk_2` FOREIGN KEY (`uid`) REFERENCES `accounts` (`uid`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `vgroups_ibfk_3` FOREIGN KEY (`agrm_id`) REFERENCES `agreements` (`agrm_id`) ON UPDATE CASCADE,
  CONSTRAINT `vgroups_ibfk_4` FOREIGN KEY (`tar_id`) REFERENCES `tarifs` (`tar_id`) ON UPDATE CASCADE,
  CONSTRAINT `vgroups_ibfk_5` FOREIGN KEY (`id`) REFERENCES `settings` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `vgroups_ibfk_6` FOREIGN KEY (`user_packet_id`) REFERENCES `user_packets` (`user_packet_id`) ON UPDATE CASCADE,
  CONSTRAINT `vgroups_ibfk_7` FOREIGN KEY (`set_id`) REFERENCES `card_set` (`set_id`) ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='Учетные записи';


