# Dump of PROCEDURE action_subservice_add
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `action_subservice_add` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `action_subservice_add`(IN in_serv_id INT, IN in_uuid char(255))
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Плата за подключение доп разовой услуги'
BEGIN
        DECLARE v_vg_id   int DEFAULT 0;
        DECLARE v_tar_id int DEFAULT 0;
        DECLARE v_cat_idx int DEFAULT -1;
        DECLARE v_person_id int DEFAULT -1;

        SELECT vg_id, tar_id, person_id into v_vg_id, v_tar_id, v_person_id from usbox_services where serv_id = in_serv_id;
        SELECT cat_idx into v_cat_idx from categories where tar_id = v_tar_id and uuid = in_uuid;

        if v_cat_idx >= 0 then
            insert into usbox_services (
                `vg_id`,
                `tar_id`,
                `cat_idx`,
                `mul`,
                `timefrom`,
                `timeto`,
                `person_id`,
                `comment`,
                `created`
            ) VALUES (
                v_vg_id,
                v_tar_id,
                v_cat_idx,
                1,
                now(),
                now(),
                v_person_id,
                'Assigned automatically',
                timestamp(now())
            );
        end if;
END */;;

