  call addfield_sp(v_afschema, v_aftabname, v_affield, v_affielddata, v_error);
  
  if v_error = 1068
    then
      
      set v_error = 0;
      call dropkey_sp(v_afschema, v_aftabname, 'PRIMARY', 'PRIMARY KEY', v_error);
      
      
