      call show_message('ERROR', 1146, concat(v_error_mess, ': table `',v_aftabname,'` doesn`t exist.'));
  elseif v_error = 1292
    then
      
      call change_datetime_fields(v_afschema, v_aftabname);
      
      set v_error = 0;
      call addfield_sp(v_afschema, v_aftabname, v_affield, v_affielddata, v_error);
