                );

END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE add_index
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `add_index` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `add_index`( IN v_aischema varchar(64)
                          , IN v_aitabname varchar(64)
                          , IN v_aikey varchar(64)
                          , IN v_aikeydata varchar(4000)
                          )
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Добавить индекс в таблицу'
BEGIN
  declare v_error, v_maxlenth int(11) default 0;
  declare v_sql, v_errormess varchar(4000);
  
  set v_error = 0;
  set v_errormess = concat('Can`t add index ',v_aikey,' into table `', v_aischema, '`.`', v_aitabname,'`');
  call addindex_sp(v_aischema, v_aitabname, v_aikey, v_aikeydata, v_error);
  if v_error = 1146
    then
      
      call show_message('ERROR', 1146, concat(v_errormess,': table doesn`t exist.'));
  elseif v_error = 1071
    then
      
      select sum(if( ifnull(s.sub_part, 0) <> 0
                   , s.sub_part
                   , c.character_maximum_length
                   ) * ifnull(chs.maxlen, 3)
                ) > if(t.engine = 'InnoDB', 767, 1000)
      into v_maxlenth
      from meta$statistics s 
      join meta$columns c 
        on s.table_name = c.table_name 
        and s.column_name = c.column_name
      join meta$tables t 
        on s.table_name = t.table_name
      left join meta$character_sets chs
        on c.character_set_name = chs.character_set_name
      where lower(c.data_type) in ('char', 'varchar', 'binary', 'varbinary', 'blob', 'text')
      and s.table_name = v_aitabname
      and s.index_name = v_aikey
      and c.table_schema = v_aischema
      group by t.engine;
      
      if v_maxlenth > 0
        then
          call show_message('ERROR', 1071, concat(v_errormess,': Specified key was too long. Table construction error. Please, contact technical support'));
      else
          
          
          set v_error = 0;
          set v_sql = concat('alter table ', v_aischema, '.', v_aitabname, ' Engine='
                            , if( v_aitabname not regexp '[tel|rad|user][0-9]{11}'
                                , (select engine from meta$tables where table_name = v_aitabname and table_schema = v_aischema)
                                , 'MyISAM'
                                )
                            );
          call exec_command(v_sql, 1, v_error);
          
          if v_error <> 0
            then
              
              call show_message('ERROR', v_error, v_errormess);
              call show_message('ERROR', 1071, concat(v_errormess,': Specified key was too long.'));
            else
              
              set v_error = 0;
              call addindex_sp(v_aischema, v_aitabname, v_aikey, v_aikeydata, v_error);
              
              if v_error <> 0 
                then 
                  
                  call show_message('ERROR', v_error, v_errormess);
                  call show_message('ERROR', 1071, concat(v_errormess,': Specified key was too long.'));
              end if;
          end if;
      end if;
  elseif v_error = 1072
    then
      
      call show_message('ERROR', 1072, concat(v_errormess, ': key column doesn`t exist.'));
  elseif v_error <> 0
    then
      call show_message('ERROR', v_error, v_errormess);
  end if;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
