/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `add_index_stat`( IN v_aisschema varchar(64)
                               , IN v_aistabprefix varchar(64)
                               , IN v_aisfield varchar(64)
                               , IN v_aiskeydata varchar(400)
                               )
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Добавить индекс'
BEGIN
  declare v_sql varchar(4000);
  declare v_tabcur varchar(64);
  declare done boolean;
  declare v_error int(11) default 0;
  declare curtabname cursor for select table_name
                                from information_schema.tables
                                where table_schema = v_aisschema
                                and table_name regexp concat(v_aistabprefix, if(v_aistabprefix = 'report', '[0-9]{6}', '[0-9]{11}'));
  declare continue handler for not found set done = 1;

  set done = false;
  open curtabname;
  fetch curtabname into v_tabcur;
  while not done do
    CALL add_index(v_aisschema, v_tabcur,v_aisfield,v_aiskeydata);
    set done = false;
    fetch curtabname into v_tabcur;
  end while;
  close curtabname;
  
  call add_index( v_aisschema
                , concat(v_aistabprefix,if(v_aistabprefix = 'report', '', 'NNN'),'YYYYmm',if(v_aistabprefix = 'report', '', 'dd'))
                , v_aisfield
                , v_aiskeydata
                );

END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE add_key
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `add_key` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `add_key`( IN v_akschema varchar(64)
                        , IN v_aktabname varchar(64)
                        , IN v_akkey varchar(64)
                        , IN v_akkeydata varchar(255)
                        )
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Добавить ключ в таблицу (PK,FK,Unique)'
BEGIN
  declare v_sql, v_sql1, v_uniquesql, v_uniquesql_check, v_uniquesql_update, v_fieldstore, v_errormess varchar(4000);
  declare v_tabfrgn varchar(64);
  declare v_error int(11) default 0;
  
  set v_error = 0;
  call show_message('INFO', 0, concat('add key `', v_akkey, '` to table `', v_akschema, '`.`', v_aktabname, '`'));
  SET v_sql = concat('alter table `', v_akschema, '`.`', v_aktabname, '` add ', v_akkeydata);
  
  call exec_command(v_sql, 1, v_error);
  if v_error = 1062  
    then
      set v_errormess = concat('Can`t add unique constraint into table ', v_akschema, '.', v_aktabname);
      
      set v_fieldstore = substring_index(substring_index(v_akkeydata, ')', 1), '(', -1);
      
      
      if v_fieldstore regexp '[0-9]+' then set v_fieldstore = substring_index(substring_index(v_akkeydata, '(', -2), '(', 1); end if;
      
      
      set v_uniquesql = concat('select ', v_fieldstore,' from (select count(1), ',v_fieldstore,' from ', v_akschema, '.', v_aktabname, if(locate(',', v_fieldstore) = 0, concat(' where ', v_fieldstore, ' is not null'), ''), ' group by ', v_fieldstore, ' having count(1) > 1) t');
      
      if locate(',', v_fieldstore) = 0
        then
          
          set @LB_SQL_CHECK = 0;
          set v_uniquesql_check = concat('select count(', v_fieldstore,') into @LB_SQL_CHECK from (select count(1), ',v_fieldstore,' from ', v_akschema, '.', v_aktabname, ' where ', v_fieldstore, ' is not null and trim(', v_fieldstore, ') <> "" group by ', v_fieldstore, ' having count(1) > 1) t');
          set v_error = 0;
          call exec_command(v_uniquesql_check, 1, v_error);
          if v_error <> 0 or @LB_SQL_CHECK <> 0
            then
              
              call show_message('ERROR', v_error, concat('Can`t execute statement ', v_sql));
              call show_message('WARNING', v_error, v_errormess);
              call show_message('INFO', v_error, concat('Please, check data by executing statement:', v_uniquesql));
          else 
            
            
            
            
            if @LB_SQL_CHECK = 0 and (select is_nullable from meta$columns where table_name = v_aktabname and column_name = v_fieldstore and table_schema = v_akschema) <> 'NO'
              then
                
                set v_uniquesql_update = concat('update ', v_akschema, '.', v_aktabname, ' set ', v_fieldstore, ' = null where trim(', v_fieldstore, ') = ""');
                set v_error = 0;
                call exec_command(v_uniquesql_update, 1, v_error);
                if v_error <> 0
                  then
                    
                    call show_message('ERROR', v_error, concat('Can`t execute statement ', v_uniquesql_update));
                    call show_message('WARNING', v_error, v_errormess);
                    call show_message('INFO', v_error, concat('Please, check data by executing statement:', v_uniquesql));
                else
                  
                  set v_error = 0;
                  call exec_command(v_sql, 1, v_error);
                  if v_error <> 0
                    then
                      
                      call show_message('WARNING', v_error, v_errormess);
                      call show_message('INFO', v_error, concat('Please, check data by executing statement:', v_uniquesql));
                  end if;
                end if;
              
              
              
            end if;
          end if;
      else
        
        
        if (v_aktabname = 'tel_cat' and v_akkey = 'tel_cat_ubk_1') then
          
          call show_message('ERROR', v_error, concat('Please, call clean_tel_cat_duplicates(true, true) to repair data'));
        elseif (v_aktabname = 'service_blocks' and v_akkey = 'service_blocks_ubk_1') then
          
          call show_message('ERROR', v_error, concat('Please, call clean_service_blocks_duplicates(true) to repair data'));
        else
          call show_message('WARNING', v_error, v_errormess);
          call show_message('INFO', v_error, concat('Please, check data by executing statement:', v_uniquesql));
        end if;
      end if;
  elseif v_error = 1452  
    then
      
      set v_fieldstore = substring_index(substring_index(v_akkeydata, ')', 1), '(', -1);
      
      if v_fieldstore regexp '[0-9]+' then set v_fieldstore = substring_index(substring_index(v_akkeydata, '(', -2), '(', 1); end if;
      
      set v_tabfrgn = substring_index(trim(substring_index(v_akkeydata, '(', 2)), ' ', -1);
      
      
      set v_uniquesql = concat('select distinct ', v_fieldstore, ' from `', v_akschema, '`.`', v_aktabname, '` where (', v_fieldstore
                              , ') not in (select ', substring_index(substring_index(v_akkeydata, ')', 2), '(', -1), ' from `', v_akschema, '`.`', v_tabfrgn,'`)'
                              );
      
      call show_message('WARNING'
                       , v_error
                       , concat('Can`t find folowing data in parent table `', v_akschema, '`.`', v_tabfrgn, '` for link it with table `', v_akschema, '`.`', v_aktabname, '`. \n Please, check data by executing statement:', v_uniquesql));
  elseif v_error = 1292
    then
      
      set v_error = 0;
      call change_datetime_fields(v_akschema, v_aktabname);
      
      call exec_command(v_sql, 1, v_error);
      if v_error = 1292
        then
          
          call show_message('ERROR', 1292, concat('Can`t add key ', v_akkey, ' into table ', v_akschema, '.', v_aktabname, ': incorrenct values in date or datetime fields. Please, check table, using GUESS_DATE function.'));
          call show_message('INFO', 1292, "Please, check table, using query like this: select birthdate,GUESS_DATE(birthdate) from accounts where GUESS_DATE(birthdate) = '0000-00-00' and ifnull(birthdate, '0000-00-00') <> '0000-00-00')");
      elseif v_error <> 0
        then
          
          
          call show_message('ERROR', 1292, concat('Can`t add key ', v_akkey, ' into table ', v_akschema, '.', v_aktabname, ': incorrenct values in date or datetime fields. Please, check table, using GUESS_DATE function.'));
          call show_message('ERROR', v_error, concat('Can`t add key ', v_akkey, ' into table ', v_akschema, '.', v_aktabname));
      end if;
  elseif v_error not in (0, 1061, 1068, 1050)
    then
      
      call show_message('ERROR', v_error, concat('Can`t add key ', v_akkey, ' into table ', v_akschema, '.', v_aktabname));
  end if;

end */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE add_key_stat
