/*!50003 DROP PROCEDURE IF EXISTS `add_key_stat` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `add_key_stat`( IN v_afsschema varchar(64)
                             , IN v_akstabprefix varchar(64)
                             , IN v_aksfield varchar(64)
                             , IN v_akskeydata varchar(400)
                             )
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Добавить ключ'
BEGIN
  declare v_sql varchar(4000);
