              , v_aksfield
              , v_akskeydata
              );

END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE add_table
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `add_table` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `add_table`( IN in_tabschema varchar(64)
                          , IN in_tabname varchar(64)
                          )
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Собрать таблицу из атрибутов'
BEGIN
    declare v_sql, v_partsql, v_partdescr, v_columns varchar(8000);
    declare v_pri_fset, v_colcomment, v_colname, v_coltype, v_isnull, v_coldefault, v_extra, v_colkey varchar(4000) default "";
    declare v_partmethod, v_partname, v_backtabname varchar(64);
    declare v_error, done int(11) default 0;
    declare columns_cur cursor for
            select column_name, column_type, is_nullable, column_default, extra, column_key, column_comment
            from meta$columns
            where lower(table_name) = lower(in_tabname)
            order by ordinal_position;
    declare parts_cur cursor for
            select partition_name, partition_description
            from meta$table_partitions
            where lower(table_name) = lower(in_tabname)
            order by partition_ordinal_position;
    declare continue handler for not found set done = 1;
    
    if(select count(1) from meta$tables where lower(table_name) = lower(in_tabname))
      then
        select case trim(trim(trailing 'KEY' from tc.constraint_type))
                 when 'PRIMARY'
                   then concat(tc.constraint_type, ' (', k.key_cols, ')')
                 when 'UNIQUE'
                   then concat(tc.constraint_type, ' KEY `', tc.constraint_name, '`(', k.key_cols, ')')
               end
        into v_pri_fset
        from meta$table_constraints tc
        join (select kcu.table_name
                   , kcu.constraint_name
                   , group_concat(concat(kcu.column_name
                                        , ifnull(if(s.sub_part <> 0, concat('(', s.sub_part, ')'),''), '')
                                        )
                                  order by kcu.ordinal_position, s.seq_in_index
                                 ) key_cols
              from meta$columns c
              join meta$key_column_usage kcu
                on c.table_name = kcu.table_name
                and c.column_name = kcu.column_name
              join meta$statistics s
                on  s.table_name = kcu.table_name
                and s.column_name = kcu.column_name
                and s.index_name = kcu.constraint_name
              where lower(c.table_name) = lower(in_tabname)
              and c.column_key = 'PRI'
              and upper(kcu.constraint_name) = 'PRIMARY'
              group by kcu.table_name, kcu.constraint_name
              order by kcu.ordinal_position
             ) k
          on  tc.table_name = k.table_name
          and tc.constraint_name = k.constraint_name
          where trim(trim(trailing 'KEY' from tc.constraint_type)) in ('PRIMARY', 'UNIQUE');






        set done = 0;
        open columns_cur;
        fetch columns_cur into v_colname, v_coltype, v_isnull, v_coldefault, v_extra, v_colkey, v_colcomment;
        while not done do
          set v_columns = concat(ifnull(v_columns, '')
                                , "`", ifnull(v_colname,''), "`"
                                , " "
                                , ifnull(v_coltype, '')
                                , " "
                                , if(v_isnull = 'NO',"NOT NULL ", "")
                                , ifnull(if( v_coldefault <> 'CURRENT_TIMESTAMP'
                                           , concat(" default '", v_coldefault, "' ")
                                           , concat(" default ", v_coldefault, " ")
                                           )
                                        , "")
                                , ifnull(v_extra, '')
                                , ifnull(concat(" COMMENT '", v_colcomment, "'"), "")
                                , ", "
                                );
          set done = 0;
          fetch columns_cur into v_colname, v_coltype, v_isnull, v_coldefault, v_extra, v_colkey, v_colcomment;
        end while;
        close columns_cur;
        
        select concat( "CREATE TABLE `"
                     , in_tabschema, "`.`"
                     , table_name, "`"
                     , "("
                     , trim(trailing ',' from trim(v_columns))
                     , ifnull(if(trim(v_pri_fset) <> '', concat(' ,', v_pri_fset), ''), '')
                     , ") ENGINE = "
                     , ifnull(engine, '')
                     , " CHARSET=utf8 "
                     , ifnull(replace(create_options,'partitioned',''), '')
                     , " COMMENT = '"
                     , ifnull(replace(table_comment, '"', ''), '')
                     , "'"
                     )
        into v_sql
        from meta$tables
        where lower(table_name) = lower(in_tabname);

        
        
        
        if substring(replace(substring_index(version(), '-', 1), '.', ''), 1, 2) >= 51
          then
            if(select count(*) from information_schema.plugins where plugin_type = 'STORAGE ENGINE' and lower(plugin_name) = 'partition')
              then
                select distinct concat(' partition by ', partition_method, '(', partition_expression, ') '
                                      , ifnull(concat(' subpartition by ', subpartition_method, '(', subpartition_expression, ')'), '')
                                      )
                     , partition_method
                into v_partsql, v_partmethod
                from meta$table_partitions
                where lower(table_name) = lower(in_tabname);

                if v_partmethod = 'RANGE'
                  then
                    set v_partsql = concat(v_partsql, '( ');
                    set done = 0;
                    open parts_cur;
                    fetch parts_cur into v_partname, v_partdescr;
                    while not done do
                      set v_partsql = concat(v_partsql
                                            , 'partition '
                                            , v_partname
                                            , ' values less than '
                                            , if(v_partdescr = 'MAXVALUE', v_partdescr, concat('(', v_partdescr,'),'))
                                            );
                      set done = 0;
                      fetch parts_cur into v_partname, v_partdescr;
                    end while;
                    close parts_cur;

                    set v_partsql = concat(trim(trailing ',' from v_partsql), ')');
                end if;
            end if;
        end if;
        set v_sql = concat(v_sql,ifnull(v_partsql, ''));
        set v_error = 0;
        
        call exec_command(v_sql, 1, v_error);
        if v_error not in (0, 1050)
          then
            call show_message('ERROR', v_error, concat('Can`t create table ', in_tabname));
        end if;
    end if;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE backup_table
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `backup_table` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `backup_table`( IN v_btschema varchar(64)
                             , IN v_bttabname varchar(64)
                             )
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
begin
  declare v_sql, v_newtab varchar(4000);
  declare v_error int(11) default 0;
  
  set @LB_UPDATESQL_PMESSID = NULL;
  set v_newtab = concat(v_btschema, '.', v_bttabname, '_backup_', date_format(now(), '%Y%m%d%h%i%s'));
  call show_message('INFO', 0, concat('Create data backup from table ', v_bttabname, ' to table ', v_newtab));
  set v_sql = concat('create table ', v_newtab, ' as select * from ', v_btschema, '.', v_bttabname);
  call exec_command(v_sql, 1, v_error);
  if v_error = 1292
    then
    SET @LB_OLD_SQL_MODE=@@SESSION.sql_mode, @@SESSION.sql_mode='';
    set v_error = 0;
    call exec_command(v_sql, 1, v_error);
    if v_error not in (0, 1050, 1146, 1243)
      then
        call show_message('ERROR', v_error, concat('Can`t create backup of table ', v_bttabname));
    end if;
    SET @@SESSION.sql_mode=@LB_OLD_SQL_MODE;
  elseif v_error not in (0, 1050, 1146, 1243)
    then
      call show_message('ERROR', v_error, concat('Can`t create backup of table ', v_bttabname));
  end if;
end */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE BALANCE_ACC_ON_DATE_CALC
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `BALANCE_ACC_ON_DATE_CALC` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `BALANCE_ACC_ON_DATE_CALC`(in_date DATE)
    READS SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Расчёт задолженности по списку договоров на дату'
BEGIN

    SET in_date = IFNULL(in_date,'0000-00-00');

    DROP TABLE IF EXISTS tmp_balance_acc_on_date;
    CREATE TEMPORARY TABLE tmp_balance_acc_on_date
    (
     agrm_id int(11) NOT NULL,
     date date NOT NULL,
     balance_acc DECIMAL(20,6) NOT NULL DEFAULT 0,
     UNIQUE KEY(agrm_id) USING hash
    ) ENGINE = MEMORY;
    
    
    
    
    
                             
    DROP TABLE IF EXISTS tmp_balance_amount;
    CREATE TEMPORARY TABLE tmp_balance_amount
    (
        agrm_id int(11) NOT NULL,
        amount DECIMAL(20,6) NOT NULL DEFAULT 0,
        UNIQUE KEY(agrm_id) USING hash
    ) ENGINE = MEMORY;
    
    
    DROP TABLE IF EXISTS agrms;
    CREATE TEMPORARY TABLE agrms(agrm_id int(11) PRIMARY KEY);
    INSERT INTO agrms SELECT agrm_id FROM vgids ON duplicate KEY UPDATE agrm_id = VALUES(agrm_id);
    
    
    DROP TABLE IF EXISTS agrms_fixed;
    CREATE TEMPORARY TABLE agrms_fixed(agrm_id int(11) PRIMARY KEY);
    INSERT INTO agrms_fixed SELECT a.agrm_id FROM agrms a join incoming_balances b on a.agrm_id = b.agrm_id and b.date = in_date;
    
    
    DELETE a.* from agrms a join agrms_fixed b using(agrm_id);
    
    INSERT INTO tmp_balance_acc_on_date(agrm_id, date) SELECT DISTINCT agrm_id, in_date FROM agrms;

    
    UPDATE tmp_balance_acc_on_date tb
    JOIN agreements a USING (agrm_id)
    SET tb.balance_acc = a.balance_acc;
    
    
    truncate table tmp_balance_amount;
    insert into tmp_balance_amount(agrm_id, amount)
        SELECT agrm_id, ifnull(sum(amount), 0)
        FROM sales s join agrms v using(agrm_id)
        WHERE 1=1 
        AND cancel_date IS NULL
        AND period_date >= in_date
        GROUP BY agrm_id;
    UPDATE tmp_balance_acc_on_date tb join tmp_balance_amount tt using(agrm_id)  set  tb.balance_acc = tb.balance_acc + tt.amount;

    
    truncate table tmp_balance_amount;
    insert into tmp_balance_amount(agrm_id, amount)
        SELECT sh.agrm_id, ifnull(sum(sh.amount), 0)
        FROM sales_history sh join agrms v using (agrm_id) join sales s using(sale_id)
        WHERE 1=1 
        AND s.period_date IS NULL
        AND sh.cancel_date IS NULL
        AND sh.period_date >= in_date
        AND sh.record_id = (SELECT max(record_id)
                            FROM sales_history 
                            WHERE sale_id = sh.sale_id 
                            AND period_date >= in_date)
        GROUP BY agrm_id;
    UPDATE tmp_balance_acc_on_date tb join tmp_balance_amount tt using(agrm_id)  set  tb.balance_acc = tb.balance_acc + tt.amount;

    
    truncate table tmp_balance_amount;
    insert into tmp_balance_amount(agrm_id, amount)
        SELECT sh.agrm_id, ifnull(sum(sh.amount), 0)
        FROM sales_history sh join agrms v using (agrm_id) join sales s using(sale_id)
        WHERE 1=1
        AND (s.period_date >= in_date 
            or 
            (select count(1) from sales_history where sale_id = sh.sale_id and record_id > sh.record_id and period_date > sh.period_date) > 0)
        AND sh.cancel_date IS NULL
        AND sh.period_date < in_date
        AND sh.record_id = (SELECT max(record_id)
                            FROM sales_history 
                            WHERE sale_id = sh.sale_id 
                            AND period_date < in_date)
        GROUP BY sh.agrm_id;
    UPDATE tmp_balance_acc_on_date tb join tmp_balance_amount tt using(agrm_id)  set  tb.balance_acc = tb.balance_acc - tt.amount;


    
    truncate table tmp_balance_amount;
    insert into tmp_balance_amount(agrm_id, amount)
        SELECT agrm_id, ifnull(sum(amount), 0)
        FROM payments s join agrms v using (agrm_id) 
        WHERE 1=1
        AND cancel_date IS NULL
        AND period_date >= in_date
        GROUP BY agrm_id;
    UPDATE tmp_balance_acc_on_date tb join tmp_balance_amount tt using(agrm_id)  set  tb.balance_acc = tb.balance_acc - tt.amount;

    
    truncate table tmp_balance_amount;
    insert into tmp_balance_amount(agrm_id, amount)
        SELECT ph.agrm_id, ifnull(sum(ph.amount), 0)
        FROM payments_history ph join agrms v using (agrm_id) 
        JOIN payments p ON ph.origin_record_id = p.record_id 
        WHERE 1=1
        AND ph.cancel_date IS NULL
        AND p.period_date >= in_date
        AND ph.period_date < in_date
        AND ph.record_id = (SELECT max(record_id)FROM payments_history 
                            WHERE origin_record_id = ph.origin_record_id 
                            AND period_date < in_date)
        GROUP BY ph.agrm_id;
    UPDATE tmp_balance_acc_on_date tb join tmp_balance_amount tt using(agrm_id)  set  tb.balance_acc = tb.balance_acc + tt.amount;

    
    truncate table tmp_balance_amount;
    insert into tmp_balance_amount(agrm_id, amount)
        SELECT ph.agrm_id, ifnull(sum(ph.amount), 0)
        FROM payments_history ph join agrms v using (agrm_id) 
        JOIN payments p ON ph.origin_record_id = p.record_id 
        WHERE 1=1
        AND ph.cancel_date IS NULL
        AND p.period_date IS NULL
        AND ph.period_date >= in_date
        AND ph.record_id = (SELECT max(record_id)FROM payments_history 
                            WHERE origin_record_id = ph.origin_record_id 
                            AND period_date >= in_date)
        GROUP BY ph.agrm_id;
    UPDATE tmp_balance_acc_on_date tb join tmp_balance_amount tt using(agrm_id)  set  tb.balance_acc = tb.balance_acc - tt.amount;


    
    truncate table tmp_balance_amount;
    insert into tmp_balance_amount(agrm_id, amount)
        SELECT from_agrm_id, ifnull(sum(amount), 0)
        FROM payments s join agrms v on s.from_agrm_id = v.agrm_id
        WHERE 1=1
        AND cancel_date IS NULL
        AND period_date >= in_date
       GROUP BY from_agrm_id;  
    UPDATE tmp_balance_acc_on_date tb join tmp_balance_amount tt using(agrm_id)  set  tb.balance_acc = tb.balance_acc + tt.amount;

    
    truncate table tmp_balance_amount;
    insert into tmp_balance_amount(agrm_id, amount)
        SELECT ph.from_agrm_id, ifnull(sum(ph.amount), 0)
        FROM payments_history ph join agrms v on ph.from_agrm_id = v.agrm_id 
        JOIN payments p ON ph.origin_record_id = p.record_id 
        WHERE 1=1
        AND p.from_agrm_id > 0
        AND ph.cancel_date IS NULL
        AND p.period_date >= in_date
        AND ph.period_date < in_date
        AND ph.record_id = (SELECT max(record_id)FROM payments_history 
                            WHERE origin_record_id = ph.origin_record_id 
                            AND period_date < in_date)
        GROUP BY p.from_agrm_id;
    UPDATE tmp_balance_acc_on_date tb JOIN tmp_balance_amount tt USING(agrm_id) SET tb.balance_acc = tb.balance_acc - tt.amount;

    
    truncate table tmp_balance_amount;
    insert into tmp_balance_amount(agrm_id, amount)
        SELECT ph.from_agrm_id, ifnull(sum(ph.amount), 0)
        FROM payments_history ph join agrms v on ph.from_agrm_id = v.agrm_id 
        JOIN payments p ON ph.origin_record_id = p.record_id 
        WHERE 1=1
        AND p.from_agrm_id > 0
        AND ph.cancel_date IS NULL
        AND p.period_date IS NULL
        AND ph.period_date >= in_date
        AND ph.record_id = (SELECT min(record_id)FROM payments_history 
                            WHERE origin_record_id = ph.origin_record_id 
                            AND period_date >= in_date)
        GROUP BY ph.from_agrm_id;
    UPDATE tmp_balance_acc_on_date tb join tmp_balance_amount tt using(agrm_id)  set  tb.balance_acc = tb.balance_acc + tt.amount;

    
    INSERT INTO tmp_balance_acc_on_date (agrm_id, date, balance_acc) select a.agrm_id, in_date, b.balance_acc from agrms_fixed a join incoming_balances b on a.agrm_id = b.agrm_id and b.date = in_date;
    
END */;;

