/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `BALANCE_BY_DOCUMENTS`(IN in_date DATE, IN in_what INTEGER)
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
BEGIN

        DECLARE tmp_uid INTEGER;                                    
        DECLARE tmp_name TEXT;
