        DECLARE agreements_all CURSOR FOR
                SELECT
                        a.uid,
                        u.name,
                        u.type,
                        u.category,
                        IFNULL(uv.str_value, IF(u.category = 1, 1, 0)),
                        a.agrm_id,
                        tb.balance_acc
                FROM agreements a
                     INNER JOIN agrms a1                   ON (a.agrm_id = a1.agrm_id)
                     INNER JOIN accounts u                 ON (u.uid  = a.uid)
                     INNER JOIN tmp_balance_acc_on_date tb ON (a.agrm_id = tb.agrm_id)
                     LEFT  JOIN accounts_addons_vals uv    ON (uv.uid = a.uid AND uv.name = 'affiliate')
                ORDER BY a.agrm_id;

        
        
        
        
        DECLARE payments_left CURSOR FOR
                SELECT p.record_id, p.receipt, p.pay_date, IF(p.cancel_date IS NULL, p.amount, 0)
                FROM payments p
                WHERE p.agrm_id = tmp_agrm_id 
                AND p.period_date < in_date
                ORDER BY p.pay_date DESC, p.local_date DESC;

        
        
        
        
        
        
        
        
        DECLARE payments_right CURSOR FOR
