                FROM sales s
                WHERE s.agrm_id = tmp_agrm_id 
                AND s.period_date < in_date
                ORDER BY s.sale_date DESC, s.local_date DESC;

        
        
        
        
        DECLARE sales_right CURSOR FOR
                SELECT sh.sale_id, sh.receipt, sh.sale_date, IF(sh.cancel_date IS NULL, -sh.amount, 0)
                FROM sales_history sh
                WHERE sh.agrm_id = tmp_agrm_id 
                AND sh.period_date < in_date
                ORDER BY sh.sale_date DESC, sh.local_date DESC;

        DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;                         


        
        
        
        
        
        DROP  TABLE IF EXISTS tmp_balance_by_documents_id;
