                                                        SET tmp_receipt = tmp_receipt_right;
                                                        SET tmp_date    = tmp_date_right;
                                                        SET tmp_amount  = tmp_amount_right;

                                                        
                                                        
                                                        
                                                        SET tmp_id_right = NULL;
                                                
                                                
                                                
                                                ELSE
                                                        SET tmp_id      = tmp_id_left;
                                                        SET tmp_receipt = tmp_receipt_left;
                                                        SET tmp_date    = tmp_date_left;
                                                        SET tmp_amount  = tmp_amount_left;

                                                        
                                                        
                                                        
                                                        SET tmp_id_left = NULL;
                                                END IF;
                                        
                                        
                                        
                                        ELSEIF tmp_id_left IS NOT NULL THEN
                                                SET tmp_id      = tmp_id_left;
                                                SET tmp_receipt = tmp_receipt_left;
                                                SET tmp_date    = tmp_date_left;
                                                SET tmp_amount  = tmp_amount_left;

                                                
                                                
                                                
                                                SET tmp_id_left = NULL;
                                        
                                        
                                        
