                                                INSERT INTO tmp_balance_by_documents_id(id) VALUES(tmp_id);

                                                
                                                
                                                
                                                IF tmp_amount > 0 THEN
                                                        
                                                        
                                                        
                                                        
                                                        IF tmp_balance_acc < tmp_amount THEN
