                                                                        tmp_uid,
                                                                        tmp_name,
                                                                        tmp_type,
                                                                        tmp_category,
                                                                        tmp_affiliate,
                                                                        tmp_agrm_id,
                                                                        1,
                                                                        tmp_id,
                                                                        tmp_receipt,
                                                                        tmp_date,
                                                                        tmp_amount
                                                                );

                                                        
                                                        
                                                        
                                                        SET tmp_balance_acc = tmp_balance_acc - tmp_amount;
                                                END IF;
                                        END IF;
                                END LOOP;
                                CLOSE sales_left;
                                CLOSE sales_right;

                                
                                
                                
                                
                                
                                IF tmp_balance_acc <= -0.01 THEN
                                        INSERT INTO
                                                tmp_balance_by_documents
                                                (
                                                        uid,
                                                        name,
                                                        type,
                                                        category,
                                                        affiliate,
                                                        agrm_id,
                                                        doctype,
                                                        id,
                                                        receipt,
                                                        date,
                                                        amount
                                                )
                                        VALUES
                                                (
                                                        tmp_uid,
                                                        tmp_name,
                                                        tmp_type,
                                                        tmp_category,
                                                        tmp_affiliate,
                                                        tmp_agrm_id,
                                                        0,
                                                        0,
                                                        NULL,
                                                        '0000-00-00',
                                                        tmp_balance_acc
                                                );
                                END IF;
                        END IF;
                END IF;
        END LOOP;
        CLOSE agreements_all;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE balance_on_date_calc
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `balance_on_date_calc` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `balance_on_date_calc`(in_date_from DATE, in_date_to DATE, in_force BOOL)
    SQL SECURITY INVOKER
    COMMENT 'Расчет тех. баланса по списку договоров'
BEGIN
    DECLARE v_cur_date DATE DEFAULT NULL;

    DROP TABLE IF EXISTS `tmp_balance_on_date`;
    CREATE TEMPORARY TABLE `tmp_balance_on_date` LIKE `balances`;

    DROP TABLE IF EXISTS `tmp_balance_on_date_working`;
    CREATE TEMPORARY TABLE `tmp_balance_on_date_working`(
        `agrm_id`         INT(11),
        `start_date`      DATE,
        `end_date`        DATE,
        `start_value`     decimal(20,6),
        `end_value`       decimal(20,6),
        `payments`        decimal(20,6) DEFAULT 0,
        `from_pays`       decimal(20,6) DEFAULT 0,
        `sales_corr`      decimal(20,6) DEFAULT 0,
        `rent`            decimal(20,6) DEFAULT 0,
        `usbox`           decimal(20,6) DEFAULT 0,
        `charges`         decimal(20,6) DEFAULT 0,
        `day`             decimal(20,6) DEFAULT 0,
        PRIMARY KEY `agrm_id` (`agrm_id`),
        KEY `start_date` (`start_date`),
        KEY `end_date` (`end_date`)) ENGINE = MEMORY;

    DROP TABLE IF EXISTS `tmp_payments`;
    DROP TABLE IF EXISTS `tmp_from_pays`;
    DROP TABLE IF EXISTS `tmp_sales_corr`;
    DROP TABLE IF EXISTS `tmp_rent`;
    DROP TABLE IF EXISTS `tmp_usbox`;
    DROP TABLE IF EXISTS `tmp_charges`;
    DROP TABLE IF EXISTS `tmp_day`;

    CREATE TEMPORARY TABLE `tmp_payments`  (`agrm_id` INT(11), `amount` decimal(20,6) DEFAULT 0, PRIMARY KEY `agrm_id`(`agrm_id`));
    CREATE TEMPORARY TABLE `tmp_from_pays` (`agrm_id` INT(11), `amount` decimal(20,6) DEFAULT 0, PRIMARY KEY `agrm_id`(`agrm_id`));
    CREATE TEMPORARY TABLE `tmp_sales_corr`(`agrm_id` INT(11), `amount` decimal(20,6) DEFAULT 0, PRIMARY KEY `agrm_id`(`agrm_id`));
    CREATE TEMPORARY TABLE `tmp_rent`      (`agrm_id` INT(11), `amount` decimal(20,6) DEFAULT 0, PRIMARY KEY `agrm_id`(`agrm_id`));
    CREATE TEMPORARY TABLE `tmp_usbox`     (`agrm_id` INT(11), `amount` decimal(20,6) DEFAULT 0, PRIMARY KEY `agrm_id`(`agrm_id`));
    CREATE TEMPORARY TABLE `tmp_charges`   (`agrm_id` INT(11), `amount` decimal(20,6) DEFAULT 0, PRIMARY KEY `agrm_id`(`agrm_id`));
    CREATE TEMPORARY TABLE `tmp_day`       (`agrm_id` INT(11), `amount` decimal(20,6) DEFAULT 0, PRIMARY KEY `agrm_id`(`agrm_id`));

    
    IF in_force THEN
        INSERT INTO `tmp_balance_on_date` (`agrm_id`, `date`, `balance`)
          SELECT `b`.`agrm_id`, `b`.`date`, `b`.`balance`
          FROM `balances` `b` JOIN `vgids` `v` USING(`agrm_id`)
          WHERE `b`.`date` = current_date();
    ELSE
        INSERT INTO `tmp_balance_on_date` (`agrm_id`, `date`, `balance`)
          SELECT `b`.`agrm_id`, `b`.`date`, `b`.`balance`
          FROM `balances` `b` JOIN `vgids` `v` USING(`agrm_id`)
          WHERE `b`.`date` >= in_date_from AND `b`.`date` < in_date_to;
    END IF;

    
    INSERT IGNORE INTO `tmp_balance_on_date_working` (`agrm_id`) SELECT `agrm_id` FROM `vgids`;
    IF NOT in_force THEN
        
        UPDATE `tmp_balance_on_date_working` `w` SET `start_date` = (SELECT MIN(`date`) FROM `balances`
                                                                     WHERE `agrm_id` = `w`.`agrm_id` AND `date` >= in_date_from);
    ELSE
        
        UPDATE `tmp_balance_on_date_working` `w` SET `start_date` = (SELECT MAX(`date`) FROM `balances`
                                                                     WHERE `agrm_id` = `w`.`agrm_id`);
    END IF;
    
    UPDATE `tmp_balance_on_date_working` `w` SET `start_value` = (SELECT `balance` FROM `balances`
                                                                  WHERE `agrm_id` = `w`.`agrm_id` AND `date` = `start_date`);
    
    DELETE `w`.* FROM `tmp_balance_on_date_working` `w` WHERE `w`.`start_date` IS NULL;

    
    SELECT MAX(`start_date`) FROM `tmp_balance_on_date_working` INTO v_cur_date;

    WHILE v_cur_date > in_date_from DO

        
        UPDATE `tmp_balance_on_date_working` `w` SET `w`.`end_date` = `w`.`start_date` - INTERVAL 1 DAY WHERE `start_date` = v_cur_date;

        
        TRUNCATE TABLE `tmp_payments`;
        TRUNCATE TABLE `tmp_from_pays`;
        TRUNCATE TABLE `tmp_sales_corr`;
        TRUNCATE TABLE `tmp_rent`;
        TRUNCATE TABLE `tmp_usbox`;
        TRUNCATE TABLE `tmp_charges`;
        TRUNCATE TABLE `tmp_day`;

        
        INSERT INTO `tmp_payments` (`agrm_id`, `amount`)
        SELECT `agrm_id`, IFNULL(SUM(`amount`),0)
        FROM `payments` JOIN `tmp_balance_on_date_working` `w` USING(`agrm_id`)
        WHERE `cancel_date` IS NULL
        AND `pay_date` >= TIMESTAMP(`end_date`) AND `pay_date` < TIMESTAMP(`start_date`) 
        AND `w`.`end_date` IS NOT NULL
        AND `w`.`start_date` = v_cur_date
        GROUP BY `agrm_id`;
        UPDATE `tmp_balance_on_date_working` `w` JOIN `tmp_payments` `t` USING(`agrm_id`) SET `w`.`payments` = `t`.`amount`;

        
        INSERT INTO `tmp_from_pays` (`agrm_id`, `amount`)
        SELECT `from_agrm_id`, IFNULL(SUM(`amount`),0)
        FROM `payments` `p` JOIN `tmp_balance_on_date_working` `w` ON `p`.`from_agrm_id` = `w`.`agrm_id`
        WHERE `cancel_date` IS NULL
        AND `pay_date` >= TIMESTAMP(`end_date`) AND `pay_date` < TIMESTAMP(`start_date`) 
        AND `w`.`end_date` IS NOT NULL
        AND `w`.`start_date` = v_cur_date
        GROUP BY `p`.`from_agrm_id`;
        UPDATE `tmp_balance_on_date_working` `w` JOIN `tmp_from_pays` `t` USING(`agrm_id`) SET `w`.`from_pays` = `t`.`amount`;

       
        INSERT INTO `tmp_sales_corr` (`agrm_id`, `amount`)
        SELECT `agrm_id`, SUM(IF(`cancel_date_new` IS NOT NULL OR `cancel_date` IS NOT NULL, 0, `amount_new`-`amount`))
        FROM `sales_history` `h` JOIN `tmp_balance_on_date_working` `w` USING(`agrm_id`)
        WHERE DATE(`local_date_new`) >= TIMESTAMP(`end_date`) AND DATE(`start_date`) < TIMESTAMP(`start_date`) 
        AND `w`.`start_date` = v_cur_date
        GROUP BY `agrm_id`;
        UPDATE `tmp_balance_on_date_working` `w` JOIN `tmp_sales_corr` `t` USING(`agrm_id`) SET `w`.`sales_corr` = `t`.`amount`;

        
        INSERT INTO `tmp_rent` (`agrm_id`, `amount`)
        SELECT `agrm_id`, IFNULL(SUM(`amount`),0)
        FROM `rentcharge` JOIN `tmp_balance_on_date_working` `w` USING(`agrm_id`)
        WHERE `period` >= `end_date` AND `period` < `start_date` 
        AND `w`.`start_date` = v_cur_date
        GROUP BY `agrm_id`;
        UPDATE `tmp_balance_on_date_working` `w` JOIN `tmp_rent` `t` USING(`agrm_id`) SET `w`.`rent` = `t`.`amount`;

        
        INSERT INTO `tmp_usbox` (`agrm_id`, `amount`)
        SELECT `agrm_id`, IFNULL(SUM(`amount`),0)
        FROM `usbox_charge` JOIN `tmp_balance_on_date_working` `w` USING(`agrm_id`)
        WHERE `period` >= `end_date` AND `period` < `start_date` 
        AND `w`.`start_date` = v_cur_date
        GROUP BY `agrm_id`;
        UPDATE `tmp_balance_on_date_working` `w` JOIN `tmp_usbox` `t` USING(`agrm_id`) SET `w`.`usbox` = `t`.`amount`;

        
        INSERT INTO `tmp_charges` (`agrm_id`, `amount`)
        SELECT `agrm_id`, IFNULL(SUM(`amount`),0)
        FROM `charges` JOIN `tmp_balance_on_date_working` `w` USING(`agrm_id`)
        WHERE `period` >= `end_date` AND `period` < `start_date` 
        AND `w`.`start_date` = v_cur_date
        GROUP BY `agrm_id`;
        UPDATE `tmp_balance_on_date_working` `w` JOIN `tmp_charges` `t` USING(`agrm_id`) SET `w`.`charges` = `t`.`amount`;

        
        INSERT INTO `tmp_day` (`agrm_id`, `amount`)
        SELECT `agrm_id`, IFNULL(SUM(`amount`),0)
        FROM `day` JOIN `tmp_balance_on_date_working` `w` USING(`agrm_id`)
        WHERE `timefrom` >= `end_date` AND `timefrom` < `start_date` 
        AND `w`.`start_date` = v_cur_date
        GROUP BY `agrm_id`;
        UPDATE `tmp_balance_on_date_working` `w` JOIN `tmp_day` `t` USING(`agrm_id`) SET `w`.`day` = `t`.`amount`;

        
        UPDATE `tmp_balance_on_date_working` `w`
        SET `end_value` = `start_value` - `payments` + `from_pays` + `sales_corr` + `rent` + `usbox` + `charges` + `day`
        WHERE `w`.`start_date` = v_cur_date;

        
        INSERT IGNORE INTO `tmp_balance_on_date` (`agrm_id`, `date`, `balance`)
        SELECT `agrm_id`, `end_date`, `end_value`
        FROM `tmp_balance_on_date_working` `w`
        WHERE `w`.`start_date` = v_cur_date
        AND `end_date` >= in_date_from
        AND `end_date` < in_date_to;

        
        UPDATE `tmp_balance_on_date_working` `w`
        SET `start_date` = `end_date`, `start_value` = `end_value`, `payments` = 0, `from_pays` = 0, `sales_corr` = 0, `rent` = 0, `usbox` = 0, `charges` = 0, `day` = 0
        WHERE `w`.`start_date` = v_cur_date;

        SET v_cur_date = v_cur_date - INTERVAL 1 DAY;
    END WHILE;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE changefield_sp
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `changefield_sp` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `changefield_sp`( IN v_chfspschema varchar(64)
                               , IN v_chfsptabname varchar(64)
                               , IN v_chfspold_field varchar(64)
                               , IN v_chfspnew_field varchar(64)
                               , IN v_chfspfielddata varchar(4000)
                               , INOUT v_sperror int(11)
                               )
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Переименовать поле в таблице'
BEGIN
  declare v_sql varchar(4000);
  
  
  if(v_chfspnew_field <> v_chfspold_field)
    then
      call show_message('INFO', 0, concat('rename field from `',v_chfspold_field,'` to `',v_chfspnew_field,'` in table `',v_chfsptabname,'`'));
      set v_sql = ifnull(concat('ALTER TABLE `', v_chfspschema, '`.`', ifnull(v_chfsptabname, ''), '` CHANGE `', ifnull(v_chfspold_field, '') , '` `', ifnull(v_chfspnew_field, ''), '` ', ifnull(v_chfspfielddata, '')), '');
  elseif ( v_chfspnew_field = v_chfspold_field )
    then
      call show_message('INFO', 0, concat('update field data for `',v_chfspold_field,'` in table `',v_chfsptabname,'`'));
      set v_sql = ifnull(concat('ALTER TABLE `', v_chfspschema, '`.`', ifnull(v_chfsptabname, ''), '` MODIFY `', ifnull(v_chfspold_field, ''), '` ', ifnull(v_chfspfielddata, '')), '');
  end if;

  call exec_command(v_sql, 1, v_sperror);

END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE change_datetime_fields
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `change_datetime_fields` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `change_datetime_fields`( IN v_chdfschema varchar(64)
                                       , IN v_chdftabname varchar(64)
                                       )
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Меняем поля даты и конвертируем их в корректную дату'
BEGIN
  declare v_error, done int(11) default 0;
  declare v_fname, v_sql varchar(4000);
  declare fields_cur cursor for select mc.column_name from meta$columns mc
                                where mc.table_name = v_chdftabname 
                                and mc.column_type in ('date', 'datetime')
                                and table_schema = v_chdfschema;
  declare continue handler for not found set done = 1;
  
  SET @LB_OLD_SQL_MODE=@@SESSION.sql_mode, @@SESSION.sql_mode='';
  call backup_table(v_chdfschema, v_chdftabname);
  SET @@SESSION.sql_mode=@LB_OLD_SQL_MODE;

  open fields_cur;
  fetch fields_cur into v_fname;
  while not done do
    SET @LB_OLD_SQL_MODE=@@SESSION.sql_mode, @@SESSION.sql_mode='';
    set v_error = 0;
    call changefield_sp(v_chdfschema, v_chdftabname, v_fname, v_fname, 'varchar(255)', v_error);
    if v_error <> 0 then call show_message('ERROR', v_error, concat('Can`t change field ', v_chfold_field, ' in table ', v_chdfschema, '`.`', v_chdftabname)); end if;
    SET @@SESSION.sql_mode=@LB_OLD_SQL_MODE;
    fetch fields_cur into v_fname;
  end while;
  close fields_cur;

  set done = 0;
  open fields_cur;
  fetch fields_cur into v_fname;
  while not done do
    set v_error = 0;
    set @LB_DISABLE_TRIGGERS = 1;
    set v_sql = concat('update ', v_chdfschema, '.', v_chdftabname, ' set ', v_fname, ' = GUESS_DATE(',v_fname,')');
    call exec_command(v_sql, 1, v_error);
    set @LB_DISABLE_TRIGGERS = 0;
    if v_error <> 0 then call show_message('ERROR', v_error, concat('Can`t execute statement:', v_sql)); end if;
    fetch fields_cur into v_fname;
  end while;
  close fields_cur;
  
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE change_field
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `change_field` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `change_field`( IN v_chfschema varchar(64)
                             , IN v_chftabname varchar(64)
                             , IN v_chfold_field varchar(64)
                             , IN v_chfnew_field varchar(64)
                             , IN v_chffielddata varchar(4000)
                             )
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Переименовать поле в таблице'
BEGIN
  declare v_error, done int(11) default 0;
  declare v_coldef_old, v_colnull_old, v_coldef_new, v_colnull_new, v_coltype_old, v_coltype_new, v_error_mess varchar(4000);
  declare v_sql_update, v_sql, v_fname, v_maxcharlength_old, v_maxcharlength_new, v_datatype_old, v_datatype_new varchar(4000);
  declare v_datalength, v_numprec_old, v_numprec_new, v_numscale_old, v_numscale_new int(11);

  declare fields_cur1 cursor for select mct.column_name 
                                 from meta$columns_tmp mct
                                 where mct.table_name = v_chftabname 
                                 and mct.data_type in ('char', 'varchar')
                                 and table_schema = v_chfschema;
  declare continue handler for not found set done = 1;
  
  set v_error = 0;
  set @LB_UPDATESQL_PMESSID = NULL;
  set v_error_mess = concat('Can`t change field ', v_chfold_field, ' in table ', v_chfschema, '.', v_chftabname);
  call changefield_sp(v_chfschema, v_chftabname, v_chfold_field, v_chfnew_field, v_chffielddata, v_error);
  
  if v_error in (1025, 1062, 1832, 1068)
    then
      
      call dropkey_sp_byfield(v_chfschema, v_chftabname, v_chfold_field);
      
      set v_error = 0;
      call changefield_sp(v_chfschema, v_chftabname, v_chfold_field, v_chfnew_field, v_chffielddata, v_error);
      if v_error <> 0 then call show_message('ERROR', v_error, v_error_mess); end if;

  elseif v_error = 1068
    then
      
      set v_error = 0;
      call drop_fkey_sp(database(), v_chftabname, v_error);
      set v_error = 0;
      call changefield_sp(v_chftabname, v_chfold_field, v_chfnew_field, replace(v_chffielddata, 'primary key', ''), v_error);
      if v_error <> 0 then call show_message('ERROR', v_error, v_error_mess); end if;

  elseif v_error in (1265, 1138)
    then
      
      
      select column_type, column_default, is_nullable, character_maximum_length, numeric_precision, numeric_scale, data_type
      into v_coltype_old, v_coldef_old, v_colnull_old, v_maxcharlength_old, v_numprec_old, v_numscale_old, v_datatype_old
      from meta$columns_tmp 
      where table_name = v_chftabname 
      and column_name = v_chfold_field
      and table_schema = v_chfschema;

      select column_type, column_default, is_nullable, character_maximum_length, numeric_precision, numeric_scale, data_type
      into v_coltype_new, v_coldef_new, v_colnull_new, v_maxcharlength_new, v_numprec_new, v_numscale_new, v_datatype_new
      from meta$columns
      where table_name = v_chftabname 
      and column_name = v_chfnew_field;


      if (v_colnull_old <> v_colnull_new)
        then
          
          set v_error = 0;
          set v_sql_update = concat('update ', v_chfschema, '.', ifnull(v_chftabname, '')
                                   , ' set ', ifnull(v_chfold_field, ''), ' = "', if( v_datatype_old like '%int%' or v_datatype_old = 'decimal'
                                                                                    , ifnull(v_coldef_new, 0)
                                                                                    , ifnull(v_coldef_new, '')
                                                                                    )
                                                                                 , '"'
                                   , ' where ', ifnull(v_chfold_field, ''), if( v_colnull_old = 'YES'
                                                                              , ' is null'
                                                                              , concat(' = "', ifnull(v_coldef_old, ''), '"')
                                                                              )
                                   );
          call exec_command(v_sql_update, 1, v_error);
          if v_error <> 0
            then
              call show_message('ERROR', v_error, concat('Can`t execute statement:', v_sql_update));
          end if;
      elseif(v_colnull_old = v_colnull_new and v_coltype_old <> v_coltype_new and v_datatype_old = v_datatype_new)
        then
          
          
          SET @LB_OLD_SQL_MODE=@@SESSION.sql_mode, @@SESSION.sql_mode='';
          set @LB_DISABLE_TRIGGERS = 1;
          call backup_table(v_chfschema, v_chftabname);

          open fields_cur1;
          fetch fields_cur1 into v_fname;
          while not done do
            set v_error = 0;
            set v_sql = concat('update ', v_chfschema, '.', v_chftabname,' set ',v_fname,' = substring(',v_fname,', 1, ',if(v_fname<>v_chfold_field, v_maxcharlength_old, v_maxcharlength_new),')');
            call exec_command(v_sql, 1, v_error);
            if v_error <> 0 then call show_message('ERROR', v_error, v_error_mess); end if;
            fetch fields_cur1 into v_fname;
          end while;
          close fields_cur1;

          set @LB_DISABLE_TRIGGERS = 0;
          SET @@SESSION.sql_mode=@LB_OLD_SQL_MODE;

      end if;
      set v_error = 0;
      call changefield_sp(v_chfschema, v_chftabname, v_chfold_field, v_chfnew_field, v_chffielddata, v_error);
      if v_error <> 0
        then
          call show_message('ERROR', v_error, v_error_mess);
      end if;
  elseif v_error = 1366
    then
      
      select column_type, column_default into v_coltype_old, v_coldef_old from meta$columns_tmp where table_name = v_chftabname and column_name = v_chfold_field;
      select column_type, column_default into v_coltype_new, v_coldef_new from meta$columns     where table_name = v_chftabname and column_name = v_chfold_field;
      if v_coltype_old like '%char%' and (v_coltype_new like '%int%' or v_coltype_new like '%decimal%')
        then
          
          set v_error = 0;
          set v_sql_update = concat('update ', ifnull(v_chftabname, '')
                                   , ' set ', ifnull(v_chfold_field, ''), ' = ', ifnull(concat('"',v_coldef_new,'"'), '-1')
                                   , ' where ', ifnull(v_chfold_field, ''), ' = "', ifnull(v_coldef_old, ''), '"'
                                   );
          
          call dropkey_sp_byfield(v_chfschema, v_chftabname, v_chfold_field);
          call exec_command(v_sql_update, 1, v_error);
          if v_error <> 0 then call show_message('ERROR', v_error, concat('Can`t execute statement:', v_sql_update)); end if;
          
          set v_error = 0;
          call changefield_sp(v_chfschema, v_chftabname, v_chfold_field, v_chfnew_field, v_chffielddata, v_error);
          if v_error <> 0 then call show_message('ERROR', v_error, v_error_mess); end if;
          
          set v_error = 0;
          set v_sql_update = concat('update ', ifnull(v_chftabname, '')
                                   , ' set ', ifnull(v_chfold_field, ''), ' = ', ifnull(concat('"',v_coldef_new,'"'), 'NULL')
                                   , ' where ', ifnull(v_chfold_field, ''), ' = -1'
                                   );
          call exec_command(v_sql_update, 1, v_error);
          if v_error <> 0 then call show_message('ERROR', v_error, concat('Can`t execute statement:', v_sql_update)); end if;
      end if;
  elseif v_error = 1406
    then
      
      select column_type into v_coltype_new from meta$columns where table_name = v_chftabname and column_name = v_chfnew_field;
      set v_datalength = substring_index(substring_index(v_coltype_new, ')', 1), '(', -1);
      set v_sql = concat('select count(*) from ', v_chftabname, ' where length(', v_chfold_field, ') > ', v_datalength);
      call show_message('ERROR', 1406, concat(v_error_mess, ': Data too long for column for column ', v_chfold_field, '\n Please, check data by executing following query: ', v_sql));
  elseif v_error = 1146
    then
      
      call show_message('ERROR', 1146, concat(v_error_mess,': table `',v_chftabname,'` doesn`t exist.'));
  elseif v_error = 1292
    then
      
      set v_error = 0;
      call change_datetime_fields(v_chfschema, v_chftabname);
      call changefield_sp(v_chfschema, v_chftabname, v_chfold_field, v_chfnew_field, v_chffielddata, v_error);
      if v_error <> 0
        then
          call show_message('WARNING', 1292, concat(v_error_mess,': table has incorrect datetime values. \n Please, check data manually, use GUESS_DATE(<datetime_value>) function.'));
          call show_message('INFO'
                           , 1292
                           , "Please, check table, using query like this: select birthdate,GUESS_DATE(birthdate) from accounts where GUESS_DATE(birthdate) = '0000-00-00' and ifnull(birthdate, '0000-00-00') <> '0000-00-00')"
                           );
      end if;
  elseif v_error = 1071
    then
      
      set v_error = 0;
      call dropkey_sp_byfield(v_chfschema, v_chftabname, v_chfold_field);
      call dropindex_sp_byfield(v_chfschema, v_chftabname, v_chfold_field);
      call changefield_sp(v_chfschema, v_chftabname, v_chfold_field, v_chfnew_field, v_chffielddata, v_error);
      if v_error <> 0
        then
          call show_message('ERROR', 1071, concat(v_error_mess, ': Specified key was too long'));
          call show_message('ERROR', v_error, v_error_mess);
      end if;
  elseif v_error <> 0
    then
      call show_message('ERROR', v_error, v_error_mess);
  end if;

END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE change_field_stat
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `change_field_stat` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `change_field_stat`( IN v_cfsschema varchar(64)
                                  , IN v_cfstabprefix varchar(64)
                                  , IN v_cfsoldfield varchar(64)
                                  , IN v_cfsnewfield varchar(64)
                                  , IN v_cfsfielddata varchar(400)
                                  )
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Добавить поле'
BEGIN
  declare v_sql varchar(4000);
  declare v_tabcur varchar(64);
  declare done boolean;
  declare curtabname cursor for select table_name
                                from information_schema.tables
                                where table_schema = v_cfsschema
                                and table_name regexp concat(v_cfstabprefix, if(v_cfstabprefix = 'report', '[0-9]{6}', '[0-9]{11}'));
  declare continue handler for not found set done = true;
  
  set done = false;
  open curtabname;
  fetch curtabname into v_tabcur;
  while not done do
    CALL change_field(v_cfsschema, v_tabcur,v_cfsoldfield, v_cfsnewfield, v_cfsfielddata);
    set done = false;
    fetch curtabname into v_tabcur;
  end while;
  close curtabname;
  
  call change_field( v_cfsschema
                   , concat(v_cfstabprefix,if(v_cfstabprefix = 'report', '', 'NNN'),'YYYYmm',if(v_cfstabprefix = 'report', '', 'dd'))
                   , v_cfsoldfield
                   , v_cfsnewfield
                   , v_cfsfielddata
                   );

END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE CHARGE_IMPL
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `CHARGE_IMPL` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`billing`@`localhost`*/ /*!50003 PROCEDURE `CHARGE_IMPL`(IN in_vg_id int, IN in_agrm_id int, IN in_date date, IN in_c_date date, IN in_amount double)
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Используется триггерами для выполнения списаний'
BEGIN
    IF round(in_amount, 6) <> 0.000000 THEN
        UPDATE `agreements` SET `balance` = `balance` - in_amount WHERE `agrm_id` = in_agrm_id;
        UPDATE `balances` SET `balance` = `balance` - in_amount WHERE `agrm_id` = in_agrm_id AND `date` > in_date;

        -- vlad addon begin
        INSERT INTO teleset_charges (agrm_id, month, fee)
        VALUES(in_agrm_id, DATE_FORMAT(in_date, '%Y-%m-01'), in_amount)
          ON DUPLICATE KEY UPDATE fee = fee + in_amount;
        -- vladd addon end

        IF in_c_date > '0000-00-00' THEN
            SET @LB_DISABLE_TRIGGERS = 1;
            UPDATE `vgroups` SET `amount` = `amount` + in_amount WHERE `vg_id` = in_vg_id AND in_c_date = `c_date`;
            SET @LB_DISABLE_TRIGGERS = NULL;
        END IF;
    END IF;
END */;;

