/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE check_db_version
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `check_db_version` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `check_db_version`(IN in_schema varchar(40))
    READS SQL DATA
    SQL SECURITY INVOKER
BEGIN
    DECLARE db_version INT(11);
    DECLARE db_version_date DATE;
    DECLARE update_version INT(11);
    DECLARE update_version_date DATE;

    SET update_version = SUBSTRING('27.0',1, IF(LOCATE('.','27.0')=0, 253, LOCATE('.','27.0')-1));
    SET update_version_date = DATE('20190423');

    
    IF (SELECT count(1) FROM information_schema.`tables` WHERE `table_schema` = in_schema AND `table_name` = 'db_options') != 0 THEN
        SELECT SUBSTRING(`value`,1, IF(LOCATE('.',`value`)=0, 253, LOCATE('.',`value`)-1)) INTO db_version FROM `db_options` WHERE `name` = 'version_build_name';
        SELECT DATE(`value`) INTO db_version_date FROM `db_options` WHERE `name` = 'version_build_date';
    ELSE
        
        SELECT SUBSTRING(`value`,1,IF(LOCATE('.',`value`)=0, 253, LOCATE('.',`value`)-1)) INTO db_version FROM `options` WHERE `name` = 'version_build_name';
        SELECT DATE(`value`) INTO db_version_date FROM `options` WHERE `name` = 'version_build_date';
    END IF;

    IF (db_version > update_version) THEN
        SET @msg = CONCAT('Update fail. Database version is ',db_version, ', but update.sql version is ',update_version);
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = @msg;
    ELSEIF (db_version = update_version AND db_version_date > update_version_date) THEN
        SET @msg = CONCAT('Update fail. Database version is dated ',db_version_date, ', but update.sql have ',update_version_date, ' date');
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = @msg;
    END IF;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE check_dictionaries
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `check_dictionaries` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `check_dictionaries`()
    READS SQL DATA
    SQL SECURITY INVOKER
BEGIN
    DECLARE rnas_cur CURSOR FOR SELECT `nas_id` FROM `rnas`;

    CALL show_msg('Check dictionary table');

    
    IF (SELECT COUNT(1) FROM `dictionary` `d` RIGHT JOIN `meta$dictionary` `md` ON `d`.`name` = `md`.`name` WHERE `d`.`name` IS NULL AND `md`.`default` = 1) > 0
    THEN
        INSERT INTO `dictionary` (`name`, `radius_type`, `vendor`, `value_type`, `replace_id`, `tagged`, `to_history`, `default`, `nas_id`)
            SELECT `md`.`name`, `md`.`radius_type`, `md`.`vendor`, `md`.`value_type`, `md`.`replace_id`, `md`.`tagged`, `md`.`to_history`,
                   `md`.`default`, `md`.`nas_id`
            FROM `dictionary` `d`
                RIGHT JOIN `meta$dictionary` `md` ON `d`.`name` = `md`.`name`
            WHERE `d`.`name` IS NULL
                AND `md`.`default` = 1;
        CALL show_msg("Dictionary table didn't have several attributes from ethalon. Attributes was added");
    END IF;

    
    IF (SELECT COUNT(1) FROM `dictionary` `d` JOIN `meta$dictionary` `md` ON `d`.`name` = `md`.`name`
        WHERE (`d`.`value_type` != `md`.`value_type`
               OR `d`.`radius_type` != `md`.`radius_type`
               OR `d`.`vendor` != `md`.`vendor`
               OR `d`.`replace_id` != `md`.`replace_id`
               OR `d`.`tagged` != `md`.`tagged`
               OR `d`.`to_history` != `md`.`to_history`)
        AND `d`.`default` = 1) > 0
    THEN
        UPDATE `dictionary` `d`
            JOIN `meta$dictionary` `md` ON `d`.`name` = `md`.`name`
        SET `d`.`radius_type` = `md`.`radius_type`,
            `d`.`vendor` = `md`.`vendor`,
            `d`.`value_type` = `md`.`value_type`,
            `d`.`replace_id` = `md`.`replace_id`,
            `d`.`tagged` = `md`.`tagged`,
            `d`.`to_history` = `md`.`to_history`,
            `d`.`default` = `md`.`default`,
            `d`.`nas_id` = `md`.`nas_id`
        WHERE `d`.`default` = 1;
        CALL show_msg("Dictionary table had wrong values in default attributes. Attributes was repaired");
    END IF;

    CALL show_msg('Check dictionary table is done');
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE check_is_db_locked
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `check_is_db_locked` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `check_is_db_locked`()
    READS SQL DATA
    SQL SECURITY INVOKER
BEGIN
  IF (select get_lock(concat("lock_db_", database()), 1)) = 0 THEN
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'database is locked by LBcore or another update.sql';
  END IF;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE check_is_right_db
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `check_is_right_db` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `check_is_right_db`()
    READS SQL DATA
    SQL SECURITY INVOKER
BEGIN
  declare project_name varchar(255);

  IF (select count(*) from information_schema.tables where table_schema = database() and table_name='db_options') = 0 THEN
      
      CREATE TABLE IF NOT EXISTS `db_options` (
        `name`              char(64) NOT NULL COMMENT 'Название опции',
        `descr`             varchar(255) COMMENT 'Комментарий',
        `value`             varchar(255)  COMMENT 'Значение опции',
        `last_mod_date`     timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'Метка времени последней модификации записи',
        `archive`           tinyint(1) NOT NULL default '0' COMMENT 'Запись удалена (флаг)',
        PRIMARY KEY  (`name`)
      ) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='Опции/настройки специфичные для конкретной БД';
  ELSE
      SELECT value INTO project_name FROM db_options WHERE name='project_name';

      IF IFNULL(project_name,'') = '' THEN
          INSERT INTO `db_options` (`name`,`descr`,`value`)
          VALUES ('project_name','project name like LBcore etc','LBcore')
          ON DUPLICATE KEY UPDATE `value` = VALUES(`value`);
      ELSEIF project_name <> 'LBcore' THEN
          SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Wrong db_version. LBcore database is needed';
      END IF;
  END IF;

END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE CHECK_SALE_STAT
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `CHECK_SALE_STAT` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `CHECK_SALE_STAT`(in_date date)
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Сверка соответствия сумм продаж (sales) и первичных списаний'
begin

    
    call `PREPARE_SALE_STAT_AMOUNTS`(in_date);

    drop table if exists check_sale_stat_report;
    create table check_sale_stat_report(
        uid int comment 'id пользователя',
        agrm_id int comment 'id договора',
        sale_id int comment 'id документа',
        number varchar(255) comment 'номер договора',
        name varchar(255) comment 'имя пользователя',
        receipt varchar(255) comment 'номер документа',
        bdate date comment 'начало периода документа',
        stat_amount decimal(20,6) comment 'сумма по статистике',
        sale_amount decimal(20,6) comment 'сумма по документу',
        sale_dictionary_id int default 0 comment 'id кода gaap',
        gaap int default 0 comment 'код gaap',
        changed int default 0 comment 'состояние продажи: 0 - новая, 1 - изменена, 2 - аннулирована, null - не найдена',
        key kk(bdate,sale_dictionary_id),
        key agrm_id(agrm_id),
        key gaap(gaap),
        key sale_id(sale_id),
        key uid(uid)
    ) engine = memory;

    insert into check_sale_stat_report (sale_id, agrm_id , bdate , sale_dictionary_id , stat_amount , sale_amount, changed)
    select d2.sale_id, d1.agrm_id, d1.bdate, d1.sale_dictionary_id, d1.amount stat_amount, d2.amount sale_amount, d2.changed from stat_amount d1 join sale_amount d2 using (agrm_id,bdate,sale_dictionary_id) where abs(d1.amount - d2.amount) > 0.01;

    insert into check_sale_stat_report (sale_id, agrm_id , bdate , sale_dictionary_id , stat_amount , sale_amount, changed)
    select d2.sale_id, d2.agrm_id, d2.bdate, d2.sale_dictionary_id, 0 stat_amount, d2.amount sale_amount, d2.changed from sale_amount d2 left join stat_amount d1 using (agrm_id,bdate,sale_dictionary_id) where d1.amount is null and d2.amount <> 0;

    insert into check_sale_stat_report (sale_id, agrm_id , bdate , sale_dictionary_id , stat_amount , sale_amount, changed)
    select NULL, d1.agrm_id, d1.bdate, d1.sale_dictionary_id, d1.amount stat_amount, NULL sale_amount, NULL from stat_amount d1 left join sale_amount d2 using (agrm_id,bdate,sale_dictionary_id) where d2.amount is null and d1.amount <> 0;


    update check_sale_stat_report r join sales s using(bdate, agrm_id) set r.sale_id = s.sale_id, changed = 2, sale_amount = 0 where r.sale_id is null and s.cancel_date is not null;
    update check_sale_stat_report r join sales s using(sale_id) set r.receipt = s.receipt;
    update check_sale_stat_report r join agreements a using(agrm_id) set r.uid = a.uid, r.number = a.number;
    update check_sale_stat_report r join accounts a using(uid) set r.name = a.name;
    update check_sale_stat_report r join sale_dictionary d on r.sale_dictionary_id = d.record_id set r.gaap = d.gaap;

END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE check_wrong_views
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `check_wrong_views` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `check_wrong_views`(IN in_schema varchar(40))
    READS SQL DATA
    SQL SECURITY INVOKER
BEGIN
  declare v_error int(11);
  declare v_sql varchar(4000);
  declare curtab_name varchar(255);
  declare done boolean default false;
  declare wrong_views_cur cursor for select table_name,VIEW_DEFINITION from information_schema.VIEWS
                                                       where TABLE_SCHEMA=in_schema;
  declare continue handler for NOT FOUND set done = true;

   

  set done = false;
  open wrong_views_cur;
  fetch wrong_views_cur into curtab_name,v_sql;

  while not done do
    set v_error = 0;
    

    
    SET @LB_UPDATESQL_DEBUG = 2;
    call show_msg(concat("check view ",curtab_name));
    SET @LB_UPDATESQL_DEBUG = 1;
    if LOCATE(" LIMIT ",v_sql) > 0 THEN
      set v_sql = CONCAT(SUBSTRING(v_sql,1,(LOCATE(" LIMIT ",v_sql) - 1))," LIMIT 1");
    else
      set v_sql = CONCAT(v_sql," LIMIT 1");
    end if;
    call exec_command(v_sql,1,v_error);

    if v_error <> 0 then
      SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'FATAL: Can`t collect metadata about columns! Check db for wrong views and/or access rights for user that executes update script';
    end if;
  
    set done = false; 
    fetch wrong_views_cur into curtab_name,v_sql;
  END WHILE;

  close wrong_views_cur;

END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE CLEAN_SERVICE_BLOCKS_DUPLICATES
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `CLEAN_SERVICE_BLOCKS_DUPLICATES` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `CLEAN_SERVICE_BLOCKS_DUPLICATES`(in in_addkey boolean)
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'удаляем дубли блокировок доп.услуг'
BEGIN
    SET @LB_UPDATESQL_DEBUG = 2;

    IF (SELECT count(1) FROM information_schema.table_constraints c
                        JOIN information_schema.key_column_usage u USING(`table_name`, `constraint_schema`, `constraint_name`)
         WHERE `table_name` = 'service_blocks'
               AND `constraint_schema` = database()
               AND `constraint_type` = 'unique'
               AND `column_name` IN ('service_id','vg_id','timefrom','timeto','blocked')) = 0
    THEN
        DROP TABLE IF EXISTS `service_blocks_duplicates`;
        CREATE TEMPORARY TABLE `service_blocks_duplicates` AS SELECT service_id, vg_id, timefrom, timeto, blocked, count(1) cnt
        FROM service_blocks GROUP BY service_id, vg_id, timefrom, timeto, blocked HAVING count(1) > 1;

        DROP TABLE IF EXISTS `service_blocks_duplicates_2`;
        CREATE TEMPORARY TABLE `service_blocks_duplicates_2` AS SELECT min(record_id) record_id
        FROM service_blocks b JOIN service_blocks_duplicates t USING(service_id, vg_id, timefrom, timeto, blocked) GROUP BY service_id;

        DELETE b.* FROM service_blocks b JOIN service_blocks_duplicates t USING(service_id, vg_id, timefrom, timeto, blocked)
        WHERE record_id NOT IN (SELECT record_id FROM service_blocks_duplicates_2);

        IF in_addkey THEN
            CALL add_key(database(), 'service_blocks', 'service_blocks_ubk_1','UNIQUE KEY `service_blocks_ubk_1` (`service_id`,`vg_id`,`timefrom`,`timeto`,`blocked`)');
        END IF;
    ELSE
        CALL show_msg('Key already exists, everything OK');
    END IF;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE CLEAN_TEL_CAT_DUPLICATES
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `CLEAN_TEL_CAT_DUPLICATES` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `CLEAN_TEL_CAT_DUPLICATES`(in in_backup boolean, in in_addkey boolean)
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'удаляем дубли направлений'
BEGIN
    declare v_zone_num varchar(32);
    declare v_catid, v_minzoneid, done, v_agentid int(11);
    declare telcat_cur cursor for select zone_num, cat_id from (select zone_num, cat_id, count(1) from tel_cat group by 1,2 having count(1) > 1) tt;
    declare agents_cur cursor for select id from settings where type in (6, 12);
    declare continue handler for not found set done = 1;

    set @LB_UPDATESQL_DEBUG = 2;
    if (select count(1) from information_schema.table_constraints c join information_schema.key_column_usage u using(table_name, constraint_schema, constraint_name)
         where table_name = 'tel_cat' and constraint_schema = database() and constraint_type = 'unique' and column_name in('cat_id','zone_num')) = 0
    then
        
        
        if(select count(1) from (
                    select distinct qq.zone_num, qq.cat_id, t.descr tariff, c1.descr cat1, c1.above above1, c2.descr cat2, c2.above above2
                    from (  select zone_num, cat_id, tar_id, direction, min(cat_idx) min_cat_idx, max(cat_idx) max_cat_idx
                            from tel_cat c join tel_cat_idx using(zone_id) group by zone_num, cat_id, tar_id, direction
                            having count(distinct cat_idx) > 1) qq
                    join tarifs t using(tar_id)
                    join categories c1 on c1.tar_id = qq.tar_id and c1.cat_idx = qq.min_cat_idx
                    join categories c2 on c2.tar_id =  qq.tar_id and c2.cat_idx = qq.max_cat_idx
                   ) tt) then
            call show_message(  'ERROR',
                                 42004,
                                'Can`t clear duplicates automatically. Please check data using following query: '
                                'select distinct qq.zone_num, qq.cat_id, t.descr tariff, c1.descr cat1, c1.above above1, c2.descr cat2, c2.above above2 '
                                'from (  select zone_num, cat_id, tar_id, direction, min(cat_idx) min_cat_idx, max(cat_idx) max_cat_idx '
                                        'from tel_cat c join tel_cat_idx using(zone_id) group by zone_num, cat_id, tar_id, direction '
                                        'having count(distinct cat_idx) > 1) qq '
                                'join tarifs t using(tar_id) '
                                'join categories c1 on c1.tar_id = qq.tar_id and c1.cat_idx = qq.min_cat_idx '
                                'join categories c2 on c2.tar_id =  qq.tar_id and c2.cat_idx = qq.max_cat_idx');
        else
            if in_backup then
                call backup_table(database(), 'tel_cat');
                call backup_table(database(), 'tel_cat_idx');
                call backup_table(database(), 'tel_cat_master_idx');
            end if;

            start transaction;
                set done = 0;
                open telcat_cur;
                fetch telcat_cur into v_zone_num, v_catid;
                while not done do
                    call show_message('INFO', 0, concat('Working with ', v_zone_num, ' from cat_id = ', v_catid));
                    
                    select min(zone_id) into v_minzoneid from tel_cat where zone_num = v_zone_num and cat_id = v_catid;

                    
                    if (select count(1) from tel_cat t join tel_cat_idx tx using(zone_id) where zone_num = v_zone_num and cat_id = v_catid) = 0
                        AND
                       (select count(1) from tel_cat t join tel_cat_master_idx tx using(zone_id) where zone_num = v_zone_num and cat_id = v_catid) = 0
                    then
                        delete from tel_cat where zone_num = v_zone_num and cat_id = v_catid and zone_id <> v_minzoneid;
                    else
                    
                    
                        
                        drop temporary table if exists tel_cat_idx_tmp;
                        create temporary table tel_cat_idx_tmp as
                                select distinct tar_id, cat_idx, direction
                                from tel_cat_idx tx
                                join tel_cat t using(zone_id)
                                where t.zone_num = v_zone_num
                                and t.cat_id = v_catid;
                        
                        alter table tel_cat_idx_tmp add unique key kk(tar_id, cat_idx, direction);

                        
                        delete tx.*
                        from tel_cat_idx tx
                        join tel_cat_idx_tmp tt using(tar_id, cat_idx, direction)
                        join tel_cat t using(zone_id)
                        where t.zone_num = v_zone_num and t.cat_id = v_catid;

                        
                        insert into tel_cat_idx(tar_id, cat_idx, direction, zone_id)
                        select tar_id, cat_idx, direction, v_minzoneid
                        from tel_cat_idx_tmp;

                    
                        
                        drop temporary table if exists tel_cat_master_idx_tmp;
                        create temporary table tel_cat_master_idx_tmp as
                                select distinct cat_idx, direction
                                from tel_cat_master_idx tx
                                join tel_cat t using(zone_id)
                                where t.zone_num = v_zone_num
                                and t.cat_id = v_catid;
                        
                        alter table tel_cat_master_idx_tmp add unique key kk(cat_idx, direction);

                        
                        delete tx.*
                        from tel_cat_master_idx tx
                        join tel_cat_master_idx_tmp tt using(cat_idx, direction)
                        join tel_cat t using(zone_id)
                        where t.zone_num = v_zone_num and t.cat_id = v_catid;

                        
                        insert into tel_cat_master_idx(cat_idx, direction, zone_id)
                        select cat_idx, direction, v_minzoneid
                        from tel_cat_master_idx_tmp;

                        
                        delete from tel_cat where zone_num = v_zone_num and cat_id = v_catid and zone_id <> v_minzoneid;
                    end if;
                    fetch telcat_cur into v_zone_num, v_catid;
                end while;
                close telcat_cur;
            commit;
            if in_addkey then
                call add_key(database(), 'tel_cat', 'tel_cat_ubk_1','UNIQUE KEY `tel_cat_ubk_1` (`cat_id`,`zone_num`)');
            end if;
        end if;
    else
        call show_msg('Key already exists, everything OK');
    end if;

END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE convert_auth_hist_session_id
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `convert_auth_hist_session_id` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `convert_auth_hist_session_id`(IN in_schema varchar(64))
    READS SQL DATA
    SQL SECURITY INVOKER
BEGIN
  declare v_sql varchar(4000);
  declare v_tabcur varchar(64);
  declare v_sperror int(11) default 0;
  declare done boolean;
  declare curtabname cursor for select table_name
                                from information_schema.tables
                                where table_schema=in_schema
                                and table_name regexp 'auth_hist[0-9]{8}';
  declare continue handler for not found set done = 1;

    set done = false;
    CALL show_msg('Start converting auth_hist tables');
    open curtabname;
    fetch curtabname into v_tabcur;
    while not done do
        call drop_index(in_schema, v_tabcur,'session_id'); 
        call change_field(in_schema, v_tabcur,'session_id','session_id',"varchar(255) DEFAULT NULL COMMENT 'Идентификатор сессии'");
        call add_index(in_schema,v_tabcur,'sessions','KEY `sessions` (`session_id`,`nas_id`)');
        set done = false;
        fetch curtabname into v_tabcur;
    end while;
    close curtabname;
    CALL show_msg('Converting auth_hist tables is done');

END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE create_meta_columns
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `create_meta_columns` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `create_meta_columns`(IN in_schema varchar(64), IN in_mode int(1))
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Метаданные столбцов'
begin
  declare continue handler for sqlwarning begin call show_message('ERROR', 46002, 'FATAL: Can`t collect metadata about columns!'); end;
  
  if(in_mode = 1) then
      drop table if exists meta$columns_tmp;
      create table meta$columns_tmp (
        `table_schema` varchar(64) not null default '',
        `table_name` varchar(64) not null default '',
        `column_name` varchar(64) not null default '',
        `ordinal_position` bigint(21) unsigned not null default '0',
        `column_default` varchar(400) default '',
        `is_nullable` varchar(3) not null default '',
        `data_type` varchar(64) not null default '',
        `character_maximum_length` bigint(21) unsigned default null,
        `character_octet_length` bigint(21) unsigned default null,
        `numeric_precision` bigint(21) unsigned default null,
        `numeric_scale` bigint(21) unsigned default null,
        `character_set_name` varchar(32) default null,
        `collation_name` varchar(32) default null,
        `column_type` varchar(400) not null,
        `column_key` varchar(3) not null default '',
        `extra` varchar(32) not null default '',
        `column_comment` varchar(1024) not null default '',
        `addfielddata` varchar(1024) not null default '',
        key meta$columns_tmp_ibk_1(`table_name`, `column_name`)
      ) engine = MyISAM default charset utf8;

      alter table meta$columns_tmp disable keys;
      insert into meta$columns_tmp( table_schema
                                  , table_name
                                  , column_name
                                  , ordinal_position
                                  , column_default
                                  , is_nullable
                                  , data_type
                                  , character_maximum_length
                                  , character_octet_length
                                  , numeric_precision
                                  , numeric_scale
                                  , character_set_name
                                  , collation_name
                                  , column_type
                                  , column_key
                                  , extra
                                  , column_comment
                                  , addfielddata
                                  )
      select table_schema
           , table_name
           , column_name
           , ordinal_position
           , column_default
           , is_nullable
           , data_type
           , character_maximum_length
           , character_octet_length
           , numeric_precision
           , numeric_scale
           , character_set_name
           , collation_name
           , column_type
           , column_key
           , extra
           , column_comment
           , concat( ifnull(column_type, '')
                   , if( data_type in ('char', 'varchar', 'text', 'shorttext', 'longtext')
                       , ifnull(concat( " CHARACTER SET ", ifnull(character_set_name, '')
                                      , " COLLATE ", ifnull(collation_name, '')
                                      )
                               , "")
                       , " "
                       )
                   , " "
                   , if(lower(ifnull(column_type, '')) <> 'timestamp'
                       , ifnull(if(is_nullable = 'NO',"NOT NULL ", ""), '')
                       , 'NOT NULL ')
                   , ifnull(if( lower(ifnull(column_default, 'NULL')) <> 'current_timestamp'
                              , concat(" default '", column_default, "' ")
                              , concat(" default ", column_default, " ")
                              )
                           , "")
                   , ifnull(if(extra = 'auto_increment', concat(extra, " primary key "), extra), "")
                   , ifnull(concat(" COMMENT '", trim( IF(have_wrong_symbols(column_comment),'',column_comment) ), "'"), "")
                   ) addfielddata
      from information_schema.columns
      where table_schema = in_schema
      and table_name not in ( 'meta$tables'
                            , 'meta$columns'
                            , 'meta$statistics'
                            , 'meta$table_constraints'
                            , 'meta$indexes'
                            , 'meta$key_column_usage'
                            , 'meta$constraints'
                            , 'meta$referential_constraints'
                            , 'meta$table_partitions'
                            , 'meta$character_sets'
                            , 'meta$collation_character_set_applicability'
                            , 'meta$table_order'
                            , 'meta$triggers'
                            );
      alter table meta$columns_tmp enable keys;

      if((select count(*) from meta$columns_tmp) = 0)
        then
          call show_message('ERROR', 46002, 'FATAL: Can`t collect metadata about columns!');
      end if;

  elseif(in_mode = 0)
    then
      drop table if exists meta$columns_tmp;
  else
    call show_message('ERROR', 46001, 'Incorrect mode for create_meta_columns!');
  end if;

end */;;

