        `update_rule` varchar(64) not null default '',
        `delete_rule` varchar(64) not null default '',
        `match_options` varchar(64) not null default '',
        `addconstr_data` varchar(1024) not null default '',
        `dropconstr_data` varchar(1024) not null default '',
        unique key `meta$constraints_tmp_ubk_1`(`table_name`, `constraint_name`),
        key `meta$constraints_tmp_ibk_1`(`table_name`, `constraint_name`, `constraint_type`)
      ) engine = MyISAM default charset utf8;

      alter table meta$constraints_tmp disable keys;
      insert into meta$constraints_tmp( constraint_name
                                      , table_schema
                                      , table_name
                                      , constraint_type
                                      , constraint_columns
                                      , referenced_table_name
                                      , referenced_columns
                                      , unique_constraint_name
                                      , update_rule
                                      , delete_rule
                                      , match_options
                                      , addconstr_data
                                      , dropconstr_data
                                      )
      select tc.constraint_name
           , tc.table_schema
           , tc.table_name
           , tc.constraint_type
           , kcu.constraint_columns
           , ifnull(kcu.referenced_table_name, '') referenced_table_name
           , ifnull(referenced_columns, '') referenced_columns
           , ifnull(rc.unique_constraint_name, '') unique_constraint_name
           , ifnull(rc.update_rule, '') update_rule
           , ifnull(rc.delete_rule, '') delete_rule
           , ifnull(rc.match_option, '') match_option
           , case trim(trim(trailing 'KEY' from tc.constraint_type))
               when 'PRIMARY'
                 then concat(tc.constraint_type, ' (', kcu.constraint_columns, ')')
               when 'UNIQUE'
                 then concat(tc.constraint_type, ' KEY `', tc.constraint_name, '`(', kcu.constraint_columns, ')')
               when 'FOREIGN'
                 then concat( 'CONSTRAINT `'
                            , tc.constraint_name
                            , '` '
                            , tc.constraint_type
                            , '('
                            , kcu.constraint_columns
                            , ') REFERENCES '
                            , ifnull(kcu.referenced_table_name, '')
                            , '('
                            , ifnull(referenced_columns, '')
                            , ')'
                            , if(ifnull(rc.match_option, '') <> 'NONE', concat(' MATCH ', ifnull(rc.match_option, '')), '')
                            , ' ON UPDATE '
                            , ifnull(rc.update_rule, '')
                            , ' ON DELETE '
                            , ifnull(rc.delete_rule, '')
                            )
             end addconstr_data
           , concat( if(trim(trim(trailing 'KEY' from tc.constraint_type)) = 'UNIQUE', '', trim(trim(trailing 'KEY' from tc.constraint_type)))
                    , ' KEY '
                    , if(trim(trim(trailing 'KEY' from tc.constraint_type)) = 'PRIMARY', '', concat(' `', tc.constraint_name,'`'))
                    ) dropconstr_data
      from meta$table_constraints_tmp tc
      join (select kcu.constraint_schema
                 , kcu.constraint_name
                 , kcu.table_schema
                 , kcu.table_name
                 , group_concat( concat('`',kcu.column_name,'`', if(ifnull(s.sub_part, 0) <> 0, ifnull(concat('(', s.sub_part, ')'), ''), ''))
                                 order by kcu.table_schema
                                        , kcu.table_name
                                        , kcu.constraint_name
                                        , kcu.ordinal_position
                                        , s.seq_in_index
                               ) constraint_columns
                 , kcu.referenced_table_name
                 , group_concat( concat('`',if(kcu.referenced_column_name <> '', kcu.referenced_column_name, null),'`')
                                 order by kcu.table_schema
                                        , kcu.table_name
                                        , kcu.constraint_name
                                        , kcu.position_in_unique_constraint
                               ) referenced_columns
            from meta$key_column_usage_tmp kcu
            left join meta$statistics_tmp s
              on kcu.table_schema = s.table_schema
              and kcu.table_name = s.table_name
              and kcu.column_name = s.column_name
              and kcu.constraint_name = s.index_name
            where kcu.constraint_schema = in_schema
            group by kcu.constraint_schema
                   , kcu.constraint_name
                   , kcu.table_schema
                   , kcu.table_name
                   , kcu.referenced_table_name
            order by kcu.table_schema
                   , kcu.table_name
                   , kcu.constraint_name
                   , kcu.ordinal_position
                   , s.seq_in_index
                   , kcu.position_in_unique_constraint
           ) kcu 
        on tc.constraint_schema = kcu.constraint_schema
        and tc.constraint_name = kcu.constraint_name
        and tc.table_schema = kcu.table_schema
        and tc.table_name = kcu.table_name
      left join meta$referential_constraints_tmp rc
        on tc.constraint_schema = rc.constraint_schema
        and tc.constraint_name = rc.constraint_name
        and tc.table_name = rc.table_name
        and ifnull(kcu.referenced_table_name, '----') = ifnull(rc.referenced_table_name, '----')
      where tc.table_schema = in_schema
      and tc.constraint_schema = in_schema
      order by tc.constraint_type desc;
      alter table meta$constraints_tmp enable keys;

      if( (select count(*) from meta$key_column_usage_tmp) = 0 
       or (select count(*) from meta$table_constraints_tmp) = 0

        )
        then
          call show_message('ERROR', 46002, 'FATAL: Can`t collect metadata about constraints!');



      end if;
  elseif(in_mode = 0)
    then
      drop table if exists meta$constraints_tmp;
      drop table if exists meta$referential_constraints_tmp;
      drop table if exists meta$key_column_usage_tmp;
      drop table if exists meta$table_constraints_tmp;
  else
    call show_message('ERROR', 46001, 'Incorrect mode for create_meta_constraints');
  end if;

end */;;

