/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `create_meta_indexes`(IN in_schema varchar(64), IN in_mode int(1))
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Метаданные индексов'
begin
