      drop table if exists meta$table_constraints_tmp;
      drop table if exists meta$indexes_tmp;

      create table meta$statistics_tmp (
        `table_schema` varchar(64) not null default '',
        `table_name` varchar(64) not null default '',
        `non_unique` int(11) not null default '0',
        `index_schema` varchar(64) not null default '',
        `index_name` varchar(64) not null default '',
        `seq_in_index` int(2) not null default '0',
        `column_name` varchar(64) not null default '',
        `sub_part` int(3) not null default '0',
        index_comment varchar(1024) not null default '',
        key `meta$statistics_tmp_ibk_1`(`table_schema`, `table_name`, `index_name`)
      ) engine = MyISAM default charset utf8;

      create table meta$table_constraints_tmp (
        `constraint_schema` varchar(64) not null default '',
        `constraint_name` varchar(64) not null default '',
        `table_schema` varchar(64) not null default '',
        `table_name` varchar(64) not null default '',
        `constraint_type` varchar(64) not null default '',
        key `meta$table_constraints_tmp_ibk_1`(`constraint_schema`, `constraint_name`, `table_schema`, `table_name`)
      ) engine = MyISAM default charset utf8;

      create table meta$indexes_tmp (
        `table_schema` varchar(64) not null default '',
        `table_name` varchar(64) not null default '',
        `index_schema` varchar(64) not null default '',
        `index_name` varchar(64) not null default '',
        `addindexdata` varchar(1024) default null,
        key `meta$indexes_tmp_ibk_1`(`table_name`, `index_name`)
      ) engine = MyISAM default charset utf8;

      alter table meta$statistics_tmp disable keys;
      insert into meta$statistics_tmp(table_schema, table_name, non_unique, index_schema, index_name, seq_in_index, column_name, sub_part, index_comment)
      select table_schema, table_name, non_unique, index_schema, index_name, seq_in_index, column_name, ifnull(sub_part, 0), index_comment
      from  information_schema.`statistics`
      where table_schema = in_schema
      and table_name not in ( 'meta$tables'
                            , 'meta$columns'
                            , 'meta$statistics'
                            , 'meta$table_constraints'
                            , 'meta$indexes'
                            , 'meta$key_column_usage'
                            , 'meta$constraints'
                            , 'meta$referential_constraints'
                            , 'meta$table_partitions'
                            , 'meta$character_sets'
                            , 'meta$collation_character_set_applicability'
                            , 'meta$table_order'
                            , 'meta$triggers'
                            );
      if v_no_cols = 1
        then 
          insert into meta$statistics_tmp(table_schema, table_name, non_unique, index_schema, index_name, seq_in_index, column_name, sub_part, index_comment)
          select table_schema, table_name, non_unique, index_schema, index_name, seq_in_index, column_name, ifnull(sub_part, 0), '' index_comment
          from  information_schema.`statistics`
          where table_schema = in_schema
          and table_name not in ( 'meta$tables'
                                , 'meta$columns'
                                , 'meta$statistics'
                                , 'meta$table_constraints'
                                , 'meta$indexes'
                                , 'meta$key_column_usage'
                                , 'meta$constraints'
                                , 'meta$referential_constraints'
                                , 'meta$table_partitions'
                                , 'meta$character_sets'
                                , 'meta$collation_character_set_applicability'
                                , 'meta$table_order'
                                , 'meta$triggers'
                                );
      end if;
      alter table meta$statistics_tmp enable keys;

      alter table meta$table_constraints_tmp disable keys;
      insert into meta$table_constraints_tmp(constraint_schema, constraint_name, table_schema, table_name, constraint_type)
      select constraint_schema, constraint_name, table_schema, table_name, constraint_type
      from information_schema.table_constraints
      where table_schema = in_schema
      and constraint_schema = in_schema
      and table_name not in ( 'meta$tables'
                            , 'meta$columns'
                            , 'meta$statistics'
                            , 'meta$table_constraints'
                            , 'meta$indexes'
                            , 'meta$key_column_usage'
                            , 'meta$constraints'
                            , 'meta$referential_constraints'
                            , 'meta$table_partitions'
                            , 'meta$character_sets'
                            , 'meta$collation_character_set_applicability'
                            , 'meta$table_order'
                            , 'meta$triggers'
                            );
      alter table meta$table_constraints_tmp enable keys;

      alter table meta$indexes_tmp disable keys;
      insert into meta$indexes_tmp( table_schema
                                  , table_name
                                  , index_schema
                                  , index_name
                                  , addindexdata
                                  )
      select s.table_schema
           , s.table_name
           , s.index_schema
           , s.index_name
           , concat('KEY `'
                   , s.index_name
                   , '`('
                   , if( index_comment = ''
                       , group_concat(concat('`', s.column_name, '`', ifnull(if(s.sub_part <> 0, concat('(', s.sub_part, ')'), ''), ''))
                                  order by s.table_name, s.index_name, s.seq_in_index
                                 )
                       , index_comment
                       )
                   , ')'
                   ) addindexdata
      from meta$statistics_tmp s
      left join meta$table_constraints_tmp tc
        on s.table_schema = tc.table_schema
        and s.table_name = tc.table_name
        and s.index_schema = tc.constraint_schema
        and s.index_name = tc.constraint_name
      where s.table_schema = in_schema
      and tc.constraint_type is null
      group by s.table_name, s.index_name
      order by s.table_name, s.index_name, s.seq_in_index;
      alter table meta$indexes_tmp enable keys;
      
      if((select count(*) from meta$statistics_tmp) = 0 or (select count(*) from meta$table_constraints_tmp) = 0)
        then
          call show_message('ERROR', 46002, 'FATAL: Can`t collect metadata about indexes!');
      end if;
  elseif(in_mode = 0)
    then
      drop table if exists meta$statistics_tmp;
      drop table if exists meta$table_constraints_tmp;
      drop table if exists meta$indexes_tmp;
  else
    call show_message('ERROR', 46001, 'Incorrect mode for create_meta_indexes');
  end if;

end */;;

