        key meta$tables_tmp_ibk_1(`table_name`)
      ) engine = MyISAM default charset = utf8;

      create table meta$table_partitions_tmp (
        `table_schema` varchar(64) not null default '',
        `table_name` varchar(64) not null default '',
        `partition_name` varchar(64) default null,
        `partition_ordinal_position` bigint(21) default null,
        `partition_method` varchar(18) default null,
        `subpartition_method` varchar(18) default null,
        `partition_expression` longtext,
        `subpartition_expression` longtext,
        `partition_description` longtext,
        `table_rows` bigint(21) unsigned default '0',
        `partition_comment` varchar(80) not null default '',
        `tablespace_name` varchar(64) default null,
        key meta$table_partitions_tmp_ibk_1(`table_name`, `partition_name`)
      ) engine = MyISAM default charset = utf8;

      alter table meta$tables_tmp disable keys;
      insert into meta$tables_tmp( table_schema
                                 , table_name
                                 , engine
                                 , table_collation
                                 , create_options
                                 , table_comment
                                 , altertabdata
                                 , table_rows
                                 )
      select table_schema
           , table_name
           , engine
           , table_collation
           , create_options
           , table_comment
           , concat(' engine='
                   , engine
                   , ' ', ifnull(create_options, '')
                   , ifnull(concat(' comment="', replace( IF(have_wrong_symbols(table_comment),'',table_comment),'"', ''), '"'), '')
                   ) altertabdata
           , table_rows
      from information_schema.tables
      where table_schema = in_schema
      and table_type = 'BASE TABLE'
      and table_name not in ( 'meta$tables'
                            , 'meta$columns'
                            , 'meta$statistics'
                            , 'meta$table_constraints'
                            , 'meta$indexes'
                            , 'meta$key_column_usage'
                            , 'meta$constraints'
                            , 'meta$referential_constraints'
                            , 'meta$table_partitions'
                            , 'meta$character_sets'
                            , 'meta$collation_character_set_applicability'
                            , 'meta$table_order'
                            , 'meta$triggers'
                            );
      alter table meta$tables_tmp enable keys;

      alter table meta$table_partitions_tmp disable keys;
      insert into meta$table_partitions_tmp ( table_schema
                                            , table_name
                                            , partition_name
                                            , partition_ordinal_position
                                            , partition_method
                                            , subpartition_method
                                            , partition_expression
                                            , subpartition_expression
                                            , partition_description
                                            , table_rows
                                            , partition_comment
                                            , tablespace_name
                                            )
      select table_schema
           , table_name
           , partition_name
           , partition_ordinal_position
           , partition_method
           , subpartition_method
           , partition_expression
           , subpartition_expression
           , partition_description
           , table_rows
           , partition_comment
           , tablespace_name
      from information_schema.partitions
      where table_schema = in_schema
      and partition_name is not null
      and table_name not in ( 'meta$tables'
                            , 'meta$columns'
                            , 'meta$statistics'
                            , 'meta$table_constraints'
                            , 'meta$indexes'
                            , 'meta$key_column_usage'
                            , 'meta$constraints'
                            , 'meta$referential_constraints'
                            , 'meta$table_partitions'
                            , 'meta$character_sets'
                            , 'meta$collation_character_set_applicability'
                            , 'meta$table_order'
                            , 'meta$triggers'
                            );
      alter table meta$table_partitions_tmp enable keys;



      select count(*) into @v_cnt
      from information_schema.tables
      where table_schema = in_schema
      and table_type = 'BASE TABLE'
      and (engine='InnoDB' and LOCATE('AVG_ROW_LENGTH',create_options) > 0)
      and table_name not in ( 'meta$tables'
                            , 'meta$columns'
                            , 'meta$statistics'
                            , 'meta$table_constraints'
                            , 'meta$indexes'
                            , 'meta$key_column_usage'
                            , 'meta$constraints'
                            , 'meta$referential_constraints'
                            , 'meta$table_partitions'
                            , 'meta$character_sets'
                            , 'meta$collation_character_set_applicability'
                            , 'meta$table_order'
                            , 'meta$triggers'
                            );
      IF @v_cnt > 0
        THEN
          call show_message('Warning', 1, 'Warning: Some tables have wrong create options! You can find it using this query: "select table_schema,table_name,engine,create_options from information_schema.tables where table_schema=database() and engine=''InnoDB'' and LOCATE(''avg_row_length'',create_options) > 0 LIMIT 10;"');
      END IF;

      if( (select count(*) from meta$tables_tmp) = 0 )
        then
          call show_message('ERROR', 46002, 'FATAL: Can`t collect metadata about tables!');
      end if;
  elseif(in_mode = 0)
    then
      drop table if exists meta$tables_tmp;
      drop table if exists meta$table_partitions_tmp;
  else
    call show_message('ERROR', 46001, 'Incorrect mode for create_meta_tables!');
  end if;
end */;;

