/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE CRED_BY_CATEGORY
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `CRED_BY_CATEGORY` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `CRED_BY_CATEGORY`(IN in_date DATE)
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
BEGIN
        
        DECLARE tmp_type INTEGER;
        
        DECLARE tmp_name VARCHAR(255);
        
        DECLARE tmp_date DATETIME;
        
        DECLARE tmp_amount DECIMAL(20,6);
        
        DECLARE tmp_amount_2 DECIMAL(20,6);
        DECLARE tmp_amount_3 DECIMAL(20,6);
        DECLARE tmp_amount_4 DECIMAL(20,6);
        
        DECLARE done BOOLEAN DEFAULT FALSE;
        
        DECLARE balance_by_documents_cred CURSOR FOR
                SELECT type, date, amount FROM tmp_balance_by_documents WHERE amount > 0;
        
        DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;
        
        CREATE TEMPORARY TABLE IF NOT EXISTS tmp_cred_by_category (
                type INTEGER NOT NULL PRIMARY KEY COMMENT 'Идентификатор категории',
                name VARCHAR(255) NOT NULL COMMENT 'Наименование категории',
                amount_2 DECIMAL(20,6) NOT NULL COMMENT 'Общая сумма кредиторской задолженности',
                amount_3 DECIMAL(20,6) NOT NULL COMMENT 'Сумма кредиторской задолженности до 36 месяцев',
                amount_4 DECIMAL(20,6) NOT NULL COMMENT 'Сумма кредиторской задолженности более 36 месяцев'
        );
        TRUNCATE TABLE tmp_cred_by_category;

        
        SET done = FALSE;
        OPEN balance_by_documents_cred;
        balance_by_documents_cred_loop: LOOP
                FETCH balance_by_documents_cred INTO tmp_type, tmp_date, tmp_amount;
                IF done THEN
                        LEAVE balance_by_documents_cred_loop;
                END IF;

                IF tmp_type = 1 THEN
                        SET tmp_name = "Юридические лица и ИП";
                ELSE
                        SET tmp_name = "Физические лица";
                END IF;

                
                SET tmp_amount_2 = tmp_amount;
                
                SET tmp_amount_3 = 0;
                SET tmp_amount_4 = 0;
                
                IF (tmp_date > (in_date - INTERVAL 36 MONTH)) THEN
                        SET tmp_amount_3 = tmp_amount;
                END IF;
                
                IF tmp_date <= (in_date - INTERVAL 36 MONTH) THEN
                        SET tmp_amount_4 = tmp_amount;
                END IF;
                
                INSERT INTO tmp_cred_by_category (type, name, amount_2, amount_3, amount_4)
                VALUES (tmp_type, tmp_name, tmp_amount_2, tmp_amount_3, tmp_amount_4)
                ON DUPLICATE KEY UPDATE
                        amount_2 = amount_2 + VALUES(amount_2),
                        amount_3 = amount_3 + VALUES(amount_3),
                        amount_4 = amount_4 + VALUES(amount_4)
                        ;

                
                
                SET done = FALSE;
        END LOOP;
        CLOSE balance_by_documents_cred;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE CURRENT_SHAPE_CALC
