/*!50003 DROP PROCEDURE IF EXISTS `CURRENT_SHAPE_CALC` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `CURRENT_SHAPE_CALC`(in_dtime datetime)
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Вычисляет текущ. знач. полосы пропускания для уч.записей'
BEGIN

    
    drop temporary table if exists tmp_current_shape_calc;
    create temporary table tmp_current_shape_calc
    (
        vg_id           int not null                        comment 'id учетной записи',
        tar_id          int not null                        comment 'id текущего тарифа',
        vg_shape        bigint unsigned default 0           comment 'скорость, выставленная в св-вах у.з',
        old_cur_shape   bigint unsigned default 0           comment 'текущее значение скорости',
        vg_climit       bigint unsigned default 0           comment 'объем, потребленный с начала период',
        vg_c_date       date NOT NULL DEFAULT '0000-00-00'  comment 'начало периода',
        tar_shape       bigint unsigned default 0           comment 'скорость, выставленная в с-вах тарифа',
        tar_shape_prior tinyint(1) unsigned default 0       comment 'приоритет применения скоростей',
        tar_traff_type  tinyint(1) unsigned default 0       comment 'тип учитываемого трафика',
        tar_type        tinyint(1) unsigned default 0       comment 'тип тарифа',
        new_cur_shape   bigint unsigned default 0           comment 'расчетное значения скорости',
        tm_shape        int unsigned default NULL           comment 'скорость от времени',
        sz_shape        int unsigned default NULL           comment 'скорость от объема',
        turbo_shape_id  int unsigned default NULL           comment 'id записи о турбокнопке',
        turbo_shape     int unsigned default NULL           comment 'скорость в соотв. с турбокнопкой',
        serv_id         int unsigned default NULL           comment 'id услуги турбокнопки',
        close_serv      tinyint(1) unsigned default 0       comment 'флаг необходимости завершения турбокнопки',

        unique key vg_id(vg_id),
        key tar_id(tar_id),
        key vg_shape(vg_shape),
        key serv_id(serv_id),
        key close_serv(close_serv),
        key turbo_shape_id(turbo_shape_id),
        key old_cur_shape(old_cur_shape),
        key new_cur_shape(new_cur_shape)
    ) Engine = Memory;

    
    drop temporary table if exists tmp_tar_tm_shapes;
    create temporary table tmp_tar_tm_shapes
    (
        tar_id int not null comment 'id тарифа',
        tm_shape int unsigned default 0 comment 'значение скорости по тарифу в зависимости от тарифа',
        unique key tar_id(tar_id)
    ) Engine = Memory;

    
    insert into tmp_current_shape_calc(vg_id, tar_id, vg_shape, old_cur_shape, vg_c_date)
    select v.vg_id, v.tar_id, v.shape, v.current_shape, v.c_date
    from vgroups v join settings s using(id)
    where v.archive  = 0
    and v.template = 0
    and s.type    <= 5
    and v.tar_id   > 0
    and v.blocked <> 10;

    
    insert into tmp_tar_tm_shapes (tar_id) select distinct tar_id from tmp_current_shape_calc where vg_shape = 0;

    
    update tmp_current_shape_calc set new_cur_shape = vg_shape where vg_shape > 0;

    
    update tmp_current_shape_calc x join tarifs t using(tar_id)
    set x.tar_shape = t.shape, x.tar_shape_prior = t.shape_prior, x.tar_traff_type = t.traff_type, x.tar_type = t.type
    where x.vg_shape = 0;

    
    update tmp_current_shape_calc x 
    set x.vg_climit = (select ifnull(SUM(CASE x.tar_traff_type
                                           WHEN 1 THEN cl.`c_limit_in` 
                                           WHEN 2 THEN cl.`c_limit_out` 
                                           WHEN 3 THEN cl.`c_limit_in` + cl.`c_limit_out` 
                                           ELSE GREATEST(cl.`c_limit_in`, cl.`c_limit_out`) 
                                         END) / IF(x.tar_type < 2, 1024 * 1024, 60), 0)
                       from `climits` cl
                       where cl.tar_id = x.tar_id 
                         and cl.vg_id  = x.vg_id
                         and cl.c_date = GET_C_DATE(x.vg_c_date, in_dtime))
    where x.vg_shape = 0;

    
    update tmp_tar_tm_shapes set tm_shape = current_time_shape(tar_id, in_dtime);
    update tmp_current_shape_calc x join tmp_tar_tm_shapes s using(tar_id) set x.tm_shape = s.tm_shape where x.vg_shape = 0;

    
    update tmp_current_shape_calc x 
    set x.sz_shape = (select `shape_rate` from `size_shape` where `tar_id` = x.tar_id and `amount` <= x.vg_climit order by `amount` desc limit 1)
    where x.vg_shape = 0;

     
     
    update tmp_current_shape_calc x
    set x.new_cur_shape = CASE tar_shape_prior 
                                WHEN 0 THEN LEAST(sz_shape, tm_shape) 
                                WHEN 1 THEN sz_shape 
                                WHEN 2 THEN tm_shape 
                                ELSE GREATEST(sz_shape, tm_shape) 
                          END
    where vg_shape = 0 and tm_shape > 0 and sz_shape > 0;

    
    update tmp_current_shape_calc x
    set x.new_cur_shape = sz_shape
    where vg_shape = 0 and tm_shape is null and sz_shape > 0;

    
    update tmp_current_shape_calc x
    set x.new_cur_shape = tm_shape
    where vg_shape = 0 and sz_shape is null and tm_shape > 0;

    
    update tmp_current_shape_calc x
    set x.new_cur_shape = tar_shape
    where vg_shape = 0 and sz_shape is null and tm_shape is null;

    
    update tmp_current_shape_calc x set turbo_shape_id = (SELECT record_id FROM turbo_shapes WHERE vg_id = x.vg_id AND in_dtime >= timefrom AND in_dtime <= timeto order by shape desc limit 1);
    update tmp_current_shape_calc x join turbo_shapes s on (x.turbo_shape_id = s.record_id) set x.turbo_shape   = s.shape, x.serv_id = s.serv_id;
    
    update tmp_current_shape_calc x set x.turbo_shape = NULL, x.serv_id = NULL, x.turbo_shape_id = NULL where x.new_cur_shape = 0 or x.turbo_shape < x.new_cur_shape;
    
    update tmp_current_shape_calc x set x.close_serv = 1 where (select count(1) from category_modifiers where includes > 0 and serv_id = x.serv_id  and includes <= c_limit);
    
    update tmp_current_shape_calc x join turbo_shapes s         using(serv_id) set s.timeto = in_dtime where x.close_serv = 1;
    update tmp_current_shape_calc x join category_modifiers m   using(serv_id) set m.timeto = in_dtime where x.close_serv = 1;
    
    update tmp_current_shape_calc x set x.new_cur_shape = x.turbo_shape where x.close_serv = 0 and x.turbo_shape_id;

    
    delete from tmp_current_shape_calc where old_cur_shape = new_cur_shape;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE debtor3month
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `debtor3month` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`billing`@`127.0.0.1`*/ /*!50003 PROCEDURE `debtor3month`(IN d DATE)
BEGIN
  select t.ip
  from (
    select vg.uid, GROUP_CONCAT(t.descr, '') as tars, GROUP_CONCAT(vg.blocked, '') as blocked, GROUP_CONCAT(SUBSTRING(INET6_NTOA(s.segment), 8), ' ') as ip
    from vgroups vg
    LEFT JOIN tarifs t ON (t.tar_id=vg.tar_id)
    LEFT JOIN staff s ON (s.vg_id = vg.vg_id)
    WHERE vg.archive=0 AND vg.blocked = 0
    GROUP BY vg.uid HAVING COUNT(vg.tar_id) >= 2
  ) t
  LEFT JOIN agreements ag ON t.uid=ag.uid
  LEFT JOIN accounts a ON t.uid=a.uid

  LEFT JOIN (
  SELECT a.agrm_id, (COALESCE(r.fee,0) + COALESCE(u.fee,0) + COALESCE(c.fee,0)) as fee
  FROM agreements a
  LEFT JOIN (SELECT agrm_id, sum(amount) as fee FROM rentcharge WHERE period >= d and period < d + interval 1 month AND amount > 0 GROUP BY agrm_id) r ON a.agrm_id = r.agrm_id
  LEFT JOIN (SELECT agrm_id, sum(amount) as fee FROM usbox_charge WHERE period >= d and period < d + interval 1 month AND amount > 0 GROUP BY agrm_id) u ON a.agrm_id = u.agrm_id
  LEFT JOIN (SELECT agrm_id, sum(amount) as fee FROM charges WHERE period >= d and period < d + interval 1 month AND amount > 0 GROUP BY agrm_id) c ON a.agrm_id = c.agrm_id
  WHERE (COALESCE(r.fee,0) + COALESCE(u.fee,0) + COALESCE(c.fee,0)) > 0
  GROUP BY a.agrm_id
  ) r ON r.agrm_id=ag.agrm_id

  WHERE a.type = 2 AND balance*-1 >= fee*3 AND fee > 0;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE DEBT_BY_CATEGORY
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `DEBT_BY_CATEGORY` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `DEBT_BY_CATEGORY`(IN in_date DATE)
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
BEGIN
        
        DECLARE tmp_type INTEGER;
        
        DECLARE tmp_name VARCHAR(255);
        
        DECLARE tmp_date DATETIME;
        
        DECLARE tmp_amount DECIMAL(20,6);
        
        DECLARE tmp_amount_2 DECIMAL(20,6);
        DECLARE tmp_amount_3 DECIMAL(20,6);
        DECLARE tmp_amount_4 DECIMAL(20,6);
        DECLARE tmp_amount_5 DECIMAL(20,6);
        DECLARE tmp_amount_6 DECIMAL(20,6);
        DECLARE tmp_amount_7 DECIMAL(20,6);
        DECLARE tmp_amount_8 DECIMAL(20,6);
        DECLARE tmp_amount_9 DECIMAL(20,6);
        DECLARE tmp_amount_10 DECIMAL(20,6);
        
        DECLARE done BOOLEAN DEFAULT FALSE;
        
        DECLARE balance_by_documents_debt CURSOR FOR
                SELECT type, date, amount FROM tmp_balance_by_documents WHERE amount < 0;
        
        DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;
        
        CREATE TEMPORARY TABLE IF NOT EXISTS tmp_debt_by_category (
                type INTEGER NOT NULL PRIMARY KEY COMMENT 'Идентификатор категории',
                name VARCHAR(255) NOT NULL COMMENT 'Наименование категории',
                amount_2 DECIMAL(20,6) NOT NULL COMMENT 'Общая сумма дебиторской задолженности',
                amount_3 DECIMAL(20,6) NOT NULL COMMENT 'Сумма дебиторской задолженности менее 30 дней',
                amount_4 DECIMAL(20,6) NOT NULL COMMENT 'Сумма дебиторской задолженности от 30 до 45 дней',
                amount_5 DECIMAL(20,6) NOT NULL COMMENT 'Сумма дебиторской задолженности от 46 до 90 дней',
                amount_6 DECIMAL(20,6) NOT NULL COMMENT 'Сумма дебиторской задолженности более 90 дней',
                amount_7 DECIMAL(20,6) NOT NULL COMMENT 'В том числе от 91 до 6 месяцев (вкл)',
                amount_8 DECIMAL(20,6) NOT NULL COMMENT 'В том числе от 7 месяцев до 12 месяцев (вкл)',
                amount_9 DECIMAL(20,6) NOT NULL COMMENT 'В том числе от 12 месяцев до 36 месяцев (вкл)',
                amount_10 DECIMAL(20,6) NOT NULL COMMENT 'Свыше 36 месяцев'
        );
        TRUNCATE TABLE tmp_debt_by_category;

        
        SET done = FALSE;
        OPEN balance_by_documents_debt;
        balance_by_documents_debt_loop: LOOP
                FETCH balance_by_documents_debt INTO tmp_type, tmp_date, tmp_amount;
                IF done THEN
                        LEAVE balance_by_documents_debt_loop;
                END IF;

                IF tmp_type = 1 THEN
                        SET tmp_name = "Юридические лица и ИП";
                ELSE
                        SET tmp_name = "Физические лица";
                END IF;

                
                SET tmp_amount_2 = -tmp_amount;
                
                SET tmp_amount_3 = 0;
                SET tmp_amount_4 = 0;
                SET tmp_amount_5 = 0;
                SET tmp_amount_6 = 0;
                SET tmp_amount_7 = 0;
                SET tmp_amount_8 = 0;
                SET tmp_amount_9 = 0;
                SET tmp_amount_10 = 0;

                
                IF (tmp_date > (in_date - INTERVAL 1 MONTH))
                THEN
                        SET tmp_amount_3 = -tmp_amount;
                END IF;

                
                IF (tmp_date <= (in_date - INTERVAL 1 MONTH)) AND (tmp_date > (in_date - INTERVAL 1 MONTH - INTERVAL 15 DAY))
                THEN
                        SET tmp_amount_4 = -tmp_amount;
                END IF;

                
                IF  (tmp_date <= (in_date - INTERVAL 1 MONTH - INTERVAL 15 DAY)) AND (tmp_date > (in_date - INTERVAL 3 MONTH))
                THEN
                        SET tmp_amount_5 = -tmp_amount;
                END IF;

                
                IF tmp_date <= (in_date - INTERVAL 3 MONTH)
                THEN
                        SET tmp_amount_6 = -tmp_amount;
                END IF;

                
                IF (tmp_date <= (in_date - INTERVAL 3 MONTH)) AND (tmp_date > (in_date - INTERVAL 6 MONTH))
                THEN
                        SET tmp_amount_7 = -tmp_amount;
                END IF;

                
                IF (tmp_date <= (in_date - INTERVAL 6 MONTH)) AND (tmp_date > (in_date - INTERVAL 12 MONTH))
                THEN
                        SET tmp_amount_8 = -tmp_amount;
                END IF;

                
                IF  (tmp_date <= (in_date - INTERVAL 12 MONTH)) AND (tmp_date > (in_date - INTERVAL 36 MONTH))
                THEN
                        SET tmp_amount_9 = -tmp_amount;
                END IF;

                
                IF tmp_date <= (in_date - INTERVAL 36 MONTH) THEN
                        SET tmp_amount_10 = -tmp_amount;
                END IF;

                
                INSERT INTO tmp_debt_by_category
                        (type, name, amount_2, amount_3, amount_4, amount_5, amount_6, amount_7, amount_8, amount_9, amount_10)
                VALUES
                        (tmp_type, tmp_name, tmp_amount_2, tmp_amount_3, tmp_amount_4, tmp_amount_5, tmp_amount_6, tmp_amount_7, tmp_amount_8, tmp_amount_9, tmp_amount_10)
                ON DUPLICATE KEY UPDATE
                        amount_2 = amount_2 + VALUES(amount_2),
                        amount_3 = amount_3 + VALUES(amount_3),
                        amount_4 = amount_4 + VALUES(amount_4),
                        amount_5 = amount_5 + VALUES(amount_5),
                        amount_6 = amount_6 + VALUES(amount_6),
                        amount_7 = amount_7 + VALUES(amount_7),
                        amount_8 = amount_8 + VALUES(amount_8),
                        amount_9 = amount_9 + VALUES(amount_9),
                        amount_10 = amount_10 + VALUES(amount_10)
                        ;

                
                
                SET done = FALSE;
        END LOOP;
        CLOSE balance_by_documents_debt;
END */;;

