# Dump of PROCEDURE delete_alien_tables
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `delete_alien_tables` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `delete_alien_tables`( IN in_database varchar(64)
                                    )
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Удалить таблицы не входящие в стандартную поставку'
BEGIN
  declare v_tabcur varchar(64);
  declare done boolean;
  declare v_error int(11) default 0;
  declare curtabname cursor for select table_name from meta$alien_tables; 
  declare continue handler for not found set done = 1;
  
  set done = false;
  open curtabname;
  fetch curtabname into v_tabcur;

  while not done do
    set v_error = 0;
    call show_message('INFO',0,concat('drop table `', in_database, '`.`',v_tabcur));
    set @s = concat('drop table ',v_tabcur);
    call exec_command(@s, 1, v_error);
    if v_error not in (0, 1146, 1051)
      then
        set v_error = 0;
        call drop_fkey_sp(in_database, v_tabcur, v_error);
        set v_error = 0;
        call show_message('INFO',0,concat('drop table `', in_database, '`.`',v_tabcur));
        set @s = concat('drop table ',v_tabcur);
        call exec_command(@s, 1, v_error);
    end if;
        
    set done = false;
    fetch curtabname into v_tabcur;
  end while;

  close curtabname;

END */;;

