/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE dropindex_sp_byfield
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `dropindex_sp_byfield` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `dropindex_sp_byfield`( IN v_dispschema varchar(64)
                                     , IN v_dispbftabname varchar(64)
                                     , IN v_dispbffield varchar(64)
                                     )
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Удалить индексы, содержащие поле'
BEGIN
  declare v_dispbfkey varchar(64);
  declare v_keycol, v_dropdata, v_dropconstdata varchar(4000);
  declare done, v_error int(11) default 0;
  
  declare ind_name cursor 
          for select distinct s.index_name 
              from meta$statistics_tmp s
              left join meta$key_column_usage_tmp mcu
                on s.table_schema = mcu.table_schema
                and s.table_name = mcu.table_name
                and s.index_name = mcu.constraint_name
              where s.table_name = v_dispbftabname
              and s.column_name = v_dispbffield
              and mcu.column_name is null
              and s.table_schema = v_dispschema;
  
  declare keys_cur cursor
      for select c.constraint_name, c.dropconstr_data
          from meta$constraints_tmp c
          join meta$key_column_usage_tmp kcu using(constraint_name, table_name)
          where kcu.column_name in (select column_name from meta$key_column_usage_tmp 
                                    where table_name = kcu.table_name 
                                    and constraint_name = v_dkkey
                                    and table_schema = kcu.table_schema)
          and kcu.constraint_name <> v_dkkey
          and kcu.table_name = v_dktabname
          and c.table_schema = v_dispschema;
  declare continue handler for not found set done = 1;
  
  call create_meta_constraints(v_dispschema, 1);
  call create_meta_indexes(v_dispschema, 1);
  set done = 0;
  open ind_name;
  fetch ind_name into v_dispbfkey;
  while not done do
    
    set v_error = 0;
    call dropindex_sp(v_dispschema, v_dispbftabname, v_dispbfkey, v_error);
    if v_error in (1025, 1553)
      then
        
        set done = 0;
        open keys_cur;
        fetch keys_cur into v_keycol, v_dropconstdata;
        while not done do
          set v_error = 0;
          call dropkey_sp(v_dispschema, v_dispbftabname, v_keycol, v_dropconstdata, v_error);
          if v_error <> 0 then call show_message('ERROR', v_error, concat('Can`t drop key ',v_keycol,' from table ',v_dispbftabname)); end if;
          set done = 0;
          fetch keys_cur into v_keycol, v_dropconstdata;
        end while;
        close keys_cur;
        set v_error = 0;
        
        call dropindex_sp(v_dispschema, v_dispbftabname, v_dikey, v_error);
        if v_error <> 0 then call show_message('ERROR', v_error, concat('Can`t drop index ',v_dikey,' from table ',v_dispbftabname)); end if;
      end if;
    fetch ind_name into v_dispbfkey;
  end while;
  close ind_name;
  call create_meta_constraints(v_dispschema, 0);
  call create_meta_indexes(v_dispschema, 0);
END */;;

