# Dump of PROCEDURE dropkey_sp_byfield
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `dropkey_sp_byfield` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `dropkey_sp_byfield`( IN v_dkspschema varchar(64)
                                   , IN v_dkspbtabname varchar(64)
                                   , IN v_dkspbcolname varchar(64)
                                   )
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Удалить ключ из таблицы по полю'
BEGIN
  declare v_error, done int(11) default 0;
  declare v_keycol, v_dropconstdata, v_ercolname, v_ercolatrs, v_dtabname varchar(4000);
  
  declare keys_cur cursor
      for select c.table_name, c.constraint_name, c.dropconstr_data
          from meta$table_constraints_tmp tc
          join meta$key_column_usage_tmp kcu using(constraint_schema, constraint_name, table_schema, table_name)
          join meta$constraints_tmp c
            on tc.constraint_name = c.constraint_name
            and tc.table_name = c.table_name
            and tc.constraint_type = c.constraint_type
          where (kcu.table_name = v_dkspbtabname and kcu.column_name = v_dkspbcolname and kcu.table_schema = v_dkspschema)
            or (kcu.referenced_table_name = v_dkspbtabname and kcu.referenced_column_name = v_dkspbcolname)
          order by c.constraint_type;

  declare continue handler for not found set done = 1;

  call create_meta_constraints(v_dkspschema, 1);
  
  set done = 0;
  open keys_cur;
  fetch keys_cur into v_dtabname, v_keycol, v_dropconstdata;
  while not done do
    set v_error = 0;
    call dropkey_sp(v_dkspschema, v_dtabname, v_keycol, v_dropconstdata, v_error);
  
    if v_error = 1075
      then
        
        
        set v_error = 0;
        select column_name
             , replace(lower(replace(addfielddata, 'auto_increment', '')), 'primary key', '')
        into v_ercolname, v_ercolatrs
        from meta$columns_tmp
        where table_name = v_dtabname
        and column_key = 'PRI'
        and table_schema = v_dkspschema;

        call changefield_sp(v_dkspschema, v_dtabname, v_ercolname, v_ercolname, v_ercolatrs, v_error);
        if v_error <> 0
          then
            
            call show_message('ERROR', v_error, concat('Can`t change field ', v_ercolname, ' in table ', v_dkspschema, '`.`', v_dtabname));
          else
            
            set v_error = 0;
            call dropkey_sp(v_dkspschema, v_dtabname, v_keycol, v_dropconstdata, v_error);
            if v_error <> 0
              then
                
                call show_message('ERROR', v_error, concat('Can`t drop key ', v_keycol, ' from table ', v_dtabname));
            end if;
        end if;
    elseif v_error <> 0
      then
        
        call show_message('ERROR', v_error, concat('Can`t drop key ', v_keycol, ' from table ', v_dtabname));
    end if;
    set done = 0;
    fetch keys_cur into v_dtabname, v_keycol, v_dropconstdata;
  end while;
  close keys_cur;
  call create_meta_constraints(v_dkspschema, 0);
end */;;

