/*!50003 DROP PROCEDURE IF EXISTS `drop_extra_rad_key_lbcore` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `drop_extra_rad_key_lbcore`(IN in_schema varchar(64))
    READS SQL DATA
    SQL SECURITY INVOKER
BEGIN
  declare v_sql varchar(4000);
  declare v_tabcur varchar(64);
  declare v_sperror int(11) default 0;
  declare done boolean;
  declare curtabname cursor for select table_name
                                from information_schema.tables
                                where table_schema=in_schema 
                                and (   table_name regexp 'rad[0-9]{11}'
                                     or table_name = 'radNNNYYYYmmdd')   ;
  declare continue handler for not found set done = 1;

    set done = false;
    CALL show_msg('Start converting rad_stat tables');
    open curtabname;
    fetch curtabname into v_tabcur;
    while not done do

        if (select check_key(database(),v_tabcur,'PRIMARY')) > 0 AND (select check_key(database(),v_tabcur,'sessions') > 0) then
            call drop_key(in_schema, v_tabcur,'PRIMARY', 'PRIMARY KEY');
        end if;     
        if (select check_key(database(),v_tabcur,'session_id')) > 0 AND (select check_key(database(),v_tabcur,'sessions') > 0) then
            call drop_index(in_schema, v_tabcur,'session_id'); 
        end if;  

        set done = false;
        fetch curtabname into v_tabcur;
    end while;
    close curtabname;
    CALL show_msg('Converting rad_stat tables is done');

END */;;

