          join meta$key_column_usage_tmp kcu using(constraint_schema, constraint_name, table_schema, table_name)
          join meta$constraints_tmp c
            on tc.constraint_name = c.constraint_name
            and tc.table_name = c.table_name
            and tc.constraint_type = c.constraint_type
          join meta$statistics_tmp s
            on s.table_name = c.table_name
          where ((kcu.referenced_table_name = v_ditabname
              and s.column_name = kcu.referenced_column_name
              and s.column_name in (select column_name from meta$statistics_tmp where index_name = v_dikey))
          or (kcu.table_name = v_ditabname
              and s.column_name = kcu.column_name
              and s.index_name = v_dikey))
          and c.table_schema = v_dischema
