        call dropkey_sp(v_dischema, v_tab_name, v_keycol, v_dropconstdata, v_error);
        if v_error <> 0 then call show_message('ERROR', v_error, concat('Can`t drop key ',v_keycol,' from table ', v_dischema, '.', v_tab_name)); end if;
        set done = 0;
        fetch keys_cur into v_tab_name, v_keycol, v_dropconstdata;
      end while;
      close keys_cur;
      call create_meta_constraints(v_dischema, 0);
      set v_error = 0;
      call dropindex_sp(v_dischema, v_ditabname, v_dikey, v_error);
      if v_error <> 0 then call show_message('ERROR', v_error, concat('Can`t drop index ', v_dikey, ' from table ', v_dischema, '.', v_ditabname)); end if;
  elseif v_error <> 0
    then
      call show_message('ERROR', v_error, concat('Can`t drop index ', v_dikey, ' from table ', v_dischema, '.', v_ditabname));
  end if;

