    then
      
      set v_error1 = 0;
      call dropkey_sp(v_dkschema, v_dktabname, v_dkkey, v_dkkeydata, v_error1);
      if v_error1 in (1553, 1025)
        then
          
          set done = 0;
          open keys_cur;
          fetch keys_cur into v_keycol, v_dropdata;
          while not done do
            set v_error = 0;
            call dropkey_sp(v_dkschema, v_dktabname, v_keycol, v_dropdata, v_error);
            if v_error <> 0 then call show_message('ERROR', v_error, concat('Can`t drop key ', v_keycol, ' from table ', v_dkschema, '.', v_dktabname)); end if;
            set done = 0;
            fetch keys_cur into v_keycol, v_dropdata;
          end while;
          close keys_cur;
          set v_error = 0;
          call dropkey_sp(v_dkschema, v_dktabname, v_dkkey, v_dkkeydata, v_error);
          if v_error <> 0
            then
              call show_message('ERROR', 1553, concat('Can`t drop index ', v_dkkey, ' from table ', v_dkschema, '.', v_dktabname, ': needs in foreign key constraint'));
              call show_message('ERROR', v_error, concat('Can`t drop key ', v_dkkey, ' from table ', v_dkschema, '.', v_dktabname));
          end if;
      elseif v_error = 1075
        then
          
          call create_meta_columns(v_dkschema, 1);
          set v_error = 0;
          select distinct column_name
               , replace(lower(replace(addfielddata, 'auto_increment', '')), 'primary key', '')
          into v_ercolname, v_ercolatrs
          from meta$columns_tmp
          where table_name = v_dktabname
          and column_key = 'PRI'
          and lower(extra) = 'auto_increment'
          and table_schema = v_dkschema;

          call changefield_sp(v_dkschema, v_dktabname, v_ercolname, v_ercolname, v_ercolatrs, v_error);
