/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `drop_rid_fields`(in_schema varchar(255))
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'удаляет колонки rid из всех таблиц схемы'
BEGIN
    DECLARE current_table VARCHAR(255);
    DECLARE v_sql VARCHAR(255);
    DECLARE v_error INT(8);
    DECLARE done BOOLEAN;
    
    DECLARE tables_cursor CURSOR FOR SELECT `table_name` FROM information_schema.columns ic
                                                      LEFT JOIN meta$alien_tables mat USING(`table_name`)
                                                      WHERE ic.`table_schema` = in_schema
                                                            AND ic.`column_name` = 'rid'
                                                            AND mat.`table_name` IS NULL;
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;

    
    
    CALL check_alien_tables(in_schema);

    OPEN tables_cursor;
    SET done = FALSE;
    FETCH tables_cursor INTO current_table;
    WHILE NOT done DO
        SELECT current_table;
        
        SET v_sql = CONCAT('ALTER TABLE', in_schema, '.', current_table, ' DROP COLUMN `rid`');
        SET v_error = 0;
        CALL exec_command(v_sql,1,v_error);
        SET done = FALSE;
        FETCH tables_cursor INTO current_table;
    END WHILE;
    CLOSE tables_cursor;
END */;;

