        insert into `meta$commands_log`(command_text, error_code, process_id, command_time) 
        values(in_command, inout_errnum, @LB_UPDATESQL_PROCESSID, now());
        commit;
        set @LB_UPDATESQL_COMMID = LAST_INSERT_ID();
    elseif(in_mode = 2)
      then
  
        insert into `commands`(com_value) values(in_command);
        commit;
    end if;
END */;;

