/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE fix_balances
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `fix_balances` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `fix_balances`(IN in_fix_date DATE)
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
BEGIN
    DECLARE l_balance, l_balance_acc, l_credit decimal(20,6);
    DECLARE l_agrm_id int(11);
    DECLARE done int(1);
    DECLARE fixed_balances_cur CURSOR FOR SELECT balance, agrm_id, credit, balance_acc FROM agreements WHERE archive = 0;
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;

    SET in_fix_date = ifnull(in_fix_date, current_date());

    SET done = 0;
    OPEN fixed_balances_cur;
    FETCH fixed_balances_cur INTO l_balance, l_agrm_id, l_credit, l_balance_acc;
    WHILE NOT done DO
        INSERT IGNORE INTO balances (`date`, balance, agrm_id)
            SELECT in_fix_date, l_balance, l_agrm_id;
        INSERT IGNORE INTO fixed_balances (`date`, balance, agrm_id, credit, balance_acc)
            SELECT in_fix_date, l_balance, l_agrm_id, l_credit, l_balance_acc;
        SET done = 0;
        FETCH fixed_balances_cur INTO l_balance, l_agrm_id, l_credit, l_balance_acc;
    END WHILE;
    CLOSE fixed_balances_cur;

    
    
    insert into options set
        name = 'last_fix_balances_date',
        descr = 'Дата последней фиксации балансов', 
        value = in_fix_date
    on duplicate key update 
        descr = values(descr),
        value = values(value);
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE get_current_tel_stat
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `get_current_tel_stat` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `get_current_tel_stat`(ym INT UNSIGNED, in_uid INT UNSIGNED)
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Подготовка таблички с детализацией звонков по договору'
BEGIN
     DECLARE done INT default 0;
     DECLARE vgid INT default 0;
     DECLARE tarid INT default 0;
     DECLARE catidx INT default 0;
     DECLARE tab VARCHAR(15);
     DECLARE tab_name CURSOR FOR SELECT table_name FROM INFORMATION_SCHEMA.tables WHERE table_schema=DATABASE() AND table_name LIKE CONCAT('tel','___',ym,'__');
     DECLARE CONTINUE HANDLER FOR NOT FOUND SET done=1;
     DECLARE CONTINUE HANDLER FOR SQLSTATE '02000' SET done=1;

     DROP TEMPORARY TABLE IF EXISTS current_tel_stat;
     CREATE TEMPORARY TABLE current_tel_stat (agrm_id INT, vg_id INT, oper_id INT default 0, tar_id INT default 0, cat_idx INT,
          rent TINYINT default 0, time_discount INT default 0, size_discount INT default 0,
          amount decimal(20,6),  numfrom VARCHAR(32), numto VARCHAR(32), direction TINYINT,
          trunk_in VARCHAR(32) default NULL, trunk_out VARCHAR(32) default NULL, timefrom datetime, duration INT, 
          duration_round INT, zone_id INT default 0, catname VARCHAR(255) default '', c_date date default '0000-00-00',
          key tar_id(tar_id),key cat_idx(cat_idx));

    SET done = 0;
    OPEN tab_name;
    FETCH tab_name INTO tab;
    WHILE NOT done DO
        SET @s = CONCAT('INSERT INTO current_tel_stat (agrm_id, vg_id, oper_id, tar_id, cat_idx, rent, time_discount, size_discount, amount, numfrom, numto, direction, trunk_in, trunk_out, timefrom, duration, duration_round, zone_id, c_date) ',
                                                            'SELECT agrm_id, vg_id, oper_id, tar_id, cat_idx, rent, time_discount, size_discount, amount, numfrom, numto, direction, trunk_in, trunk_out, timefrom, duration, duration_round, zone_id, c_date ',
                                                            'FROM ', tab, ' WHERE uid = ', in_uid);
        PREPARE stmt FROM @s;
        EXECUTE stmt;
        DEALLOCATE PREPARE stmt;

        SET done = 0;
        FETCH tab_name INTO tab;
    END WHILE;
    CLOSE tab_name;

    UPDATE current_tel_stat s, categories c SET s.catname=c.descr where c.tar_id = s.tar_id and c.cat_idx = s.cat_idx;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE get_ipdet
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `get_ipdet` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `get_ipdet`(in_vgid INT UNSIGNED, in_id INT UNSIGNED, in_dt date)
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Подготовка таблички с детализацией по ip'
BEGIN
    DECLARE l_db VARCHAR(32);
    
    DECLARE CONTINUE HANDLER FOR 1146 BEGIN END;
    DECLARE CONTINUE HANDLER FOR 1243 BEGIN END;

    select na_db into l_db from settings where id = in_id;

    DROP TEMPORARY TABLE IF EXISTS ipdet;
    SET @s = CONCAT('CREATE TEMPORARY TABLE ipdet like ', if(l_db > '', l_db, DATABASE()), '.user', LPAD(in_id,3,'0'), DATE_FORMAT(in_dt,'%Y%m%d'));
        
    PREPARE stmt FROM @s;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;

    
    SET @s = CONCAT('INSERT INTO ipdet select * from ', if(l_db > '', l_db, DATABASE()), '.user', LPAD(in_id,3,'0'), DATE_FORMAT(in_dt,'%Y%m%d'),' WHERE vg_id = ', in_vgid);
        
    PREPARE stmt FROM @s;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE GET_TIME_OUT
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `GET_TIME_OUT` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `GET_TIME_OUT`(in_vg_id int,             
                              in_tar_id int,            
                              in_dyn_route int,         
                              in_check_multitar int,    
                              in_zone_num char(32),     
                              in_direction boolean,     
                              in_oper_id int)
    SQL SECURITY INVOKER
    COMMENT 'определение направления и маршрутов при авторизации VoIP'
BEGIN
    declare done boolean;
    declare l_vg_id int;
    declare l_tar_id int;
    declare l_oper_id int;
      
      
      
      
    declare rows_cursor cursor for select distinct d.oper_id, v.vg_id, v.tar_id
                            from tmp_vgroup_directions d
                                join vgroups v on v.uid = d.oper_id
                            where v.archive = 0
                                and v.blocked <> 10
                                and (select count(1) from categories
                                     where tar_id = v.tar_id and oper_id = d.oper_id) > 0;
    declare continue handler for not found set done = 1;

    
    call GET_TMP_DIRECTIONS(in_vg_id, in_tar_id, in_check_multitar, in_zone_num, in_direction, in_oper_id );
    drop temporary table if exists tmp_vgroup_directions;
    create temporary table tmp_vgroup_directions like tmp_directions;
    insert into tmp_vgroup_directions select * from tmp_directions;

    
    drop temporary table if exists tmp_routes;
    create temporary table tmp_routes(
        oper_id  int comment 'оператор, через которого пойдет вызов',
        vg_id    int comment 'у.з. оператора, через которого пойдет вызов',
        zone_id  int comment 'направление в каталоге',
        cat_idx  int comment 'категория тарифа',
        tar_id   int comment 'тариф',
        is_multi tinyint(1) comment 'признак мультитарифа',
        mgmn     tinyint(1) default 0 comment 'признак МГ/МН направления',
        route    char(255) default '' comment 'маршрут, как описано в документации',
        key zone_id(zone_id)
    ) engine = memory comment = 'данные для маршрутизации';

    if not in_dyn_route then
    
        insert into tmp_routes(oper_id, zone_id, cat_idx, tar_id, is_multi)
            select oper_id, zone_id, cat_idx, tar_id, is_multi
            from tmp_vgroup_directions
            order by def_oper desc
            limit 1;
        update tmp_routes r set vg_id = (select vg_id
                                         from vgroups
                                         where uid = r.oper_id
                                         and archive = 0
                                         order by vg_id
                                         limit 1);
    else
    
        drop temporary table if exists tmp_oper_directions;
        create temporary table tmp_oper_directions like tmp_directions;
        open rows_cursor;
        set done = 0;
        fetch rows_cursor into l_oper_id, l_vg_id, l_tar_id;
        while not done do
            call GET_TMP_DIRECTIONS(l_vg_id, l_tar_id, in_check_multitar, in_zone_num, not in_direction, l_oper_id );
            insert ignore into tmp_oper_directions select * from tmp_directions;
            set done = 0;
            fetch rows_cursor into l_oper_id, l_vg_id, l_tar_id;
        end while;
        close rows_cursor;
        
        
        alter table tmp_oper_directions add (route_weight decimal(10,3) default 0, price decimal(10,3) default 0, route char(32) default '');
        if in_dyn_route = 1 then
        
            update tmp_oper_directions d set price   = (select above
                                                        from category_prices
                                                        where tar_id = d.tar_id
                                                        and cat_idx = d.cat_idx
                                                        and timefrom < now()
                                                        order by timefrom desc
                                                        limit 1);
        end if;
        
        update tmp_oper_directions d
        join categories c using(tar_id, cat_idx)
        join routes r on r.oper_id = c.oper_id
        left join route_weights w using(route_id) 
        set d.route_weight = ifnull(w.weight, 0), d.route = r.number;


        insert into tmp_routes(oper_id, vg_id, zone_id, cat_idx, tar_id, is_multi)
            select v.oper_id, o.vg_id, v.zone_id, v.cat_idx, v.tar_id, v.is_multi
            from tmp_vgroup_directions v
            left join tmp_oper_directions o  using(oper_id)
            order by ifnull(o.price, 999999) asc, ifnull(o.route_weight, 0) desc
            limit 1;

        update tmp_routes set route = ( select ifnull(group_concat(route order by price asc, route_weight desc),'')
                                        from tmp_oper_directions
                                        where route > '');
                                        
        if (select count(1) from tmp_routes) = 0 then
            insert into tmp_routes set
                oper_id  = in_oper_id,
                vg_id    = NULL,
                zone_id  = NULL,
                cat_idx  = 0,
                tar_id   = in_tar_id,
                is_multi = 0,
                mgmn     = 0,
                route    = '';
        end if;

    end if;

    update tmp_routes t join tel_cat c using(zone_id) join tel_classes s on c.class = s.id set t.mgmn = s.mgmn;

END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE GET_TMP_DIRECTIONS
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `GET_TMP_DIRECTIONS` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `GET_TMP_DIRECTIONS`(in_vg_id int,           
                                    in_tar_id int,          
                                    in_check_multitar int,  
                                    in_zone_num char(32),   
                                    in_direction boolean,   
                                    in_oper_id int)
    SQL SECURITY INVOKER
    COMMENT 'Вспомогательная процедура получения карты возможных направлений'
BEGIN
    declare l_found_in_main_tariff int default 0;   
    declare l_max_weight int default 0;             

    
    drop temporary table if exists tmp_vgroup_tarifs;
    create temporary table tmp_vgroup_tarifs(tar_id int primary key, is_multi tinyint(1),  key is_multi(is_multi)) engine = memory;
    insert ignore into tmp_vgroup_tarifs(tar_id, is_multi) select tar_id, 1 multi from multitarifs where vg_id = in_vg_id and dtto > now();
    insert ignore into tmp_vgroup_tarifs(tar_id, is_multi) select in_tar_id, 0 from dual;

    
    drop temporary table if exists tmp_directions;
    create temporary table tmp_directions(
        oper_id  int comment 'оператор, через которого пойдет вызов',
        vg_id    int comment 'у.з., для которой определяем направления',
        zone_id  int comment 'направление в каталоге',
        tar_id   int comment 'категория тарифа',
        cat_idx  int comment 'тариф',
        is_multi int comment 'признак мультитарифа',
        weight   int comment 'маршрут "по умолчанию" (как в документации)',
        def_oper int comment 'признак оператора - владельца договора',
        unique key uk(oper_id,vg_id,tar_id,cat_idx),
        key is_multi(is_multi),
        key oper_id(oper_id),
        key weight(weight),
        key def_oper(def_oper)
    ) engine = memory comment='карта возможных направлений';
    insert into tmp_directions(oper_id, vg_id, zone_id, tar_id, cat_idx, is_multi, weight, def_oper)
            select oper_id, in_vg_id, zone_id, tar_id, cat_idx, is_multi, num, oper_id = in_oper_id
            from recalc_tmp_tel_cat
            join tmp_vgroup_tarifs using(tar_id)
            where direction = in_direction
            and in_zone_num like zone_num
            on duplicate key update weight = if(weight > values(weight), weight, values(weight));

    
    if not in_check_multitar then
        select count(1) from tmp_directions where is_multi = 0 into l_found_in_main_tariff;
        if l_found_in_main_tariff then
            delete from tmp_directions where is_multi;
        end if;
    end if;

    
    select max(weight) from tmp_directions into l_max_weight;
    delete from tmp_directions where weight < l_max_weight;

END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE MAKE_TMP_TABLES
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `MAKE_TMP_TABLES` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `MAKE_TMP_TABLES`(in_vgroups int, in_agreements int, in_accounts int, in_currency int, in_settings int, in_tarifs int, in_categories int)
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Копируем таблички во временные'
begin
    
    if in_vgroups then
        drop temporary table if exists vgroups_tmp;
        create temporary table vgroups_tmp(id int, uid int, vg_id int, agrm_id int, login varchar(255), tar_id int, key uid(uid), key vg_id(vg_id), key agrm_id(agrm_id))    ENGINE=MEMORY;
        insert into vgroups_tmp select id, uid, vg_id, agrm_id, login, tar_id from vgroups;
    end if;

    if in_agreements then
        drop temporary table if exists agreements_tmp;
        create temporary table agreements_tmp(agrm_id int, uid int, number varchar(255), cur_id int, oper_id int, key cur_id(cur_id), key agrm_id(agrm_id), key uid(uid))    ENGINE=MEMORY;
        insert into agreements_tmp select agrm_id, uid, number, cur_id, oper_id from agreements;
    end if;

    if in_accounts then
        drop temporary table if exists accounts_tmp;
        create temporary table accounts_tmp(uid int, type int, name varchar(255), key uid(uid))    ENGINE=MEMORY;
        insert into accounts_tmp select uid, type, name from accounts;
    end if;

    if in_currency then
        drop temporary table if exists currency_tmp;
        create temporary table currency_tmp(id int, symbol varchar(255), key id(id))    ENGINE=MEMORY;
        insert into currency_tmp select id, symbol from currency;
    end if;

    if in_settings then
        drop temporary table if exists settings_tmp;
        create temporary table settings_tmp(id int, descr varchar(255), type int, multiply int, key id(id))    ENGINE=MEMORY;
        insert into settings_tmp select id, descr, type, multiply from settings;
    end if;

    if in_tarifs then
        drop temporary table if exists tarifs_tmp;
        create temporary table tarifs_tmp(tar_id int, descr varchar(255), type int, traff_type int, rent decimal(20,6), key tar_id(tar_id))    ENGINE=MEMORY;
        insert into tarifs_tmp select tar_id, descr, type, traff_type, rent from tarifs;
    end if;

    if in_categories then
        drop temporary table if exists categories_tmp;
        create temporary table categories_tmp(tar_id int, cat_idx int, descr varchar(255), key cat_idx(tar_id, cat_idx))    ENGINE=MEMORY;
        insert into categories_tmp select tar_id, cat_idx, descr from categories;
    end if;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE n_convert_blocks
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `n_convert_blocks` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `n_convert_blocks`()
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Конвертация расписания блокировок в новый формат'
BEGIN
    DECLARE thistime TIMESTAMP;
    SELECT NOW() + INTERVAL 1 MINUTE INTO thistime;
    START TRANSACTION;
        INSERT INTO vg_blocks_rasp (vg_id, blk_req, change_time, request_by, id) SELECT vg_id, 0, acc_ondate, 0, id FROM vgroups WHERE acc_ondate > thistime AND archive = 0;
        UPDATE vgroups SET acc_ondate = 0 WHERE acc_ondate > thistime AND archive = 0;
        INSERT INTO vg_blocks_rasp (vg_id, blk_req, change_time, request_by, id) SELECT vg_id, 10, acc_offdate, 0, id FROM vgroups WHERE acc_offdate > thistime AND archive = 0;
        UPDATE vgroups SET acc_offdate = 0 WHERE acc_offdate > thistime AND archive = 0;
   COMMIT;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE OB_BY_CONTRACTORS
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `OB_BY_CONTRACTORS` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `OB_BY_CONTRACTORS`(IN in_bdate DATE, IN in_edate DATE)
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
BEGIN
        
        CREATE TEMPORARY TABLE IF NOT EXISTS tmp_ob_by_contractors
        (
                uid      INTEGER NOT NULL COMMENT 'Идентификатор абонента',
                name     VARCHAR(255) NOT NULL COMMENT 'Наименование абонента',
                bdebt DECIMAL(20,6) NOT NULL COMMENT 'Дебиторская задолженность на начало периода',
                bcred DECIMAL(20,6) NOT NULL COMMENT 'Кредиторская задолженность на начало периода',
                debt  DECIMAL(20,6) NOT NULL COMMENT 'Оборот по дебету за период',
                cred  DECIMAL(20,6) NOT NULL COMMENT 'Оборот по кредиту за период',
                edebt DECIMAL(20,6) NOT NULL COMMENT 'Дебиторская задолженность на конец периода',
                ecred DECIMAL(20,6) NOT NULL COMMENT 'Кредиторская задолженность на конец периода',

                PRIMARY KEY(uid)
        ) ENGINE=MEMORY, DEFAULT CHARSET=utf8;
        TRUNCATE TABLE tmp_ob_by_contractors;

        
        CALL BALANCE_BY_DOCUMENTS(in_bdate, 0);

        
        
        DROP TABLE IF EXISTS agrms;
        CREATE TEMPORARY TABLE agrms(agrm_id int(11) PRIMARY KEY);
        INSERT INTO agrms SELECT agrm_id FROM vgids ON duplicate KEY UPDATE agrm_id = VALUES(agrm_id);

        
        INSERT INTO tmp_ob_by_contractors(uid, name, bdebt, bcred, debt, cred, edebt, ecred)
        SELECT a.uid, u.name, 
        IF(d.doctype or (d.id = 0 and d.amount < 0), -d.amount, 0       ),
        IF(d.doctype or (d.id = 0 and d.amount < 0), 0,        d.amount),
        0,0,0,0
        FROM tmp_balance_by_documents d
        JOIN agreements a ON d.agrm_id = a.agrm_id
        JOIN accounts u ON a.uid = u.uid
        ON DUPLICATE KEY UPDATE
            bdebt = bdebt + IF(d.doctype or (d.id = 0 and d.amount < 0), -d.amount, 0       ),
            bcred = bcred + IF(d.doctype or (d.id = 0 and d.amount < 0), 0,        d.amount);

        
        DROP TABLE tmp_balance_by_documents;

        
        CALL PAYMENTS_BY_PERIOD(in_bdate, in_edate);

        
        INSERT INTO tmp_ob_by_contractors(uid, name, bdebt, bcred, debt, cred, edebt, ecred )
        SELECT a.uid, u.name, 0, 0, 0, d.amount, 0, 0
        FROM tmp_payments_by_period d
        JOIN agreements a ON d.agrm_id = a.agrm_id
        JOIN accounts u ON a.uid = u.uid
        JOIN agrms a1 ON d.agrm_id = a1.agrm_id
        ON DUPLICATE KEY UPDATE 
            cred = cred + d.amount;
        
        

        
        
        INSERT INTO tmp_ob_by_contractors(uid, name, bdebt, bcred, debt, cred, edebt, ecred)
        SELECT a.uid, u.name, 0, 0, 0, d.amount, 0, 0
        FROM tmp_payments_by_period d
        JOIN agreements a ON d.from_agrm_id = a.agrm_id
        JOIN accounts u ON a.uid = u.uid
        JOIN agrms a1 ON d.from_agrm_id = a1.agrm_id
        ON DUPLICATE KEY UPDATE 
            cred = cred + d.amount ;        
        
        

        
        DROP TABLE tmp_payments_by_period;

        
        CALL SALES_BY_PERIOD(in_bdate, in_edate);

        
        INSERT INTO tmp_ob_by_contractors(uid, name, bdebt, bcred, debt, cred, edebt, ecred)
        SELECT a.uid, u.name, 0, 0, d.amount, 0, 0, 0
        FROM tmp_sales_by_period d
        JOIN agreements a ON d.agrm_id = a.agrm_id
        JOIN accounts u ON a.uid = u.uid
        ON DUPLICATE KEY UPDATE 
            debt = debt + d.amount; 
        
        

        
        DROP TABLE tmp_sales_by_period;
        DROP TABLE tmp_sale_by_period_details;

        
        CALL BALANCE_BY_DOCUMENTS(in_edate, 0);
        
        
        INSERT INTO tmp_ob_by_contractors(uid, name, bdebt, bcred, debt, cred, edebt, ecred)
        SELECT a.uid, u.name, 0, 0, 0, 0, 
        IF(d.doctype or (d.id = 0 and d.amount < 0), -d.amount, 0       ),
        IF(d.doctype or (d.id = 0 and d.amount < 0), 0,        d.amount)
        FROM tmp_balance_by_documents d
        JOIN agreements a ON d.agrm_id = a.agrm_id
        JOIN accounts u ON a.uid = u.uid
        ON DUPLICATE KEY UPDATE 
            edebt = edebt + IF(d.doctype or (d.id = 0 and d.amount < 0), -d.amount, 0       ),
            ecred = ecred + IF(d.doctype or (d.id = 0 and d.amount < 0), 0,        d.amount);

        
        DROP TABLE tmp_balance_by_documents;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE PAYMENTS_BY_EPS
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `PAYMENTS_BY_EPS` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `PAYMENTS_BY_EPS`(IN in_bdate DATE, IN in_edate DATE)
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
BEGIN
        
        
        
        CREATE TEMPORARY TABLE IF NOT EXISTS tmp_payments_by_eps
        (
                external_id VARCHAR(64) NOT NULL COMMENT 'Идентификатор ВПС',
                name        VARCHAR(255) NOT NULL COMMENT 'Наименование ВПС',
                amount      DECIMAL(20,6) NOT NULL COMMENT 'Сумма платежей',

                PRIMARY  KEY(external_id)
        ) ENGINE=MEMORY, DEFAULT CHARSET=utf8;
        TRUNCATE TABLE tmp_payments_by_eps;

        
        
        
        CALL PAYMENTS_BY_PERIOD(in_bdate, in_edate);

        
        
        
        INSERT INTO tmp_payments_by_eps
        (
                external_id,
                name,
                amount
        )
        SELECT
                m.external_id,
                m.fio,
                p.amount
        FROM
                tmp_payments_by_period p,
                managers m
        WHERE
                p.from_agrm_id IS NULL AND
                IFNULL((SELECT ph.mod_person FROM payments_history ph WHERE ph.origin_record_id = p.origin_record_id ORDER BY ph.local_date ASC LIMIT 1), p.mod_person) = m.person_id AND
                m.payments = 1 AND
                m.external_id IS NOT NULL AND
                m.external_id <> ''
        ON DUPLICATE KEY UPDATE
                amount = tmp_payments_by_eps.amount + VALUES(amount);

END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE PAYMENTS_BY_PERIOD
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `PAYMENTS_BY_PERIOD` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `PAYMENTS_BY_PERIOD`(IN in_bdate DATE, IN in_edate DATE)
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
BEGIN
    declare l_lock_period DATE default 0;
    select date(value) into l_lock_period from options where name = 'lock_period';

	DROP TABLE IF EXISTS tmp_payments_by_period;
	CREATE TEMPORARY TABLE IF NOT EXISTS tmp_payments_by_period
	(
		record_id        INT(11) NOT NULL COMMENT 'Идентификатор версии платежа',
		origin_record_id INT(11) NOT NULL COMMENT 'Идентификатор платежа, к которому относится данное исправление',
		agrm_id          INT(11) NOT NULL COMMENT 'Идентификатор лицевого счета зачисления платёжа',
		amount           DECIMAL(20,6) NOT NULL COMMENT 'Сумма платежа в валюте лицевого счета, пересчитанная на дату платежа',
		comment          VARCHAR(500) NOT NULL COMMENT 'Комментарий к платежу',
		receipt          VARCHAR(255) DEFAULT NULL COMMENT 'Идентификатор документа, подтверждающего платёж',
		pay_date         DATETIME NOT NULL COMMENT 'Дата платежа (пересчёты сумм(разностей сумм) из одной валюты в другую выполняются на эту дату)',
		local_date       DATETIME NOT NULL COMMENT 'Дата создания/изменения платежа по часам АСР',
		cancel_date      DATETIME DEFAULT NULL COMMENT 'Дата аннулирования платежа',
		period_date      DATE DEFAULT NULL COMMENT 'Период бух.учта, к которому относится платёж',
		status           TINYINT(1) NOT NULL DEFAULT 0 COMMENT 'Статус платежа: 0-платеж проведен, 1-проведен и подтвержден сверкой (при загрузке файла сверки), 2-платеж аннулирован',
		mod_person       INT(11) NOT NULL COMMENT 'Идентификатор менеджера создавшего/изменившего платёж',
		order_id         INT(11) DEFAULT NULL COMMENT 'Идентификатор оплачиваемого счёта',
		class_id         INT(11) NOT NULL COMMENT 'Идентификатор категории платежа',
		agrm_number      VARCHAR(64) DEFAULT NULL COMMENT 'Номер договора авансового платежа',
		amount_cur       DECIMAL(20,6) NOT NULL COMMENT 'Сумма платежа в валюте платежа',
		amount_cur_id    INT(11) NOT NULL COMMENT 'Валюта платежа',
		from_agrm_id     INT(11) DEFAULT NULL COMMENT 'Идентификатор лицевого счёта, с которого поступил платёж',
		bso_id           INT(11) DEFAULT NULL COMMENT 'Идентификатор бланка строгой отчетности',
		uuid             VARCHAR(40) DEFAULT NULL COMMENT 'Идентификатор платежа для интеграции с внешними системами',

		PRIMARY KEY(record_id, origin_record_id, agrm_id),
		UNIQUE KEY origin_record_id(agrm_id, origin_record_id),
		key agrm_id(agrm_id),
		key origin(origin_record_id),
		key mod_person(mod_person),
		key from_agrm_id(from_agrm_id)
		
	) ENGINE=MEMORY, DEFAULT CHARSET=utf8;

    
    drop temporary table if exists agrms;
    create temporary table agrms(agrm_id int(11) primary key);
    insert into agrms select distinct agrm_id from vgids;

    
    
    
    

    
    insert into tmp_payments_by_period 
            ( record_id, origin_record_id, agrm_id, amount, comment, receipt, pay_date, local_date, cancel_date, period_date, status, mod_person, order_id, class_id, agrm_number, amount_cur, amount_cur_id, bso_id, uuid, from_agrm_id)
    select            0,        record_id, agrm_id, amount, comment, receipt, pay_date, local_date, cancel_date, period_date, status, mod_person, order_id, class_id, agrm_number, amount_cur, amount_cur_id, bso_id, uuid, from_agrm_id
    from payments p 
    join agrms v using (agrm_id)
    where 1=1 
    and cancel_date is null 
    and period_date >= in_bdate 
    and period_date < in_edate;
    

    
    
    insert into tmp_payments_by_period 
            ( record_id, origin_record_id,    agrm_id,     amount,    comment,    receipt,    pay_date,    local_date,    cancel_date, period_date,                                                             status,    mod_person,    order_id,    class_id,    agrm_number,     amount_cur,    amount_cur_id,    from_agrm_id,    bso_id,    uuid)
    select            1,      p.record_id, ph.agrm_id, -ph.amount, ph.comment, ph.receipt, ph.pay_date, ph.local_date, ph.cancel_date, IFNULL(p.period_date, EXPECT_PERIOD_DATE2(p.pay_date, l_lock_period)),   ph.status, ph.mod_person, ph.order_id, ph.class_id, ph.agrm_number, -ph.amount_cur, ph.amount_cur_id, ph.from_agrm_id, ph.bso_id, ph.uuid
    from payments_history ph 
    join agrms v using (agrm_id)
    join payments p on ph.origin_record_id = p.record_id
    where 1=1 
    and ph.cancel_date is null
    and IFNULL(p.period_date, EXPECT_PERIOD_DATE2(p.pay_date, l_lock_period)) >= in_bdate 
    and IFNULL(p.period_date, EXPECT_PERIOD_DATE2(p.pay_date, l_lock_period)) < in_edate 
    and ph.period_date < in_bdate 
    and ph.record_id = (select max(record_id)from payments_history 
                        where origin_record_id = ph.origin_record_id  
                        and period_date < in_bdate)  
    on duplicate key update tmp_payments_by_period.amount       = tmp_payments_by_period.amount     + values(amount),
                            tmp_payments_by_period.amount_cur   = tmp_payments_by_period.amount_cur + values(amount_cur);
                            
                            


    
    insert into tmp_payments_by_period 
            ( record_id, origin_record_id,    agrm_id,     amount,    comment,    receipt,    pay_date,    local_date,    cancel_date,    period_date,    status,    mod_person,    order_id,    class_id,    agrm_number,     amount_cur,    amount_cur_id,    from_agrm_id,    bso_id,    uuid)
    select            1,      p.record_id, ph.agrm_id,  ph.amount, ph.comment, ph.receipt, ph.pay_date, ph.local_date, ph.cancel_date, ph.period_date, ph.status, ph.mod_person, ph.order_id, ph.class_id, ph.agrm_number,  ph.amount_cur, ph.amount_cur_id, ph.from_agrm_id, ph.bso_id, ph.uuid
    from payments_history ph 
    join agrms v using (agrm_id)
    JOIN payments p ON ph.origin_record_id = p.record_id 
    WHERE 1=1
    AND ph.cancel_date IS NULL
    and IFNULL(p.period_date, EXPECT_PERIOD_DATE2(p.pay_date, l_lock_period)) >= in_edate
    AND ph.period_date >= in_bdate
    AND ph.period_date < in_edate
    AND ph.record_id = (SELECT max(record_id)FROM payments_history 
                        WHERE origin_record_id = ph.origin_record_id 
                        AND period_date >= in_bdate
                        AND period_date < in_edate)
    on duplicate key update tmp_payments_by_period.amount       = tmp_payments_by_period.amount     + values(amount),
                            tmp_payments_by_period.amount_cur   = tmp_payments_by_period.amount_cur + values(amount_cur);
       


    
    insert into tmp_payments_by_period 
            ( record_id, origin_record_id,      agrm_id,   amount, comment, receipt, pay_date, local_date, cancel_date, period_date, status, mod_person, order_id, class_id, agrm_number,   amount_cur, amount_cur_id, bso_id, uuid, from_agrm_id)
    select            0,        record_id, from_agrm_id, - amount, comment, receipt, pay_date, local_date, cancel_date, period_date, status, mod_person, order_id, class_id, agrm_number, - amount_cur, amount_cur_id, bso_id, uuid, from_agrm_id
    from payments p 
    join agrms v on p.from_agrm_id = v.agrm_id
    where 1=1 
    and cancel_date is null 
    and period_date >= in_bdate 
    and period_date < in_edate
    on duplicate key update tmp_payments_by_period.amount       = tmp_payments_by_period.amount     + values(amount),
                            tmp_payments_by_period.amount_cur   = tmp_payments_by_period.amount_cur + values(amount_cur);



    
    insert into tmp_payments_by_period 
            ( record_id, origin_record_id,        agrm_id,     amount,    comment,    receipt,    pay_date,    local_date,    cancel_date, period_date,                                                             status,    mod_person,    order_id,    class_id,    agrm_number,     amount_cur,    amount_cur_id,    from_agrm_id,    bso_id,    uuid)
    select            1,      p.record_id, p.from_agrm_id,  ph.amount, ph.comment, ph.receipt, ph.pay_date, ph.local_date, ph.cancel_date, IFNULL(p.period_date, EXPECT_PERIOD_DATE2(p.pay_date, l_lock_period)),   ph.status, ph.mod_person, ph.order_id, ph.class_id, ph.agrm_number,  ph.amount_cur, ph.amount_cur_id, ph.from_agrm_id, ph.bso_id, ph.uuid
    from payments_history ph 
    join agrms v on ph.from_agrm_id = v.agrm_id 
    join payments p on ph.origin_record_id = p.record_id 
    where 1 = 1
    and ph.cancel_date is null 
    and IFNULL(p.period_date, EXPECT_PERIOD_DATE2(p.pay_date, l_lock_period)) >= in_bdate 
    and IFNULL(p.period_date, EXPECT_PERIOD_DATE2(p.pay_date, l_lock_period)) < in_edate 
    and ph.period_date < in_bdate 
    and ph.record_id = (select max(record_id)from payments_history 
                        where origin_record_id = ph.origin_record_id 
                        and period_date < in_bdate)
    on duplicate key update tmp_payments_by_period.amount       = tmp_payments_by_period.amount     + values(amount),
                            tmp_payments_by_period.amount_cur   = tmp_payments_by_period.amount_cur + values(amount_cur);
	

	
    
    insert into tmp_payments_by_period 
            ( record_id, origin_record_id,    agrm_id,           amount,    comment,    receipt,    pay_date,    local_date,    cancel_date,    period_date,    status,    mod_person,    order_id,    class_id,    agrm_number,     amount_cur,    amount_cur_id,    from_agrm_id,    bso_id,    uuid)
    select            1,      p.record_id, ph.from_agrm_id,  -ph.amount, ph.comment, ph.receipt, ph.pay_date, ph.local_date, ph.cancel_date, ph.period_date, ph.status, ph.mod_person, ph.order_id, ph.class_id, ph.agrm_number, -ph.amount_cur, ph.amount_cur_id, ph.from_agrm_id, ph.bso_id, ph.uuid
    from payments_history ph 
    join payments p on ph.origin_record_id = p.record_id
    join agrms v on p.from_agrm_id = v.agrm_id
    where 1=1 
    and ph.cancel_date is null
    and IFNULL(p.period_date, EXPECT_PERIOD_DATE2(p.pay_date, l_lock_period)) >= in_edate
    and ph.period_date >= in_bdate 
    and ph.period_date < in_edate 
    and ph.record_id = (select min(record_id)from payments_history 
                        where origin_record_id = ph.origin_record_id  
                        and period_date >= in_bdate 
                        and period_date < in_edate)  
    on duplicate key update tmp_payments_by_period.amount       = tmp_payments_by_period.amount     + values(amount),
                            tmp_payments_by_period.amount_cur   = tmp_payments_by_period.amount_cur + values(amount_cur);


	update tmp_payments_by_period set from_agrm_id = NULL where from_agrm_id = agrm_id;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE PORT_CONDITION_1
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `PORT_CONDITION_1` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `PORT_CONDITION_1`(IN in_port int, OUT out_state int)
    READS SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Определение состояние для политики отключения порта'
BEGIN
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET out_state = 0;
    SELECT IF(`vgroups`.`blocked`, 2, 1) INTO out_state FROM `vgroups`,`ports` WHERE `vgroups`.`vg_id` = `ports`.`vg_id` AND `ports`.`port_id`= in_port;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE PORT_CONDITION_2
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `PORT_CONDITION_2` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `PORT_CONDITION_2`(IN in_port int, OUT out_state int)
    READS SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Определение состояние для политики Redirect'
BEGIN
    DECLARE p_agrm_id int;
    DECLARE p_balance decimal DEFAULT 0;
    DECLARE tv_sum decimal DEFAULT 0;
    DECLARE services_sum decimal DEFAULT 0;
    DECLARE inet_sum decimal DEFAULT 0; 
    -- DECLARE CONTINUE HANDLER FOR NOT FOUND SET out_state = 0;

    SELECT `vgroups`.`agrm_id` INTO p_agrm_id FROM `vgroups`,`ports` WHERE `vgroups`.`vg_id` = `ports`.`vg_id` AND `ports`.`port_id`= in_port;

    SELECT `balance` INTO p_balance FROM `agreements` WHERE `agrm_id`= p_agrm_id;
    
    -- Get services rent
    SELECT COALESCE(SUM(sc.`above`),0) INTO services_sum
    FROM `vgroups` vg 
    JOIN `services` s ON vg.`vg_id` = s.`vg_id`
    JOIN `service_categories` sc ON s.`tar_id` = sc.`tar_id` AND s.`serv_cat_idx` = sc.`serv_cat_idx`
    WHERE vg.`agrm_id` = p_agrm_id 
      AND vg.`blocked` = 0 
      AND vg.`archive` = 0
      AND s.`need_calc` = 1;

    -- Get TV rent
    SELECT COALESCE(SUM(c.`above`),0) INTO tv_sum
    FROM `vgroups` vg 
    JOIN `usbox_services` s ON vg.`vg_id` = s.`vg_id`
    JOIN `categories` c ON s.`tar_id` = c.`tar_id` AND s.`cat_idx` = c.`cat_idx`
    WHERE vg.`agrm_id` = p_agrm_id 
      AND vg.`blocked` = 0 
      AND vg.`archive` = 0
      AND s.`need_calc` = 1
      AND c.`archive` = 0;

    -- Get INTERNET rent
    SELECT COALESCE(SUM(t.`rent`),0) INTO inet_sum
    FROM `vgroups` vg 
    JOIN `tarifs` t ON vg.`tar_id` = t.`tar_id`
    WHERE vg.`agrm_id` = p_agrm_id AND vg.`blocked` = 0 AND vg.`archive` = 0 AND vg.`id` = 1;

    SELECT IF(-1*p_balance >= (services_sum + tv_sum + inet_sum)*3, 1, 0) INTO out_state;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE PREPARE_REPORT
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `PREPARE_REPORT` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`billing`@`127.0.0.1`*/ /*!50003 PROCEDURE `PREPARE_REPORT`(in in_ym int, in in_uid int, in in_ugrp int, in in_grp int)
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Формирует reportYYYYMM для группы юзеров (v.2.013.2015-03-19)'
BEGIN
    DECLARE `done` int;
    DECLARE `startdate` varchar(32);
    DECLARE `tabname` varchar(32);

    DECLARE CONTINUE  HANDLER FOR NOT FOUND SET done = 1;


    set startdate = concat(in_ym, "01000000");
    set tabname   = concat("report", in_ym);
    set @s        = concat("drop table if exists ", tabname,";");

    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;

    set @s        = concat("create table ", tabname, " like `reportYYYYmm`;");

    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;

    drop table if exists acc4rep;
    create temporary table acc4rep (
        uid int default 0,
        vg_id int default 0,
        `id` int default 0,
        agrm_id int default 0,
        key uid(uid),
        key vg_id(vg_id),
        key `id`(`id`, vg_id),
        key agrm_id(agrm_id)
    );
    -- `MAKE_TMP_TABLES`(in_vgroups int, in_agreements int, in_accounts int, in_currency int, in_settings int, in_tarifs int, in_categories int) MODIFIES SQL DATA
    call `MAKE_TMP_TABLES`(1,1,0,0,0,1,0);

    if ( in_uid > 0 ) then
        insert into acc4rep select v.uid, v.vg_id, v.id, v.agrm_id from vgroups_tmp v where v.uid = in_uid;
    elseif ( in_ugrp > 0 ) then
        insert into acc4rep select distinct v.uid, v.vg_id, v.id, v.agrm_id from vgroups_tmp v join usergroups_staff ugs on v.uid = ugs.uid where ugs.group_id = in_ugrp;
    elseif ( in_grp > 0 ) then
        insert into acc4rep select distinct v.uid, v.vg_id, v.id, v.agrm_id from vgroups_tmp v join gr_staff gs on v.vg_id = gs.vg_id where gs.group_id = in_grp;
    else
        insert into acc4rep select v.uid, v.vg_id, v.id, v.agrm_id from vgroups_tmp v;
    end if;
    -- phone, cable, radius dialup stats
    set @s = concat( 'insert into ', tabname
                   , ' (id, uid, vg_id, oper_id, agrm_id, tar_id, cat_idx, serv_cat_idx, time_discount, size_discount, rent, type, volume, amount, sum_in, sum_out, sum_cntin, sum_cntout, additional)'
                   , ' select r.id, r.uid, r.vg_id, r.oper_id, r.agrm_id, r.tar_id, r.cat_idx, NULL, r.time_discount, r.size_discount, r.rent '
                   , ', if(t.type in (3,4), 2, if(t.type = 0, 1, t.type)) as type '
                   , ', case
                          when t.type = 0 then case t.traff_type
                                                 when 1 then sum(r.cin)
                                                 when 2 then sum(r.cout)
                                                 when 3 then sum(r.cin+r.cout)
                                                 else if(sum(r.cin)>sum(r.cout),sum(r.cin),sum(r.cout))
                                               end
                          when t.type = 1 then case t.traff_type
                                                 when 1 then sum(r.cin)
                                                 when 2 then sum(r.cout)
                                                 else sum(r.cin+r.cout)
                                               end
                          when t.type = 2 then sum(cin)
                          when t.type in (3,4) then sum(cin+cout)
                        end as volume'
                   , ', sum(r.amount) as amount
                      , sum(cin) as sum_in, sum(cout) as sum_out
                      , if(t.type in (3,4), sum(cntin), 0) as sum_cntin
                      , if(t.type in (3,4), sum(cntout), 0) as sum_cntout
                      , r.additional'
                   , ' from day r'
                   , ' join tarifs_tmp t using (tar_id)'
                   , ' join acc4rep ar on ar.vg_id = r.vg_id and ar.id = r.id'
                   , ' where r.timefrom >= date("', startdate,'")'
                   , ' and   r.timefrom < date("', startdate,'") + interval 1 month'
                   , ' group by r.id, r.uid, r.vg_id, r.oper_id, r.agrm_id, r.tar_id, r.cat_idx, r.time_discount, r.size_discount, r.rent, r.additional'
                   );
    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;

    -- rent
    set @s = concat( "INSERT INTO ", tabname," (id, uid, vg_id, agrm_id, tar_id, cat_idx, serv_cat_idx, rent, type, volume, amount, tariff_modifier_id) "
                   , " SELECT ar.id, ar.uid, r.vg_id, r.agrm_id, r.tar_id, 0 as cat_idx, NULL, 1 as rent, 0 as type, 1 as vol, sum(r.amount), r.tariff_modifier_id"
                   , " FROM rentcharge r"
                   , " JOIN acc4rep ar on ar.vg_id = r.vg_id "
                   , " WHERE r.period >= date('", startdate,"') and r.period < '", startdate, "' + interval 1 month"
                   , " GROUP BY ar.id, ar.uid, r.vg_id, r.agrm_id, r.tar_id, r.tariff_modifier_id"
                   );

    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;

    -- usbox
    set @s = concat( "INSERT INTO ", tabname, " (id, uid, vg_id, agrm_id, tar_id, cat_idx, serv_cat_idx, rent, type, volume, amount, tariff_modifier_id) "
                   , " SELECT ar.id, ar.uid, ar.vg_id, ar.agrm_id, s.tar_id, s.cat_idx, NULL, 0 as rent, if (s.timefrom=s.timeto,3,4) as type, if (s.timefrom=s.timeto,count(distinct(s.serv_id))+s.mul-1,s.mul) as vol, sum(r.amount), r.tariff_modifier_id "
                   , " FROM usbox_charge r JOIN usbox_services s ON r.serv_id = s.serv_id "
                   , " join acc4rep ar on ar.vg_id = s.vg_id "
                   , " WHERE r.period >= date('", startdate,"') AND r.period < date('", startdate,"') + interval 1 month"
                   , " GROUP BY ar.id, ar.uid, ar.vg_id, ar.agrm_id, s.tar_id, s.cat_idx, tariff_modifier_id "
                   );
    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;

    -- RM 21380
    /*
      при вставке выше появляются дубли если считаем разовые услуги, для обхода этой ситуации была внесена проверка на то разовая услуга или нет
      для периодических услуг все равно сумма объема оказанной услуги, как оказалось, считается не верно.
      при подсчете нужно проверять тип услуги, а также есть ли по ней списания в usbox_charge/charges, если списаний нет,
      то объем также не считаем.
      Чтобы не сломать работающую логику и не добавить багов, добавляя новые джойны и условия к уже немаленькому запросу выше
      апдейт сумм предоставленной услуги делаем отдельным запросом, считающим только это.
    */
    set @s = concat( "UPDATE ", tabname," r join ( "
                   , " SELECT r.tar_id,r.cat_idx,SUM(mul) as summ,r.vg_id FROM usbox_services r join acc4rep ac on r.vg_id = ac.vg_id "
                   , " WHERE NOT(timefrom > DATE('", startdate,"') + interval 1 month OR timeto < DATE('", startdate,"')) "
                   , " AND r.serv_id in (SELECT DISTINCT(serv_id) FROM usbox_charge uc WHERE uc.vg_id = ac.vg_id) "
                   , " GROUP BY ac.id, ac.uid, ac.vg_id, ac.agrm_id, r.tar_id, r.cat_idx ) as r1 USING(tar_id,cat_idx,vg_id) "
                   , " SET r.volume = r1.summ WHERE r.cat_idx IS NOT NULL ;"
                   );
    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;

    -- services
    set @s = concat( "INSERT INTO ", tabname, " (id, uid, vg_id, agrm_id, tar_id, cat_idx, serv_cat_idx, rent, type, volume, amount, tariff_modifier_id) "
                   , " SELECT ar.id, ar.uid, ar.vg_id, ar.agrm_id, s.tar_id, NULL, s.serv_cat_idx, 0 as rent, if (s.timefrom=s.timeto,3,4) as type, if (s.timefrom=s.timeto,count(distinct(s.service_id))+s.mul-1,sum(s.mul)) as vol, sum(r.amount), null as tariff_modifier_id "
                   , " FROM charges r JOIN services s using(service_id) "
                   , " join acc4rep ar on ar.vg_id = s.vg_id "
                   , " WHERE r.period >= date('", startdate,"') AND r.period < date('", startdate,"') + interval 1 month"
                   , " GROUP BY ar.id, ar.uid, ar.vg_id, ar.agrm_id, s.tar_id, s.serv_cat_idx "
                   );
    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;

    -- RM 21380
    set @s = concat( "UPDATE ", tabname," r join ( "
                   , " SELECT r.tar_id,r.serv_cat_idx,SUM(mul) as summ,r.vg_id FROM services r JOIN acc4rep ac ON r.vg_id = ac.vg_id "
                   , " WHERE NOT(timefrom > DATE('", startdate,"') + interval 1 month OR timeto < DATE('", startdate,"')) "
                   , " AND r.service_id IN (SELECT DISTINCT(service_id) FROM charges c WHERE c.vg_id = ac.vg_id) "
                   , " GROUP BY ac.id, ac.uid, ac.vg_id, ac.agrm_id, r.tar_id, r.serv_cat_idx ) as r1 USING(tar_id,serv_cat_idx,vg_id) "
                   , " SET r.volume = r1.summ WHERE r.serv_cat_idx IS NOT NULL ;"
                   );
    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;

    set @s = concat('update ', tabname, ' r join agreements_tmp a using(agrm_id) set r.oper_id = a.oper_id where r.oper_id = 0');

    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;

    drop table if exists current_report;
    set @s = concat("create temporary table current_report like ", tabname, ";");

    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;

    set @s = concat("insert into current_report select * from ",tabname, ";");

    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE PREPARE_SALE_STAT_AMOUNTS
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `PREPARE_SALE_STAT_AMOUNTS` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `PREPARE_SALE_STAT_AMOUNTS`(in_date date)
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Подготовка табличек сумм продаж (sales) и первичных списаний'
begin
    set @curdate = null;
    select date_format(in_date, '%Y-%m-01') into @curdate;

    drop table if exists stat_amount;
    create table stat_amount(
        agrm_id int default 0,
        sale_dictionary_id int default 0,
        bdate date default 0,
        amount decimal(20,6) default 0,
        changed int default 0 comment 'состояние продажи: 0 - новая, 1 - изменена, 2 - аннулирована, null - не найдена',
        sale_id int default 0,
        primary key (agrm_id, sale_dictionary_id, bdate),
        key changed(changed)
    ) engine = memory;

    drop table if exists sale_amount;
    create table sale_amount like stat_amount;


    insert into stat_amount (agrm_id, sale_dictionary_id, amount, bdate)
    select  agrm_id,
            IFNULL(t.sale_dictionary_id, IF(t.type = 0, 4, IF(t.type = 1, 5, IF(t.type = 2, 6, IF(t.type = 3, 7, IF(t.type = 4, 8, 1)))))),
            sum(ifnull(r.amount, 0)),
            @curdate
    from rentcharge r join vgids using(agrm_id) join tarifs t using(tar_id)
    where r.amount <> 0 and r.period >= @curdate and r.period < @curdate + interval 1 month
    group by r.agrm_id, IFNULL(t.sale_dictionary_id, IF(t.type = 0, 4, IF(t.type = 1, 5, IF(t.type = 2, 6, IF(t.type = 3, 7, IF(t.type = 4, 8, 1))))))
    on duplicate key update amount = amount + values(amount);

    insert into stat_amount (agrm_id, sale_dictionary_id, amount, bdate)
    select  agrm_id,
            ifnull(c.sale_dictionary_id, 2),
            sum(ifnull(u.amount, 0)),
            @curdate
    from usbox_charge u join usbox_services s using (serv_id) join vgids using(agrm_id) join categories c using(tar_id, cat_idx)
    where u.amount <> 0 and u.period >= @curdate and u.period < @curdate + interval 1 month
    group by u.agrm_id, ifnull(c.sale_dictionary_id, 2)
    on duplicate key update amount = amount + values(amount);

    insert into stat_amount (agrm_id, sale_dictionary_id, amount, bdate)
    select  agrm_id,
            ifnull(c.sale_dictionary_id, if(t.type = 0, 9, if(t.type = 1, 10, if(t.type = 2, 11, if(t.type = 3, 12, if(t.type = 4, 13, 3)))))),
            sum(ifnull(d.amount, 0)),
            @curdate
    from day d join vgids using(agrm_id) join categories c using(tar_id, cat_idx) join tarifs t using(tar_id)
    where d.amount <> 0 and d.timefrom >= @curdate and d.timefrom < @curdate + interval 1 month
    group by d.agrm_id, ifnull(c.sale_dictionary_id, if(t.type = 0, 9, if(t.type = 1, 10, if(t.type = 2, 11, if(t.type = 3, 12, if(t.type = 4, 13, 3))))))
    on duplicate key update amount = amount + values(amount);

    insert into stat_amount (agrm_id, sale_dictionary_id, amount, bdate)
    select  c.agrm_id,
            ifnull(t.sale_dictionary_id, if(t.type = 0, 4, if(t.type = 1, 5, if(t.type = 2, 6, if(t.type = 3, 7, if(t.type = 4, 8, 1)))))),
            sum(ifnull(c.amount, 0)),
            @curdate
    from charges c  join vgids using(agrm_id) left join vgroups v on c.vg_id = v.vg_id left join tarifs t on t.tar_id = v.tar_id
    where c.amount <> 0 and c.period >= @curdate and c.period < @curdate + interval 1 month
    group by c.agrm_id, ifnull(t.sale_dictionary_id, if(t.type = 0, 4, if(t.type = 1, 5, if(t.type = 2, 6, if(t.type = 3, 7, if(t.type = 4, 8, 1))))))
    on duplicate key update amount = amount + values(amount);

    insert into sale_amount (sale_id, agrm_id, sale_dictionary_id, amount, bdate, changed)
    select  s.sale_id,
            s.agrm_id,
            sd.sale_dictionary_id,
            sum(sd.amount),
            s.bdate ,
            if((select count(1) from sales_history sh where sh.sale_id = s.sale_id) > 0, 1, 0) state
    from sales s join vgids v using(agrm_id) join sale_details sd using(sale_id)
    where s.bdate = @curdate and s.cancel_date is null
    group by s.agrm_id, sd.sale_dictionary_id;

END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE renametable_sp
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `renametable_sp` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `renametable_sp`( IN v_sprtoldschema varchar(64)
                               , IN v_sprtoldtabname varchar(64)
                               , IN v_sprtnewschema varchar(64)
                               , IN v_sprtnewtabname varchar(64)
                               , INOUT v_sperror int(11)
                               )
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Переименовать таблицу'
begin
  declare v_sql varchar(4000);

  if check_table(database(), v_sprtoldtabname)
    then
      call show_message('INFO', 0, concat('Table renamed from ', v_sprtoldtabname,' to ', v_sprtnewtabname));
      set v_sql = concat('RENAME TABLE ', v_sprtoldtabname, ' TO ', v_sprtnewtabname);
      call exec_command(v_sql, 1, v_sperror);
      if v_sperror = 1050
        then
          set v_sql = concat('RENAME TABLE ', v_sprtnewtabname, ' TO ', v_sprtnewtabname, '_', date_format(now(), '%Y%m%d%h%i%s'));
          call exec_command(v_sql, 1, v_sperror);
      end if;
  end if;
end */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE rename_table
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `rename_table` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `rename_table`( IN v_rtoldschema varchar(64)
                             , IN v_rtoldtabname varchar(64)
                             , IN v_rtnewschema varchar(64)
                             , IN v_rtnewtabname varchar(64)
                             )
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Переименовать таблицу'
begin
  declare v_error int(11) default 0;
  declare v_err_msg, v_ok_msg varchar(4000);
  
  set @LB_UPDATESQL_PMESSID = NULL;
  set v_err_msg = concat('Can`t rename table ', v_rtoldtabname, ' to table ', v_rtnewtabname);
  set v_ok_msg = concat('Table renamed from ', v_rtoldschema, '.', v_rtoldtabname,' to ', v_rtnewschema, '.', v_rtnewtabname);
  call show_message('INFO', 0, v_ok_msg);
  call renametable_sp(v_rtoldschema, v_rtoldtabname, v_rtnewschema, v_rtnewtabname, v_error);
  
  if v_error <> 0 then call show_message('INFO', v_error, v_err_msg); end if;
end */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE rm6239_prepare_pay_detail
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `rm6239_prepare_pay_detail` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `rm6239_prepare_pay_detail`(in_dtfrom date, in_dtto date, in_type int)
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
BEGIN

    declare l_dtfrom, l_dtto, l_lock_period, l_cancel_date, l_cancel_date_new, l_local_date, l_local_date_new, l_period_date, l_p_period_date  date;
    declare l_recordid, l_payid, l_revisions, l_from_agrm_id, l_type, l_agrm_id_new, l_agrm_id_old, l_recordid_h int;
    declare l_isupdating, l_is_prev_period boolean;
    declare l_amount_old, l_amount_new decimal(20,6);
    declare l_done boolean default false;
    declare l_transfer int default 0;
    declare l_tr_agrm int default 0;
    declare l_nodate date default '1970-01-01';
    declare l_havepaymenttool boolean default false;



    declare pays cursor for
        select record_id, pay_id, revisions, from_agrm_id, cancel_date, local_date
        from rm6239_prepare_pay_detail_buf
        order by pay_date desc, pay_id desc, local_date desc, revno asc;




    declare once_history_by_local_date cursor
        for select record_id, amount, amount_new, agrm_id, agrm_id_new, from_agrm_id, ifnull(date(cancel_date), l_nodate), ifnull(date(cancel_date_new), l_nodate), ifnull(date(local_date), l_nodate), ifnull(date(local_date_new),  l_nodate), ifnull(date(period_date),  l_nodate)
        from payments_history
        where origin_record_id = l_payid
        order by record_id;


    declare once_history_by_pay_date cursor
        for select record_id, amount, amount_new, agrm_id, agrm_id_new, from_agrm_id, ifnull(date(cancel_date), l_nodate), ifnull(date(cancel_date_new), l_nodate), ifnull(date(local_date), l_nodate), ifnull(date(local_date_new), l_nodate), ifnull(date(period_date),  l_nodate)
        from payments_history
        where origin_record_id = l_payid
        order by record_id;


    declare once_history_by_period_date cursor
        for select record_id, amount, amount_new, agrm_id, agrm_id_new, from_agrm_id, ifnull(date(cancel_date), l_nodate), ifnull(date(cancel_date_new), l_nodate), ifnull(date(local_date), l_nodate), ifnull(date(local_date_new), l_nodate), ifnull(date(period_date),  l_nodate)
        from payments_history
        where origin_record_id = l_payid
        order by record_id;

    declare continue handler for not found set l_done = true;

    select date(value) into l_lock_period from options where name = 'lock_period';


    if in_type < 0 or in_type > 2 then
        CALL ERROR_INVALID_IN_TYPE();
    end if;

    if in_dtfrom is null or in_dtfrom < 20000101 then
        CALL ERROR_INVALID_IN_DTFROM();
    end if;

    if in_dtto is null or in_dtto < 20000101 then
        CALL ERROR_INVALID_IN_DTTO();
    end if;

    if l_lock_period is null or l_lock_period < 20000101 then
        set l_lock_period = '2014-01-01';
    end if;

    set l_dtfrom    = in_dtfrom;
    set l_dtto      = in_dtto;

    set @OPERATION_TRANSFER_FROM            = 1;        
    set @OPERATION_TRANSFER_TO              = 2;        
    set @OPERATION_TRANSFER_ORIGIN          = 3;        
    set @OPERATION_CORRECT_NEW              = 4;        
    set @OPERATION_CORRECT_ORIGIN           = 5;        
    set @OPERATION_CORRECT_CANCEL           = 6;        
    set @OPERATION_CANCEL_ORIGIN            = 7;        
    set @OPERATION_CANCEL_CANCEL            = 8;        
    set @OPERATION_CANCEL_ORIGIN2           = 9;        
    set @OPERATION_CANCEL_CANCEL2           = 10;       
    set @OPERATION_CANCEL_TRANSFER_FROM     = 11;       
    set @OPERATION_CANCEL_TRANSFER_TO       = 12;       
    set @OPERATION_CANCEL_TRANSFER_FROM2    = 13;       
    set @OPERATION_CANCEL_TRANSFER_TO2      = 14;       
    set @OPERATION_CANCEL_TRANSFER_ORIGIN   = 15;       
    set @OPERATION_CANCEL_TRANSFER_CANCEL   = 16;       
    set @OPERATION_RECOVER_TRANSFER_ORIGIN  = 17;       
    set @OPERATION_RECOVER_TRANSFER_CANCEL  = 18;       


    drop table if exists rm6239_prepare_pay_detail_result;
    create table rm6239_prepare_pay_detail_result(
                    record_id           int auto_increment,
                    pay_id              int default 0           comment 'payments.record_id',
                    pay_class_id        int default 0           comment 'pay_classes.class_id',
                    manager_id          int default 0           comment 'managers.person_id',
                    is_correct          int default null        comment 'see declaration of @OPERATION_[X] variables',
                    registry_id         int default null        comment 'registry_payments.registry_id',
                    agrm_id             int default 0           comment 'agreements.agrm_id',
                    from_agrm_id        int default null        comment 'agreements.agrm_id',
                    uid                 int default 0           comment 'accounts.uid',
                    revno               int default 0           comment 'версия платежа',
                    revisions           int default 0           comment 'общее кол-во исправлений платежа',
                    period_date         date                    comment '2.2.6 Отчетный период',
                    pay_date            date not null           comment '2.2.7 Дата платежа',
                    local_date          date not null           comment '2.2.8 Дата регистрации платежа',
                    cancel_date         date                    comment 'Признак аннулированного платежа',
                    amount              decimal(20,6) default 0        comment '2.2.14 Сумма платежа',
                    type                varchar(32) default ''  comment '2.2.13    Тип пользователя',
                    registry_name       varchar(128) default '' comment '2.2.9 № реестра',
                    extern_code_lb      varchar(32) default ''  comment '2.2.1 Тип платежа в ЛБ',
                    extern_code_sou     varchar(32) default ''  comment '2.2.2 Тип платежа в СОУ',
                    pay_class_name      varchar(32) default ''  comment '2.2.3 Категория платежа ЛБ',
                    manager_name        varchar(240) default '' comment '2.2.4 Менеджер',
                    is_correct_name     varchar(64) default ''  comment '2.2.5 Признак скорректированного платежа ',
                    receipt             varchar(128) default '' comment '2.2.10 № п./п.',
                    number              varchar(128) default '' comment '2.2.11 № договора',
                    name                varchar(255) default '' comment '2.2.12    Наименование абонента',
                    paymenttool         varchar(255) default '' comment 'Тип и номер платежного инструмента (html)',
                    primary key         (record_id),
                    key pay_class_id    (pay_class_id),
                    key pay_id          (pay_id),
                    key manager_id      (manager_id),
                    key is_correct      (is_correct),
                    key registry_id     (registry_id),
                    key agrm_id         (agrm_id),
                    key uid             (uid),
                    key type            (type),
                    key receipt         (receipt),
                    key orderby         (pay_date, pay_id, local_date, revno),
                    key groupby         (extern_code_lb, extern_code_sou, pay_class_id, period_date, pay_date, local_date),
                    key cancel_date     (cancel_date)
                ) engine = innodb;


    drop table if exists rm6239_prepare_pay_detail_buf;
    create table rm6239_prepare_pay_detail_buf like rm6239_prepare_pay_detail_result;


    if in_type = 0     then
        set @date_condition = concat(" and IFNULL(period_date, EXPECT_PERIOD_DATE2(pay_date, '", l_lock_period, "')) >= '",  l_dtfrom, "' and IFNULL(period_date, EXPECT_PERIOD_DATE2(pay_date, '", l_lock_period, "')) < '",  l_dtto, "'");
    elseif in_type = 1 then
        set @date_condition = concat(" and pay_date >= '",      l_dtfrom, "' and pay_date < '",     l_dtto, "'");
    elseif in_type = 2 then
        set @date_condition = concat(" and local_date >= '",    l_dtfrom, "' and local_date < '",   l_dtto, "'");
    end if;





    set @additional_term = " and not (amount_cur=amount_cur_new and agrm_id=agrm_id_new and ifnull(order_id,0) = ifnull(order_id_new,0) and ifnull(cancel_date,0) = ifnull(cancel_date_new,0)) ";

    set @s  = concat(
                "insert into rm6239_prepare_pay_detail_buf ( "
                    "pay_id, "
                    "pay_class_id, "
                    "manager_id, "
                    "agrm_id, "
                    "from_agrm_id, "
                    "revno, "
                    "revisions, "
                    "period_date, "
                    "pay_date, "
                    "local_date, "
                    "cancel_date, "
                    "amount, "
                    "receipt ) "
                "select "
                    "record_id, "
                    "class_id, "
                    "mod_person, "
                    "agrm_id, "
                    "from_agrm_id, "
                    "0 as revno, "
                    "(SELECT COUNT(*) FROM payments_history WHERE origin_record_id = p.record_id " , @additional_term, ") as revisions, "
                    "IFNULL(period_date, EXPECT_PERIOD_DATE2(pay_date, '", l_lock_period, "')) period_date, "
                    "pay_date, "
                    "local_date, "
                    "cancel_date, "
                    "amount, "
                    "IFNULL(order_number, receipt) "
                "from payments p "
                "join vgids using(agrm_id) "
                "where 1=1 ");

    set @s = concat(@s, @date_condition);


    PREPARE stmt FROM @s;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;



    set @s  = concat(
            "insert into rm6239_prepare_pay_detail_buf ( "
                "pay_id, "
                "pay_class_id, "
                "manager_id, "
                "agrm_id, "
                "from_agrm_id, "
                "revno, "
                "revisions, "
                "period_date, "
                "pay_date, "
                "local_date, "
                "cancel_date, "
                "amount, "
                "receipt ) "
            "select "
                "origin_record_id, "
                "class_id, "
                "mod_person, "
                "agrm_id, "
                "from_agrm_id, "
                "(SELECT COUNT(*) + 1 FROM payments_history WHERE origin_record_id = ph.origin_record_id AND record_id > ph.record_id " , @additional_term, " )  as revno, "
                "(SELECT COUNT(*) FROM payments_history WHERE origin_record_id = ph.origin_record_id " , @additional_term, " ) as pay_revisions, "
                "IFNULL(period_date, EXPECT_PERIOD_DATE2(pay_date, '", l_lock_period, "')) period_date, "
                "pay_date, "
                "local_date, "
                "cancel_date, "
                "amount, "
                "receipt "
            "from payments_history ph "
            "join vgids using(agrm_id) "
            "where 1=1 " , @additional_term );

    set @s = concat(@s, @date_condition);



    PREPARE stmt FROM @s;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;



    drop table if exists rm6239_corrected_payments;
    create table rm6239_corrected_payments(pay_id int, unique key pay_id(pay_id)) engine = innodb;
    set l_done = false;
    open pays;
    fetch pays into l_recordid, l_payid, l_revisions, l_from_agrm_id, l_cancel_date, l_local_date;


    while not l_done do
    
    

        
        
        
        
        
        
        
        
        
        
        
        

        set @kurgan = 0;
        set @k_period_date = NULL;
        set @k_local_date = NULL;
        set @k_mod_person = NULL;
        SET @prev_period = NULL;  

        if ((select count(1) from payments_history where origin_record_id = l_payid) = 2                                            and
            (select period_date from payments_history where origin_record_id = l_payid order by record_id desc limit 1) IS NULL     and
            (select status_new from payments_history where origin_record_id = l_payid order by record_id desc limit 1) = 2          and
            (select status from payments_history where origin_record_id = l_payid order by record_id desc limit 1) = 0              and
            (select status_new from payments_history where origin_record_id = l_payid order by record_id limit 1) = 0               and
            (select amount_new - amount from payments_history where origin_record_id = l_payid order by record_id limit 1) = 0      and
