                    select origin_record_id, p.class_id, h.mod_person, p.from_agrm_id,
                            ifnull(h.period_date, EXPECT_PERIOD_DATE2(p.pay_date, l_lock_period)),
                            p.pay_date, h.local_date_new, -h.amount, IFNULL(p.order_number, p.receipt), @OPERATION_TRANSFER_FROM
                    from payments_history h join payments p on h.origin_record_id = p.record_id
                    where h.record_id = l_recordid_h;

                elseif  (l_agrm_id_old   <> l_agrm_id_new and l_period_date = l_p_period_date and @recover = 0)        then
                
                
                    
                    insert into rm6239_prepare_pay_detail_result
                            (pay_id, pay_class_id, manager_id, agrm_id,
                            period_date,
                            pay_date, local_date, amount, receipt, is_correct)
                    select origin_record_id, p.class_id, h.mod_person, h.agrm_id,
                            ifnull(h.period_date, EXPECT_PERIOD_DATE2(p.pay_date, l_lock_period)),
                            p.pay_date, h.local_date_new, -h.amount, IFNULL(p.order_number, p.receipt), @OPERATION_TRANSFER_FROM
                    from payments_history h join payments p on h.origin_record_id = p.record_id
                    where h.record_id = l_recordid_h;

                    
                    insert into rm6239_prepare_pay_detail_result
                            (pay_id, pay_class_id, manager_id, agrm_id,
                            period_date,
                            pay_date, local_date, amount, receipt, is_correct)
                    select origin_record_id, p.class_id, h.mod_person, h.agrm_id_new,
                            ifnull(h.period_date, EXPECT_PERIOD_DATE2(p.pay_date, l_lock_period)),
                            p.pay_date, h.local_date_new, h.amount, IFNULL(p.order_number, p.receipt), @OPERATION_TRANSFER_TO
                    from payments_history h join payments p on h.origin_record_id = p.record_id
                    where h.record_id = l_recordid_h;

                    if @origin = 0 then
                        
                        insert into rm6239_prepare_pay_detail_result
                                (pay_id, pay_class_id, manager_id, agrm_id,
                                period_date,
                                pay_date, local_date, amount, receipt, is_correct)
                        select origin_record_id, p.class_id, h.mod_person, h.agrm_id,
                                ifnull(@prev_period,ifnull(h.period_date, EXPECT_PERIOD_DATE2(p.pay_date, l_lock_period))),
                                p.pay_date, h.local_date, h.amount, IFNULL(p.order_number, p.receipt), @OPERATION_TRANSFER_ORIGIN
                        from payments_history h join payments p on h.origin_record_id = p.record_id
                        where h.record_id = l_recordid_h;

                        set @origin = 1;
                    end if;


                elseif  (l_agrm_id_old   <> l_agrm_id_new and l_period_date <> l_p_period_date and @recover = 0)        then
                
                
                    



                    set l_is_prev_period = false;

                    
                    select ifnull(h.period_date, EXPECT_PERIOD_DATE2(h.pay_date, l_lock_period)) < ifnull(l_p_period_date, date(ifnull(l_cancel_date_new, l_nodate)))
                    into l_is_prev_period
                    from payments_history h
                    where h.record_id = l_recordid_h;



                    insert into rm6239_prepare_pay_detail_result
                            (pay_id, pay_class_id, manager_id, agrm_id,
                            period_date,
                            pay_date, local_date, amount, receipt, is_correct)
                    select origin_record_id, p.class_id, h.mod_person, h.agrm_id,
                            ifnull(if(l_is_prev_period, p.period_date, h.period_date), EXPECT_PERIOD_DATE2(p.pay_date, l_lock_period)),
                            p.pay_date, h.local_date_new, -h.amount, IFNULL(p.order_number, p.receipt), @OPERATION_TRANSFER_FROM
                    from payments_history h join payments p on h.origin_record_id = p.record_id
                    where h.record_id = l_recordid_h;

                    
                    insert into rm6239_prepare_pay_detail_result
                            (pay_id, pay_class_id, manager_id, agrm_id,
                            period_date,
                            pay_date, local_date, amount, receipt, is_correct)
                    select origin_record_id, p.class_id, h.mod_person, h.agrm_id_new,
                            ifnull(if(l_is_prev_period, p.period_date, h.period_date), EXPECT_PERIOD_DATE2(p.pay_date, l_lock_period)),
                            p.pay_date, h.local_date_new, h.amount, IFNULL(p.order_number, p.receipt), @OPERATION_TRANSFER_TO
                    from payments_history h join payments p on h.origin_record_id = p.record_id
                    where h.record_id = l_recordid_h;

                    if @origin = 0 then
                        
                        insert into rm6239_prepare_pay_detail_result
                                (pay_id, pay_class_id, manager_id, agrm_id,
                                period_date,
                                pay_date, local_date, amount, receipt, is_correct)
                        select origin_record_id, p.class_id, h.mod_person, h.agrm_id,
                                ifnull(h.period_date, EXPECT_PERIOD_DATE2(p.pay_date, l_lock_period)),
                                p.pay_date, h.local_date, h.amount, IFNULL(p.order_number, p.receipt), @OPERATION_TRANSFER_ORIGIN
                        from payments_history h join payments p on h.origin_record_id = p.record_id
                        where h.record_id = l_recordid_h;
                        set @origin = 1;
                    end if;

                end if;

                
                
                
                
                select ifnull(h.period_date, EXPECT_PERIOD_DATE2(p.pay_date, l_lock_period)) into @prev_period
                from payments_history h join payments p on h.origin_record_id = p.record_id
                where h.record_id = l_recordid_h;

                set l_done = false;
                if      in_type = 0 then fetch once_history_by_period_date  into l_recordid_h, l_amount_old, l_amount_new, l_agrm_id_old, l_agrm_id_new, l_from_agrm_id, l_cancel_date, l_cancel_date_new, l_local_date, l_local_date_new, l_period_date;
                elseif  in_type = 1 then fetch once_history_by_pay_date     into l_recordid_h, l_amount_old, l_amount_new, l_agrm_id_old, l_agrm_id_new, l_from_agrm_id, l_cancel_date, l_cancel_date_new, l_local_date, l_local_date_new, l_period_date;
                elseif  in_type = 2 then fetch once_history_by_local_date   into l_recordid_h, l_amount_old, l_amount_new, l_agrm_id_old, l_agrm_id_new, l_from_agrm_id, l_cancel_date, l_cancel_date_new, l_local_date, l_local_date_new, l_period_date;

                end if;
            end while;

            
            if      in_type = 0 then close once_history_by_period_date;
            elseif  in_type = 1 then close once_history_by_pay_date;
            elseif  in_type = 2 then close once_history_by_local_date;
            end if;

        end if;

        set l_done = false;
        fetch pays into l_recordid, l_payid, l_revisions, l_from_agrm_id, l_cancel_date, l_local_date;
    end while;
    close pays;




    
    
    
    
    
    
    

    
    
    
    
    
    
    

    update rm6239_prepare_pay_detail_result r join pay_classes c on r.pay_class_id = c.class_id     set r.pay_class_name = c.name, r.extern_code_lb=c.extern_code, r.extern_code_sou =  c.extern_code;
    update rm6239_prepare_pay_detail_result r join managers m on r.manager_id = m.person_id         set r.extern_code_sou = 3 where m.payments = 1;
    update rm6239_prepare_pay_detail_result r join payments_history h on(r.pay_id = h.origin_record_id) join managers m on h.mod_person = m.person_id set r.extern_code_sou = 3 where m.payments = 1 and h.record_id = (select min(record_id) from payments_history where h.origin_record_id = origin_record_id);
    
    select record_id > 0 from payments_ext where paymenttooltype is not null limit 1 into l_havepaymenttool;
    update rm6239_prepare_pay_detail_result r left join payments_ext x on r.pay_id = x.payment_id   set r.paymenttool = if(l_havepaymenttool, concat('<TD ALIGN=LEFT><FONT>', ifnull(x.paymenttooltype,''), '&nbsp;</FONT></TD><TD ALIGN=LEFT><FONT>', ifnull(x.paymenttoolnumber,''), '&nbsp;</FONT></TD>'), '');
    update rm6239_prepare_pay_detail_result r join payments_ext x on r.pay_id = x.payment_id set r.receipt = x.checknumber where x.paymenttooltype = 77 and ifnull(x.checknumber,'') > '';

    update rm6239_prepare_pay_detail_result r                                                       set r.extern_code_sou = 2 where is_correct in (@OPERATION_TRANSFER_FROM, @OPERATION_TRANSFER_TO, @OPERATION_CANCEL_TRANSFER_FROM, @OPERATION_CANCEL_TRANSFER_FROM2,@OPERATION_CANCEL_TRANSFER_ORIGIN,@OPERATION_CANCEL_TRANSFER_CANCEL,@OPERATION_RECOVER_TRANSFER_ORIGIN,@OPERATION_RECOVER_TRANSFER_CANCEL);
    
    update rm6239_prepare_pay_detail_result r join managers m on r.manager_id = m.person_id         set r.manager_name = m.fio;

    
    
    update rm6239_prepare_pay_detail_result set is_correct_name = 'Перевод снятие платежа'                                      where is_correct = @OPERATION_TRANSFER_FROM             ;
    update rm6239_prepare_pay_detail_result set is_correct_name = 'Перевод зачисление платежа'                                  where is_correct = @OPERATION_TRANSFER_TO               ;
    update rm6239_prepare_pay_detail_result set is_correct_name = 'Перевод первичный платеж'                                    where is_correct = @OPERATION_TRANSFER_ORIGIN           ;
    update rm6239_prepare_pay_detail_result set is_correct_name = 'Корректировка Новое значение'                                where is_correct = @OPERATION_CORRECT_NEW               ;
    update rm6239_prepare_pay_detail_result set is_correct_name = 'Корректировка Первичный платеж'                              where is_correct = @OPERATION_CORRECT_ORIGIN            ;
    update rm6239_prepare_pay_detail_result set is_correct_name = 'Корректировка Сторно платежа'                                where is_correct = @OPERATION_CORRECT_CANCEL            ;
    update rm6239_prepare_pay_detail_result set is_correct_name = 'Аннулирование Первичный платеж'                              where is_correct = @OPERATION_CANCEL_ORIGIN             ;
    update rm6239_prepare_pay_detail_result set is_correct_name = 'Аннулирование Сторно платежа'                                where is_correct = @OPERATION_CANCEL_CANCEL             ;
    update rm6239_prepare_pay_detail_result set is_correct_name = 'Аннулирование за прош. период Первичный платеж'              where is_correct = @OPERATION_CANCEL_ORIGIN2            ;
    update rm6239_prepare_pay_detail_result set is_correct_name = 'Аннулирование за прош. период Сторно платежа'                where is_correct = @OPERATION_CANCEL_CANCEL2            ;
    update rm6239_prepare_pay_detail_result set is_correct_name = 'Аннулирование Перевод Снятие платежа'                        where is_correct = @OPERATION_CANCEL_TRANSFER_FROM      ;
    update rm6239_prepare_pay_detail_result set is_correct_name = 'Аннулирование платежа'                                       where is_correct = @OPERATION_CANCEL_TRANSFER_TO        ;
    update rm6239_prepare_pay_detail_result set is_correct_name = 'Аннулирование за прош.период  Перевод Снятие платежа'        where is_correct = @OPERATION_CANCEL_TRANSFER_FROM2     ;
    update rm6239_prepare_pay_detail_result set is_correct_name = 'Аннулирование платежа прошлого периода'                      where is_correct = @OPERATION_CANCEL_TRANSFER_TO2       ;
    update rm6239_prepare_pay_detail_result set is_correct_name = 'Аннулирование перевода Первичный платеж'                     where is_correct = @OPERATION_CANCEL_TRANSFER_ORIGIN    ;
    update rm6239_prepare_pay_detail_result set is_correct_name = 'Аннулирование перевода Сторно платежа'                       where is_correct = @OPERATION_CANCEL_TRANSFER_CANCEL    ;
    update rm6239_prepare_pay_detail_result set is_correct_name = 'Восстановление перевода  Первичный платеж'                   where is_correct = @OPERATION_RECOVER_TRANSFER_ORIGIN   ;
    update rm6239_prepare_pay_detail_result set is_correct_name = 'Восстановление перевода Сторно платежа'                      where is_correct = @OPERATION_RECOVER_TRANSFER_CANCEL   ;


    
    
    update rm6239_prepare_pay_detail_result r join registry_payments rp on r.pay_id = rp.payment_id join registries rr on rr.registry_id = rp.registry_id set r.registry_id = rr.registry_id, r.registry_name = rr.receipt;

    
    
    
    
    
    
    update rm6239_prepare_pay_detail_result r join agreements a using(agrm_id) set r.uid = a.uid, r.number = a.number;
    update rm6239_prepare_pay_detail_result r join accounts a using(uid) set r.name = a.name, r.type = if(a.type = 1, 'ЮЛ', 'ФЛ');

    
    if  in_type = 2 then
        
        delete from rm6239_prepare_pay_detail_result where local_date<in_dtfrom or local_date>=in_dtto;
    elseif  in_type = 0 then
        
        delete from rm6239_prepare_pay_detail_result where period_date<in_dtfrom or period_date>=in_dtto;
    end if;


    
    
    
    
    if in_type = 0     then
        delete from rm6239_prepare_pay_detail_result
            where   (select count(1) from payments_history where origin_record_id = pay_id) > 0
            and     (select count(1) from payments_history where origin_record_id = pay_id and (amount <> amount_new or agrm_id <> agrm_id_new or cancel_date <> cancel_date_new )) = 0
            and     (select min(IFNULL(period_date, EXPECT_PERIOD_DATE2(pay_date, l_lock_period))) from payments_history where origin_record_id = pay_id) < l_dtfrom;
    elseif in_type = 1 then
        delete from rm6239_prepare_pay_detail_result
            where   (select count(1) from payments_history where origin_record_id = pay_id) > 0
            and     (select count(1) from payments_history where origin_record_id = pay_id and (amount <> amount_new or agrm_id <> agrm_id_new or cancel_date <> cancel_date_new )) = 0
            and     (select min(pay_date) from payments_history where origin_record_id = pay_id) < l_dtfrom;
    elseif in_type = 2 then
        delete from rm6239_prepare_pay_detail_result
            where   (select count(1) from payments_history where origin_record_id = pay_id) > 0
            and     (select count(1) from payments_history where origin_record_id = pay_id and (amount <> amount_new or agrm_id <> agrm_id_new or cancel_date <> cancel_date_new )) = 0
            and     (select min(local_date) from payments_history where origin_record_id = pay_id) < l_dtfrom;
    end if;


END */;;

