  insert ignore into object_visibility_level(visible_view_name)
  select role_name from `roles`;

  insert into object_visibility_area(role_id, level_id)
  select r.role_id, v.level_id
  from roles r
  join object_visibility_level v
  on r.role_name = v.visible_view_name
  on duplicate key update level_id = values(level_id);


  update man_staff ms set level_id = (select level_id from object_visibility_level
                                      where visible_view_name = case ms.rw_flag
                                                                when 1 then 'usergroups_r'
                                                                when 2 then 'usergroups_rw'
                                                                end
                                     ) where person_id is NOT NULL;

  update `man_staff` `ms` join `man_staff_backup` `msb` ON (`ms`.`level_id` = `msb`.`level_id`)
                      join `object_visibility_level` `ovl` ON (`msb`.`visible_view_name` = `ovl`.`visible_view_name`)
                      SET `ms`.`level_id` = `ovl`.`level_id` WHERE `ms`.`person_id` IS NULL;


  update `managers_tarifs_staff` `ms` join `managers_tarifs_staff_backup` `msb` ON (`ms`.`level_id` = `msb`.`level_id`)
                      join `object_visibility_level` `ovl` ON (`msb`.`visible_view_name` = `ovl`.`visible_view_name`)
                      SET `ms`.`level_id` = `ovl`.`level_id` WHERE `ms`.`person_id` IS NULL;


  select count(1) into l_check_broken FROM `man_staff` WHERE `person_id` is NULL and `level_id` is NULL;
  if (l_check_broken > 0) then
      call show_message('WARNING',1,'Some data in man_staff are broken. You can check it by executing this statement: select * from `man_staff` where `person_id` is NULL and `level_id` is NULL');
  end if;

  CALL add_key(database(),
               'man_staff',
               'man_staff_ibfk_3',
               "foreign key (`level_id`) references `object_visibility_level` (`level_id`) ON DELETE CASCADE ON UPDATE CASCADE");
  
  CALL add_key(database(),
               'managers_tarifs_staff',
               'managers_tarifs_staff_ibfk_3',
               "foreign key (`level_id`) references `object_visibility_level` (`level_id`) ON DELETE CASCADE ON UPDATE CASCADE");
end */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE SALES_BY_CLIENTS
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `SALES_BY_CLIENTS` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `SALES_BY_CLIENTS`(IN in_bdate DATE, IN in_edate DATE)
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
BEGIN
        
        
        
        CREATE TEMPORARY TABLE IF NOT EXISTS tmp_sales_by_clients
        (
                uid    INT(11) NOT NULL COMMENT 'Идентификатор абонента',
                name   VARCHAR(255) NOT NULL COMMENT 'Наименование абонента',
                gaap   INT(11) NOT NULL COMMENT 'Код вида услуги',
                amount DECIMAL(20,6) NOT NULL COMMENT 'Сумма с НДС',

                PRIMARY  KEY(uid, gaap),
                KEY name_gaap(name, gaap)
        ) ENGINE=MEMORY, DEFAULT CHARSET=utf8;
        TRUNCATE TABLE tmp_sales_by_clients;

        
        
        
        CALL SALES_BY_PERIOD(in_bdate, in_edate);

        
        
        
        
        INSERT INTO tmp_sales_by_clients
        (
                uid,
                name,
                gaap,
                amount
        )
        SELECT
                a.uid,
                u.name,
                ssd.gaap,
                sd.amount
        FROM
                tmp_sales_by_period s,
                tmp_sale_by_period_details sd,
                sale_dictionary ssd,
                agreements a,
                accounts u
        WHERE
                s.record_id = sd.record_id AND
                s.sale_id = sd.sale_id AND
                sd.sale_dictionary_id = ssd.record_id AND
                s.agrm_id = a.agrm_id AND
                a.uid = u.uid
        ON DUPLICATE KEY UPDATE
                amount = tmp_sales_by_clients.amount + VALUES(amount);

END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE SALES_BY_DICT
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `SALES_BY_DICT` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `SALES_BY_DICT`(IN in_bdate DATE, IN in_edate DATE)
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
BEGIN
        
        
        
        CREATE TEMPORARY TABLE IF NOT EXISTS tmp_sales_by_dict
        (
                type     INTEGER NOT NULL COMMENT 'Идентификатор категории абонента',
                code     INTEGER NOT NULL COMMENT 'Код услуги',
                name     VARCHAR(255) NOT NULL COMMENT 'Наименование услуги',
                gaap     INTEGER NOT NULL COMMENT 'Код вида услуги',
                amount_3 DECIMAL(20,6) NOT NULL COMMENT 'Текущий год/текущий период без НДС',
                amount_4 DECIMAL(20,6) NOT NULL COMMENT 'Текущий год/текущий период НДС',
                amount_5 DECIMAL(20,6) NOT NULL COMMENT 'Текущий год/текущий период с НДС',
                amount_6 DECIMAL(20,6) NOT NULL COMMENT 'Прошлый год/текущий период без НДС',
                amount_7 DECIMAL(20,6) NOT NULL COMMENT 'Прошлый год/текущий период НДС',
                amount_8 DECIMAL(20,6) NOT NULL COMMENT 'Прошлый год/текущий период с НДС',

                PRIMARY KEY(type, code),
                KEY type_name(type, name)
        ) ENGINE=MEMORY, DEFAULT CHARSET=utf8;
        TRUNCATE TABLE tmp_sales_by_dict;

        
        
        
        CALL SALES_BY_PERIOD(in_bdate, in_edate);

        
        
        
        
        INSERT INTO tmp_sales_by_dict
        (
                type,
                code,
                name,
                gaap,
                amount_3,
                amount_4,
                amount_5,
                amount_6,
                amount_7,
                amount_8
        )
        SELECT
                u.type,
                ssd.record_id,
                ssd.name,
                ssd.gaap,
                IF(s.period_date < s.edate, sd.amount - sd.amount_vat, 0) t1, 
                IF(s.period_date < s.edate, sd.amount_vat, 0) t2,
                IF(s.period_date < s.edate, sd.amount, 0) t3,
                IF(s.period_date < s.edate, 0, sd.amount - sd.amount_vat) t4,
                IF(s.period_date < s.edate, 0, sd.amount_vat) t5,
                IF(s.period_date < s.edate, 0, sd.amount) t6
        FROM
                tmp_sales_by_period s 
                JOIN tmp_sale_by_period_details sd USING(sale_id)
                JOIN sale_dictionary ssd ON sd.sale_dictionary_id = ssd.record_id
                JOIN agreements a USING(agrm_id)
                JOIN accounts u USING(uid)
        ON DUPLICATE KEY UPDATE
                amount_3 = amount_3 + IF(s.period_date < s.edate, sd.amount - sd.amount_vat, 0),
                amount_4 = amount_4 + IF(s.period_date < s.edate, sd.amount_vat, 0),
                amount_5 = amount_5 + IF(s.period_date < s.edate, sd.amount, 0),
                amount_6 = amount_6 + IF(s.period_date < s.edate, 0, sd.amount - sd.amount_vat),
                amount_7 = amount_7 + IF(s.period_date < s.edate, 0, sd.amount_vat),
                amount_8 = amount_8 + IF(s.period_date < s.edate, 0, sd.amount);

END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE SALES_BY_PERIOD
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `SALES_BY_PERIOD` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `SALES_BY_PERIOD`(IN in_bdate DATE, IN in_edate DATE)
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
BEGIN
        
        
        
        DECLARE tmp_record_id      INT(11);
        DECLARE tmp_sale_id        INT(11);
        DECLARE tmp_agrm_id        INT(11);
        DECLARE tmp_oper_id        INT(11);
        DECLARE tmp_owner_id       INT(11);
        DECLARE tmp_amount_cur_id  INT(11);
        DECLARE tmp_amount_cur     DECIMAL(20,6);
        DECLARE tmp_amount_cur_vat DECIMAL(20,6);
        DECLARE tmp_amount         DECIMAL(20,6);
        DECLARE tmp_amount_vat     DECIMAL(20,6);
        DECLARE tmp_receipt_seq    INT(11);
        DECLARE tmp_receipt        VARCHAR(255);
        DECLARE tmp_sale_date      DATETIME;
        DECLARE tmp_local_date     DATETIME;
        DECLARE tmp_cancel_date    DATETIME;
        DECLARE tmp_period_date    DATE;
        DECLARE tmp_bdate          DATE;
        DECLARE tmp_edate          DATE;
        DECLARE tmp_comment        VARCHAR(255);
        DECLARE tmp_mod_person     INT(11);

        
        
        
        DECLARE tmp_record_id_prev      INT(11);
        DECLARE tmp_sale_id_prev        INT(11);
        DECLARE tmp_agrm_id_prev        INT(11);
        DECLARE tmp_oper_id_prev        INT(11);
        DECLARE tmp_owner_id_prev       INT(11);
        DECLARE tmp_amount_cur_id_prev  INT(11);
        DECLARE tmp_amount_cur_prev     DECIMAL(20,6);
        DECLARE tmp_amount_cur_vat_prev DECIMAL(20,6);
        DECLARE tmp_amount_prev         DECIMAL(20,6);
        DECLARE tmp_amount_vat_prev     DECIMAL(20,6);
        DECLARE tmp_receipt_seq_prev    INT(11);
        DECLARE tmp_receipt_prev        VARCHAR(255);
        DECLARE tmp_sale_date_prev      DATETIME;
        DECLARE tmp_local_date_prev     DATETIME;
        DECLARE tmp_cancel_date_prev    DATETIME;
        DECLARE tmp_period_date_prev    DATE;
        DECLARE tmp_bdate_prev          DATE;
        DECLARE tmp_edate_prev          DATE;
        DECLARE tmp_comment_prev        VARCHAR(255);
        DECLARE tmp_mod_person_prev     INT(11);

        
        
        
        DECLARE tmp_record_id_left      INT(11);
        DECLARE tmp_sale_id_left        INT(11);
        DECLARE tmp_agrm_id_left        INT(11);
        DECLARE tmp_oper_id_left        INT(11);
        DECLARE tmp_owner_id_left       INT(11);
        DECLARE tmp_amount_cur_id_left  INT(11);
        DECLARE tmp_amount_cur_left     DECIMAL(20,6);
        DECLARE tmp_amount_cur_vat_left DECIMAL(20,6);
        DECLARE tmp_amount_left         DECIMAL(20,6);
        DECLARE tmp_amount_vat_left     DECIMAL(20,6);
        DECLARE tmp_receipt_seq_left    INT(11);
        DECLARE tmp_receipt_left        VARCHAR(255);
        DECLARE tmp_sale_date_left      DATETIME;
        DECLARE tmp_local_date_left     DATETIME;
        DECLARE tmp_cancel_date_left    DATETIME;
        DECLARE tmp_period_date_left    DATE;
        DECLARE tmp_bdate_left          DATE;
        DECLARE tmp_edate_left          DATE;
        DECLARE tmp_comment_left        VARCHAR(255);
        DECLARE tmp_mod_person_left     INT(11);

        
        
        
        DECLARE tmp_record_id_right      INT(11);
        DECLARE tmp_sale_id_right        INT(11);
        DECLARE tmp_agrm_id_right        INT(11);
        DECLARE tmp_oper_id_right        INT(11);
        DECLARE tmp_owner_id_right       INT(11);
        DECLARE tmp_amount_cur_id_right  INT(11);
        DECLARE tmp_amount_cur_right     DECIMAL(20,6);
        DECLARE tmp_amount_cur_vat_right DECIMAL(20,6);
        DECLARE tmp_amount_right         DECIMAL(20,6);
        DECLARE tmp_amount_vat_right     DECIMAL(20,6);
        DECLARE tmp_receipt_seq_right    INT(11);
        DECLARE tmp_receipt_right        VARCHAR(255);
        DECLARE tmp_sale_date_right      DATETIME;
        DECLARE tmp_local_date_right     DATETIME;
        DECLARE tmp_cancel_date_right    DATETIME;
        DECLARE tmp_period_date_right    DATE;
        DECLARE tmp_bdate_right          DATE;
        DECLARE tmp_edate_right          DATE;
        DECLARE tmp_comment_right        VARCHAR(255);
        DECLARE tmp_mod_person_right     INT(11);

        
        
        
        DECLARE done BOOLEAN DEFAULT FALSE;

        
        
        
        
        DECLARE sales_left CURSOR FOR
                SELECT
                        0,
                        s.sale_id,
                        s.agrm_id,
                        s.oper_id,
                        s.owner_id,
                        s.amount_cur_id,
                        s.amount_cur,
                        s.amount_cur_vat,
                        s.amount,
                        s.amount_vat,
                        s.receipt_seq,
                        s.receipt,
                        s.sale_date,
                        s.local_date,
                        s.cancel_date,
                        s.period_date,
                        s.bdate,
                        s.edate,
                        s.comment,
                        s.mod_person
                FROM
                        sales s
                WHERE
                        s.period_date >= in_bdate AND
                        s.period_date <  in_edate AND
                        (SELECT count(*) FROM vgids v WHERE v.agrm_id = s.agrm_id) > 0
                ORDER BY
                        s.sale_date DESC, s.local_date DESC;

        
        
        
        
        DECLARE sales_right CURSOR FOR
                SELECT
                        sh.record_id,
                        sh.sale_id,
                        sh.agrm_id,
                        sh.oper_id,
                        sh.owner_id,
                        sh.amount_cur_id,
                        sh.amount_cur,
                        sh.amount_cur_vat,
                        sh.amount,
                        sh.amount_vat,
                        sh.receipt_seq,
                        sh.receipt,
                        sh.sale_date,
                        sh.local_date,
                        sh.cancel_date,
                        sh.period_date AS period_date,
                        sh.bdate,
                        sh.edate,
                        sh.comment,
                        sh.mod_person
                FROM
                        sales_history sh
                WHERE
                        sh.period_date >= in_bdate AND
                        sh.period_date <  in_edate AND
                        (SELECT count(*) FROM vgids v WHERE v.agrm_id = sh.agrm_id) > 0
                ORDER BY
                        sh.sale_date DESC, sh.local_date DESC;

        
        
        
        DECLARE sales_by_period CURSOR FOR
                SELECT
                        sp.record_id,
                        sp.sale_id,
                        sp.agrm_id,
                        sp.oper_id,
                        sp.owner_id,
                        sp.amount_cur_id,
                        sp.amount_cur,
                        sp.amount_cur_vat,
                        sp.amount,
                        sp.amount_vat,
                        sp.receipt_seq,
                        sp.receipt,
                        sp.sale_date,
                        sp.local_date,
                        sp.cancel_date,
                        sp.period_date,
                        sp.bdate,
                        sp.edate,
                        sp.comment,
                        sp.mod_person
                FROM
                        tmp_sales_by_period sp;

        
        
        
        DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;

        
        
        
        CREATE TEMPORARY TABLE IF NOT EXISTS tmp_sales_by_period
        (
                record_id      INT(11) NOT NULL COMMENT 'Идентификатор версии документа',
                sale_id        INT(11) NOT NULL COMMENT 'Идентификатор документа',
                agrm_id        INT(11) NOT NULL COMMENT 'Идентификатор лицевого счета для которого оформлен документ',
                oper_id        INT(11) NOT NULL COMMENT 'Оператор, оказавший услуги абоненту',
                owner_id       INT(11) NOT NULL COMMENT 'Оператор, посчитавший услуги, оказанные абоненту',
                amount_cur_id  INT(11) NOT NULL COMMENT 'Валюта документа',
                amount_cur     DECIMAL(20,6) NOT NULL COMMENT 'Сумма по документу с НДС в валюте документа',
                amount_cur_vat DECIMAL(20,6) NOT NULL COMMENT 'Сумма НДС по документу в валюте документа',
                amount         DECIMAL(20,6) NOT NULL COMMENT 'Сумма по документу с НДС в валюте лицевого счета (пересчитанная на дату платежа)',
                amount_vat     DECIMAL(20,6) NOT NULL COMMENT 'Сумма НДС по документу в валюте лицевого счета (пересчитанная на дату платежа)',
                receipt_seq    INT(11) NOT NULL COMMENT 'Внутренний номер акта/счёта фактуры',
                receipt        VARCHAR(255) NOT NULL COMMENT 'Номер акта/счёта-фактуры',
                sale_date      DATETIME NOT NULL COMMENT 'Дата документа (Все пересчёты сумм(разностей сумм) из одной валюты в другую выполняются на эту дату)',
                local_date     DATETIME NOT NULL COMMENT 'Дата последнего изменения документа по часам АСР',
                cancel_date    DATETIME DEFAULT NULL COMMENT 'Дата аннулирования документа',
                period_date    DATE DEFAULT NULL COMMENT 'Период бух.учта, к которому относится последняя версия документа',
                bdate          DATE NOT NULL COMMENT 'Начало периода, за который рассчитаны услуги (Услуги за эту дату включены в документ)',
                edate          DATE NOT NULL COMMENT 'Конец периода, за который рассчитаны услуги (Услуги за эту дату НЕ включены в документ)',
                comment        VARCHAR(255) NOT NULL COMMENT 'Комментарий к документу',
                mod_person     INT(11) NOT NULL COMMENT 'Идентификатор менеджера, создавшего документ',

                PRIMARY KEY(record_id, sale_id),
        KEY bdate(bdate), KEY cancel_date(cancel_date),
                UNIQUE KEY sale_id(sale_id)
        ) ENGINE=MEMORY, DEFAULT CHARSET=utf8;
        TRUNCATE TABLE tmp_sales_by_period;

        
        
        
        CREATE TEMPORARY TABLE IF NOT EXISTS tmp_sale_by_period_details
        (
                record_id          INT(11) NOT NULL COMMENT 'Идентификатор версии документа о начислениях',
                sale_id            INT(11) NOT NULL COMMENT 'Идентификатор документа о начислениях',
                sale_dictionary_id INT(11) NOT NULL COMMENT 'Идентификатор услуги',
                vat                DECIMAL(20,6) NOT NULL COMMENT 'Ставка НДС по услуге в %',
                count              DECIMAL(20,6) NOT NULL COMMENT 'Количество единиц оказанной услуги в единицах из справочника услуг',
                price_cur          DECIMAL(20,6) NOT NULL COMMENT 'Цена за единицу услуги с НДС в валюте документа',
                amount_cur         DECIMAL(20,6) NOT NULL COMMENT 'Стоимость услуги с НДС в валюте документа',
                amount_cur_vat     DECIMAL(20,6) NOT NULL COMMENT 'Сумма НДС в валюте документа',
                price              DECIMAL(20,6) NOT NULL COMMENT 'Цена за единицу услуги с НДС в валюте договора',
                amount             DECIMAL(20,6) NOT NULL COMMENT 'Стоимость услуги с НДС в валюте договора',
                amount_vat         DECIMAL(20,6) NOT NULL COMMENT 'Сумма НДС в валюте договора',

                PRIMARY KEY(record_id, sale_id, sale_dictionary_id),
        KEY kk(sale_id, sale_dictionary_id), KEY sale_id(sale_id)
        ) ENGINE=MEMORY DEFAULT CHARSET=utf8 COMMENT='Детализация документов о начислениях';
        TRUNCATE TABLE tmp_sale_by_period_details;

        
        
        
        OPEN sales_left;
        OPEN sales_right;

        
        
        
        sales_all_loop: LOOP
                
                
                
                IF tmp_record_id_left IS NULL THEN
                        SET done = FALSE;
                        FETCH sales_left INTO
                                tmp_record_id_left,
                                tmp_sale_id_left,
                                tmp_agrm_id_left,
                                tmp_oper_id_left,
                                tmp_owner_id_left,
                                tmp_amount_cur_id_left,
                                tmp_amount_cur_left,
                                tmp_amount_cur_vat_left,
                                tmp_amount_left,
                                tmp_amount_vat_left,
                                tmp_receipt_seq_left,
                                tmp_receipt_left,
                                tmp_sale_date_left,
                                tmp_local_date_left,
                                tmp_cancel_date_left,
                                tmp_period_date_left,
                                tmp_bdate_left,
                                tmp_edate_left,
                                tmp_comment_left,
                                tmp_mod_person_left;
                        IF done THEN
                                SET tmp_record_id_left = NULL;
                        END IF;
                END IF;

                
                
                
                IF tmp_record_id_right IS NULL THEN
                        SET done = FALSE;
                        FETCH sales_right INTO
                                tmp_record_id_right,
                                tmp_sale_id_right,
                                tmp_agrm_id_right,
                                tmp_oper_id_right,
                                tmp_owner_id_right,
                                tmp_amount_cur_id_right,
                                tmp_amount_cur_right,
                                tmp_amount_cur_vat_right,
                                tmp_amount_right,
                                tmp_amount_vat_right,
                                tmp_receipt_seq_right,
                                tmp_receipt_right,
                                tmp_sale_date_right,
                                tmp_local_date_right,
                                tmp_cancel_date_right,
                                tmp_period_date_right,
                                tmp_bdate_right,
                                tmp_edate_right,
                                tmp_comment_right,
                                tmp_mod_person_right;
                        IF done THEN
                                SET tmp_record_id_right = NULL;
                        END IF;
                END IF;

                
                
                
                IF tmp_record_id_left IS NOT NULL AND tmp_record_id_right IS NOT NULL THEN
                        
                        
                        
                        IF tmp_sale_date_left < tmp_sale_date_right THEN
                                SET tmp_record_id      = tmp_record_id_right;
                                SET tmp_sale_id        = tmp_sale_id_right;
                                SET tmp_agrm_id        = tmp_agrm_id_right;
                                SET tmp_oper_id        = tmp_oper_id_right;
                                SET tmp_owner_id       = tmp_owner_id_right;
                                SET tmp_amount_cur_id  = tmp_amount_cur_id_right;
                                SET tmp_amount_cur     = tmp_amount_cur_right;
                                SET tmp_amount_cur_vat = tmp_amount_cur_vat_right;
                                SET tmp_amount         = tmp_amount_right;
                                SET tmp_amount_vat     = tmp_amount_vat_right;
                                SET tmp_receipt_seq    = tmp_receipt_seq_right;
                                SET tmp_receipt        = tmp_receipt_right;
                                SET tmp_sale_date      = tmp_sale_date_right;
                                SET tmp_local_date     = tmp_local_date_right;
                                SET tmp_cancel_date    = tmp_cancel_date_right;
                                SET tmp_period_date    = tmp_period_date_right;
                                SET tmp_bdate          = tmp_bdate_right;
                                SET tmp_edate          = tmp_edate_right;
                                SET tmp_comment        = tmp_comment_right;
                                SET tmp_mod_person     = tmp_mod_person_right;

                                
                                
                                
                                SET tmp_record_id_right = NULL;
                        
                        
                        
                        ELSE
                                SET tmp_record_id      = tmp_record_id_left;
                                SET tmp_sale_id        = tmp_sale_id_left;
                                SET tmp_agrm_id        = tmp_agrm_id_left;
                                SET tmp_oper_id        = tmp_oper_id_left;
                                SET tmp_owner_id       = tmp_owner_id_left;
                                SET tmp_amount_cur_id  = tmp_amount_cur_id_left;
                                SET tmp_amount_cur     = tmp_amount_cur_left;
                                SET tmp_amount_cur_vat = tmp_amount_cur_vat_left;
                                SET tmp_amount         = tmp_amount_left;
                                SET tmp_amount_vat     = tmp_amount_vat_left;
                                SET tmp_receipt_seq    = tmp_receipt_seq_left;
                                SET tmp_receipt        = tmp_receipt_left;
                                SET tmp_sale_date      = tmp_sale_date_left;
                                SET tmp_local_date     = tmp_local_date_left;
                                SET tmp_cancel_date    = tmp_cancel_date_left;
                                SET tmp_period_date    = tmp_period_date_left;
                                SET tmp_bdate          = tmp_bdate_left;
                                SET tmp_edate          = tmp_edate_left;
                                SET tmp_comment        = tmp_comment_left;
                                SET tmp_mod_person     = tmp_mod_person_left;

                                
                                
                                
                                SET tmp_record_id_left = NULL;
                        END IF;
                
                
                
                ELSEIF tmp_record_id_left IS NOT NULL THEN
                        SET tmp_record_id      = tmp_record_id_left;
                        SET tmp_sale_id        = tmp_sale_id_left;
                        SET tmp_agrm_id        = tmp_agrm_id_left;
                        SET tmp_oper_id        = tmp_oper_id_left;
                        SET tmp_owner_id       = tmp_owner_id_left;
                        SET tmp_amount_cur_id  = tmp_amount_cur_id_left;
                        SET tmp_amount_cur     = tmp_amount_cur_left;
                        SET tmp_amount_cur_vat = tmp_amount_cur_vat_left;
                        SET tmp_amount         = tmp_amount_left;
                        SET tmp_amount_vat     = tmp_amount_vat_left;
                        SET tmp_receipt_seq    = tmp_receipt_seq_left;
                        SET tmp_receipt        = tmp_receipt_left;
                        SET tmp_sale_date      = tmp_sale_date_left;
                        SET tmp_local_date     = tmp_local_date_left;
                        SET tmp_cancel_date    = tmp_cancel_date_left;
                        SET tmp_period_date    = tmp_period_date_left;
                        SET tmp_bdate          = tmp_bdate_left;
                        SET tmp_edate          = tmp_edate_left;
                        SET tmp_comment        = tmp_comment_left;
                        SET tmp_mod_person     = tmp_mod_person_left;

                        
                        
                        
                        SET tmp_record_id_left = NULL;
                
                
                
                ELSEIF tmp_record_id_right IS NOT NULL THEN
                        SET tmp_record_id      = tmp_record_id_right;
                        SET tmp_sale_id        = tmp_sale_id_right;
                        SET tmp_agrm_id        = tmp_agrm_id_right;
                        SET tmp_oper_id        = tmp_oper_id_right;
                        SET tmp_owner_id       = tmp_owner_id_right;
                        SET tmp_amount_cur_id  = tmp_amount_cur_id_right;
                        SET tmp_amount_cur     = tmp_amount_cur_right;
                        SET tmp_amount_cur_vat = tmp_amount_cur_vat_right;
                        SET tmp_amount         = tmp_amount_right;
                        SET tmp_amount_vat     = tmp_amount_vat_right;
                        SET tmp_receipt_seq    = tmp_receipt_seq_right;
                        SET tmp_receipt        = tmp_receipt_right;
                        SET tmp_sale_date      = tmp_sale_date_right;
                        SET tmp_local_date     = tmp_local_date_right;
                        SET tmp_cancel_date    = tmp_cancel_date_right;
                        SET tmp_period_date    = tmp_period_date_right;
                        SET tmp_bdate          = tmp_bdate_right;
                        SET tmp_edate          = tmp_edate_right;
                        SET tmp_comment        = tmp_comment_right;
                        SET tmp_mod_person     = tmp_mod_person_right;

                        
                        
                        
                        SET tmp_record_id_right = NULL;
                
                
                
                ELSE
                        LEAVE sales_all_loop;
                END IF;

                
                
                
                IF (SELECT count(*) FROM tmp_sales_by_period WHERE sale_id = tmp_sale_id) = 0 THEN
                        
                        
                        
                        SET tmp_amount_cur     = IF(tmp_cancel_date IS NULL, tmp_amount_cur    , 0);
                        SET tmp_amount_cur_vat = IF(tmp_cancel_date IS NULL, tmp_amount_cur_vat, 0);
                        SET tmp_amount         = IF(tmp_cancel_date IS NULL, tmp_amount        , 0);
                        SET tmp_amount_vat     = IF(tmp_cancel_date IS NULL, tmp_amount_vat    , 0);

                        
                        
                        
                        INSERT INTO tmp_sales_by_period
                        (
                                record_id,
                                sale_id,
                                agrm_id,
                                oper_id,
                                owner_id,
                                amount_cur_id,
                                amount_cur,
                                amount_cur_vat,
                                amount,
                                amount_vat,
                                receipt_seq,
                                receipt,
                                sale_date,
                                local_date,
                                cancel_date,
                                period_date,
                                bdate,
                                edate,
                                comment,
                                mod_person
                        )
                        VALUES
                        (
                                tmp_record_id,
                                tmp_sale_id,
                                tmp_agrm_id,
                                tmp_oper_id,
                                tmp_owner_id,
                                tmp_amount_cur_id,
                                tmp_amount_cur,
                                tmp_amount_cur_vat,
                                tmp_amount,
                                tmp_amount_vat,
                                tmp_receipt_seq,
                                tmp_receipt,
                                tmp_sale_date,
                                tmp_local_date,
                                tmp_cancel_date,
                                tmp_period_date,
                                tmp_bdate,
                                tmp_edate,
                                tmp_comment,
                                tmp_mod_person
                        );

                        
                        
                        
                        IF tmp_record_id = 0 THEN
                                INSERT INTO tmp_sale_by_period_details
                                (
                                        record_id,
                                        sale_id,
                                        sale_dictionary_id,
                                        vat,
                                        count,
                                        price_cur,
                                        amount_cur,
                                        amount_cur_vat,
                                        price,
                                        amount,
                                        amount_vat
                                )
                                SELECT
                                        0,
                                        tmp_sale_id,
                                        sd.sale_dictionary_id,
                                        sd.vat,
                                        IF(tmp_cancel_date IS NULL, sd.count, 0),
                                        sd.price_cur,
                                        IF(tmp_cancel_date IS NULL, sd.amount_cur, 0),
                                        IF(tmp_cancel_date IS NULL, sd.amount_cur_vat, 0),
                                        sd.price,
                                        IF(tmp_cancel_date IS NULL, sd.amount, 0),
                                        IF(tmp_cancel_date IS NULL, sd.amount_vat, 0)
                                FROM
                                        sale_details sd
                                WHERE
                                        sd.sale_id = tmp_sale_id
                                ON DUPLICATE KEY UPDATE
                                        count          = tmp_sale_by_period_details.count          + VALUES(count),
                                        amount_cur     = tmp_sale_by_period_details.amount_cur     + VALUES(amount_cur),
                                        amount_cur_vat = tmp_sale_by_period_details.amount_cur_vat + VALUES(amount_cur_vat),
                                        amount         = tmp_sale_by_period_details.amount         + VALUES(amount),
                                        amount_vat     = tmp_sale_by_period_details.amount_vat     + VALUES(amount_vat);
                        ELSE
                                INSERT INTO tmp_sale_by_period_details
                                (
                                        record_id,
                                        sale_id,
                                        sale_dictionary_id,
                                        vat,
                                        count,
                                        price_cur,
                                        amount_cur,
                                        amount_cur_vat,
                                        price,
                                        amount,
                                        amount_vat
                                )
                                SELECT
                                        tmp_record_id,
                                        tmp_sale_id,
                                        sd.sale_dictionary_id,
                                        sd.vat,
                                        IF(tmp_cancel_date IS NULL, sd.count, 0),
                                        sd.price_cur,
                                        IF(tmp_cancel_date IS NULL, sd.amount_cur, 0),
                                        IF(tmp_cancel_date IS NULL, sd.amount_cur_vat, 0),
                                        sd.price,
                                        IF(tmp_cancel_date IS NULL, sd.amount, 0),
                                        IF(tmp_cancel_date IS NULL, sd.amount_vat, 0)
                                FROM
                                        sale_history_details sd
                                WHERE
                                        sd.record_id = tmp_record_id
                                ON DUPLICATE KEY UPDATE
                                        count          = tmp_sale_by_period_details.count          + VALUES(count),
                                        amount_cur     = tmp_sale_by_period_details.amount_cur     + VALUES(amount_cur),
                                        amount_cur_vat = tmp_sale_by_period_details.amount_cur_vat + VALUES(amount_cur_vat),
                                        amount         = tmp_sale_by_period_details.amount         + VALUES(amount),
                                        amount_vat     = tmp_sale_by_period_details.amount_vat     + VALUES(amount_vat);
                        END IF;
                END IF;
        END LOOP;
        CLOSE sales_left;
        CLOSE sales_right;

        
        
        
        OPEN sales_by_period;
        sales_prev_loop: LOOP
                SET done = FALSE;
                FETCH sales_by_period INTO
                        tmp_record_id,
                        tmp_sale_id,
                        tmp_agrm_id,
                        tmp_oper_id,
                        tmp_owner_id,
                        tmp_amount_cur_id,
                        tmp_amount_cur,
                        tmp_amount_cur_vat,
                        tmp_amount,
                        tmp_amount_vat,
                        tmp_receipt_seq,
                        tmp_receipt,
                        tmp_sale_date,
                        tmp_local_date,
                        tmp_cancel_date,
                        tmp_period_date,
                        tmp_bdate,
                        tmp_edate,
                        tmp_comment,
                        tmp_mod_person;
                IF done THEN
                        LEAVE sales_prev_loop;
                END IF;

                
                
                
                SET tmp_record_id_prev = NULL;
                SELECT
                        record_id,
                        agrm_id,
                        oper_id,
                        owner_id,
                        amount_cur_id,
                        amount_cur,
                        amount_cur_vat,
                        amount,
                        amount_vat,
                        receipt_seq,
                        receipt,
                        sale_date,
                        local_date,
                        cancel_date,
                        period_date,
                        bdate,
                        edate,
                        comment,
                        mod_person
                INTO
                        tmp_record_id_prev,
                        tmp_agrm_id_prev,
                        tmp_oper_id_prev,
                        tmp_owner_id_prev,
                        tmp_amount_cur_id_prev,
                        tmp_amount_cur_prev,
                        tmp_amount_cur_vat_prev,
                        tmp_amount_prev,
                        tmp_amount_vat_prev,
                        tmp_receipt_seq_prev,
                        tmp_receipt_prev,
                        tmp_sale_date_prev,
                        tmp_local_date_prev,
                        tmp_cancel_date_prev,
                        tmp_period_date_prev,
                        tmp_bdate_prev,
                        tmp_edate_prev,
                        tmp_comment_prev,
                        tmp_mod_person_prev
                FROM
                        sales_history sh
                WHERE
                        sh.sale_id = tmp_sale_id AND
                        sh.period_date < in_bdate
                ORDER BY
                        sh.local_date DESC
                LIMIT 1;

                
                
                
                IF tmp_record_id_prev IS NOT NULL THEN
                        
                        
                        
                        SET tmp_amount_cur_prev     = IF(tmp_cancel_date_prev IS NULL, tmp_amount_cur_prev    , 0);
                        SET tmp_amount_cur_vat_prev = IF(tmp_cancel_date_prev IS NULL, tmp_amount_cur_vat_prev, 0);
                        SET tmp_amount_prev         = IF(tmp_cancel_date_prev IS NULL, tmp_amount_prev        , 0);
                        SET tmp_amount_vat_prev     = IF(tmp_cancel_date_prev IS NULL, tmp_amount_vat_prev    , 0);

                        
                        
                        
                        INSERT INTO tmp_sales_by_period
                        (
                                record_id,
                                sale_id,
                                agrm_id,
                                oper_id,
                                owner_id,
                                amount_cur_id,
                                amount_cur,
                                amount_cur_vat,
                                amount,
                                amount_vat,
                                receipt_seq,
                                receipt,
                                sale_date,
                                local_date,
                                cancel_date,
                                period_date,
                                bdate,
                                edate,
                                comment,
                                mod_person
                        )
                        VALUES
                        (
                                tmp_record_id,
                                tmp_sale_id,
                                tmp_agrm_id,
                                tmp_oper_id,
                                tmp_owner_id,
                                tmp_amount_cur_id,
                                tmp_amount_cur - tmp_amount_cur_prev,
                                tmp_amount_cur_vat - tmp_amount_cur_vat_prev,
                                tmp_amount - tmp_amount_prev,
                                tmp_amount_vat - tmp_amount_vat_prev,
                                tmp_receipt_seq,
                                tmp_receipt,
                                tmp_sale_date,
                                tmp_local_date,
                                tmp_cancel_date,
                                tmp_period_date,
                                tmp_bdate,
                                tmp_edate,
                                tmp_comment,
                                tmp_mod_person
                        )
                        ON DUPLICATE KEY UPDATE
                                amount_cur     = VALUES(amount_cur),
                                amount_cur_vat = VALUES(amount_cur_vat),
                                amount         = VALUES(amount),
                                amount_vat     = VALUES(amount_vat);

                        
                        
                        
                        INSERT INTO tmp_sale_by_period_details
                        (
                                record_id,
                                sale_id,
                                sale_dictionary_id,
                                vat,
                                count,
                                price_cur,
                                amount_cur,
                                amount_cur_vat,
                                price,
                                amount,
                                amount_vat
                        )
                        SELECT
                                tmp_record_id,
                                tmp_sale_id,
                                sd.sale_dictionary_id,
                                sd.vat,
                                IF(tmp_cancel_date_prev IS NULL, -sd.count, 0),
                                sd.price_cur,
                                IF(tmp_cancel_date_prev IS NULL, -sd.amount_cur, 0),
                                IF(tmp_cancel_date_prev IS NULL, -sd.amount_cur_vat, 0),
                                sd.price,
                                IF(tmp_cancel_date_prev IS NULL, -sd.amount, 0),
                                IF(tmp_cancel_date_prev IS NULL, -sd.amount_vat, 0)
                        FROM
                                sale_history_details sd
                        WHERE
                                sd.record_id = tmp_record_id_prev
                        ON DUPLICATE KEY UPDATE
                                count          = tmp_sale_by_period_details.count          + VALUES(count),
                                amount_cur     = tmp_sale_by_period_details.amount_cur     + VALUES(amount_cur),
                                amount_cur_vat = tmp_sale_by_period_details.amount_cur_vat + VALUES(amount_cur_vat),
                                amount         = tmp_sale_by_period_details.amount         + VALUES(amount),
                                amount_vat     = tmp_sale_by_period_details.amount_vat     + VALUES(amount_vat);
                END IF;
        END LOOP;
        CLOSE sales_by_period;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE SET_AGENT_OPTION
