/*!50003 DROP PROCEDURE IF EXISTS `SET_AGENT_OPTION` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `SET_AGENT_OPTION`(IN new_id INT(11),IN new_name VARCHAR(32),IN new_value VARCHAR(32))
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Добавляет (или заменяет существующую) агентскую опцию'
BEGIN
    
    IF ( new_id IS NOT NULL ) THEN
        INSERT INTO agent_options ( `id`, `name`, `value` )
