    END IF;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE SET_C_DATE
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `SET_C_DATE` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `SET_C_DATE`(in_id INT, in_date DATETIME)
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Обновление поля c_date в таблице vgroups'
BEGIN
     DECLARE done INT DEFAULT 0;
    DECLARE l_vg_id INT DEFAULT 0;
    DECLARE l_cdate DATE DEFAULT 0;
    DECLARE l_new_cdate DATE DEFAULT 0;
    
    
    DECLARE vgids CURSOR FOR 
        SELECT `vg_id`, GET_C_DATE(`c_date`, DATE(in_date)), `c_date`
        FROM vgroups 
        WHERE IF(in_id = 0, true, in_id = id) AND `archive` = '0' AND `template` = '0';
    
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done=1;
    
    OPEN vgids;
    FETCH vgids INTO l_vg_id, l_new_cdate, l_cdate;
    WHILE NOT done DO
        IF l_new_cdate <> l_cdate THEN
            START TRANSACTION;
                
                SET @LB_DISABLE_TRIGGERS = 1;
                    UPDATE `vgroups` SET `amount` = '0', `c_date` = l_new_cdate WHERE vg_id = l_vg_id;        
                SET @LB_DISABLE_TRIGGERS = NULL;
            COMMIT;
        END IF;
        SET done = 0;
        FETCH vgids INTO l_vg_id, l_new_cdate, l_cdate;
    END WHILE;
    CLOSE vgids;     
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE set_default_roles
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `set_default_roles` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `set_default_roles`()
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Восстанавливает список системных ролей'
begin
  
  drop temporary table if exists `user_roles_backup`;
  create temporary table `user_roles_backup` as select role_name,descr from roles where issystem = 0 and descr != 'System role';

  drop temporary table if exists `user_rules_backup`;
  create temporary table `user_rules_backup` as select r.`role_id`,r.`rule_template_id`,r.`rights_level` from rules r join roles rs using(role_id)
  where rs.`issystem` = 0 and rs.`descr` != 'System role';

  delete from rules;

  insert into roles(role_name, descr, issystem)
  select role_name, descr, issystem
  from meta$roles
  on duplicate key update descr = values(descr), issystem = values(issystem);

  
  insert into roles(role_name, descr)
  select role_name, descr
  from `user_roles_backup`
  on duplicate key update descr = values(descr);

  insert into rule_templates(name, descr, enabled, rights)
  select name, descr, 0, rights from meta$rule_templates
  on duplicate key update descr = values(descr), rights = values(rights);

  insert into rules(role_id, rule_template_id, rights_level)
  select r.role_id, rt.rule_template_id, t.rights_level
  from (select a.role_name,b.rights_level, c.name
        from meta$roles a
        join meta$rules b on a.role_id = b.role_id
        join meta$rule_templates c on c.rule_template_id = b.rule_template_id
        ) t
  join roles r on r.role_name = t.role_name
  join rule_templates rt on t.name = rt.name
  on duplicate key update rights_level = values(rights_level);

  
  insert into rules(role_id, rule_template_id, rights_level)
    select `role_id`, `rule_template_id`, `rights_level` from `user_rules_backup`
  on duplicate key update rights_level = values(rights_level);

end */;;

