# Dump of PROCEDURE show_error
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `show_error` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `show_error`(v_errorcode varchar(10))
    SQL SECURITY INVOKER
BEGIN
  declare v_messageText varchar(4000);

  SELECT CONCAT(message_level, ':', code, ' : ', message)
  INTO v_messageText
  FROM meta$messages
  WHERE code = errorCode;

  SIGNAL SQLSTATE '45001' SET MESSAGE_TEXT = v_messageText;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE show_message
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `show_message` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `show_message`(IN v_msg_lvl varchar(64), IN v_err_num int(11), IN v_msg varchar(4000))
    READS SQL DATA
    SQL SECURITY INVOKER
begin
    if(v_msg_lvl = 'ERROR' and ifnull(@LB_UPDATESQL_DEBUG, '0') = '0')
     or (v_msg_lvl in ('ERROR', 'WARNING') and @LB_UPDATESQL_DEBUG = '1')
     or (v_msg_lvl in ('INFO', 'ERROR', 'WARNING') and @LB_UPDATESQL_DEBUG = '2')
      then
        SELECT now() as "", concat(v_msg_lvl, ': ', if(v_err_num <> 0, concat(v_err_num,' : '), ''), v_msg) as "";
        insert into `meta$message_log`(process_id, command_id, error_code, user_message, parent_id, message_time, message_lvl)
        values (@LB_UPDATESQL_PROCESSID, @LB_UPDATESQL_COMMID, v_err_num, v_msg, @LB_UPDATESQL_PMESSID, now(), v_msg_lvl);
        select LAST_INSERT_ID() into @LB_UPDATESQL_PMESSID;
    end if;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE show_msg
# ------------------------------------------------------------

