/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `show_msg`(IN v_msg varchar(4000))
    DETERMINISTIC
    SQL SECURITY INVOKER
begin
    call show_message('INFO', 0, v_msg);
END */;;

