/*!50003 DROP PROCEDURE IF EXISTS `SPLIT_STRING` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `SPLIT_STRING`(IN in_str VARCHAR(1024),IN in_delimiter VARCHAR(1))
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
BEGIN
  DECLARE i int(11) default NULL;
  DECLARE sub_str VARCHAR(1024) default '';
  DECLARE token VARCHAR(1024) default '';
  SET sub_str = in_str;

   DROP TEMPORARY TABLE IF EXISTS tmp_split_string;
   CREATE TEMPORARY TABLE tmp_split_string (
        id VARCHAR(1024) default '',
        UNIQUE KEY `id` (`id`)
    ) ENGINE=MEMORY DEFAULT CHARSET=utf8;

    WHILE LENGTH(sub_str) > 0 DO
        SET i = LOCATE(in_delimiter, sub_str);
        IF i > 0 THEN
            SET token = SUBSTRING(sub_str, 1, i - 1);
            SET sub_str = SUBSTRING(sub_str, i + 1);
        ELSE
            SET token = sub_str;
            SET sub_str = '';
        END IF;
        INSERT IGNORE INTO tmp_split_string ( id ) SELECT token;
    END WHILE;
END */;;

