/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `STAT_13217_PROC`()
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Подготовка таблички со списаниями и платежами по договору'
begin
    declare datfromdate varchar(32);
    declare dattodate varchar(32);


    drop temporary table if exists `stat_13217_table`;
    create temporary table stat_13217_table( `uid`          int(11) COMMENT 'Идентификатор пользователя',
                                            `agrm_id`       int(11) COMMENT 'Идентификатор договора',
                                            `vg_id`         int(11) COMMENT 'Идентификатор у.з.',
                                            `period`        date NOT NULL DEFAULT '0000-00-00' COMMENT 'День, за который выполнено списание',
                                            `tar_id`        int(11) COMMENT 'Идентификатор тарифа',
                                            `rent`          decimal(20,6) default 0 COMMENT 'ап по тарифу',
                                            `above`         decimal(20,6) default 0 COMMENT 'списания свыше ап',
                                            `pays`          decimal(20,6) default 0 COMMENT 'Сумма платежей'
                                            );

    select ifnull(date_format(val, '%Y%m%d%H%i%s'),'1970-01-01 00:00:00') into datfromdate    from filter where name = 'dtfrom'        ;
    select ifnull(date_format(val, '%Y%m%d%H%i%s'),'9999-12-31 23:59:59') into dattodate      from filter where name = 'dtto'            ;

    drop temporary table if exists `stat_13217_table_buf`;
    create temporary table `stat_13217_table_buf` like `stat_13217_table`;

 
    set @s = concat( " INSERT INTO stat_13217_table_buf (uid, vg_id, agrm_id, period, tar_id, rent) "
                   , " SELECT v.uid, r.vg_id, r.agrm_id, date_format(r.period, '%Y-%m-01'), r.tar_id, sum(r.amount) as amount"
                   , " FROM rentcharge r"
                   , " JOIN vgids v on v.vg_id = r.vg_id "
                   , " WHERE r.period >= date('", datfromdate,"') and r.period < '", dattodate, "' and amount<>0 "
                   , " GROUP BY v.uid, r.vg_id, r.agrm_id, r.tar_id, date_format(r.period, '%Y-%m-01') "
                   );
    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;

 
    set @s = concat( " INSERT INTO stat_13217_table_buf (uid, vg_id, agrm_id, period, tar_id, rent) "
                   , " SELECT v.uid, v.vg_id, v.agrm_id, date_format(r.period, '%Y-%m-01'), s.tar_id, sum(r.amount) as amount "
                   , " FROM usbox_charge r JOIN usbox_services s ON r.serv_id = s.serv_id "
                   , " JOIN categories c ON s.tar_id = c.tar_id and s.cat_idx = c.cat_idx "
                   , " JOIN vgids v on v.vg_id = s.vg_id "
                   , " WHERE r.period >= date('", datfromdate,"') and r.period < '", dattodate, "' and amount<>0 and c.auto_assign=1 "
                   , " GROUP BY v.uid, v.vg_id, v.agrm_id, s.tar_id, date_format(r.period, '%Y-%m-01') "
                   );
    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;

 
    set @s = concat( " INSERT INTO stat_13217_table_buf (uid, vg_id, agrm_id, period, tar_id, rent) "
                   , " SELECT v.uid, v.vg_id, v.agrm_id, date_format(r.period, '%Y-%m-01'), s.tar_id, sum(r.amount) as amount "
                   , " FROM charges r JOIN services s using(service_id) "
                   , " JOIN service_categories c on c.tar_id=s.tar_id and c.serv_cat_idx=s.serv_cat_idx "
                   , " JOIN vgids v on v.vg_id = s.vg_id "
                   , " WHERE r.period >= date('", datfromdate,"') and r.period < '", dattodate, "' and amount<>0 and c.auto_assign=1 "
                   , " GROUP BY v.uid, r.vg_id, r.agrm_id, r.tar_id, date_format(r.period, '%Y-%m-01') "
                   );
    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;

 
    set @s = concat( " INSERT INTO stat_13217_table_buf (uid, vg_id, agrm_id, period, tar_id, above) "
                   , " SELECT v.uid, v.vg_id, v.agrm_id, date_format(r.period, '%Y-%m-01'), s.tar_id, sum(r.amount) as amount "
                   , " FROM usbox_charge r JOIN usbox_services s ON r.serv_id = s.serv_id "
                   , " JOIN categories c ON s.tar_id = c.tar_id and s.cat_idx = c.cat_idx "
                   , " JOIN vgids v on v.vg_id = s.vg_id "
                   , " WHERE r.period >= date('", datfromdate,"') and r.period < '", dattodate, "' and amount<>0 and c.auto_assign=0 "
                   , " GROUP BY v.uid, v.vg_id, v.agrm_id, s.tar_id, date_format(r.period, '%Y-%m-01') "
                   );
    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;

 
    set @s = concat( " INSERT INTO stat_13217_table_buf (uid, vg_id, agrm_id, period, tar_id, above) "
                   , " SELECT v.uid, v.vg_id, v.agrm_id, date_format(r.period, '%Y-%m-01'), s.tar_id, sum(r.amount) as amount "
                   , " FROM charges r JOIN services s using(service_id) "
                   , " JOIN service_categories c on c.tar_id=s.tar_id and c.serv_cat_idx=s.serv_cat_idx "
                   , " JOIN vgids v on v.vg_id = s.vg_id "
                   , " WHERE r.period >= date('", datfromdate,"') and r.period < '", dattodate, "' and amount<>0 and c.auto_assign=0 "
                   , " GROUP BY v.uid, r.vg_id, r.agrm_id, r.tar_id, date_format(r.period, '%Y-%m-01') "
                   );
    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;

 
    set @s = concat( " INSERT INTO stat_13217_table_buf "
                   , " (uid, vg_id, agrm_id, period, tar_id, above) "
                   , " SELECT r.uid, r.vg_id, r.agrm_id, date_format(r.timefrom, '%Y-%m-01'), r.tar_id, sum(r.amount) as amount "
                   , " FROM day r "
                   , " JOIN vgids v on v.vg_id = r.vg_id "
                   , " WHERE r.timefrom >= date('", datfromdate,"') "
                   , " AND   r.timefrom < date('", dattodate,"') and amount<>0 "
                   , " GROUP BY v.uid, r.vg_id, r.agrm_id, r.tar_id, date_format(r.timefrom, '%Y-%m-01') "
                   );
    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;

 
    set @s = concat( " INSERT INTO stat_13217_table_buf (agrm_id, pays) "
                   , " SELECT p.agrm_id, sum(p.amount) "
                   , " FROM payments p "
                   , " WHERE p.pay_date >= date('", datfromdate,"') and p.pay_date < '", dattodate, "' "
                   , " AND p.agrm_id in (select agrm_id from vgids) "
                   , " GROUP BY p.agrm_id "
                   );

    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;


    insert into stat_13217_table (uid, vg_id, agrm_id, period, tar_id, rent, above) select uid, vg_id, agrm_id, period, tar_id, sum(rent), sum(above) from stat_13217_table_buf where period<>'0000-00-00' group by uid, vg_id, agrm_id, tar_id, period;
    insert into stat_13217_table (agrm_id, period, pays) select agrm_id, period, sum(pays) from stat_13217_table_buf where period='0000-00-00' group by agrm_id;

end */;;

