/*!50003 DROP PROCEDURE IF EXISTS `STAT_16736_PROC` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `STAT_16736_PROC`()
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Процедура для отложенного отключения пакета каналов из ЛК'
begin
    declare l_action,l_today varchar(255);
    declare l_serv_id int(11);
    declare l_timeto_fact,l_timeto_plan,l_cancel_date datetime;

    drop temporary table if exists `stat_16736_table`;
    create temporary table stat_16736_table(`result` int(11) COMMENT 'Результат');

    CREATE TABLE IF NOT EXISTS itgc55854_data_table(
        serv_id int(11) default 0,
        service_id int(11) default 0,
        timeto_fact datetime not null,
        timeto_plan datetime not null,
        cancel_date datetime,
        person varchar(255),
        event_date datetime not null
    ) engine=InnoDB;

    select val into l_action from filter where name='descr';
    case l_action
        when 'setDeleteTvUsbox' then
            select val into l_serv_id from filter where name='catid';
            select val into l_timeto_fact from filter where name='dtcreated';
            select val into l_timeto_plan from filter where name='dtactivated';
            UPDATE itgc55854_data_table SET cancel_date = now() WHERE serv_id = l_serv_id AND cancel_date="0000-00-00 00:00:00" AND date_format(timeto_fact,"%Y-%m") = date_format(now(),"%Y-%m");
            INSERT INTO itgc55854_data_table VALUES (l_serv_id,0,l_timeto_fact,l_timeto_plan,"0000-00-00 00:00:00","Клиент",now());
            insert into stat_16736_table SELECT 1;
        when 'updDeleteTvUsbox' then
            select val into l_serv_id from filter where name='catid';
            select val into l_cancel_date from filter where name='dtto';
            UPDATE itgc55854_data_table SET cancel_date = l_cancel_date WHERE serv_id = l_serv_id AND cancel_date="0000-00-00 00:00:00" AND date_format(timeto_fact,"%Y-%m") = date_format(now(),"%Y-%m");
            insert into stat_16736_table SELECT 1;
        when 'getDeleteTvUsbox' then
            select val into l_serv_id from filter where name='catid';
            insert into stat_16736_table SELECT count(1) FROM itgc55854_data_table WHERE serv_id = l_serv_id AND date_format(timeto_fact,"%Y-%m-%d") = date_format(now(),"%Y-%m-%d") and person='Клиент';
        when 'setDeleteTvServ' then
            select val into l_serv_id from filter where name='catid';
            select val into l_timeto_fact from filter where name='dtcreated';
            select val into l_timeto_plan from filter where name='dtactivated';
            UPDATE itgc55854_data_table SET cancel_date = now() WHERE service_id = l_serv_id AND cancel_date="0000-00-00 00:00:00" AND date_format(timeto_fact,"%Y-%m") = date_format(now(),"%Y-%m");
            INSERT INTO itgc55854_data_table VALUES (0,l_serv_id,l_timeto_fact,l_timeto_plan,"0000-00-00 00:00:00","Клиент",now());
            insert into stat_16736_table SELECT 1;
        when 'updDeleteTvServ' then
            select val into l_serv_id from filter where name='catid';
            select val into l_cancel_date from filter where name='dtto';
            UPDATE itgc55854_data_table SET cancel_date = l_cancel_date WHERE service_id = l_serv_id AND cancel_date="0000-00-00 00:00:00" AND date_format(timeto_fact,"%Y-%m") = date_format(now(),"%Y-%m");
            insert into stat_16736_table SELECT 1;
        when 'getDeleteTvServ' then
            select val into l_serv_id from filter where name='catid';
            insert into stat_16736_table SELECT count(1) FROM itgc55854_data_table WHERE service_id = l_serv_id AND date_format(timeto_fact,"%Y-%m-%d") = date_format(now(),"%Y-%m-%d") and person='Клиент';
    end case;

end */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
