/*!50003 DROP PROCEDURE IF EXISTS `STAT_1_PROC` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `STAT_1_PROC`()
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Подготовка таблички с общей статистикой клиента'
begin
  declare done int default 0;
  declare tab varchar(64);
  declare tabfromdate varchar(32);
  declare tabtodate varchar(32);
  declare datfromdate varchar(32);
  declare dattodate varchar(32);
  declare userid int default 0;
  declare vgid int default 0;
  declare vgidcurr int default 0;
  declare vgclause varchar(255);
  declare agentdescr varchar(255);
  declare tabname varchar(255);
  declare tabprefix varchar(32);
  declare fldname varchar(32);
  declare repdetail int;
  declare agentid int;
  declare agenttype int;
  declare agrmid int;
  declare vgrs cursor for
          select distinct vg_id,agrm_id,id,type from vgids;
  declare tab_name cursor for
          select table_name from information_schema.tables
          where table_schema=database() and table_name >= concat(tabprefix,lpad(agentid,3,'0'),tabfromdate)  and table_name <= concat(tabprefix,lpad(agentid,3,'0'),tabtodate);

  declare continue handler for not found set done=1;

  drop temporary table if exists `stat_1_table`;
  create temporary table stat_1_table(
    dt datetime default 0,
    agrm_id int default 0,
    vg_id int default 0,
    agent_id int default 0,
    agent_type int default 0,
    agent_descr varchar(255) default '',
    curr_symbol varchar(255) default '',
    duration decimal(20,6) default 0,
    volume bigint(20) default 0,
    volume_in bigint(20) default 0,
    volume_out bigint(20) default 0,
    cnt_in int default 0,
    cnt_out int default 0,
    amount decimal(20,6) default 0,
    total bigint(20) default 0
  );

  drop temporary table if exists `stat_1_table_buf`;
  create temporary table stat_1_table_buf like stat_1_table;

  select ifnull(date_format(val, '%Y%m%d%H%i%s'),'1970-01-01 00:00:00') into datfromdate    from filter where name = 'dtfrom'       ;
  select ifnull(date_format(val, '%Y%m%d%H%i%s'),'9999-12-31 23:59:59') into dattodate      from filter where name = 'dtto'         ;
  select ifnull(date_format(val, '%Y%m%d'),'1970-01-01')                into tabfromdate    from filter where name = 'dtfrom'       ;
  select ifnull(date_format(val, '%Y%m%d'),'9999-12-31')                into tabtodate      from filter where name = 'dtto'         ;
  select val                                into vgid       from filter where name = 'vgid';
  select val                                into userid     from filter where name = 'userid';
  select val                                into repdetail      from filter where name = 'repdetail';

  set done = 0;
  open vgrs;
  fetch vgrs into vgidcurr,agrmid,agentid,agenttype;
  while not done do
    if  ( (vgid > 0 and vgidcurr=vgid) or (vgid = 0) or (vgid is null) ) then
      select type, replace(descr,'"','\\"') into agenttype, agentdescr from settings where id = agentid;
      if ( agenttype = 13 ) then
        set @s = concat( 'insert into stat_1_table_buf(dt,agrm_id, vg_id, agent_id, agent_type, agent_descr, volume, amount)'
                       , ' select date_format(c.period, "%Y%m%d%H0000"),',agrmid,',',vgidcurr,',',agentid,',',agenttype,',"',agentdescr,'",count(c.serv_id), sum(c.amount)'
                       , ' from usbox_charge c, usbox_services s'
                       , ' where c.serv_id = s.serv_id'
                       , ' and s.vg_id = ',vgidcurr
                       , ' and c.period >= "', datfromdate
                       , '" and   c.period < "', dattodate
                       , '" group by date_format(c.period, "%Y%m%d%H0000")'
                       );
        prepare stmt from @s;
        execute stmt;
        deallocate prepare stmt;
      elseif ( agenttype = 14 ) then
        set done = 0;
      else
        if agenttype in (1,2,3,4,5) then
          set tabprefix = 'user';
        elseif agenttype in (6) then
          set tabprefix = 'rad';
        elseif agenttype in (7,8,9,10,11,12) then
          set tabprefix = 'tel';
        else
          call ERROR_INVALID_AGENT_TYPE(agenttype);
        end if;

        if agenttype in (1,2,3,4,5) then
          if ( repdetail <> 2 ) then
            set @s = concat( 'insert into stat_1_table_buf(dt, vg_id, agent_id, agent_type, agent_descr, volume, volume_in, volume_out, amount)'
                           , ' select date_format(timefrom, "%Y%m%d%H0000"),',vgidcurr,',',agentid,',',agenttype,',"',agentdescr,'",sum(cin+cout),sum(cin),sum(cout),sum(amount)'
                           , ' from day where vg_id = ',vgidcurr
                           , ' and timefrom >= "',datfromdate,'"'
                           , ' and timefrom < "',dattodate, '"'
                           , ' and id = ', agentid
                           , ' group by date_format(timefrom, "%Y%m%d%H0000")'
                           );
            prepare stmt from @s;
            execute stmt;
            deallocate prepare stmt;

            if date(tabtodate) >= date(now()) then
               select table_name into tabname
               from information_schema.tables
               where table_schema=database() and table_name = concat('user',lpad(agentid,3,'0'),date_format(now(), '%Y%m%d'));
               if ( tabname > 'user')  then
                 set @s = concat( 'insert into stat_1_table_buf(dt, agrm_id, vg_id, agent_id, agent_type, agent_descr, volume, volume_in, volume_out, amount)'
                                , ' select date_format(timefrom, "%Y%m%d%H0000"),',agrmid,',',vgidcurr,',',agentid,',',agenttype,',"',agentdescr,'",sum(cin+cout),sum(cin),sum(cout),sum(amount)'
                                , ' from ', tabname
                                , ' where vg_id = ', vgidcurr
                                , ' and timeto >= "', datfromdate, '"'
                                , ' and timeto < "', dattodate, '"'
                                , ' group by date_format(timefrom, "%Y%m%d%H0000")'
                                );
                 prepare stmt from @s;
                 execute stmt;
                 deallocate prepare stmt;
               end if;
            end if;
          else   
            set done = 0;
            open tab_name;
            fetch tab_name into tabname;
            while not done do
              set @s = concat( 'insert into stat_1_table_buf(dt, agrm_id, vg_id, agent_id, agent_type, agent_descr, volume, volume_in, volume_out, amount)'
                             , 'select date_format(timefrom, "%Y%m%d%H0000"),',agrmid,',',vgidcurr,',',agentid,',',agenttype,',"',agentdescr,'",sum(cin+cout),sum(cin),sum(cout),sum(amount)'
                             , ' from ', tabname
                             , ' where vg_id = ',vgidcurr
                             , ' and timeto >= "',datfromdate,'"'
                             , ' and timeto < "',dattodate, '"'
                             , ' group by date_format(timefrom, "%Y%m%d%H0000")'
                             );
              prepare stmt from @s;
              execute stmt;
              deallocate prepare stmt;
              set done = 0;
              fetch tab_name into tabname;
            end while;
            close tab_name;
          end if;
        elseif agenttype in (6) then
          if ( repdetail <> 2 ) then
            set @s = concat( 'insert into stat_1_table_buf(dt, vg_id, agent_id, agent_type, agent_descr, volume, volume_in, volume_out, amount)'
                           , ' select date_format(timefrom, "%Y%m%d%H0000"),',vgidcurr,',',agentid,',',agenttype,',"',agentdescr,'",sum(cin+cout),sum(cin),sum(cout),sum(amount)'
                           , ' from day where vg_id = ',vgidcurr
                           , ' and timefrom >= "',datfromdate,'"'
                           , ' and timefrom < "',dattodate, '"'
                           , ' and id = ', agentid
                           , ' group by date_format(timefrom, "%Y%m%d%H0000")'
                           );
            prepare stmt from @s;
            execute stmt;
            deallocate prepare stmt;

            if date(tabtodate) >= date(now()) then
               select table_name into tabname
               from information_schema.tables
               where table_schema=database() and table_name = concat('rad',lpad(agentid,3,'0'),date_format(now(), '%Y%m%d'));
               if ( tabname > 'rad')  then
                 set @s = concat( 'insert into stat_1_table_buf(dt, agrm_id, vg_id, agent_id, agent_type, agent_descr, volume, volume_in, volume_out, amount)'
                                , ' select date_format(timefrom, "%Y%m%d%H0000"),',agrmid,',',vgidcurr,',',agentid,',',agenttype,',"',agentdescr,'",sum(cin+cout),sum(cin),sum(cout),sum(amount)'
                                , ' from ', tabname
                                , ' where vg_id = ', vgidcurr
                                , ' and timeto >= "', datfromdate, '"'
                                , ' and timeto < "', dattodate, '"'
                                , ' group by date_format(timefrom, "%Y%m%d%H0000")'
                                );
                 prepare stmt from @s;
                 execute stmt;
                 deallocate prepare stmt;
               end if;
            end if;
          else
            set done = 0;
            open tab_name;
            fetch tab_name into tabname;
            while not done do
              set @s = concat( 'insert into stat_1_table_buf(dt, vg_id, agent_id, agent_type, agent_descr, duration, volume, volume_in, volume_out, amount)'
                             , 'select date_format(timefrom, "%Y%m%d%H0000"),',vgidcurr,',',agentid,',',agenttype,',"',agentdescr
                             ,'",sum(unix_timestamp(timeto)-unix_timestamp(timefrom)),sum(cin+cout),sum(cin),sum(cout),sum(amount)'
                             , ' from ', tabname
                             , ' where vg_id = ',vgidcurr
                             , ' and timeto >= "',datfromdate,'"'
                             , ' and timeto < "',dattodate, '"'
                             , ' group by date_format(timefrom, "%Y%m%d%H0000")'
                             );
              prepare stmt from @s;
              execute stmt;
              deallocate prepare stmt;
              set done = 0;
              fetch tab_name into tabname;
            end while;
            close tab_name;
          end if;
        elseif  agenttype in (7,8,9,10,11,12) then
          if ( repdetail <> 2 ) then
            set @s = concat( 'insert into stat_1_table_buf(dt, vg_id, agent_id, agent_type, agent_descr, volume, volume_in, volume_out, amount, cnt_in, cnt_out)'
                           , ' select date_format(timefrom, "%Y%m%d%H0000"),',vgidcurr,',',agentid,',',agenttype,',"',agentdescr,'",sum(cin+cout),sum(cin),sum(cout),sum(amount),sum(cntin),sum(cntout)'
                           , ' from day where vg_id = ',vgidcurr
                           , ' and timefrom >= "',datfromdate,'"'
                           , ' and timefrom < "',dattodate, '"'
                           , ' and id = ', agentid
                           , ' group by date_format(timefrom, "%Y%m%d%H0000")'
                           );
            prepare stmt from @s;
            execute stmt;
            deallocate prepare stmt;

            if date(tabtodate) >= date(now()) then
               select table_name into tabname
               from information_schema.tables
               where table_schema=database() and table_name = concat('tel',lpad(agentid,3,'0'),date_format(now(), '%Y%m%d'));
               if ( tabname > 'tel')  then
                   set @s = concat( 'insert into stat_1_table_buf(dt, vg_id, agent_id, agent_type, agent_descr, volume, volume_in, cnt_in, amount)'
                                 , ' select date_format(timefrom, "%Y%m%d%H0000"),',vgidcurr,',',agentid,',',agenttype,',"',agentdescr,'",sum(duration),sum(duration),count(*),sum(amount)'
                                 , ' from ', tabname
                                 , ' where vg_id = ',vgidcurr,' and direction = 0'
                                 , ' and timefrom >= "', datfromdate, '" and   timefrom < "', dattodate
                                 , '" group by date_format(timefrom, "%Y%m%d%H0000")'
                                 );
                  prepare stmt from @s;
                  execute stmt;
                  deallocate prepare stmt;
                  set @s = concat( 'insert into stat_1_table_buf(dt, vg_id, agent_id, agent_type, agent_descr, volume, volume_out, cnt_out, amount)'
                                 , ' select date_format(timefrom, "%Y%m%d%H0000"),',vgidcurr,',',agentid,',',agenttype,',"',agentdescr,'",sum(duration),sum(duration),count(*),sum(amount)'
                                 , ' from ', tabname
                                 , ' where vg_id = ',vgidcurr,' and direction = 1'
                                 , ' and   timefrom >= "',datfromdate,'" and timefrom < "',dattodate
                                 ,'" group by date_format(timefrom, "%Y%m%d%H0000")'
                                 );
                  prepare stmt from @s;
                  execute stmt;
                  deallocate prepare stmt;
               end if;
            end if;
          else
            set done = 0;
            open tab_name;
            fetch tab_name into tabname;
            while not done do
              set @s = concat( 'insert into stat_1_table_buf(dt, vg_id, agent_id, agent_type, agent_descr, volume, volume_in, cnt_in, amount)'
                             , ' select date_format(timefrom, "%Y%m%d%H0000"),',vgidcurr,',',agentid,',',agenttype,',"',agentdescr,'",sum(duration),sum(duration),count(*),sum(amount)'
                             , ' from ', tabname
                             , ' where vg_id = ',vgidcurr,' and direction = 0'
                             , ' and timefrom >= "', datfromdate, '" and   timefrom < "', dattodate
                             , '" group by date_format(timefrom, "%Y%m%d%H0000")'
                             );
              prepare stmt from @s;
              execute stmt;
              deallocate prepare stmt;
              set @s = concat( 'insert into stat_1_table_buf(dt, vg_id, agent_id, agent_type, agent_descr, volume, volume_out, cnt_out, amount)'
                             , ' select date_format(timefrom, "%Y%m%d%H0000"),',vgidcurr,',',agentid,',',agenttype,',"',agentdescr,'",sum(duration),sum(duration),count(*),sum(amount)'
                             , ' from ', tabname
                             , ' where vg_id = ',vgidcurr,' and direction = 1'
                             , ' and   timefrom >= "',datfromdate,'" and timefrom < "',dattodate
                             ,'" group by date_format(timefrom, "%Y%m%d%H0000")'
                             );
              prepare stmt from @s;
              execute stmt;
              deallocate prepare stmt;
              set done = 0;
              fetch tab_name into tabname;
            end while;
            close tab_name;
          end if;
        else
          call ERROR_INVALID_AGENT_TYPE(agenttype);
        end if;
        set done = 0;
      end if;
    end if;
    if @safe then
      set @s = concat('insert into stat_1_table_buf select * from safe_stat_1_table_buf where vg_id = ', vgidcurr);
      prepare stmt from @s;
      execute stmt;
      deallocate prepare stmt;
    end if;
    set done = 0;
    fetch vgrs into vgidcurr,agrmid,agentid,agenttype;
  end while;
  close vgrs;

  call `MAKE_TMP_TABLES`(1,1,0,1,1,0,0);
  

  update stat_1_table_buf stb join settings_tmp stmp on stb.agent_id=stmp.id
  set stb.volume=ROUND((stb.volume/POW(stmp.multiply,2)),3),
      stb.volume_in=ROUND((stb.volume_in/POW(stmp.multiply,2)),3),
      stb.volume_out=ROUND((stb.volume_out/POW(stmp.multiply,2)),3)
  where stb.agent_type in (1,2,3,4,5,6);

  update stat_1_table_buf sf, vgroups_tmp v
  set sf.agrm_id = v.agrm_id
  where sf.vg_id = v.vg_id;
  update stat_1_table_buf sf, currency_tmp c, agreements_tmp ag, settings_tmp s
  set sf.agent_descr = s.descr, sf.curr_symbol = c.symbol
  where sf.agrm_id = ag.agrm_id and sf.agent_id = s.id and ag.cur_id = c.id;

  if ( 1 = repdetail ) then
    insert into stat_1_table(dt,agrm_id,vg_id,agent_id,agent_type,agent_descr,curr_symbol,duration,volume,volume_in,volume_out,cnt_in,cnt_out,amount)
    select dt, agrm_id, vg_id, agent_id, agent_type, agent_descr, curr_symbol, sum(duration), sum(volume), sum(volume_in), sum(volume_out), sum(cnt_in), sum(cnt_out), round(sum(amount),2)
    from stat_1_table_buf
     group by agrm_id, vg_id, agent_id, agent_type, agent_descr, curr_symbol, date_format(dt, "%Y%m%d");
  elseif ( 2 = repdetail ) then
    insert into stat_1_table(dt,agrm_id,vg_id,agent_id,agent_type,agent_descr,curr_symbol,duration,volume,volume_in,volume_out,cnt_in,cnt_out,amount)
    select dt, agrm_id, vg_id, agent_id, agent_type, agent_descr, curr_symbol, sum(duration), sum(volume), sum(volume_in), sum(volume_out), sum(cnt_in), sum(cnt_out), round(sum(amount),2)
    from stat_1_table_buf
    group by agrm_id, vg_id, agent_id, agent_type, agent_descr, curr_symbol, date_format(dt, "%Y%m%d%H");
  elseif ( 3 = repdetail ) then
    insert into stat_1_table(dt,agrm_id,vg_id,agent_id,agent_type,agent_descr,curr_symbol,duration,volume,volume_in,volume_out,cnt_in,cnt_out,amount)
    select dt, agrm_id, vg_id, agent_id, agent_type, agent_descr, curr_symbol, sum(duration), sum(volume), sum(volume_in), sum(volume_out), sum(cnt_in), sum(cnt_out), round(sum(amount),2)
    from stat_1_table_buf
    group by agrm_id, vg_id, agent_id, agent_type, agent_descr, curr_symbol, date_format(dt, "%Y%m%");
  else
    insert into stat_1_table(agrm_id,vg_id,agent_id,agent_type,agent_descr,curr_symbol,duration,volume,volume_in,volume_out,cnt_in,cnt_out,amount)
    select agrm_id, vg_id, agent_id,agent_type,agent_descr,curr_symbol,sum(duration),sum(volume),sum(volume_in),sum(volume_out),sum(cnt_in), sum(cnt_out), round(sum(amount),2)
    from stat_1_table_buf
    group by agrm_id, vg_id, agent_id, agent_type, agent_descr, curr_symbol;
  end if;

  select count(1) from stat_1_table into @cnt;
  update stat_1_table set total = @cnt;
end */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE stat_21_proc
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `stat_21_proc` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `stat_21_proc`()
    SQL SECURITY INVOKER
begin
  declare v_tab_name varchar(64);
  declare done, v_istemplate, v_count, v_stlim, v_pgnum, v_pgsizem, v_agentid int(11) default 0;
  declare v_vglogin, v_acc_name, v_agrmnum, v_ani, v_fullsearch, v_match, v_status, v_nas, v_sort_field, v_sort_order, v_ip, v_prefix varchar(255);
  declare v_start_date, v_end_date date;
  declare auth_tab_cur cursor for select table_name from information_schema.tables
                                  where table_schema=database()
                                  and table_name like concat('auth_hist', lpad(v_agentid, 3, '0'), '________')
                                  and substring(table_name, 13) >= date_format(v_start_date, "%Y%m%d")
                                  and substring(table_name, 13) <= date_format(if(v_end_date,v_end_date,"99991231"), "%Y%m%d");
  declare rad_tab_cur cursor for select table_name from information_schema.tables
                                  where table_schema=database()
                                  and table_name like concat(v_prefix, '___________')
                                  and table_name <> concat(v_prefix, 'NNNYYYYmmdd')
                                  and substring(table_name, 7)>=date_format(v_start_date, "%Y%m%d")
                                  and substring(table_name, 7)<date_format(v_end_date, "%Y%m%d");
  declare continue handler for not found set done = 1;

  select date_format(val, '%Y-%m-%d') into v_start_date from `filter` where name = 'dtfrom';
  select date_format(val, '%Y-%m-%d') into v_end_date   from `filter` where name = 'dtto';
  if date_format(v_end_date, '%Y-%m-%d 00:00:00')<(select date_format(val, '%Y-%m-%d %H:%i:%s') from `filter` where name = 'dtto')
    then
       set v_end_date = v_end_date + interval 1 day;
  end if;

  drop temporary table if exists stat_21_table_buf;
  create temporary table stat_21_table_buf(
    `dt` datetime DEFAULT NULL,
    `vg_id` int(11) unsigned DEFAULT NULL,
    `result` int(11) unsigned DEFAULT NULL,
    `comment` varchar(255) DEFAULT NULL,
    `nas_id` int(11) unsigned DEFAULT NULL,
    `session_id` varchar(255) DEFAULT NULL,
    `ip` binary(16) DEFAULT NULL,
    `nas_ip` binary(16) DEFAULT NULL,
    `mac` varchar(255) DEFAULT NULL,
    `vg_login` varchar(255) default null,
    `id` int(11) default null,
    `duration` int(255) default 0,
    `attrs` varchar(255) default '',
    key `vgid` (`vg_id`),
    key `sess` (`session_id`),
    key `res` (`result`),
    key `nas` (`nas_id`)
  ) ENGINE=MyISAM DEFAULT CHARSET=utf8;


  select val from filter where name = 'status' limit 1 into v_status;
  select val from filter where name = 'ani' limit 1 into v_ani;
  select val from filter where name = 'search_match' limit 1 into v_match;
  select val from filter where name = 'nas_ids' limit 1 into v_nas;
  select val from filter where name = 'sort_field' limit 1 into v_sort_field;
  select val from filter where name = 'sort_order' limit 1 into v_sort_order;
  select val from filter where name = 'ip' limit 1 into v_ip;
  select val from filter where name = 'vg_login' limit 1 into v_vglogin;
  select val from filter where name = 'agent_id' limit 1 into v_agentid;
  select count(*) from vgids into v_count;
  select prefix into v_prefix from settings s join agent_types t on s.type = t.record_id where s.id = v_agentid;

  set done = 0;
  open auth_tab_cur;
  fetch auth_tab_cur into v_tab_name;
  while not done do
    set @s = concat('insert into stat_21_table_buf(dt, vg_id, result, comment, nas_id, session_id, ip, mac, attrs, nas_ip, vg_login)
                     select dt, vg_id, result, comment, nas_id, session_id, ip, mac, attrs, nas_ip, vg_login from ', v_tab_name, ' t'
                   , if(v_count > 1, ' join vgids using(vg_id)','')
                   , ' where 1 = 1'
                   , if(v_start_date > 0, concat(" and dt >= '", v_start_date, " 00:00:00'"), '')
                   , if(v_end_date > 0, concat(" and dt < '", v_end_date, " 00:00:00'"), '')
                   , case lower(ifnull(v_status, 'all'))
                        when '' then ''
                        when 'all' then ''
                        when 'err' then ' and result > 0'
                        when 'ok' then ' and result = 0'
                        else concat(' and result = ',v_status)
                      end
                   , if(v_count = 1
                       , concat(' and vg_id = ', (select vg_id from vgids))
                       , ''
                       )
                   , ifnull( concat(' and mac like '
                                   , if( v_match=0
                                       , concat('"', v_ani ,'"')
                                       , concat('"%', v_ani ,'%"')
                                       )
                                   )
                           , ''
                           )
                   , ifnull( concat(' and nas_id in (', v_nas,')')
                           , ''
                           )
                   , ifnull( concat(' and vg_login like '
                                   , if( v_match=0
                                       , concat('"', v_vglogin ,'"')
                                       , concat('"%', v_vglogin ,'%"')
                                       )
                                   )
                           , ''
                           )
                   );
    prepare stmt from @s;execute stmt;deallocate prepare stmt;
    set done = 0;
    fetch auth_tab_cur into v_tab_name;
  end while;
  close auth_tab_cur;

  open rad_tab_cur;
  set done = 0;
  fetch rad_tab_cur into v_tab_name;
  while not done do
    set @stat = concat( 'update  stat_21_table_buf t join '
                      , v_tab_name
                      , ' r on r.vg_id = t.vg_id and r.session_id = t.session_id'
                      , ' set t.duration = r.duration'
                      , ' where 1=1'
                      , ifnull(concat(' and hex(r.ip) like concat("%", conv(inet_aton("', v_ip, '"), 10, 16), "%")'), '')
                      );
    prepare stmt from @stat;execute stmt;deallocate prepare stmt;
    set done = 0;
    fetch rad_tab_cur into v_tab_name;
  end while;
  close rad_tab_cur;

  drop temporary table if exists stat_21_table;
  set @s = concat( 'create temporary table stat_21_table select * from stat_21_table_buf '
                 , ifnull(concat(' where hex(ip) like concat("%", conv(inet_aton("', v_ip, '"), 10, 16), "%")'), '')
                 , if( ifnull(v_sort_field, '') <> ''
                     , concat(' order by '
                            , v_sort_field
                            , ' '
                            , ifnull(v_sort_order, '')
                            )
                     , ''
                     )
                 );
  prepare stmt from @s;execute stmt;deallocate prepare stmt;
end */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE STAT_24_PROC
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `STAT_24_PROC` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `STAT_24_PROC`()
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Подготовка таблички со списком модификаторов тарифов.'
begin
    declare datfromdate varchar(32);
    declare dattodate varchar(32);
    declare vgid int default 0;
    declare modname varchar(255);

    drop temporary table if exists `stat_24_table`;
    create temporary table stat_24_table(    `record_id`     int(11)  COMMENT 'Идентификатор записи',
                                            `name`            char(64) COMMENT 'код модификатора',
                                            `tar_id`        int(11) COMMENT 'Идентификатор тарифа',
                                            `vg_id`            int(11) COMMENT 'Идентификатор у.з.',
                                            `agrm_id`        int(11) COMMENT 'Идентификатор договора',
                                            `timefrom`        datetime COMMENT 'Начало действия модификатора',
                                            `timeto`        datetime COMMENT 'Окончание действия модификатора',
                                            `rent`            decimal(20,6) COMMENT 'ап по тарифу',
                                            `rate`            decimal(20,6) default NULL COMMENT 'процент скидки. если not null, то используем его, иначе абс. значения',
                                            `newrent`        decimal(20,6) COMMENT 'ап с учетом модификатора',
                                            `vglogin`        char(64) COMMENT 'логин у.з.',
                                            `agrmnum`        char(64) COMMENT 'номер договора',
                                            `tarname`        char(64) COMMENT 'название тарифа',
                                            key `tar_id`    (`tar_id`    ),
                                            key `vg_id`        (`vg_id`    )                                
                                            );
                                        
    select ifnull(date_format(val, '%Y%m%d%H%i%s'),'1970-01-01 00:00:00') into datfromdate    from filter where name = 'dtfrom'        ;
    select ifnull(date_format(val, '%Y%m%d%H%i%s'),'9999-12-31 23:59:59') into dattodate        from filter where name = 'dtto'            ;
    select val                                into vgid        from filter where name = 'vgid'            ;
    select val                                into modname        from filter where name = 'name'            ;

    set @adds = '';
    if    (modname <> '')    then set @adds = concat(@adds, ' and m.name = ',        modname    );        end if;
    if    (vgid)            then set @adds = concat(@adds, ' and m.vg_id = ',        vgid    );        end if;

    set @s = concat('insert into stat_24_table(`record_id`,`name`,`tar_id`,`vg_id`,`timefrom`,`timeto`,`rate`)',
        ' select `record_id`,`name`,`tar_id`,`vg_id`,`timefrom`,`timeto`,`rate`',
        ' from `tariff_modifiers` `m`',
        ' where tar_id > 0 ',
        
        @adds,
        ' order by vg_id, timefrom');

    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;
    
    call `MAKE_TMP_TABLES`(1,1,0,0,0,1,0);
    
    
    update stat_24_table st join vgroups_tmp v using(vg_id) set st.vglogin = v.login, st.agrm_id = v.agrm_id;
    update stat_24_table st join tarifs_tmp t using(tar_id) set st.tarname  = t.descr, st.rent = t.rent, st.newrent = t.rent * st.rate;
    update stat_24_table st join agreements_tmp a using(agrm_id) set st.agrmnum  = a.number;
    update stat_24_table st set name = 'Индивидуальная скидка' where name = '' or name is NULL;

end */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE STAT_4AGR
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `STAT_4AGR` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`billing`@`localhost`*/ /*!50003 PROCEDURE `STAT_4AGR`( IN in_repn int(11)
                            , IN in_repd int(11)
                            , IN in_fromtab varchar(64)
                            , IN in_totab varchar(64)
                            )
    MODIFIES SQL DATA
    COMMENT 'Агрегирование данных из временной статитики в результирующую таблицу'
begin
  declare v_date_expr varchar(255);
  declare to_date_expr varchar(255);
  declare valsums_def varchar(255);
  declare sums_def varchar(255);
  declare vals varchar(255);
  declare tab varchar(12);

  select tab_prefix from meta$stat_params where rep_num=in_repn and rep_detail=in_repd into tab;
  set to_date_expr = case
                       when tab='rad' then 'dt'
                       when tab='user' then 'dt'
                       when tab='tel' then 'timefrom'
                       when tab='usl' then 'dt'
                       when tab='rent' then 'period'
                       when tab='bal' then 'dt'
                       else 'timefrom'
                     end;
  set v_date_expr = case
                      when in_fromtab in ('rent', 'usbox', 'servs') then 'period'
                      when in_fromtab like 'rad%' then 'timefrom'
                      when in_fromtab like 'user%' then 'timefrom'
                      when in_fromtab like 'tel%' then 'timefrom'
                      when in_fromtab like '%_buf' then to_date_expr
                      when in_fromtab like 'bal%' then 'date'
                      else 'timefrom'
                    end;

  if in_fromtab='stat_9_table_buf1' then set valsums_def = (select val_sums from meta$stat_params where rep_num=9 and rep_detail='9'); end if;
  if in_fromtab='stat_9_table_buf1' then set sums_def = (select sums from meta$stat_params where rep_num=9 and rep_detail='9'); end if;

  select concat( 'insert into ', in_totab,'(agent_id'
    , if(ifnull(f.vals, '') = '', '', concat(', ', f.vals)), if(valsums_def<>'', concat(', ',valsums_def), if(ifnull(f.val_sums, '') = '', '', concat(', ', f.val_sums)))
    , ', ',to_date_expr, ') select agent_id'
    , if(f.selected_4agr<>'', concat(', ', f. selected_4agr), if(ifnull(f.selected, '') = '', '', concat(', ', f.selected)))
    , if(sums_def<>'', concat(', ',sums_def), if(f.sums_4agr<>'', concat(', ', f.sums_4agr), if(ifnull(f.sums, '') = '', '', concat(', ', f.sums))))
    , concat(', ', v_date_expr)
    , concat(' from ', in_fromtab)
    , if(in_fromtab='stat_9_table_buf',concat(' where direction = ?'),'')
    , if(ifnull(f.sums, '') like '%sum%' or (f.detail_date is not null and f.detail_date<>0) or f.groupby_4agr<>''
        , concat(' group by ', if(ifnull(f.groupby_4agr, '') = '', if(ifnull(f.groupby, '') = '', '1', f.groupby), f.groupby_4agr)
          , if(ifnull(f.detail_date, '')  = '' or ifnull(f.detail_date, '') = 0, '', concat(' ,' , v_date_expr)))
        , ''
      )
    , if(ifnull(f.orderby, '') = '', '', concat(' order by ', f.orderby))
  ) into @sql
  from meta$stat_params f where ifnull(rep_detail, in_repd) = in_repd and rep_num = in_repn;
  if in_fromtab='stat_9_table_buf'
    then
      call stat_str_replace(1,'select','_new','_in');
      prepare stmt from @sql_r;set @a='0';execute stmt using @a;deallocate prepare stmt;
      call stat_str_replace(1,'select','_new','_out');
      prepare stmt from @sql_r;set @a='1';execute stmt using @a;deallocate prepare stmt;
    else
      prepare stmt from @sql;execute stmt;deallocate prepare stmt;
  end if;
end */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE STAT_9_PROC
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `STAT_9_PROC` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `STAT_9_PROC`()
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Подготовка таблички с телефонной статистикой (админской)'
begin
	declare done int default 0;
	declare tab varchar(64);
	declare tabfromdate varchar(32);
	declare tabtodate varchar(32);
	declare datfromdate varchar(32);
	declare dattodate varchar(32);
	declare cdate varchar(32);
	declare userid int default 0;
	declare vgid int default 0;
	declare vgidcurr int default 0;
	declare tabname varchar(255);
	declare srcip	 varchar(32);
	declare dstip	varchar(32);
	declare vglogin varchar(255);
	declare login varchar(255);
	declare username varchar(255);
	declare agrmnum varchar(255);
	declare numfrom varchar(255);
	declare numto varchar(255);

	declare amountfrom decimal(20,6) default 0;
	declare amountto decimal(20,6) default 0;
	declare durfrom int default 0;
	declare durto int default 0;
	declare dir int default 0;
	declare operid int default 0;

	declare repdetail int;
	declare agentid int;
	declare agenttype int;
	declare agrmid int;
	declare port int;
	declare proto int;

	declare tab_name cursor for select table_name from information_schema.tables where table_schema=database() and table_name >= concat('tel',lpad(agentid,3,'0'),tabfromdate)  and table_name <= concat('tel',lpad(agentid,3,'0'),tabtodate);

	declare continue handler for not found set done=1;

	drop temporary table if exists `stat_9_table`;
	create temporary table stat_9_table(oper_id int default 0,
										agrm_id int default 0,
										vg_id int default 0,
										agent_id int default 0,
										timefrom datetime default 0,
										duration_in int default 0,
										duration_round_in int default 0,
										duration_out int default 0,
										duration_round_out int default 0,
										curr_id int default 0,
										numfrom varchar(255) default '',
										numto varchar(255) default '',
										tar_id int default 0,
										cat_idx int default 0,
										tar_descr varchar(255) default '',
										cat_descr varchar(255) default '',
										oper_descr varchar(255) default '',
										agent_descr varchar(255) default '',
										amount_in decimal(20,6) default 0,
										amount_out decimal(20,6) default 0,
										curr_symbol varchar(255) default '',
										user_name varchar(255) default '',
										agrm_num varchar(255) default '',
										vg_login varchar(255) default '',
										cnt_in int default 0,
										cnt_out int default 0,
										direction int default 0,
										trunk_out varchar(255) default '',
										trunk_in varchar(255) default '',
										cause int(11) default 0,
										class varchar(255) default '',
										zone_id int(11) default 0,
										c_date date default '0000-00-00');

	drop temporary table if exists `stat_9_table_buf`;
	create temporary table stat_9_table_buf like stat_9_table;

	select ifnull(date_format(val, '%Y%m%d%H%i%s'),'1970-01-01 00:00:00') into datfromdate	from filter where name = 'dtfrom'		;
	select ifnull(date_format(val, '%Y%m%d%H%i%s'),'9999-12-31 23:59:59') into dattodate		from filter where name = 'dtto'			;
	select ifnull(date_format(val, '%Y%m%d'),'1970-01-01')                into tabfromdate	from filter where name = 'dtfrom'		;
	select ifnull(date_format(val, '%Y%m%d'),'9999-12-31')                into tabtodate		from filter where name = 'dtto'			;
	select val								into vgid			from filter where name = 'vgid'			;
	select val								into userid			from filter where name = 'userid'		;
	select val								into repdetail		from filter where name = 'repdetail'	;
	select val								into agentid		from filter where name = 'agentid'		;
	select val								into numfrom		from filter where name = 'numfrom'		;
	select val								into numto			from filter where name = 'numto'		;
	select val								into amountfrom		from filter where name = 'amountfrom'	;
	select val								into amountto		from filter where name = 'amountto'		;
	select val								into durfrom		from filter where name = 'durfrom'		;
	select val								into durto			from filter where name = 'durto'		;
	select val								into dir			from filter where name = 'direction'	;
	select val								into operid			from filter where name = 'operid'		;
	select val								into cdate			from filter where name = 'c_date'		;

	set @adds = '';

	if		dir = 1		then set @adds = concat(@adds, ' and st.direction = 0');
	elseif 	dir = 2		then set @adds = concat(@adds, ' and st.direction = 1');
	end if;

	if numfrom <> ''	then set @adds = concat(@adds, ' and st.numfrom regexp "', numfrom, '"');	end if;
	if numto <> ''		then set @adds = concat(@adds, ' and st.numto regexp "',	numto, '"');	end if;
	if amountfrom <> 0	then set @adds = concat(@adds, ' and st.amount >=',		amountfrom);	end if;
	if amountto <> 0	then set @adds = concat(@adds, ' and st.amount <',		amountto);		end if;
	if durfrom			then set @adds = concat(@adds, ' and st.duration >=',		durfrom);		end if;
	if durto			then set @adds = concat(@adds, ' and st.duration <',		durto);			end if;
	if cdate			then set @adds = concat(@adds, ' and st.c_date ="',		cdate, '"');			end if;



	select distinct ifnull(type,0) into agenttype from settings where id = agentid;
	set done = 0;
	open tab_name;
	fetch tab_name into tabname;

	while not done do
 		if	repdetail = 1 then
			
			set @s = concat('insert into stat_9_table_buf(timefrom, oper_id, agrm_id, agent_id, duration_in, duration_round_in, amount_in, cnt_in, c_date)',
				' select date_format(st.timefrom, "%Y%m%d%H0000"), st.oper_id, st.agrm_id, ',agentid,',sum(st.duration),sum(st.duration_round),sum(st.amount),count(*),st.c_date',
				' from ', tabname, ' st join vgids using (agrm_id)',
				' where st.timefrom >= "', datfromdate, '"',
				' and   st.timefrom < "', dattodate, '"',
				' and	st.direction = 0',
				@adds,
				' group by st.oper_id, st.agrm_id, date_format(st.timefrom, "%Y%m%d%H0000"), st.c_date');
			prepare stmt from @s;
			execute stmt;
			deallocate prepare stmt;
			set @s = concat('insert into stat_9_table_buf(timefrom, oper_id, agrm_id, agent_id, duration_out, duration_round_out, amount_out, cnt_out, c_date)',
				' select date_format(st.timefrom, "%Y%m%d%H0000"), st.oper_id, st.agrm_id, ',agentid,',sum(st.duration),sum(st.duration_round),sum(st.amount),count(*),st.c_date',
				' from ', tabname, ' st join vgids using (agrm_id)',
				' where st.timefrom >= "', datfromdate, '"',
				' and   st.timefrom < "', dattodate, '"',
				' and	st.direction = 1',
				@adds,
				' group by  st.oper_id, st.agrm_id, date_format(st.timefrom, "%Y%m%d%H0000"), st.c_date');
			prepare stmt from @s;
			execute stmt;
			deallocate prepare stmt;
		elseif	repdetail = 2 then
			
			set @s = concat('insert into stat_9_table_buf(timefrom, oper_id, agrm_id, agent_id, duration_in,	duration_round_in,		amount_in,				cnt_in, c_date)',
				' select date_format(st.timefrom, "%Y%m%d000000"), st.oper_id, st.agrm_id,',agentid,',sum(st.duration),sum(st.duration_round),sum(st.amount),count(*),st.c_date',
				' from ', tabname, ' st join vgids using (agrm_id)',
				' where st.timefrom >= "', datfromdate, '"',
				' and   st.timefrom < "', dattodate, '"',
				' and	st.direction = 0',
				@adds,
				' group by st.oper_id, st.agrm_id, date_format(st.timefrom, "%Y%m%d000000"), st.c_date');
			prepare stmt from @s;
			execute stmt;
			deallocate prepare stmt;
			set @s = concat('insert into stat_9_table_buf(timefrom, oper_id, agrm_id, agent_id, duration_out, duration_round_out,	amount_out, cnt_out, c_date)',
				' select date_format(st.timefrom, "%Y%m%d000000"), st.oper_id, st.agrm_id,',agentid,',sum(st.duration),sum(st.duration_round),sum(st.amount),count(*),st.c_date',
				' from ', tabname, ' st join vgids using (agrm_id)',
				' where st.timefrom >= "', datfromdate, '"',
				' and   st.timefrom < "', dattodate, '"',
				' and	st.direction = 1',
				@adds,
				' group by st.oper_id, st.agrm_id, date_format(st.timefrom, "%Y%m%d000000"), st.c_date');
			prepare stmt from @s;
			execute stmt;
			deallocate prepare stmt;
		elseif	repdetail = 3 then
			
			set @s = concat('insert into stat_9_table_buf(oper_id, agrm_id, vg_id, agent_id, duration_in, duration_round_in, amount_in,	cnt_in, c_date)',
				' select st.oper_id, st.agrm_id, st.vg_id,',agentid,',sum(st.duration),sum(st.duration_round),sum(st.amount),count(*), st.c_date',
				' from ', tabname, ' st join vgids using (agrm_id)',
				' where st.timefrom >= "', datfromdate, '"',
				' and   st.timefrom < "', dattodate, '"',
				' and	st.direction = 0',
				@adds,
				' group by st.oper_id, st.agrm_id, st.vg_id, st.c_date');
			prepare stmt from @s;
			execute stmt;
			deallocate prepare stmt;
			set @s = concat('insert into stat_9_table_buf(oper_id, agrm_id, vg_id, agent_id, duration_out, duration_round_out, amount_out, cnt_out, c_date)',
				' select st.oper_id, st.agrm_id, st.vg_id,',agentid,',sum(st.duration),sum(st.duration_round),sum(st.amount),count(*), st.c_date',
				' from ', tabname, ' st join vgids using (agrm_id)',
				' where st.timefrom >= "', datfromdate, '"',
				' and   st.timefrom < "', dattodate, '"',
				' and	st.direction = 1',
				@adds,
				' group by st.oper_id, st.agrm_id,  st.vg_id, st.c_date');
			prepare stmt from @s;
			execute stmt;
			deallocate prepare stmt;
		else
		 
			if operid > -1 then set @adds = concat(@adds, ' and st.oper_id = ', operid); end if;

			
			if vgid > 0 then
				set @JOINUSING = 'vg_id';
			else
				set @JOINUSING = 'agrm_id';
			end if;
			
			set @s = concat('insert into stat_9_table_buf(oper_id, agrm_id, vg_id, agent_id, timefrom, duration_in, duration_round_in, numfrom, numto, tar_id, cat_idx, cat_descr, amount_in, direction,trunk_out,trunk_in, cause, zone_id, c_date)',
				' select st.oper_id, st.agrm_id,st.vg_id,',agentid,',st.timefrom,st.duration,st.duration_round,st.numfrom,st.numto,st.tar_id,st.cat_idx,"",round(st.amount,2),st.direction,st.trunk_out,st.trunk_in,st.cause,st.zone_id,st.c_date',
				' from ', tabname, ' st join vgids using (',@JOINUSING,')',
				' where st.timefrom >= "', datfromdate, '"',
				' and   st.timefrom < "', dattodate, '"',
				' and   st.direction = 0',
				@adds                   );
			
			prepare stmt from @s;
			execute stmt;
			deallocate prepare stmt;
			
			set @s = concat('insert into stat_9_table_buf(oper_id, agrm_id, vg_id, agent_id, timefrom, duration_out, duration_round_out, numfrom, numto, tar_id, cat_idx, cat_descr, amount_out, direction,trunk_out,trunk_in, cause, zone_id, c_date)',
				' select st.oper_id, st.agrm_id,st.vg_id,',agentid,',st.timefrom,st.duration,st.duration_round,st.numfrom,st.numto,st.tar_id,st.cat_idx,"",round(st.amount,2),st.direction,st.trunk_out,st.trunk_in,st.cause,st.zone_id,st.c_date',
				' from ', tabname, ' st join vgids using (',@JOINUSING,')',
				' where st.timefrom >= "', datfromdate, '"',
				' and   st.timefrom < "', dattodate, '"',
				' and   st.direction = 1',
				@adds                   );
			prepare stmt from @s;
			execute stmt;
			deallocate prepare stmt;
						
		end if;

		set done = 0;
		fetch tab_name into tabname;
		
	end while;
	close tab_name;

	if @safe then
		insert into stat_9_table_buf select * from safe_stat_9_table_buf;
	end if;

	call `MAKE_TMP_TABLES`(1,1,1,1,1,1,1);
	


	update stat_9_table_buf sf, currency_tmp c, agreements_tmp ag, settings_tmp s	set sf.agrm_num		= ag.number, sf.agent_descr = s.descr, sf.curr_symbol = c.symbol, sf.curr_id = c.id	where sf.agrm_id	= ag.agrm_id 	and sf.agent_id = s.id		and ag.cur_id	= c.id		;
	update stat_9_table_buf sf, vgroups_tmp v, agreements_tmp ag, accounts_tmp a	set sf.user_name	= a.name, sf.vg_login = v.login														where sf.agrm_id	= ag.agrm_id	and sf.vg_id	= v.vg_id	and ag.uid		= a.uid		;
	update stat_9_table_buf sf, tarifs_tmp t, categories_tmp c						set sf.tar_descr	= t.descr, sf.cat_descr = c.descr													where sf.tar_id		= t.tar_id		and sf.tar_id	= c.tar_id	and sf.cat_idx	= c.cat_idx	;
	update stat_9_table_buf sf, accounts_tmp o										set sf.oper_descr	= o.name																			where sf.oper_id	= o.uid																	;
	update stat_9_table_buf sf, tel_cat c, tel_classes tc							set sf.class		= tc.name																			where sf.zone_id	= c.zone_id 	and ifnull(c.class,0) = tc.id							;
	update stat_9_table_buf sf, tel_classes tc										set sf.class		= tc.name																			where sf.zone_id	= 0			 	and tc.id = 0											;

	if		repdetail = 1 then
		insert into stat_9_table(curr_id, timefrom, oper_id, curr_symbol, oper_descr, duration_in, duration_round_in, amount_in, cnt_in, duration_out, duration_round_out, amount_out, cnt_out, c_date) select curr_id, timefrom, oper_id, curr_symbol, oper_descr, sum(duration_in), sum(duration_round_in), round(sum(amount_in),2), sum(cnt_in), sum(duration_out), sum(duration_round_out), round(sum(amount_out),2), sum(cnt_out), c_date from stat_9_table_buf group by timefrom, oper_id, curr_symbol, c_date;
	elseif	repdetail = 2 then
		insert into stat_9_table(curr_id, timefrom, oper_id, curr_symbol, oper_descr, duration_in, duration_round_in, amount_in, cnt_in, duration_out, duration_round_out, amount_out, cnt_out, c_date) select curr_id, timefrom, oper_id, curr_symbol, oper_descr, sum(duration_in), sum(duration_round_in), round(sum(amount_in),2), sum(cnt_in), sum(duration_out), sum(duration_round_out), round(sum(amount_out),2), sum(cnt_out), c_date from stat_9_table_buf group by timefrom, oper_id, curr_symbol, c_date;
	elseif	repdetail = 3 then
		insert into stat_9_table(curr_id, vg_id, oper_id, curr_symbol, oper_descr, duration_in, duration_round_in, amount_in, cnt_in, duration_out, duration_round_out, amount_out, cnt_out, vg_login, user_name, agrm_num, c_date) select curr_id, vg_id, oper_id, curr_symbol, oper_descr, sum(duration_in), sum(duration_round_in), round(sum(amount_in),2), sum(cnt_in), sum(duration_out), sum(duration_round_out), round(sum(amount_out),2), sum(cnt_out), vg_login, user_name, agrm_num, c_date from stat_9_table_buf group by vg_id, oper_id, curr_symbol, c_date;
	else
		insert into stat_9_table select * from stat_9_table_buf order by timefrom;
	end if;
end */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE STAT_DETAIL_BSQUE
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `STAT_DETAIL_BSQUE` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`billing`@`localhost`*/ /*!50003 PROCEDURE `STAT_DETAIL_BSQUE`( IN in_repn int(11)
                                    , IN in_repd int(11)
                                    , IN in_dfrom datetime
                                    , IN in_dto datetime
                                    , IN in_vg_id int(11)
                                    , IN in_agent_id int(11)
                                    , IN in_fl varchar(255)
                                    , IN in_tab_prefix varchar(6)
                                    , IN in_fromtab varchar(64)
                                    , IN in_totab varchar(64)
                                    )
    MODIFIES SQL DATA
    COMMENT 'Получение детальной статистики'
begin
  declare v_date_expr varchar(255);
  declare to_date_expr varchar(255);
  declare tab varchar(12);

  select tab_prefix from meta$stat_params where rep_num=in_repn and rep_detail=in_repd into tab;
  set to_date_expr = case
                       when tab='rad' then 'dt'
                       when tab='user' then 'dt'
                       when tab='tel' then 'timefrom'
                       when tab='usl' then 'dt'
                       when tab='rent' then 'period'
                       when tab='bal' then 'dt'
                       when tab='block' then 'timefrom'
                       else 'timefrom'
                     end;
  set v_date_expr = case
                      when in_fromtab in ('rent', 'usbox', 'servs') then 'period'
                      when in_fromtab like 'rad%' then 'timefrom'
                      when in_fromtab like 'user%' then 'timefrom'
                      when in_fromtab like 'tel%' then 'timefrom'
                      when in_fromtab like '%_buf' then to_date_expr
                      when in_fromtab like 'bal%' then 'date'
                      when in_fromtab like 'block%' then 'timefrom'
                      else 'timefrom'
                    end;

  select concat( 'insert into ', in_totab,'(agent_id'
    , if(ifnull(f.vals, '') = '', '', concat(', ', f.vals)), if(ifnull(f.val_sums, '') = '', '', concat(', ', f.val_sums))
    , ', ',to_date_expr, ') select ', in_agent_id
    , if(ifnull(f.selected, '') = '', '', concat(', ', f.selected))
    , if(ifnull(f.sums, '') = '', '', concat(', ', f.sums))
    , case f.detail_date
        when 0 then concat(', date_format(', v_date_expr, ', "%Y%m%d%H%i%s")')
        when 1 then concat(', date_format(', v_date_expr, ', "%Y%m%d%H%i00")')
        when 2 then concat(', date_format(', v_date_expr, ', "%Y%m%d%H0000")')
        when 3 then concat(', date_format(', v_date_expr, ', "%Y%m%d000000")')
        when 4 then concat(', date_format(', v_date_expr, ', "%Y%m01000000")')
        when 5 then concat(', date_format(', v_date_expr, ', "%Y0101000000")')
        else ", '0000-00-00 00:00:00' "
      end
    , case in_fromtab
        when 'rent' then ' from rentcharge t'
        when 'day' then ' from day t'
        when 'bal' then ' from balances b join vgroups t  on b.agrm_id=t.agrm_id'
        when 'block' then ' from vg_blocks t join vgroups v on t.vg_id=v.vg_id  left join vg_blocks_history vbh on t.record_id=vbh.vg_blocks_id'
        when 'usbox' then ' from usbox_charge c join usbox_services t using(serv_id) join categories s on t.tar_id=s.tar_id and t.cat_idx=s.cat_idx'
        when 'servs' then ' from charges c join services t using(service_id) join service_categories s on t.tar_id=s.tar_id and t.cat_idx=s.cat_idx'
        else concat(' from ', in_fromtab, ' t')
      end
    , if(ifnull(in_vg_id, 0) <> 0, '', ' join vgids vs on t.vg_id = vs.vg_id')
    , ' where 1=1 '
    , if(in_fromtab in ('day', 'month') and ifnull(in_vg_id, 0) = 0, 'and t.id = vs.id', '')
    , if(ifnull(in_vg_id, 0) = 0, '', concat(' and t.vg_id = ', in_vg_id))
    , if(in_fromtab='block',
        concat( ' and ((',to_date_expr,' >= "', date_format(ifnull(in_dfrom,'19700101000000'), '%Y%m%d%H%i%s'), '"'
        , ' and ',to_date_expr,' < "', date_format(ifnull(in_dto,'99991231235959'), '%Y%m%d%H%i%s'), '") '
        ' or (timeto >= "', date_format(ifnull(in_dfrom,'19700101000000'), '%Y%m%d%H%i%s'), '"'
        , ' and timeto < "', date_format(ifnull(in_dto,'99991231235959'), '%Y%m%d%H%i%s'), '")) '
        )
        ,
        concat( ' and ', v_date_expr, ' >= "', date_format(ifnull(in_dfrom,'19700101000000'), '%Y%m%d%H%i%s'), '"'
        , ' and ', v_date_expr, ' < "', date_format(ifnull(in_dto,'99991231235959'), '%Y%m%d%H%i%s'), '" '
        )
      )
    , ifnull(f.static_filter, '')
    , ifnull(in_fl, '')
    , if(ifnull(f.sums, '') like '%sum%' or (f.detail_date is not null and f.detail_date<>0) or f.groupby<>''
        , concat(' group by ', if(ifnull(f.groupby, '') = '', 1, f.groupby))
        , ''
      )
    , case f.detail_date
        when 0 then ''
        when 1 then concat(', date_format(', v_date_expr, ', "%Y%m%d%H%i00")')
        when 2 then concat(', date_format(', v_date_expr, ', "%Y%m%d%H0000")')
        when 3 then concat(', date_format(', v_date_expr, ', "%Y%m%d000000")')
        when 4 then concat(', date_format(', v_date_expr, ', "%Y%m01000000")')
        when 5 then concat(', date_format(', v_date_expr, ', "%Y0101000000")')

        else ", '0000-00-00 00:00:00' "
      end
  ) into @sql from meta$stat_params f where ifnull(rep_detail, in_repd) = in_repd and rep_num = in_repn;
  if in_fromtab='servs' then
    call stat_str_replace('2','select','cat_idx','serv_cat_idx');
    prepare stmt from @sql_r;execute stmt;deallocate prepare stmt;
  else
    prepare stmt from @sql;execute stmt;deallocate prepare stmt;
  end if;
end */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE STAT_DETAIL_PROC
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `STAT_DETAIL_PROC` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`billing`@`localhost`*/ /*!50003 PROCEDURE `STAT_DETAIL_PROC`( IN in_repnum int(11)
                                   , IN in_repdet int(11)
                                   , IN in_dtfrom datetime
                                   , IN in_dtto datetime
                                   , IN in_vg_id int(11)
                                   , IN in_agent_id int(11)
                                   , IN in_flt varchar(255)
                                   , IN in_tab_prefix varchar(6)
                                   , IN in_totab varchar(64)
                                   )
begin
  declare done_tab, det_n int(1) default 0;
  declare v_sttabname, v_startday, v_endday, v_endtab, v_starttab varchar(255);
  declare tab_name cursor for
    select table_name from information_schema.tables
    where table_schema=database()
    and table_name >= concat(in_tab_prefix,lpad(in_agent_id,3,'0'),ifnull(date_format(in_dtfrom, '%Y%m%d'),'1970-01-01'))
    and table_name <= concat(in_tab_prefix,lpad(in_agent_id,3,'0'),ifnull(date_format(in_dtto, '%Y%m%d'),'9999-12-31'));
  declare continue handler for not found begin set done_tab=1; end;

  select detail_needed from meta$stat_params where rep_detail = in_repdet and rep_num = in_repnum into det_n;
  set v_startday = date_format(in_dtfrom, '%Y%m%d000000') + interval 1 day;
  set v_endday = date_format(in_dtto, '%Y%m%d000000') - interval 1 day;
  select table_name from information_schema.tables where table_schema=database() and table_name = concat(in_tab_prefix,lpad(in_agent_id,3,'0'),date_format(in_dtfrom, '%Y%m%d')) into v_starttab;
  select table_name from information_schema.tables where table_schema=database() and table_name = concat(in_tab_prefix,lpad(in_agent_id,3,'0'),date_format(in_dtto, '%Y%m%d')) into v_endtab;

  if in_tab_prefix in ('user', 'tel', 'rad')
    then
      case
        when datediff(in_dtto, in_dtfrom) < 2 or det_n = 1
          then
            set done_tab=0;
            open tab_name;
            fetch tab_name into v_sttabname;
            while done_tab<>1 do
              call stat_detail_bsque(in_repnum, in_repdet, in_dtfrom, in_dtto, in_vg_id, in_agent_id, in_flt, in_tab_prefix, v_sttabname, in_totab);
              fetch tab_name into v_sttabname;
            end while;
            close tab_name;
        when datediff(in_dtto, in_dtfrom) >=2 and det_n = 0 and in_dtfrom like '%00:00:00' and in_dtto like '%00:00:00'
          then
            call stat_detail_bsque(in_repnum, in_repdet, in_dtfrom, in_dtto, in_vg_id, in_agent_id, in_flt, in_tab_prefix, 'day', in_totab);
        when datediff(in_dtto, in_dtfrom) >=2 and det_n = 0 and in_dtfrom like '%00:00:00' and in_dtto not like '%00:00:00'
          then
            call stat_detail_bsque(in_repnum, in_repdet, in_dtfrom, v_endday, in_vg_id, in_agent_id, in_flt, in_tab_prefix, 'day', in_totab);
            if v_endtab then call stat_detail_bsque(in_repnum, in_repdet, v_endday, in_dtto, in_vg_id, in_agent_id, in_flt, in_tab_prefix, v_endtab, in_totab); end if;
        when datediff(in_dtto, in_dtfrom) >=2 and det_n = 0 and in_dtfrom not like '%00:00:00' and in_dtto like '%00:00:00'
          then
            if v_starttab then call stat_detail_bsque(in_repnum, in_repdet, in_dtfrom, v_startday, in_vg_id, in_agent_id, in_flt, in_tab_prefix, v_starttab, in_totab); end if;
            call stat_detail_bsque(in_repnum, in_repdet, v_startday, in_dtto, in_vg_id, in_agent_id, in_flt, in_tab_prefix, 'day', in_totab);
        when datediff(in_dtto, in_dtfrom) >=2 and det_n = 0 and in_dtfrom not like '%00:00:00' and in_dtto not like '%00:00:00'
          then
            if v_starttab then call stat_detail_bsque(in_repnum, in_repdet, in_dtfrom, v_startday, in_vg_id, in_agent_id, in_flt, in_tab_prefix, v_starttab, in_totab); end if;
            call stat_detail_bsque(in_repnum, in_repdet, v_endday, v_startday, in_vg_id, in_agent_id, in_flt, in_tab_prefix, 'day', in_totab);
            if v_endtab then call stat_detail_bsque(in_repnum, in_repdet, v_endday, in_dtto, in_vg_id, in_agent_id, in_flt, in_tab_prefix, v_endtab, in_totab); end if;
      end case;
    else call stat_detail_bsque(in_repnum,in_repdet,in_dtfrom, in_dtto, in_vg_id, in_agent_id, in_flt, in_tab_prefix, in_tab_prefix, in_totab);
  end if;
end */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE STAT_STR_REPLACE
