/*!50003 DROP PROCEDURE IF EXISTS `STAT_STR_REPLACE` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`billing`@`localhost`*/ /*!50003 PROCEDURE `STAT_STR_REPLACE`( IN in_pos int(2)
                                   , IN in_con varchar(25)
                                   , IN in_sfr varchar(25)
                                   , IN in_sto varchar(25)
                                   )
    MODIFIES SQL DATA
begin
  declare tmp_str1, tmp_str2, tmp_str11, tmp_str22 varchar(1000);
  if in_pos=1
    then
      set tmp_str1=SUBSTRING_INDEX(@sql, in_con, 1);
      set tmp_str2=SUBSTRING_INDEX(@sql, in_con, -1);
      set tmp_str11=replace(tmp_str1, in_sfr, in_sto);
      set @sql_r=concat(tmp_str11,in_con,tmp_str2);
  end if;
  if in_pos=2
    then
      set tmp_str1=SUBSTRING_INDEX(@sql, in_con, 1);
      set tmp_str2=SUBSTRING_INDEX(@sql, in_con, -1);
      set tmp_str22=replace(tmp_str2, in_sfr, in_sto);
      set @sql_r=concat(tmp_str1,in_con,tmp_str22);
  end if;
end */;;

