/*!50003 DROP PROCEDURE IF EXISTS `STAT_TABLE_CREATE` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`billing`@`localhost`*/ /*!50003 PROCEDURE `STAT_TABLE_CREATE`( IN in_repn int(1)
                                    , IN in_crucial int(1)
                                    , IN in_account int(1)
                                    , IN in_account_det int(1)
                                    , IN in_tarif int(1)
                                    , IN in_session int(1)
                                    , IN in_volume int(1)
                                    , IN in_fin int(1)
                                    , IN in_equipment int(1)
                                    , IN in_other int(1)
                                    , IN in_buf int(1)
                                    )
    MODIFIES SQL DATA
    COMMENT 'Создание временных таблиц для stat процедур'
begin
declare crucial_def varchar(255);
declare account_def varchar(255);
declare account_detail_def varchar(255);
declare tarif_def varchar(255);
declare session_def varchar(255);
declare session_detail_def varchar(255);
declare volume_def varchar(255);
declare fin_def varchar(255);
declare equipment_def varchar(255);

  select crucial_cols,account_cols,account_detail_cols,tarif_cols,session_cols,volume_cols,fin_cols,equipment_cols
  into crucial_def,account_def,account_detail_def,tarif_def,session_def,volume_def,fin_def,equipment_def from meta$stat_table_creator where rep_num=0;
  select concat('CREATE TEMPORARY TABLE stat_',in_repn,'_table',if(in_buf=1,'_buf',''),'('
    , case in_crucial
        when 1 then concat(crucial_cols)
        when 2 then concat(crucial_cols, if(ifnull(crucial_def,'')='','', concat(',',crucial_def)))
        when 3 then if(ifnull(crucial_def,'')='','', concat(crucial_def))
        else ''
      end
    , case in_account
        when 1 then if(ifnull(account_cols,'')='','', concat(',',account_cols))
        when 2 then concat(if(ifnull(account_cols,'')='','', concat(',',account_cols)), if(ifnull(account_def,'')='','', concat(',',account_def)))
        when 3 then if(ifnull(account_def,'')='','', concat(',',account_def))
        else ''
      end
    , case in_account_det
        when 1 then if(ifnull(account_detail_cols,'')='','', concat(',',account_detail_cols))
        when 2 then concat(if(ifnull(account_detail_cols,'')='','', concat(',',account_detail_cols)), if(ifnull(account_detail_def,'')='','', concat(',',account_detail_def)))
        when 3 then if(ifnull(account_detail_def,'')='','', concat(',',account_detail_def))
        else ''
      end
    , case in_tarif
        when 1 then if(ifnull(tarif_cols,'')='','', concat(',',tarif_cols))
        when 2 then concat(if(ifnull(tarif_cols,'')='','', concat(',',tarif_cols)), if(ifnull(tarif_def,'')='','', concat(',',tarif_def)))
        when 3 then if(ifnull(tarif_def,'')='','', concat(',',tarif_def))
        else ''
      end
    , case in_session
        when 1 then if(ifnull(session_cols,'')='','', concat(',',session_cols))
        when 2 then concat(if(ifnull(session_cols,'')='','', concat(',',session_cols)), if(ifnull(session_def,'')='','', concat(',',session_def)))
        when 3 then if(ifnull(session_def,'')='','', concat(',',session_def))
        else ''
      end
    , case in_volume
        when 1 then if(ifnull(volume_cols,'')='','', concat(',',volume_cols))
        when 2 then concat(if(ifnull(volume_cols,'')='','', concat(',',volume_cols)), if(ifnull(volume_def,'')='','', concat(',',volume_def)))
        when 3 then if(ifnull(volume_def,'')='','', concat(',',volume_def))
        else ''
      end
    , case in_fin
        when 1 then if(ifnull(fin_cols,'')='','', concat(',',fin_cols))
        when 2 then concat(if(ifnull(fin_cols,'')='','', concat(',',fin_cols)), if(ifnull(fin_def,'')='','', concat(',',fin_def)))
        when 3 then if(ifnull(fin_def,'')='','', concat(',',fin_def))
        else ''
      end
    , case in_equipment
        when 1 then if(ifnull(equipment_cols,'')='','', concat(',',equipment_cols))
        when 2 then concat(if(ifnull(equipment_cols,'')='','', concat(',',equipment_cols)), if(ifnull(equipment_def,'')='','', concat(',',equipment_def)))
        when 3 then if(ifnull(equipment_def,'')='','', concat(',',equipment_def))
        else ''
      end
    , case in_other
        when 1 then if(ifnull(other_cols,'')='',');', concat(',', other_cols, ');'))
        else ');'
      end
  ) into @s from meta$stat_table_creator where rep_num=in_repn;
  prepare stmt from @s;execute stmt;deallocate prepare stmt;
end */;;

