    MODIFIES SQL DATA
    COMMENT 'Заполнение доп.информации в stat таблице'
begin

  if tmp_va=1 then call make_tmp_tables(tmp_vg,'1','1','1',tmp_se,tmp_ta,tmp_ca); else call make_tmp_tables(tmp_vg,tmp_ag,tmp_ac,tmp_cu,tmp_se,tmp_ta,tmp_ca); end if;

  if tmp_va=1 then
    set @s = concat(
