    );
    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;
  end if;

  if tmp_ca=1 then
    set @s = concat(
    'update stat_', proc_number, '_table st,  categories_tmp t
    set st.cat_descr=t.descr where st.tar_id=t.tar_id and st.cat_idx=t.cat_idx;'
    );
    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;
  end if;

  if tmp_ag=1 then
    set @s = concat(
    'update stat_', proc_number, '_table st,  agreements_tmp t
    set st.agrm_num=t.number where st.agrm_id = t.agrm_id;'
    );
    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;
  end if;

  if tmp_vg=1 then
    set @s = concat(
    'update stat_', proc_number, '_table st, vgroups_tmp t
