    );
    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;
  end if;

  if tmp_ac=1 then
    set @s = concat(
    'update stat_', proc_number, '_table st, accounts_tmp t
    set st.user_name=t.name where st.uid=t.uid;'
    );
    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;
  end if;

  if tmp_ta=1 then
    set @s = concat(
    'update stat_', proc_number, '_table st, tarifs_tmp t
    set st.tar_descr=t.descr where st.tar_id=t.tar_id;'
    );
    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;
  end if;

  if tmp_se=1 then
    set @s = concat(
    'update stat_', proc_number, '_table st, settings_tmp t
    set st.agent_descr=t.descr where st.agent_id=t.agent_id;'
    );
    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;
  end if;

  if tmp_ot=1 then
    case proc_number
      when 2 then
        if (select val from filter where name='repdetail')=0 then
          set @s = concat('update stat_2_table st
          left join tel_cat t on st.zone_id=t.zone_id
          left join tel_classes ts on ifnull(t.class,0)=ts.id
          set st.class=ts.descr');
        end if;
      when 3 then
        set @s = concat('update stat_3_table
        set zone_descr=cat_descr');
      when 9 then
        set @s = concat('update stat_9_table st
        join accounts_tmp t on st.oper_id=t.uid
        set st.oper_descr=t.name;');
        if (select val from filter where name='repdetail')=0 then
          set @s1 = concat('update stat_9_table st
          left join tel_cat t on st.zone_id=t.zone_id
          left join tel_classes ts on ifnull(t.class,0)=ts.id
          set st.class=ts.descr');
          prepare stmt from @s1;execute stmt;deallocate prepare stmt;
        end if;
      when 12 then
        if (select val from filter where name='repdetail')=0 then
