          set st.manager_name=t.fio');
        end if;
    end case;
    prepare stmt from @s;
    execute stmt;
    deallocate prepare stmt;
  end if;
end */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE TURBO_SHAPE
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `TURBO_SHAPE` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `TURBO_SHAPE`(IN in_vgid int(11), IN in_dtime datetime, INOUT inout_cur_shape bigint(11) unsigned)
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
begin
  
    declare v_turbo_shape bigint(11) unsigned;
  declare v_servid int(11);

  SELECT shape, serv_id INTO v_turbo_shape, v_servid FROM turbo_shapes WHERE vg_id = in_vgid AND in_dtime >= timefrom AND in_dtime <= timeto order by shape desc limit 1;


  IF ( inout_cur_shape <> 0 AND v_turbo_shape > inout_cur_shape ) THEN
    IF (SELECT COUNT(1) FROM category_modifiers WHERE includes > 0 AND serv_id = v_servid  AND includes <= c_limit)
       THEN  
         UPDATE turbo_shapes         SET timeto = in_dtime WHERE serv_id = v_servid;
         UPDATE category_modifiers   SET timeto = in_dtime WHERE serv_id = v_servid;
       ELSE
         SET inout_cur_shape = v_turbo_shape;
    END IF;
  END IF;
END */;;

