BEGIN
	
	DECLARE tmp_origin_agrm_id       INTEGER;
	DECLARE tmp_origin_amount        decimal(20,6);
	DECLARE tmp_origin_comment       TEXT;
	DECLARE tmp_origin_receipt       VARCHAR(255);
	DECLARE tmp_origin_pay_date      DATETIME;
	DECLARE tmp_origin_local_date    DATETIME;
	DECLARE tmp_origin_cancel_date   DATETIME;
	DECLARE tmp_origin_period_date   DATETIME;
	DECLARE tmp_origin_status        INTEGER;
	DECLARE tmp_origin_manager_id    INTEGER;
	DECLARE tmp_origin_order_id      INTEGER;
	DECLARE tmp_origin_class_id      INTEGER;
	DECLARE tmp_origin_agrm_number   VARCHAR(64);
	DECLARE tmp_origin_amount_cur    decimal(20,6);
	DECLARE tmp_origin_amount_cur_id INTEGER;
	DECLARE tmp_origin_from_agrm_id  INTEGER;
	DECLARE tmp_origin_bso_id        INTEGER;
	
	DECLARE tmp_record_id INTEGER;
	
	DECLARE done BOOLEAN DEFAULT FALSE;
	
	DECLARE payments_history_records CURSOR FOR
		SELECT p.record_id
		FROM payments_history p
		WHERE p.origin_record_id = in_origin_record_id
		ORDER BY p.local_date_new ASC;
	
	DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;

    CALL show_msg('>>CALL update_010_payments_copy_data();');

	
	SELECT  p.agrm_id,              p.amount,           	p.comment,              p.receipt,              p.pay_date,
		    p.local_date,           p.cancel_date,          p.period_date,          p.status,               p.mod_person,
		    p.order_id,             p.class_id,             p.agrm_number,          p.amount_cur,           p.amount_cur_id,
		    p.from_agrm_id,         p.bso_id
	INTO    tmp_origin_agrm_id,     tmp_origin_amount,      tmp_origin_comment,     tmp_origin_receipt,     tmp_origin_pay_date,
            tmp_origin_local_date,  tmp_origin_cancel_date, tmp_origin_period_date, tmp_origin_status,      tmp_origin_manager_id,
            tmp_origin_order_id,    tmp_origin_class_id,    tmp_origin_agrm_number, tmp_origin_amount_cur,  tmp_origin_amount_cur_id,
		    tmp_origin_from_agrm_id,tmp_origin_bso_id
	FROM  payments p
	WHERE p.record_id = in_origin_record_id;

	
	SET done = FALSE;
	OPEN payments_history_records;
	payments_history_records_loop: LOOP
		FETCH payments_history_records INTO tmp_record_id;
		IF done THEN
			LEAVE payments_history_records_loop;
		END IF;

		
		UPDATE payments_history
		SET comment = tmp_origin_comment, receipt = tmp_origin_receipt, pay_date = tmp_origin_pay_date, local_date = tmp_origin_local_date,
			cancel_date = IF(amount = 0, local_date, NULL), cancel_date_new = IF(amount_new = 0, local_date_new, NULL),
			period_date = tmp_origin_period_date, status = IF(amount = 0, 2, 0), status_new = IF(amount_new = 0, 2, 0),
			mod_person = tmp_origin_manager_id, class_id = tmp_origin_class_id, agrm_number = tmp_origin_agrm_number,
			amount_cur_id = tmp_origin_amount_cur_id, from_agrm_id = tmp_origin_from_agrm_id, bso_id = tmp_origin_bso_id
		WHERE record_id = tmp_record_id;

		
			
			
		UPDATE payments_history SET `agrm_id_new` = `agrm_id`, `comment_new` = `comment`, `amount_cur_new` = `amount_cur`,
			`amount_new` = `amount`, `order_id_new` = `order_id`
	  WHERE record_id = tmp_record_id;

		
		
		UPDATE payments_history SET `agrm_id` = `origin_agrm_id`, `amount_cur` = `origin_amount_cur`, `amount` = `origin_amount`,
			`order_id` = `origin_order_id`
		WHERE record_id = tmp_record_id;

		
		SELECT p.comment_new,       p.local_date_new,       p.cancel_date_new,        p.status_new,         p.mod_person_new
		INTO tmp_origin_comment,    tmp_origin_local_date,  tmp_origin_cancel_date,   tmp_origin_status,    tmp_origin_manager_id
		FROM  payments_history p
		WHERE p.record_id = tmp_record_id;
		
		
		SET done = FALSE;
	END LOOP;
	CLOSE payments_history_records;

	
	UPDATE payments
	SET	comment = tmp_origin_comment, local_date = tmp_origin_local_date, mod_person = tmp_origin_manager_id
	WHERE record_id = in_origin_record_id;
END */;;

