    delete from `roles` where `role_name` = 'options_requisite_r' and `role_id` = l_role_r;
    delete from `roles` where `role_name` = 'options_requisite_rw' and `role_id` = l_role_rw;

    
    if(select count(*) from `options` where `name` = 'money_decimal_precision') = 0
      then
        INSERT INTO `options`(`name`, `descr`, `value`)
        VALUES ("money_decimal_precision", "Количество знаков после запятой", "2");
    end if;

    
    select `role_id` into l_role_r from `roles` where `role_name` = 'options_functions_r';
    select `role_id` into l_role_rw from `roles` where `role_name` = 'options_functions_rw';
    select `rule_template_id` into l_rtmp from `rule_templates`
                                           where `name` = 'Options.Functions'
                                           and  `descr` = 'Rule for access to options of functions'
                                           and `enabled` = 0 and `rights` = 15;
    delete from `object_visibility_area` where role_id = l_role_r;
    delete from `object_visibility_area` where role_id = l_role_rw;
    delete from `manager_roles` where role_id = l_role_r;
    delete from `manager_roles` where role_id = l_role_rw;
    delete from `rules` where `role_id` = l_role_r and `rights_level` = 1;
    delete from `rules` where `role_id` = l_role_rw and `rights_level` = 15;
    delete from `rule_templates` where `name` = 'Options.Functions'
                                 and `descr` = 'Rule for access to options of functions'
