    delete from `roles` where `role_name` = 'options_functions_r' and `role_id` = l_role_r;
    delete from `roles` where `role_name` = 'options_functions_rw' and `role_id` = l_role_rw;
 
    
    UPDATE `roles` SET `issystem` = 1 WHERE `role_name` = 'radius_sync_r';

    
    CALL drop_index(database(), 'ports', 'portid');



    update `db_options` set `value` = concat(build_version, '-', build_name, '-', replace(build_date, '-', '')) WHERE `name` = 'version';
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE update_marks
