/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `update_marks`()
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
BEGIN
    INSERT INTO `tm_agent_options` (`id`, `name`, `tm_mark`) SELECT `id`, `name`,  unix_timestamp() FROM `agent_options` on duplicate key update `tm_mark` = `tm_mark`;
    INSERT INTO `tm_categories` (`tar_id`,`cat_idx`,`tm_mark`) SELECT `tar_id`,`cat_idx`,  unix_timestamp() FROM `categories` on duplicate key update `tm_mark` = `tm_mark`;
