/*!50003 DROP PROCEDURE IF EXISTS `update_meta_columns` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `update_meta_columns`(in in_schema varchar(64), in in_mode int(1))
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
begin
  declare v_tab_name, v_colname, v_oldcolname, v_prefix varchar(255);
  declare v_fdata varchar(4000);
  declare done int(1) default 0;
  
  declare columns_cur CURSOR for
          select ifnull(mc.table_name, '')
               , ifnull(mc.column_name, '')
               , mc.addfielddata field_data
               , mct.column_name
          from meta$columns mc
          left join meta$columns_tmp mct using(table_name, column_name)
          where (mct.column_name is null or (mc.addfielddata <> mct.addfielddata and mct.column_name is not null))
          and mc.table_name not regexp '[tel|rad|user][0-9]{11}'
          and mc.table_name not regexp '[report][0-9]{6}'
          and mc.table_name not regexp 'auth_hist[0-9]{8}'
          and mc.table_name not in ('telNNNYYYYmmdd', 'radNNNYYYYmmdd', 'userNNNYYYYmmdd', 'reportYYYYmm', 'auth_histYYYYmmdd');

  declare tables_cur_stat CURSOR for 
          select distinct table_name, 
                 case
                   when table_name regexp 'tel[0-9]{11}' then 'tel'
                   when table_name regexp 'rad[0-9]{11}' then 'rad'
                   when table_name regexp 'user[0-9]{11}' then 'user'
                   when table_name regexp 'report[0-9]{6}' then 'report'
                   when table_name regexp 'auth_hist[0-9]{8}' then 'auth_hist'
                   when table_name = 'telNNNYYYYmmdd' then 'tel'
                   when table_name = 'radNNNYYYYmmdd' then 'rad'
                   when table_name = 'userNNNYYYYmmdd' then 'user'
                   when table_name = 'reportYYYYmm' then 'report'
                   when table_name = 'auth_histYYYYmmdd' then 'auth_hist'
                 end as prefix
          from meta$columns_tmp
          where table_name regexp '[tel|rad|user][0-9]{11}'
          or table_name regexp 'report[0-9]{6}'
          or table_name regexp '[tel|rad|user]NNNYYYYmmdd'
          or table_name regexp 'auth_hist[0-9]{8}'
          or table_name = 'reportYYYYmm'
          or table_name = 'auth_histYYYYmmdd'
          ;
          
  declare columns_cur_stat CURSOR for
          select ifnull(mc1.column_name, '')
               , mc1.addfielddata field_data
               , mct1.column_name
          from (select * from (
                select case table_name
                         when 'telNNNYYYYmmdd' then 'tel'
                         when 'radNNNYYYYmmdd' then 'rad'
                         when 'userNNNYYYYmmdd' then 'user'
                         when 'reportYYYYmm' then 'report'
                         when 'auth_histYYYYmmdd' then 'auth_hist'
                       end as prefix
                     , mc.*
                from meta$columns mc
                where mc.table_name in ('telNNNYYYYmmdd', 'radNNNYYYYmmdd', 'userNNNYYYYmmdd', 'reportYYYYmm', 'auth_histYYYYmmdd')
                ) tt where prefix = v_prefix
               ) mc1
          left join (select distinct case
                         when table_name regexp 'tel[0-9]{11}' then 'tel'
                         when table_name regexp 'rad[0-9]{11}' then 'rad'
                         when table_name regexp 'user[0-9]{11}' then 'user'
                         when table_name regexp 'report[0-9]{6}' then 'report'
                         when table_name regexp 'auth_hist[0-9]{8}' then 'auth_hist'
                         when table_name = 'telNNNYYYYmmdd' then 'tel'
                         when table_name = 'radNNNYYYYmmdd' then 'rad'
                         when table_name = 'userNNNYYYYmmdd' then 'user'
                         when table_name = 'reportYYYYmm' then 'report'
                         when table_name = 'auth_histYYYYmmdd' then 'auth_hist'
                       end as prefix
                     , mct.*
                from meta$columns_tmp mct
                where (mct.table_name = v_tab_name)
               ) mct1
            on mc1.prefix = mct1.prefix and mc1.column_name = mct1.column_name
          where mct1.column_name is null 
          or (replace(lower(trim(mc1.addfielddata)), 'default null ', '') <> replace(lower(trim(mct1.addfielddata)), 'default null ', '') 
              and mct1.column_name is not null
              )
          ;

  declare continue handler for NOT FOUND set done = 1;

  call create_meta_columns(in_schema, 1);

  if in_mode = 0
    then
      open columns_cur;
      fetch columns_cur into v_tab_name, v_colname, v_fdata, v_oldcolname;
      while not done do
        if v_oldcolname is null
          then
            call add_field(in_schema, v_tab_name, v_colname, v_fdata);
        else
          call change_field(in_schema, v_tab_name, v_colname, v_colname, v_fdata);
        end if;
        set done=0;
        fetch columns_cur into v_tab_name, v_colname, v_fdata, v_oldcolname;
      end while;
      close columns_cur;
  elseif in_mode = 1
    then
      open tables_cur_stat;
      fetch tables_cur_stat into v_tab_name, v_prefix;
      while not done do
        open columns_cur_stat;
        fetch columns_cur_stat into v_colname, v_fdata, v_oldcolname;
        while not done do
          if v_oldcolname is null
            then
              call add_field(in_schema, v_tab_name, v_colname, v_fdata);
          else
            call change_field(in_schema, v_tab_name, v_colname, v_colname, v_fdata);
          end if;
          set done=0;
          fetch columns_cur_stat into v_colname, v_fdata, v_oldcolname;
        end while;
        close columns_cur_stat;
        set done = 0;
        fetch tables_cur_stat into v_tab_name, v_prefix;
      end while;
      close tables_cur_stat;
  end if;
  
  call create_meta_columns(in_schema, 0);

end */;;

