                   when mc.table_name regexp 'auth_hist[0-9]{8}' then 'auth_hist'
                   when mc.table_name = 'telNNNYYYYmmdd' then 'tel'
                   when mc.table_name = 'radNNNYYYYmmdd' then 'rad'
                   when mc.table_name = 'userNNNYYYYmmdd' then 'user'
                   when mc.table_name = 'reportYYYYmm' then 'report'
                   when mc.table_name = 'auth_histYYYYmmdd' then 'auth_hist'
                 end as prefix
          from meta$constraints_tmp mc
          join meta$table_order mo 
