          where (mc.table_name regexp '[tel|rad|user][0-9]{11}'
          or mc.table_name regexp 'report[0-9]{6}'
          or mc.table_name regexp '[tel|rad|user]NNNYYYYmmdd'
          or mc.table_name regexp 'auth_hist[0-9]{8}'
          or mc.table_name in ('reportYYYYmm', 'auth_histYYYYmmdd'))
          and mc.table_schema = in_schema
