/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `update_meta_tables`(in in_schema varchar(64), in in_mode int(1))
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
begin
  declare v_tab_name, v_oldtab_name, v_tabcur, v_afstabprefix varchar(64);
  declare v_error int(11) default 0;
  declare v_alttabdata varchar(4000);
  declare v_tabrows bigint(21);
  declare done int(1) default 0;
  declare tables_cur cursor for
          select mt.table_name
               , mtt.table_name
               , mt.altertabdata
               , ifnull(mtt.table_rows, 0)
          from meta$tables mt
          join meta$table_order mo 
            on mt.table_name = mo.table_name
          left join meta$tables_tmp mtt 
            on mt.table_name = mtt.table_name
          where 1=1


          and mtt.table_name is null or (mtt.altertabdata <> mt.altertabdata and mtt.table_name is not null)
          and mt.table_name not regexp '[tel|rad|user][0-9]{11}'
          and mt.table_name not regexp 'report[0-9]{6}'
          and mt.table_name not regexp 'auth_hist[0-9]{8}'
          and mt.table_name not in ('telNNNYYYYmmdd', 'radNNNYYYYmmdd', 'userNNNYYYYmmdd', 'reportYYYYmm', 'auth_histYYYYmmdd')
          order by mo.id;

  declare tables_cur_stat cursor for
          select mt.table_name
               , mtt.table_name
               , mt.altertabdata
               , ifnull(mtt.table_rows, 0)
          from meta$tables mt
          left join meta$tables_tmp mtt 
            on mt.table_name = mtt.table_name
          where 1=1
          and mtt.table_name is null or (mtt.altertabdata <> mt.altertabdata and mtt.table_name is not null)
          and mt.table_name in ('telNNNYYYYmmdd', 'radNNNYYYYmmdd', 'userNNNYYYYmmdd', 'reportYYYYmm', 'auth_histYYYYmmdd')
          union
          select mt1.table_name
               , mtt1.table_name
               , mt1.altertabdata
               , ifnull(mtt1.table_rows, 0)
          from (select case table_name
                         when 'telNNNYYYYmmdd' then 'tel'
                         when 'radNNNYYYYmmdd' then 'rad'
                         when 'userNNNYYYYmmdd' then 'user'
                         when 'reportYYYYmm' then 'report'
                         when 'auth_histYYYYmmdd' then 'auth_hist'
                       end as prefix
                     , mt.*
                from meta$tables mt
                where mt.table_name in ('telNNNYYYYmmdd', 'radNNNYYYYmmdd', 'userNNNYYYYmmdd', 'reportYYYYmm', 'auth_histYYYYmmdd')
               ) mt1
          join (select case
                         when table_name regexp 'tel[0-9]{11}' then 'tel'
                         when table_name regexp 'rad[0-9]{11}' then 'rad'
                         when table_name regexp 'user[0-9]{11}' then 'user'
                         when table_name regexp 'report[0-9]{6}' then 'report'
                         when table_name regexp 'auth_hist[0-9]{8}' then 'auth_hist'
                         when table_name = 'telNNNYYYYmmdd' then 'tel'
                         when table_name = 'radNNNYYYYmmdd' then 'rad'
                         when table_name = 'userNNNYYYYmmdd' then 'user'
                         when table_name = 'reportYYYYmm' then 'report'
                         when table_name = 'auth_histYYYYmmdd' then 'auth_hist'
                       end as prefix
                     , mtt.*
                from meta$tables_tmp mtt
                where (mtt.table_name regexp '[tel|rad|user][0-9]{11}' 
                    or mtt.table_name regexp 'report[0-9]{6}'
                    or mtt.table_name regexp 'auth_hist[0-9]{8}')
               ) mtt1
            on mt1.prefix = mtt1.prefix
          where mtt1.altertabdata <> mt1.altertabdata
          order by 1;

  declare continue handler for NOT FOUND set done = 1;

  call create_meta_tables(in_schema, 1);
  call create_meta_columns(in_schema, 1);








  set done = 0;
  if in_mode = 0
    then
      open tables_cur;
      fetch tables_cur into v_tab_name, v_oldtab_name, v_alttabdata, v_tabrows;  
      while not done do
        if (v_oldtab_name is null or v_tabrows > 10000000)
          then
            call add_table(in_schema, v_tab_name);
          else
            call show_message('INFO',0,concat('alter table `', in_schema, '`.`',v_tab_name, '` ',replace(v_alttabdata, 'partitioned', '')));
            call exec_command(concat('alter table `', in_schema, '`.`', v_tab_name, '` ', replace(v_alttabdata, 'partitioned', '')), 1, v_error);
        end if;
        fetch tables_cur into v_tab_name, v_oldtab_name, v_alttabdata, v_tabrows;
      end while;
      close tables_cur;
  elseif in_mode = 1
    then
      open tables_cur_stat;
      fetch tables_cur_stat into v_tab_name, v_oldtab_name, v_alttabdata, v_tabrows;
      while not done do
        if (v_oldtab_name is null or v_tabrows > 10000000)
          then
            call add_table(in_schema, v_tab_name);
          else
            call show_message('INFO',0,concat('alter table `', in_schema, '`.`',v_tab_name, '` ',replace(v_alttabdata, 'partitioned', '')));
            call exec_command(concat('alter table `', in_schema, '`.`', v_tab_name, '` ', replace(v_alttabdata, 'partitioned', '')), 1, v_error);
        end if;
        fetch tables_cur_stat into v_tab_name, v_oldtab_name, v_alttabdata, v_tabrows;
      end while;
      close tables_cur_stat;
  end if; 

  call create_meta_tables(in_schema, 0);
  call create_meta_columns(in_schema, 0);


end */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE update_meta_triggers
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `update_meta_triggers` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `update_meta_triggers`(in in_schema varchar(64))
    MODIFIES SQL DATA
    SQL SECURITY INVOKER
begin
  declare v_trname, v_sql varchar(255);
  declare done, v_error int(11) default 0;
  declare triggers_cur cursor for select mtt.trigger_name
                                  from meta$triggers mt 
                                  join meta$triggers_tmp mtt 
                                    using(event_manipulation, event_object_table, action_orientation, action_timing)
                                  where mt.trigger_name <> mtt.trigger_name;

  declare continue handler for NOT FOUND set done = 1;

  call create_meta_triggers(in_schema, 1);

  set done = 0;
  open triggers_cur;
  fetch triggers_cur into v_trname;
  while not done do
    set v_error = 0;
    set v_sql = concat('DROP TRIGGER IF EXISTS ', v_trname);
    call show_message('WARNING', 0, concat('Trigger `', v_trname, '` must be droped by hand!'));
    
    
    fetch triggers_cur into v_trname;
  end while;
  close triggers_cur;
  
  call create_meta_triggers(in_schema, 0);

end */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of PROCEDURE usbox_to_services
# ------------------------------------------------------------

/*!50003 DROP PROCEDURE IF EXISTS `usbox_to_services` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 PROCEDURE `usbox_to_services`(in_date datetime)
    SQL SECURITY INVOKER
begin
    declare v_stypeid, v_defoper, v_newcat int(11);

    select `value` into v_defoper from options where name = 'default_operator';

    IF (select count(1) from service_types where type_code = '0;0;0;0;0;1;1;1' and type_name = 'Migrated from USBOX') = 0
    THEN
        insert into service_types(type_code, type_name) VALUES('0;0;0;0;0;1;1;1', 'Migrated from USBOX');
        select LAST_INSERT_ID() into v_stypeid;
    ELSE
        select type_id into v_stypeid from service_types where type_code = '0;0;0;0;0;1;1;1' and type_name = 'Migrated from USBOX';
    END IF;

    if (select count(1) from catalog where cat_name = 'From_USBOX' and cat_type = 4) = 0
    then
        start transaction;  

            insert into catalog(cat_name, cat_type, oper_id) values('From_USBOX', 4, v_defoper);
            select LAST_INSERT_ID() into v_newcat;

            insert into service_cat(cat_id, descr, type_id, uuid, is_periodic)
            select distinct v_newcat, c.descr, v_stypeid, c.uuid, common <> 0 as is_periodic 
            from categories c join tarifs t using(tar_id)  
            where t.type = 5 
            and not exists (select 1 from service_cat sc join categories c1 on sc.uuid = c1.uuid and c1.descr = sc.descr and sc.cat_id = v_newcat join tarifs t1 using(tar_id) where t1.type = 5);

            
            drop temporary table if exists cat_ids;
            create temporary table cat_ids as select tar_id, cat_idx, (select ifnull(max(serv_cat_idx),0)+1 from service_categories where tar_id = t.tar_id) serv_cat_idx_offset, common <> 0 is_periodic from categories c join tarifs t using(tar_id) where t.type = 5;

            insert into service_categories(tar_id, serv_cat_idx, uuid, above, perm_above, usr_block_above, adm_block_above, includes, rent_period, descr, enabled, available, archive, script, script_off, sale_dictionary_id, keep_turned_on, auto_assign, descr_full, link, service_cat_id, include_above, dtv_type, service_type)
            select c.tar_id, t.cat_idx + t.serv_cat_idx_offset, c.uuid, above, perm_above, usr_block_above, adm_block_above, includes, common, c.descr, enabled, available, c.archive, script, script_off, c.sale_dictionary_id, keep_turned_on, auto_assign, c.descr_full, c.link, sc.record_id, include_above, dtv_type, 0
            from categories c 
            join cat_ids t using(tar_id, cat_idx)  
            join service_cat sc on sc.descr = c.descr and sc.cat_id = v_newcat and c.uuid = sc.uuid and sc.type_id = v_stypeid;

            
            drop temporary table if exists uservs;
            create temporary table uservs as select serv_id, vg_id, tar_id, cat_idx, mul, person_id, comment, created, timefrom, timeto, need_calc, external_data, state, activated, serv_cat_idx_offset
            from usbox_services join cat_ids using(tar_id, cat_idx) where timeto > in_date and is_periodic;

            insert into services(vg_id, tar_id, serv_cat_idx, mul, person_id, comment, created, timefrom, timeto, need_calc, external_data, state, activated) 
            select vg_id, tar_id, cat_idx  + serv_cat_idx_offset, mul, person_id, comment, created, in_date, timeto, need_calc, external_data, state, activated 
            from uservs;

            insert into service_blocks(service_id, vg_id, timefrom, timeto, blocked)
            select s.service_id, s.vg_id, v.timefrom, v.timeto, v.block_type 
            from services s
            join uservs u on s.vg_id = u.vg_id and s.tar_id = u.tar_id and s.serv_cat_idx = u.cat_idx + serv_cat_idx_offset and s.timefrom = in_date and u.timeto = s.timeto and s.mul = u.mul and s.created = u.created
            join vg_blocks v on v.vg_id = s.vg_id;

            drop temporary table if exists cmask;
            create temporary table cmask as select * from cerber_mask cm join cat_ids c using(tar_id, cat_idx);

            insert into cerber_mask(tar_id, serv_cat_idx, mask) 
            select c.tar_id, s.serv_cat_idx, c.mask 
            from cmask c
            join services s on s.tar_id = c.tar_id and s.serv_cat_idx = c.cat_idx + c.serv_cat_idx_offset;

            drop temporary table if exists tariff_mods;
            create temporary table tariff_mods as select tm.* from tariff_modifiers tm join uservs using(serv_id);
            
            insert into tariff_modifiers(name, tar_id, vg_id, timefrom, timeto, rent, block_rent, rate, discount, block_discount, block_state, service_id)
            select t.name, t.tar_id, t.vg_id, in_date, t.timeto, t.rent, t.block_rent, t.rate, t.discount, t.block_discount, t.block_state, s.service_id 
            from services s
            join uservs u on s.vg_id = u.vg_id and s.tar_id = u.tar_id and s.serv_cat_idx = u.cat_idx + serv_cat_idx_offset and s.timefrom = in_date and u.timeto = s.timeto and s.mul = u.mul and s.created = u.created
            join tariff_mods t using(serv_id);
 
            update tariff_modifiers tm join tariff_mods m using(record_id) set tm.timeto = in_date;
            update usbox_services s join uservs u using(serv_id) set s.timeto = in_date;

        commit; 
    else 
        select "Already done";
    end if;
END */;;

