/*!50003 DROP FUNCTION IF EXISTS `ADDRESS_FORMAT` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 FUNCTION `ADDRESS_FORMAT`(in_type tinyint, in_id int, in_format varchar(255)) RETURNS varchar(255) CHARSET utf8
    READS SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Возвращает адрес в виде строки с заданным форматом'
BEGIN
    DECLARE l_country varchar(255);
    DECLARE l_region varchar(255);
    DECLARE l_area varchar(255);
    DECLARE l_city varchar(255);
    DECLARE l_settl varchar(255);
    DECLARE l_street varchar(255);
    DECLARE l_building varchar(255);
    DECLARE l_flat varchar(255);
    DECLARE l_region_s varchar(255);
    DECLARE l_area_s varchar(255);
    DECLARE l_city_s varchar(255);
    DECLARE l_settl_s varchar(255);
    DECLARE l_street_s varchar(255);
    DECLARE l_building_s varchar(255);
    DECLARE l_entrance varchar(255);
    DECLARE l_entrance_s varchar(255);
    DECLARE l_floor varchar(255);
    DECLARE l_floor_s varchar(255);
    DECLARE l_flat_s varchar(255);
    DECLARE l_index int unsigned;
    DECLARE i int;
    DECLARE len int;
    DECLARE c smallint unsigned;
    DECLARE addr varchar(255);
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET len = 1;
    SET len = 0;
    IF in_type < 20 THEN
        SELECT convert(t1.`name` using utf8)
             , convert(t2.`name` using utf8)
             , convert(t3.`name` using utf8)
             , convert(t4.`name` using utf8)
             , convert(t5.`name` using utf8)
             , convert(t6.`name` using utf8)
             , convert(CONCAT(t7.`name`, if (t7.`block` > '', concat(' / ', t7.`block`),'')) using utf8)
             , convert(t8.`name` using utf8)
             , convert(t9.`name` using utf8)
             , convert(t10.`name` using utf8)
             , convert(t2.`short` using utf8)
             , convert(t3.`short` using utf8)
             , convert(t4.`short` using utf8)
             , convert(t5.`short` using utf8)
             , convert(t6.`short` using utf8)
             , convert(t7.`short` using utf8)
             , convert(t8.`short` using utf8)
             , convert(t9.`short` using utf8)
             , convert(t10.`short` using utf8)
             , IF(t7.`idx` > 0, t7.`idx`, t6.`idx`)
            INTO l_country, l_region, l_settl, l_area, l_city, l_street, l_building, l_entrance, l_floor, l_flat,
            l_region_s, l_settl_s, l_area_s, l_city_s, l_street_s, l_building_s, l_entrance_s, l_floor_s, l_flat_s, l_index
            FROM `accounts_addr` a
            LEFT JOIN `address_country` t1 ON t1.`record_id` = a.`country`
            LEFT JOIN `address_region` t2 ON t2.`record_id` = a.`region`
            LEFT JOIN `address_settl` t3 ON t3.`record_id` = a.`settl`
            LEFT JOIN `address_area` t4 ON t4.`record_id` = a.`area`
            LEFT JOIN `address_city` t5 ON t5.`record_id` = a.`city`
            LEFT JOIN `address_street` t6 ON t6.`record_id` = a.`street`
            LEFT JOIN `address_building` t7 ON t7.`record_id` = a.`building`
            LEFT JOIN `address_entrance` t8 ON t8.`record_id` = a.`entrance`
            LEFT JOIN `address_floor` t9 ON t9.`record_id` = a.`floor`
            LEFT JOIN `address_flat` t10 ON t10.`record_id` = a.`flat`
            WHERE a.`type` = in_type AND a.`uid` = in_id;
    ELSEIF (in_type >= 20 and in_type < 40) THEN
        SELECT convert(t1.`name` using utf8)
             , convert(t2.`name` using utf8)
             , convert(t3.`name` using utf8)
             , convert(t4.`name` using utf8)
             , convert(t5.`name` using utf8)
             , convert(t6.`name` using utf8)
             , convert(CONCAT(t7.`name`, ' / ', t7.`block`) using utf8)
             , convert(t8.`name` using utf8)
             , convert(t9.`name` using utf8)
             , convert(t10.`name` using utf8)
             , convert(t2.`short` using utf8)
             , convert(t3.`short` using utf8)
             , convert(t4.`short` using utf8)
             , convert(t5.`short` using utf8)
             , convert(t6.`short` using utf8)
             , convert(t7.`short` using utf8)
             , convert(t8.`short` using utf8)
             , convert(t9.`short` using utf8)
             , convert(t10.`short` using utf8)
             , IF(t7.`idx` > 0, t7.`idx`, t6.`idx`)
            INTO l_country, l_region, l_settl, l_area, l_city, l_street, l_building, l_entrance, l_floor, l_flat,
            l_region_s, l_settl_s, l_area_s, l_city_s, l_street_s, l_building_s, l_entrance_s, l_floor_s, l_flat_s, l_index
            FROM `devices` `d`
            LEFT JOIN `address_country` t1 ON t1.`record_id` = `d`.`country_id`
            LEFT JOIN `address_region` t2 ON t2.`record_id` = `d`.`region_id`
            LEFT JOIN `address_settl` t3 ON t3.`record_id` = `d`.`settle_id`
            LEFT JOIN `address_area` t4 ON t4.`record_id` = `d`.`area_id`
            LEFT JOIN `address_city` t5 ON t5.`record_id` = `d`.`city_id`
            LEFT JOIN `address_street` t6 ON t6.`record_id` = `d`.`street_id`
            LEFT JOIN `address_building` t7 ON t7.`record_id` = d.`building_id`
            LEFT JOIN `address_entrance` t8 ON t8.`record_id` = d.`entrance_id`
            LEFT JOIN `address_floor` t9 ON t9.`record_id` = d.`floor_id`
            LEFT JOIN `address_flat` t10 ON t10.`record_id` = d.`flat_id`
            WHERE `d`.`device_id` = in_id;
    ELSE     SELECT convert(t1.`name` using utf8)
                  , convert(t2.`name` using utf8)
                  , convert(t3.`name` using utf8)
                  , convert(t4.`name` using utf8)
                  , convert(t5.`name` using utf8)
                  , convert(t6.`name` using utf8)
                  , convert(CONCAT(t7.`name`, if (t7.`block` > '', concat(' / ', t7.`block`),'')) using utf8)
                  , convert(t8.`name` using utf8)
                  , convert(t9.`name` using utf8)
                  , convert(t10.`name` using utf8)
                  , convert(t2.`short` using utf8)
                  , convert(t3.`short` using utf8)
                  , convert(t4.`short` using utf8)
                  , convert(t5.`short` using utf8)
                  , convert(t6.`short` using utf8)
                  , convert(t7.`short` using utf8)
                  , convert(t8.`short` using utf8)
                  , convert(t9.`short` using utf8)
                  , convert(t10.`short` using utf8)
                  , IF(t7.`idx` > 0, t7.`idx`, t6.`idx`)
            INTO l_country, l_region, l_settl, l_area, l_city, l_street, l_building, l_entrance, l_floor, l_flat,
            l_region_s, l_settl_s, l_area_s, l_city_s, l_street_s, l_building_s, l_entrance_s, l_floor_s, l_flat_s, l_index
            FROM `vgroups_addr` a
            LEFT JOIN `address_country` t1 ON t1.`record_id` = a.`country`
            LEFT JOIN `address_region` t2 ON t2.`record_id` = a.`region`
            LEFT JOIN `address_settl` t3 ON t3.`record_id` = a.`settl`
            LEFT JOIN `address_area` t4 ON t4.`record_id` = a.`area`
            LEFT JOIN `address_city` t5 ON t5.`record_id` = a.`city`
            LEFT JOIN `address_street` t6 ON t6.`record_id` = a.`street`
            LEFT JOIN `address_building` t7 ON t7.`record_id` = a.`building`
            LEFT JOIN `address_entrance` t8 ON t8.`record_id` = a.`entrance`
            LEFT JOIN `address_floor` t9 ON t9.`record_id` = a.`floor`
            LEFT JOIN `address_flat` t10 ON t10.`record_id` = a.`flat`
            WHERE a.`vg_id` = in_id;
    END IF;
    IF len THEN
        RETURN NULL;
    END IF;
    SET i = 1;
    SET len = LENGTH(in_format);
    SET addr = '';
    WHILE i <= len DO
        SET c = ORD(SUBSTR(in_format, i, 1));
        IF c = ORD('%') THEN
            SET i = i + 1;
            IF i <= len THEN
                SET c = ORD(SUBSTR(in_format, i, 1));
                SET addr = CONCAT(addr, CASE c
                    WHEN ORD('Y') THEN IFNULL(l_country, '')
                    WHEN ORD('R') THEN IFNULL(l_region, '')
                    WHEN ORD('r') THEN IFNULL(l_region_s, '')
                    WHEN ORD('L') THEN IFNULL(l_settl, '')
                    WHEN ORD('l') THEN IFNULL(l_settl_s, '')
                    WHEN ORD('A') THEN IFNULL(l_area, '')
                    WHEN ORD('a') THEN IFNULL(l_area_s, '')
                    WHEN ORD('C') THEN IFNULL(l_city, '')
                    WHEN ORD('c') THEN IFNULL(l_city_s, '')
                    WHEN ORD('S') THEN IFNULL(l_street, '')
                    WHEN ORD('s') THEN IFNULL(l_street_s, '')
                    WHEN ORD('B') THEN IFNULL(l_building, '')
                    WHEN ORD('b') THEN IFNULL(l_building_s, '')
                    WHEN ORD('E') THEN IFNULL(l_entrance, '')
                    WHEN ORD('e') THEN IFNULL(l_entrance_s, '')
                    WHEN ORD('Q') THEN IFNULL(l_floor, '')
                    WHEN ORD('q') THEN IFNULL(l_floor_s, '')
                    WHEN ORD('F') THEN IFNULL(l_flat, '')
                    WHEN ORD('f') THEN IFNULL(l_flat_s, '')
                    WHEN ORD('I') THEN IFNULL(l_index, '')
                    ELSE CHAR(c) END);
            END IF;
        ELSE
            SET addr = CONCAT(addr, CHAR(c));
        END IF;
        SET i = i + 1;
    END WHILE;
    RETURN trim(both char(0x00) from addr);
END */;;

