/*!50003 DROP FUNCTION IF EXISTS `ADDRESS_INDEXES` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 FUNCTION `ADDRESS_INDEXES`(in_addr varchar(255), in_create boolean) RETURNS varchar(64) CHARSET utf8
    READS SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Возвращает индексы КЛАДР по адресу'
BEGIN
    DECLARE tok varchar(255);
    DECLARE str varchar(255) default '';
    DECLARE i int(11);
    DECLARE idx int(11);
    DECLARE short_tok varchar(32);
    DECLARE prev_country int(11) default '0';
    DECLARE prev_region int(11) default '0';
    DECLARE prev_area int(11) default '0';
    DECLARE prev_city int(11) default '0';
    DECLARE prev_settl int(11) default '0';
    DECLARE prev_street int(11) default '0';
    DECLARE prev_building int(11) default '0';
    DECLARE prev_flat int(11) default '0';
    DECLARE prev_entrance int(11) default '0';
    DECLARE prev_floor int(11) default '0';
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET idx = 0;

    SET i = 0;
    WHILE ( str <> in_addr ) DO
        SET i = i + 1;
        SET str = SUBSTRING_INDEX(in_addr, ',', i);
        SELECT SUBSTRING_INDEX(str, ',', -1) INTO tok;
        SET tok = TRIM(tok);
        IF ( tok <> '' AND tok <> '/' ) THEN
            
            SET short_tok = '';
            SELECT convert(`short` using utf8) INTO short_tok 
            FROM `address_meaning` 
            WHERE tok LIKE CONCAT(`short`, ' _%') OR tok LIKE CONCAT(`short`, '._%') LIMIT 1;
            IF ( short_tok <> '' ) THEN
                SET tok = trim(both '.' from TRIM(SUBSTRING(tok, LOCATE(short_tok, tok) + char_length(short_tok))));
            ELSE
                SELECT convert(`short` using utf8) INTO short_tok FROM `address_meaning` WHERE tok LIKE CONCAT('_% ', `short`) OR tok LIKE CONCAT('_% ',`short`, '.') LIMIT 1;
                IF ( short_tok <> '' ) THEN
                    SET tok = TRIM(SUBSTRING(tok, 1, char_length(tok) - char_length(short_tok)));
                ELSE
                    SET short_tok = NULL;
                END IF;
            END IF;

            IF ( i = 1 ) THEN                               
                SELECT `record_id` INTO idx 
                FROM `address_country` 
                WHERE upper(`name`) = trim(upper(tok)) 
                LIMIT 1;
                IF ( idx = 0 AND in_create ) THEN
                    INSERT INTO `address_country`(`name`) VALUES(tok);
                    SELECT LAST_INSERT_ID() INTO idx;
                END IF;
                SET prev_country = idx;
            ELSEIF ( i = 2  AND prev_country > 0 ) THEN     
                SELECT `record_id` INTO idx 
                FROM `address_region` 
                WHERE upper(`name`) = trim(upper(tok)) 
                AND `country`=prev_country 
                ORDER BY `country` DESC, record_id
                LIMIT 1;
                IF ( idx = 0 AND in_create ) THEN
                    INSERT INTO `address_region`(`name`, `country`, `short`) VALUES (tok, prev_country, short_tok);
                    SELECT LAST_INSERT_ID() INTO idx;
                END IF;
                SET prev_region = idx;
            ELSEIF ( i = 3 AND prev_region > 0 ) THEN       
                SELECT `record_id` INTO idx 
                FROM `address_area` 
                WHERE upper(`name`) = trim(upper(tok)) 
                AND `region`=prev_region
                ORDER BY `region` DESC, record_id
                LIMIT 1;
                IF ( idx = 0 AND in_create ) THEN
                    INSERT INTO `address_area`(`name`, `region`, `short`) VALUES (tok, prev_region, short_tok);
                    SELECT LAST_INSERT_ID() INTO idx;
                END IF;
                SET prev_area = idx;
            ELSEIF ( i = 4 AND prev_region > 0 ) THEN       
                SELECT `record_id` INTO idx 
                FROM `address_city`
                WHERE upper(`name`) = trim(upper(tok))
                AND `area` = prev_area
                AND `region` = prev_region
                ORDER BY `area` DESC, `region` DESC, record_id
                LIMIT 1;
                IF ( idx = 0 AND in_create ) THEN
                    INSERT INTO `address_city`(`name`, `area`, `region`, `short`) VALUES(tok, prev_area, prev_region, short_tok);
                    SELECT LAST_INSERT_ID() INTO idx;
                END IF;
                SET prev_city = idx;
            ELSEIF ( i = 5 AND prev_region > 0 ) THEN       
                SELECT `record_id` INTO idx 
                FROM `address_settl`
                WHERE upper(`name`) = trim(upper(tok))
                AND `region` = prev_region
                AND `area`=prev_area
                AND `city` = prev_city
                ORDER BY `region` DESC, `area` DESC, `city` DESC, record_id
                LIMIT 1;
                IF ( idx = 0 AND in_create ) THEN
                    INSERT INTO `address_settl`(`name`, `area`, `region`, `city`, `short`) VALUES(tok, prev_area, prev_region, prev_city, short_tok);
                    SELECT LAST_INSERT_ID() INTO idx;
                END IF;
                SET prev_settl = idx;
            ELSEIF ( i = 6 AND prev_region > 0 ) THEN       
                SELECT `record_id` INTO idx
                FROM `address_street`
                WHERE upper(`name`) = upper(trim(tok))
                AND region=prev_region
                AND `city`=prev_city
                AND `settl`=prev_settl
                AND  (`short`=short_tok OR short_tok IS NULL OR short_tok='') 
                ORDER BY `region` DESC, `city` DESC, `settl` DESC, record_id
                LIMIT 1;
                IF ( idx = 0 AND in_create ) THEN
                    INSERT INTO `address_street`(`name`, `region`, `city`, `settl`, `short`, `idx`) VALUES(tok, prev_region, prev_city, prev_settl, short_tok, 0);
                    SELECT LAST_INSERT_ID() INTO idx;
                END IF;
                SET prev_street = idx;
            ELSEIF ( i = 7 AND prev_region > 0 ) THEN       
                SELECT `record_id` INTO idx 
                FROM `address_building` 
                WHERE ((upper(`name`)=replace(TRIM(upper(tok)), ' ', '') and trim(ifnull(`block`, '')) = '') 
                        or upper(concat(`name`, '/', `block`))=replace(TRIM(upper(tok)),' ','')
                        or upper(concat(`name`, 'кор.', `block`))=replace(TRIM(upper(tok)),' ','')
                        or (TRIM(upper(`name`))= TRIM(upper(tok)) and trim(ifnull(`block`, '')) = '')
                       )
                AND `region` = prev_region
                AND `city` = prev_city
                AND `settl` = prev_settl
                AND `street` = prev_street
                ORDER BY `region` DESC, `city` DESC, `settl` DESC, `street` DESC, record_id 
                LIMIT 1;
                if prev_street = 0 then
                   SELECT `record_id` INTO prev_street 
                   FROM `address_street` 
                   WHERE `name` = 'Unknown' 
                   AND `region` = prev_region 
                   AND `city` = prev_city 
                   AND `settl` = prev_settl;
                   if prev_street <> 0 then
                       SELECT `record_id` INTO idx 
                       FROM `address_building` 
                       WHERE ((upper(`name`)=replace(TRIM(upper(tok)), ' ', '') and trim(ifnull(`block`, '')) = '') 
                              or upper(concat(`name`, '/', `block`))=replace(TRIM(upper(tok)),' ','')
                              or upper(concat(`name`, 'кор.', `block`))=replace(TRIM(upper(tok)),' ','')
                              or (TRIM(upper(`name`))= TRIM(upper(tok)) and trim(ifnull(`block`, '')) = '')
                             )
                       AND `region` = prev_region
                       AND `city` = prev_city
                       AND `settl` = prev_settl
                       AND `street` = prev_street
                       ORDER BY `region` DESC, `city` DESC, `settl` DESC, `street` DESC, record_id 
                       LIMIT 1;
                   end if;
                end if;
                IF ( idx = 0 AND in_create ) THEN
                    IF prev_street = 0 THEN
                        SELECT `record_id` INTO prev_street 
                        FROM `address_street` 
                        WHERE `name` = 'Unknown' 
                        AND `region` = prev_region 
                        AND `city` = prev_city 
                        AND `settl` = prev_settl;
                        IF prev_street = 0 THEN
                            INSERT INTO `address_street`(`name`, `region`, `city`, `settl`, `short`, idx) VALUES('Unknown', prev_region, prev_city, prev_settl, null, 0);
                            SELECT LAST_INSERT_ID() INTO prev_street;
                        END IF;
                    END IF;
                    SET @th = replace(TRIM(tok), ' ', '');
                    INSERT INTO `address_building`(`name`, `block`, `region`, `city`, `settl`, `street`, `short`, idx)
                    VALUES ( if(instr(@th, '/')>0, substr(@th, 1, instr(@th, '/')-1), if(instr(@th, 'кор.' )>0, left(@th, instr(@th, 'кор.')-1),@th))
                           , if(instr(@th, '/')>0, substr(@th, instr(@th, '/')+1), if(instr(@th, 'кор.' )>0, trim(substr(@th, instr(@th, 'кор.')+4)),''))
                           , prev_region, prev_city, prev_settl, prev_street, short_tok, 0);
                    SELECT LAST_INSERT_ID() INTO idx;
                END IF;
                SET prev_building = idx;
            ELSEIF ( i = 8 AND prev_region > 0 AND prev_building > 0 ) THEN     
                SELECT `record_id` INTO idx FROM `address_flat` WHERE upper(`name`) = trim(upper(tok)) AND `building` = prev_building ORDER BY `building` DESC LIMIT 1;
                IF ( idx = 0 AND in_create ) THEN
                    INSERT INTO `address_flat`(`name`, `region`, `building`, `short`) VALUES (tok, prev_region, prev_building, short_tok);
                    SELECT LAST_INSERT_ID() INTO idx;
                END IF;
                SET prev_flat = idx;
            ELSEIF ( i = 9 AND prev_building > 0 ) THEN     
                SELECT `record_id` INTO idx FROM `address_entrance` WHERE upper(`name`) = trim(upper(tok)) AND `building` = prev_building ORDER BY `building` DESC LIMIT 1;
                IF ( idx = 0 AND in_create ) THEN
                    INSERT INTO `address_entrance`(`name`, `region`, `building`, `short`) VALUES (tok, prev_region, prev_building, short_tok);
                    SELECT LAST_INSERT_ID() INTO idx;
                END IF;
                SET prev_entrance = idx;
            ELSEIF ( i = 10 AND prev_building > 0 ) THEN     
                SELECT `record_id` INTO idx FROM `address_floor` WHERE upper(`name`) = trim(upper(tok)) AND `building` = prev_building ORDER BY `building` DESC LIMIT 1;
                IF ( idx = 0 AND in_create ) THEN
                    INSERT INTO `address_floor`(`name`, `region`, `building`, `entrance`, `short`) VALUES (tok, prev_region, prev_building, prev_entrance, short_tok);
                    SELECT LAST_INSERT_ID() INTO idx;
                END IF;
                SET prev_floor = idx;
            ELSEIF ( i = 11 AND in_create AND prev_building AND tok REGEXP '[0-9]{6}' ) THEN     
                UPDATE `address_building` SET `idx` = tok WHERE `record_id` = prev_building;
            END IF;
        END IF;
    END WHILE;
    
    RETURN CONCAT(prev_country, ',', prev_region, ',', prev_area, ',', prev_city, ',', prev_settl, ',', prev_street, ',', prev_building,  ',',  prev_flat, ',', prev_entrance,  ',', prev_floor);
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
