/*!50003 DROP FUNCTION IF EXISTS `ADDRESS_STRING` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 FUNCTION `ADDRESS_STRING`(in_country int, in_region int, in_area int, in_city int, in_settl int,in_street int, in_building int, in_entrance int, in_floor int, in_flat int, skip_empty boolean) RETURNS varchar(255) CHARSET utf8
    READS SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Возвращает адрес в виде строки по индексам КЛАДР'
BEGIN
    DECLARE l_name varchar(255);
    DECLARE l_short varchar(32);
    DECLARE found boolean;
    DECLARE addr varchar(255) default '';
    DECLARE idx1 int unsigned default 0;
    DECLARE idx2 int unsigned default 0;
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET found = FALSE;
    IF in_country > 0 THEN
        SET found = TRUE;
        SELECT convert(`name` using utf8) INTO l_name FROM `address_country` WHERE `record_id` = in_country;
        IF found THEN SET addr = IFNULL(TRIM(l_name), ''); END IF;
    END IF;
    IF NOT skip_empty THEN SET addr = CONCAT(addr, ','); END IF;
    IF in_region > 0 THEN
        SET found = TRUE;
        SELECT convert(`name` using utf8), convert(`short` using utf8) INTO l_name, l_short FROM `address_region` WHERE `record_id` = in_region;
        IF found THEN SET addr = CONCAT(addr, IF(RIGHT(addr, 1) = ',' OR addr = '', '', ','), IFNULL(TRIM(l_short), ''), ' ', IFNULL(TRIM(l_name), '')); END IF;
    END IF;
    IF NOT skip_empty THEN SET addr = CONCAT(addr, ','); END IF;
    IF in_area > 0 THEN
        SET found = TRUE;
        SELECT convert(`name` using utf8), convert(`short` using utf8) INTO l_name, l_short FROM `address_area` WHERE `record_id` = in_area;
        IF found THEN SET addr = CONCAT(addr, IF(RIGHT(addr, 1) = ',' OR addr = '', '', ','), IFNULL(TRIM(l_short), ''), ' ', IFNULL(TRIM(l_name), '')); END IF;
    END IF;
    IF NOT skip_empty THEN SET addr = CONCAT(addr, ','); END IF;
    IF in_city > 0 THEN
        SET found = TRUE;
        SELECT convert(`name` using utf8), convert(`short` using utf8) INTO l_name, l_short FROM `address_city` WHERE `record_id` = in_city;
        IF found THEN SET addr = CONCAT(addr, IF(RIGHT(addr, 1) = ',' OR addr = '', '', ','), IFNULL(TRIM(l_short), ''), ' ', IFNULL(TRIM(l_name), '')); END IF;
    END IF;
    IF NOT skip_empty THEN SET addr = CONCAT(addr, ','); END IF;
    IF in_settl > 0 THEN
        SET found = TRUE;
        SELECT convert(`name` using utf8), convert(`short` using utf8) INTO l_name, l_short FROM `address_settl` WHERE `record_id` = in_settl;
        IF found THEN SET addr = CONCAT(addr, IF(RIGHT(addr, 1) = ',' OR addr = '', '', ','), IFNULL(TRIM(l_short), ''), ' ', IFNULL(TRIM(l_name), '')); END IF;
    END IF;
    IF NOT skip_empty THEN SET addr = CONCAT(addr, ','); END IF;
    IF in_street > 0 THEN
        SET found = TRUE;
        SELECT convert(`name` using utf8), convert(`short` using utf8), `idx` INTO l_name, l_short, idx1 FROM `address_street` WHERE `record_id` = in_street;
        IF found THEN SET addr = CONCAT(addr, IF(RIGHT(addr, 1) = ',' OR addr = '', '', ','), IFNULL(TRIM(l_short), ''), ' ', IFNULL(TRIM(l_name), '')); END IF;
    END IF;
    IF NOT skip_empty THEN SET addr = CONCAT(addr, ','); END IF;
    IF in_building > 0 THEN
        SET found = TRUE;
        SELECT IF(TRIM(`block`) <> '', CONCAT(`name`, ' / ', `block`), `name`), `short`, `idx` INTO l_name, l_short, idx2 FROM `address_building` WHERE `record_id` = in_building;
        IF found THEN SET addr = CONCAT(addr, IF(RIGHT(addr, 1) = ',' OR addr = '', '', ','), IFNULL(TRIM(l_short), ''), ' ', IFNULL(TRIM(l_name), '')); END IF;
    END IF;
    IF NOT skip_empty THEN SET addr = CONCAT(addr, ','); END IF;
    IF in_flat > 0 THEN
        SET found = TRUE;
        SELECT convert(`name` using utf8), convert(`short` using utf8) INTO l_name, l_short FROM `address_flat` WHERE `record_id` = in_flat;
        IF found THEN SET addr = CONCAT(addr, IF(RIGHT(addr, 1) = ',' OR addr = '', '', ','), IFNULL(TRIM(l_short), ''), ' ', IFNULL(TRIM(l_name), '')); END IF;
    END IF;
    IF NOT skip_empty THEN SET addr = CONCAT(addr, ','); END IF;
    IF in_entrance > 0 THEN
        SET found = TRUE;
        SELECT convert(`name` using utf8), convert(`short` using utf8) INTO l_name, l_short FROM `address_entrance` WHERE `record_id` = in_entrance;
        IF found THEN SET addr = CONCAT(addr, IF(RIGHT(addr, 1) = ',' OR addr = '', '', ','), IFNULL(TRIM(l_short), ''), ' ', IFNULL(TRIM(l_name), '')); END IF;
    END IF;
    IF NOT skip_empty THEN SET addr = CONCAT(addr, ','); END IF;
    IF in_floor > 0 THEN
        SET found = TRUE;
        SELECT convert(`name` using utf8), convert(`short` using utf8) INTO l_name, l_short FROM `address_floor` WHERE `record_id` = in_floor;
        IF found THEN SET addr = CONCAT(addr, IF(RIGHT(addr, 1) = ',' OR addr = '', '', ','), IFNULL(TRIM(l_short), ''), ' ', IFNULL(TRIM(l_name), '')); END IF;
    END IF;
    IF NOT skip_empty THEN SET addr = CONCAT(addr, ','); END IF;
    IF idx1 > 0 OR idx2 > 0 THEN
        SET addr = convert(CONCAT(addr, IF(RIGHT(addr, 1) = ',' OR addr = '', '', ','), IF(idx2 > 0, idx2, idx1)) using utf8);
    END IF;
    RETURN addr;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of FUNCTION APP_RESTRICTIONS
# ------------------------------------------------------------

/*!50003 DROP FUNCTION IF EXISTS `APP_RESTRICTIONS` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 FUNCTION `APP_RESTRICTIONS`(in_final DATE, in_type INT) RETURNS int(10) unsigned
    READS SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Проверка даты окочания заявки на превыешение количество в день'
BEGIN
    DECLARE result tinyint(1) DEFAULT '0';
    IF in_final IS NOT NULL THEN
        SELECT IF(`sbss_appl_exceptions`.`restriction` IS NULL,
            IF(COUNT(*) < `sbss_appl_classes_rules`.`restriction` OR `sbss_appl_classes_rules`.`restriction` IS NULL, 0, 1),
            IF(`sbss_appl_exceptions`.`restriction` = 0, 0, IF(COUNT(*) < `sbss_appl_exceptions`.`restriction`, 0, 1))
        ) INTO result
            FROM `applications` LEFT JOIN `sbss_statuses` ON (`type` = 2 AND `sbss_statuses`.`id` = `applications`.`status_id`)
            LEFT JOIN `sbss_appl_classes_rules` ON (`sbss_appl_classes_rules`.`id` = `applications`.`type_id` AND `sbss_appl_classes_rules`.`restriction` > 0 AND `sbss_appl_classes_rules`.`week_day_num` = (DAYOFWEEK(DATE(`applications`.`execute_final`)) - 2))
            LEFT JOIN `sbss_appl_exceptions` ON (`sbss_appl_exceptions`.`id` = `applications`.`type_id` AND `sbss_appl_exceptions`.`except_day` = `applications`.`execute_final`)
        WHERE `type_id` = in_type AND DATE(`execute_final`) = DATE(in_final) AND `sbss_statuses`.`default_answer` IS NULL GROUP BY DATE(`execute_final`);
    END IF;
    RETURN result;
END */;;

