/*!50003 DROP FUNCTION IF EXISTS `BALANCE_ACC_ON_DATE` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 FUNCTION `BALANCE_ACC_ON_DATE`(in_agrm_id INTEGER, in_date DATE) RETURNS decimal(20,6)
    READS SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Расчёт задолженности по договору на дату'
BEGIN
    DECLARE tmp_balance_acc, tmp_result DECIMAL(20,6);
    
    SET in_date = IFNULL(in_date,'0000-00-00');

    
    SET tmp_balance_acc = 0;
    SELECT balance_acc INTO tmp_balance_acc                                     
    FROM agreements 
    WHERE agrm_id = in_agrm_id;
    
    
    set tmp_result = 0;
    SELECT ifnull(sum(amount),0) INTO tmp_result      
    FROM sales s 
    WHERE 1=1 
    AND agrm_id =  in_agrm_id
    AND cancel_date IS NULL
    AND period_date >= in_date;
    set tmp_balance_acc = tmp_balance_acc + tmp_result;
    
    
    
    set tmp_result = 0;
    SELECT IFNULL(sum(sh.amount), 0) INTO tmp_result     
    FROM sales_history sh
    JOIN sales s using (sale_id)
    WHERE 1=1
    AND s.agrm_id = in_agrm_id 
    AND s.period_date IS NULL
    AND sh.cancel_date IS NULL
    AND sh.period_date >= in_date
    AND sh.record_id = (SELECT max(record_id)
                        FROM sales_history 
                        WHERE sale_id = sh.sale_id 
                        AND period_date >= in_date);
    set tmp_balance_acc = tmp_balance_acc + tmp_result;
    
    
    set tmp_result = 0;
    SELECT IFNULL(sum(sh.amount), 0) INTO tmp_result   
    FROM sales_history sh
    JOIN sales s using (sale_id)
    WHERE 1=1
    AND s.agrm_id = in_agrm_id 
    AND (s.period_date >= in_date 
        or 
        (select count(1) from sales_history where sale_id = sh.sale_id and record_id > sh.record_id and period_date > sh.period_date) > 0)
    AND sh.cancel_date IS NULL
    AND sh.period_date < in_date
    AND sh.record_id = (SELECT max(record_id)
                        FROM sales_history 
                        WHERE sale_id = sh.sale_id 
                        AND period_date < in_date);
    set tmp_balance_acc = tmp_balance_acc - tmp_result;

    
    set tmp_result = 0;
    SELECT ifnull(sum(amount),0) INTO tmp_result      
    FROM payments s 
    WHERE 1=1 
    AND agrm_id = in_agrm_id
    AND cancel_date IS NULL
    AND period_date >= in_date;
    set tmp_balance_acc = tmp_balance_acc - tmp_result;

    
    set tmp_result = 0;
    SELECT IFNULL(sum(ph.amount), 0) INTO tmp_result   
    FROM payments_history ph 
    JOIN payments p ON ph.origin_record_id = p.record_id 
    WHERE 1=1
    AND ph.agrm_id = in_agrm_id 
    AND ph.cancel_date IS NULL
    AND p.period_date >= in_date
    AND ph.period_date < in_date
    AND ph.record_id = (SELECT max(record_id)FROM payments_history 
                        WHERE origin_record_id = ph.origin_record_id 
                        AND period_date < in_date);
    set tmp_balance_acc = tmp_balance_acc + tmp_result;

    
    set tmp_result = 0;
    SELECT IFNULL(sum(ph.amount), 0) INTO tmp_result
    FROM payments_history ph
    JOIN payments p ON ph.origin_record_id = p.record_id 
    WHERE 1=1
    AND ph.agrm_id = in_agrm_id 
    AND ph.cancel_date IS NULL
    AND p.period_date IS NULL
    AND ph.period_date >= in_date
    AND ph.record_id = (SELECT max(record_id)FROM payments_history 
                        WHERE origin_record_id = ph.origin_record_id 
                        AND period_date >= in_date);
    set tmp_balance_acc = tmp_balance_acc - tmp_result;
                        

    
    set tmp_result = 0;
    SELECT ifnull(sum(amount),0) INTO tmp_result      
    FROM payments p 
    WHERE 1=1
    AND from_agrm_id = in_agrm_id
    AND cancel_date IS NULL
    AND period_date >= in_date;
    set tmp_balance_acc = tmp_balance_acc + tmp_result;

    
    set tmp_result = 0;
    SELECT ifnull(sum(ph.amount), 0) into tmp_result
    FROM payments_history ph 
    JOIN payments p ON ph.origin_record_id = p.record_id 
    WHERE 1=1
    AND p.from_agrm_id = in_agrm_id
    AND ph.cancel_date IS NULL
    AND p.period_date >= in_date
    AND ph.period_date < in_date
    AND ph.record_id = (SELECT max(record_id)FROM payments_history 
                        WHERE origin_record_id = ph.origin_record_id 
                        AND period_date < in_date);
    set tmp_balance_acc = tmp_balance_acc - tmp_result;

    
    set tmp_result = 0;
    SELECT ifnull(sum(ph.amount), 0) into tmp_result
    FROM payments_history ph 
    JOIN payments p ON ph.origin_record_id = p.record_id 
    WHERE 1=1
    AND p.from_agrm_id = in_agrm_id
    AND ph.cancel_date IS NULL
    AND p.period_date IS NULL
    AND ph.period_date >= in_date
    AND ph.record_id = (SELECT min(record_id)FROM payments_history 
                        WHERE origin_record_id = ph.origin_record_id 
                        AND period_date >= in_date);
    set tmp_balance_acc = tmp_balance_acc + tmp_result;

    RETURN ifnull(tmp_balance_acc,0);
         
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of FUNCTION BALANCE_ACC_TO_DATE
# ------------------------------------------------------------

/*!50003 DROP FUNCTION IF EXISTS `BALANCE_ACC_TO_DATE` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 FUNCTION `BALANCE_ACC_TO_DATE`(in_agrm_id INTEGER, in_date DATE) RETURNS decimal(20,6)
    READS SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Расчёт задолженности по договору на дату'
BEGIN
	
	
	
	DECLARE tmp_balance_acc DECIMAL(20,6);


	
	
	
	

		
	
	
	
	SELECT
		IFNULL(SUM(balance), 0)
	INTO
		tmp_balance_acc
	FROM
		balances
	WHERE
		agrm_id = in_agrm_id AND date = in_date;

	
	
	
	
	
	SELECT 		tmp_balance_acc + IFNULL(SUM(p.amount), 0)
	INTO		tmp_balance_acc
	FROM		payments p
	WHERE		p.agrm_id = in_agrm_id AND p.cancel_date IS NULL AND p.period_date >= in_date;

	
	
	
	
	
	SELECT
		tmp_balance_acc - IFNULL(SUM(s.amount), 0)
	INTO
		tmp_balance_acc
	FROM
		(
			SELECT
				IF(p.agrm_id = in_agrm_id AND p.cancel_date IS NULL, p.amount, 0) -
				IFNULL(SUM(IF(ph.agrm_id_new = in_agrm_id AND ph.cancel_date_new IS NULL, ph.amount_new, 0) -
							IF(ph.agrm_id     = in_agrm_id AND ph.cancel_date     IS NULL, ph.amount    , 0)), 0) AS amount
			FROM
				payments p, payments_history ph
			WHERE
				p.record_id = ph.origin_record_id AND
				p.period_date  >= in_date AND
				ph.period_date >= in_date AND
				(ph.agrm_id = in_agrm_id OR ph.agrm_id_new = in_agrm_id) AND
				(SELECT count(*) FROM payments_history WHERE origin_record_id = p.record_id AND period_date < in_date) > 0
			GROUP BY
				p.record_id
		) s;

	
	
	
	
	
	SELECT
		tmp_balance_acc - IFNULL(SUM(p.amount), 0)
	INTO
		tmp_balance_acc
	FROM
		payments p
	WHERE
		p.from_agrm_id = in_agrm_id AND p.cancel_date IS NULL AND
		p.period_date >= in_date;

	
	
	
	
	
	SELECT
		tmp_balance_acc + IFNULL(SUM(s.amount), 0)
	INTO
		tmp_balance_acc
	FROM
		(
			SELECT
				IF(p.cancel_date IS NULL, p.amount, 0) -
				IFNULL(SUM(IF(ph.cancel_date_new IS NULL, ph.amount_new, 0) -
							IF(ph.cancel_date     IS NULL, ph.amount    , 0)), 0) AS amount
			FROM
				payments p, payments_history ph
			WHERE
				p.record_id = ph.origin_record_id AND
				p.period_date >= in_date AND
				ph.period_date >= in_date AND
				ph.from_agrm_id = in_agrm_id AND
				(SELECT count(*) FROM payments_history WHERE origin_record_id = p.record_id AND period_date < in_date) > 0
			GROUP BY
				p.record_id
		) s;

	
	
	
	
	SELECT tmp_balance_acc - IFNULL(SUM(s.amount), 0)
	INTO   tmp_balance_acc
	FROM   sales s
	WHERE s.agrm_id = in_agrm_id AND s.cancel_date IS NULL AND s.period_date >= in_date;


	
	
	
	
	
	SELECT
		tmp_balance_acc + IFNULL(SUM(s.amount), 0)
	INTO
		tmp_balance_acc
	FROM
		(
			SELECT IFNULL(SUM( IF(sh.cancel_date_new IS NULL, sh.amount, 0) ), 0) AS amount
			FROM   sales s join sales_history sh on s.sale_id = sh.sale_id
			WHERE  s.agrm_id = in_agrm_id AND s.period_date >= in_date AND 
			      (SELECT count(*) FROM sales_history WHERE sale_id = s.sale_id AND period_date < in_date) > 0 AND
			      sh.record_id = (SELECT min(record_id) FROM sales_history WHERE sale_id = s.sale_id AND period_date < in_date) > 0
			GROUP BY
				s.sale_id
		) s;

    RETURN ifnull(tmp_balance_acc,0);
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of FUNCTION balance_on_date
# ------------------------------------------------------------

/*!50003 DROP FUNCTION IF EXISTS `balance_on_date` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 FUNCTION `balance_on_date`(in_agrm_id INTEGER, in_date DATE) RETURNS decimal(20,6)
    READS SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'расчет тех. баланса по договору'
BEGIN
    DECLARE v_ret           decimal(20,6) DEFAULT NULL;    
    DECLARE v_start_value   decimal(20,6) DEFAULT NULL;    
    DECLARE v_payments      decimal(20,6) DEFAULT NULL;    
    DECLARE v_from          decimal(20,6) DEFAULT NULL;    
    DECLARE v_sales_corr    decimal(20,6) DEFAULT NULL;    
    DECLARE v_rent          decimal(20,6) DEFAULT NULL;    
    DECLARE v_usbox         decimal(20,6) DEFAULT NULL;    
    DECLARE v_charges       decimal(20,6) DEFAULT NULL;    
    DECLARE v_day           decimal(20,6) DEFAULT NULL;    

    DECLARE v_start_date DATE DEFAULT NULL;

    
    SET v_start_date = current_date() + INTERVAL 1 DAY;
    SELECT balance FROM agreements WHERE agrm_id = in_agrm_id INTO v_start_value;

    
    SELECT IFNULL(SUM(`amount`),0)
    FROM `payments`
    WHERE `cancel_date` IS NULL
    AND `pay_date` >= TIMESTAMP(in_date) AND `pay_date` < TIMESTAMP(v_start_date)
    AND `agrm_id` = in_agrm_id
    INTO v_payments;

    
    SELECT IFNULL(SUM(`amount`),0)
    FROM `payments`
    WHERE `cancel_date` IS NULL
    AND `pay_date` >= TIMESTAMP(in_date) AND `pay_date` < TIMESTAMP(v_start_date)
    AND `from_agrm_id` = in_agrm_id
    INTO v_from;

    
    SELECT IFNULL(SUM(IF(`cancel_date_new` IS NOT NULL OR `cancel_date` IS NOT NULL, 0, `amount_new` - `amount`)),0)
    FROM `sales_history` `h`
    WHERE `agrm_id` = in_agrm_id
    AND DATE(`local_date_new`) >= TIMESTAMP(in_date) AND DATE(`local_date_new`) < TIMESTAMP(`v_start_date`)
    INTO v_sales_corr;

    
    SELECT IFNULL(SUM(`amount`),0)
    FROM `rentcharge`
    WHERE `agrm_id` = in_agrm_id
    AND `period` >= in_date AND `period` < v_start_date
    INTO v_rent;

    
    SELECT IFNULL(SUM(`amount`),0)
    FROM `usbox_charge`
    WHERE `agrm_id` = in_agrm_id
    AND `period` >= in_date AND `period` < v_start_date
    INTO v_usbox;

    
    SELECT IFNULL(SUM(`amount`),0)
    FROM `charges`
    WHERE `agrm_id` = in_agrm_id
    AND `period` >= in_date AND `period` < v_start_date
    INTO v_charges;

    
    SELECT IFNULL(SUM(`amount`),0)
    FROM `day`
    WHERE `agrm_id` = in_agrm_id
    AND `timefrom` >= in_date AND `timefrom` < v_start_date
    INTO v_day;

    SET v_ret = v_start_value - v_payments + v_from + v_sales_corr + v_rent + v_usbox + v_charges + v_day;
    RETURN v_ret;

END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
