/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of FUNCTION consonant
# ------------------------------------------------------------

/*!50003 DROP FUNCTION IF EXISTS `consonant` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 FUNCTION `consonant`(in_string VARCHAR(255), no_space TINYINT UNSIGNED) RETURNS varchar(255) CHARSET utf8
    NO SQL
    DETERMINISTIC
    SQL SECURITY INVOKER
BEGIN
  DECLARE out_string VARCHAR(255);
  DECLARE str_pos INT UNSIGNED DEFAULT 2;
  DECLARE in_length INT UNSIGNED DEFAULT 0;

  IF no_space < 0 OR no_space > 1 THEN SET no_space = 0; END IF;

  SET in_string = LOWER(in_string);
  SET in_string = REPLACE(in_string, 'а', '');
  SET in_string = REPLACE(in_string, 'е', '');
  SET in_string = REPLACE(in_string, 'ё', '');
  SET in_string = REPLACE(in_string, 'и', '');
  SET in_string = REPLACE(in_string, 'й', '');
  SET in_string = REPLACE(in_string, 'о', '');
  SET in_string = REPLACE(in_string, 'у', '');
  SET in_string = REPLACE(in_string, 'э', '');
  SET in_string = REPLACE(in_string, 'ю', '');
  SET in_string = REPLACE(in_string, 'я', '');
  SET in_string = REPLACE(in_string, 'ы', '');
  SET in_string = REPLACE(in_string, 'ъ', '');
  SET in_string = REPLACE(in_string, 'ь', '');

  SET in_length = LENGTH(in_string);
  SET out_string = SUBSTRING(in_string, 1, 1);
  WHILE str_pos < in_length DO
    IF SUBSTRING(in_string, str_pos, 1) != SUBSTRING(in_string, (str_pos - 1), 1) THEN
      SET out_string = CONCAT(out_string, SUBSTRING(in_string, str_pos, 1));
    END IF;
    SET str_pos = str_pos + 1;
  END WHILE;

  IF no_space = 1 THEN SET out_string = REPLACE(out_string, ' ', ''); END IF;

  RETURN out_string;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of FUNCTION CURRENT_SHAPE
# ------------------------------------------------------------

/*!50003 DROP FUNCTION IF EXISTS `CURRENT_SHAPE` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 FUNCTION `CURRENT_SHAPE`(in_vg_id int(11), in_dtime datetime) RETURNS bigint(20) unsigned
    READS SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Вычисляет текущ. знач. полосы пропускания для данной уч.записи'
BEGIN

    DECLARE v_cur_shape bigint unsigned;
    DECLARE v_timeshape bigint unsigned DEFAULT NULL;
    DECLARE v_tarshape bigint unsigned DEFAULT NULL;
    DECLARE sshape bigint unsigned DEFAULT NULL;
    DECLARE tarid int;
    DECLARE priority tinyint;
    DECLARE v_climit bigint unsigned;
    DECLARE CONTINUE HANDLER FOR SQLSTATE '02000' BEGIN END;

    SELECT v.`shape`, t.`shape`, t.`tar_id`, t.`shape_prior`,
           
           ifnull(SUM(CASE t.`traff_type` 
                        WHEN 1 THEN cl.`c_limit_in` 
                        WHEN 2 THEN cl.`c_limit_out` 
                        WHEN 3 THEN cl.`c_limit_in` + cl.`c_limit_out` 
                        ELSE GREATEST(cl.`c_limit_in`, cl.`c_limit_out`) 
                      END) / IF(t.`type` < 2, IF(s.`multiply` > 0, s.`multiply` * s.`multiply`, 1024 * 1024), 60)
                 ,0) 
    INTO v_cur_shape, v_tarshape, tarid, priority, v_climit
    FROM `vgroups` v 
    JOIN `tarifs` t ON v.`tar_id` = t.`tar_id`
    JOIN `settings` s ON s.`id` = v.`id` 
    LEFT JOIN `categories` c ON c.tar_id = t.tar_id
    LEFT JOIN `climits` cl ON c.tar_id = cl.tar_id 
                      AND cl.`cat_idx` = c.`cat_idx`
                      and cl.c_date = GET_C_DATE(v.`c_date`, in_dtime)
                      and cl.vg_id = v.vg_id
    WHERE v.`vg_id` = in_vg_id
    GROUP BY v.`shape`, t.`shape`, t.`tar_id`, t.`shape_prior`, t.`traff_type`;

    IF ( v_cur_shape = 0 ) THEN
    
        SET v_cur_shape = v_tarshape;

        SELECT `shape_rate` INTO sshape FROM `size_shape` WHERE `tar_id` = tarid AND `amount` <= v_climit ORDER BY `amount` DESC LIMIT 1;

        select current_time_shape(tarid, in_dtime) into v_timeshape from dual;
        
        IF ( v_timeshape IS NULL AND sshape IS NOT NULL ) THEN
            SET v_cur_shape = sshape;
        ELSEIF ( sshape IS NULL AND v_timeshape IS NOT NULL ) THEN
            SET v_cur_shape = v_timeshape;
        ELSEIF ( v_timeshape IS NOT NULL AND sshape IS NOT NULL ) THEN
            SET v_cur_shape = CASE priority 
                                WHEN 0 THEN LEAST(sshape, v_timeshape) 
                                WHEN 1 THEN sshape 
                                WHEN 2 THEN v_timeshape 
                                ELSE GREATEST(sshape, v_timeshape) 
                            END;
        END IF;
    END IF;
    
    call turbo_shape(in_vg_id, in_dtime, v_cur_shape);
    RETURN v_cur_shape;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of FUNCTION current_time_shape
# ------------------------------------------------------------

/*!50003 DROP FUNCTION IF EXISTS `current_time_shape` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 FUNCTION `current_time_shape`(in_tar_id int(11), in_dtime datetime) RETURNS int(10) unsigned
    READS SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Calcs current timeshape'
BEGIN
  DECLARE v_tshape bigint unsigned DEFAULT NULL;
  DECLARE v_holiday tinyint DEFAULT NULL;

  SELECT `we_flag` INTO v_holiday FROM `weekends` WHERE `date` = DATE(in_dtime);

  SELECT `shape_rate` INTO v_tshape
  FROM `time_shape`
  WHERE `tar_id` = in_tar_id
  AND ((IF(`timefrom` < `timeto`
          , TIME(in_dtime) >= `timefrom` AND TIME(in_dtime) < `timeto`
          , TIME(in_dtime) >= `timefrom` OR TIME(in_dtime) < `timeto`
          )
        AND `week` & (1 << (DAYOFWEEK(DATE(in_dtime))-1))
        AND `use_weekend` = 0
       )
       OR (`use_weekend` AND ifnull(v_holiday, 0) > 0)
      )


  ORDER BY `week` * (IF(`timefrom` < `timeto`, 0, 86400) + TIME_TO_SEC(SUBTIME(`timeto`, `timefrom`)))
                   , IF(`timefrom` <= `timeto`, -`timefrom`, SUBTIME('24:00:00', `timefrom`))
  LIMIT 1;
  
  RETURN v_tshape;
END */;;

