/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 FUNCTION `EXPECT_PERIOD_DATE2`(in_date DATE, in_lock_period_date DATE) RETURNS date
    NO SQL
    DETERMINISTIC
    SQL SECURITY INVOKER
    COMMENT 'Прогноз даты привязки документа'
BEGIN
        DECLARE tmp_date DATE;

        
        
        IF in_lock_period_date IS NULL OR (in_lock_period_date < in_date) THEN
            SET tmp_date = in_date;
        ELSE
            SET tmp_date = in_lock_period_date;
        END IF;
        
        
        RETURN last_day(tmp_date);
END */;;

