begin
  return last_day(in_date - interval 1 month) + interval 1 day;
end */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of FUNCTION get_advance_payments
# ------------------------------------------------------------

/*!50003 DROP FUNCTION IF EXISTS `get_advance_payments` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 FUNCTION `get_advance_payments`(in_sale_id int) RETURNS varchar(1024) CHARSET utf8
    READS SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Получение списка авансовых платежей для с/ф'
BEGIN
    declare l_ret varchar(1024) default '______________';
    declare l_payment_id int default 0;
    declare l_pay_date varchar(255) default '';
    declare l_receipt varchar(255) default '';
    declare l_order_number varchar(255) default '';
    declare l_payments int default 0;
    declare l_extern_code varchar(255) default '';
    declare l_paymenttooltype int default 0;
    declare l_checknumber int default 0;
    declare l_orig_payments int default 0;
    declare l_number varchar(255) default '';
    declare const_type_eps varchar(10) default '3';
    declare const_tooltype_77 int default 77;

    declare l_first boolean default true;
    declare done boolean default false;
    
    declare advance_payments cursor for 
        select  c.payment_id,
                date_format(p.pay_date, ' от %d.%m.%Y') pay_date,
                ifnull(p.receipt,'') receipt,
                ifnull(p.order_number,'') order_number,
                m.payments,
                x.extern_code, 
                ifnull(e.paymenttooltype, 0) paymenttooltype, 
                ifnull(e.checknumber, 0) checknumber,
                ifnull((select m.payments from payments_history h join managers m on h.mod_person = m.person_id where origin_record_id = c.payment_id order by record_id limit 1),0) orig_payments
        from sales_cover c
            join sales s using(sale_id)
            join payments p on p.record_id = c.payment_id
            join pay_classes x using(class_id) 
            join managers m on p.mod_person = m.person_id
            left join payments_ext e on p.record_id = e.payment_id  
        where p.cancel_date is null
            and c.amount >= 0.01
            and ifnull(s.period_date, EXPECT_PERIOD_DATE(s.sale_date)) >= ifnull(p.period_date, EXPECT_PERIOD_DATE(p.pay_date))
            and sale_id = in_sale_id
        order by c.payment_id;

    declare continue handler for not found set done = true;

    set done = false;
    open advance_payments;
    fetch advance_payments into l_payment_id, l_pay_date, l_receipt, l_order_number, l_payments, l_extern_code, l_paymenttooltype, l_checknumber, l_orig_payments;
    while not done do
        set l_number = '';
        
        if l_first then
            set l_ret = '';
        else
            set l_ret = concat(l_ret, ', ');
        end if;
        
        
        if l_payments > 0 or l_orig_payments > 0 then
            set l_extern_code = const_type_eps;
        end if;
        
        if l_extern_code = const_type_eps and l_paymenttooltype = const_tooltype_77 then
            set l_number = ifnull(cast(l_checknumber as char), '--');
        elseif l_extern_code = const_type_eps then
            set l_number = ifnull(l_receipt, '--');
        else
            set l_number = ifnull(l_order_number, '--');
        end if;
        
        set l_ret = concat(l_ret, l_number, l_pay_date);

        set l_first = false;
        set done = false;
        fetch advance_payments into l_payment_id, l_pay_date, l_receipt, l_order_number, l_payments, l_extern_code, l_paymenttooltype, l_checknumber, l_orig_payments;
    end while;
    close advance_payments;
    
    return l_ret;
            
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of FUNCTION GET_BLOCK_DAYS
# ------------------------------------------------------------

/*!50003 DROP FUNCTION IF EXISTS `GET_BLOCK_DAYS` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 FUNCTION `GET_BLOCK_DAYS`(in_vg_id int, in_period_start date, in_period_end date, in_block_set set ('0','1','2','3','4','5','10')) RETURNS int(11)
    READS SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Возвращает число "заблокированных дней" для уч.записи'
BEGIN
    DECLARE days int;
    DECLARE l_tf, l_timefrom datetime;
    DECLARE l_tt, l_timeto datetime;
    DECLARE done boolean default FALSE;
    DECLARE blocks CURSOR FOR 
        SELECT CAST(GREATEST(in_period_start, `timefrom`) as datetime) `timefrom`, CAST(LEAST(in_period_end, `timeto`) as datetime) `timeto` 
        FROM `vg_blocks`
        WHERE `vg_id` = in_vg_id AND DATE(`timefrom`) <= in_period_end AND `timeto` > in_period_start AND FIND_IN_SET(`block_type`, in_block_set) 
        ORDER BY `timefrom`;
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;
  
    SET days = 0;
    OPEN blocks;
    FETCH blocks INTO l_tf, l_tt;
    WHILE NOT done DO
        IF TIMESTAMPDIFF(SECOND, l_timeto, l_tf) < 43200 THEN
            SET l_timeto = l_tt;
        ELSE
            IF l_timeto IS NOT NULL THEN
              SET days = days + GREATEST(0, DATEDIFF(date_round(l_timeto), date_round(l_timefrom)));
            END IF;
            SET l_timefrom = l_tf;
            SET l_timeto = l_tt;
        END IF;
        SET done = FALSE;
        FETCH blocks INTO l_tf, l_tt;
    END WHILE;
    CLOSE blocks;
    IF l_timeto IS NOT NULL THEN
        SET days = days + GREATEST(0, DATEDIFF(date_round(l_timeto), date_round(l_timefrom)));
    END IF;
    RETURN IFNULL(days, 0);
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of FUNCTION GET_C_DATE
# ------------------------------------------------------------

/*!50003 DROP FUNCTION IF EXISTS `GET_C_DATE` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 FUNCTION `GET_C_DATE`(in_cdate DATE, in_current DATETIME) RETURNS date
    NO SQL
    DETERMINISTIC
    SQL SECURITY INVOKER
    COMMENT 'Возвращает начало отчетного периода'
BEGIN
    IF(DAY(in_cdate) <= DAY(in_current)) THEN
        RETURN DATE(YEAR(in_current)*10000 + MONTH(in_current)*100 + IF(DAY(in_cdate) > 0, DAY(in_cdate), 1));
    ELSE
        IF DAY(in_current) = DAY(LAST_DAY(in_current)) THEN
            RETURN DATE(in_current);
        END IF;
        SET in_current = DATE_SUB(in_current, INTERVAL 1 MONTH);
        IF DAY(in_cdate) > DAY(LAST_DAY(in_current)) THEN
            RETURN LAST_DAY(in_current);
        ELSE
            RETURN DATE(YEAR(in_current)*10000 + MONTH(in_current)*100 + DAY(in_cdate));
        END IF;
    END IF;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of FUNCTION GET_SERVICE_BLOCK_DAYS
# ------------------------------------------------------------

/*!50003 DROP FUNCTION IF EXISTS `GET_SERVICE_BLOCK_DAYS` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 FUNCTION `GET_SERVICE_BLOCK_DAYS`(in_service_id int, in_period_start date, in_period_end date, in_block_set set ('1','2','3','4','5','10')) RETURNS int(11)
    READS SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Возвращает число "заблокированных дней" для услуги'
BEGIN
    DECLARE days int;
    DECLARE l_tt, l_tf, l_tstart, l_tend datetime default '0000-00-00 00:00:00';
    DECLARE done boolean default FALSE;
    DECLARE blocks CURSOR FOR
        SELECT CAST(GREATEST(in_period_start, `timefrom`, l_tstart) as datetime) `timefrom`, CAST(LEAST(in_period_end, `timeto`, l_tend) as datetime) `timeto`
        FROM `service_blocks` s
        WHERE `service_id` = in_service_id
        AND DATE(`timefrom`) < in_period_end
        AND `timeto` >= in_period_start
        AND FIND_IN_SET(`blocked`, in_block_set)
        GROUP BY s.`timefrom`, s.`timeto`
        ORDER BY s.`timefrom`;
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;

    
    select timefrom, timeto into l_tstart, l_tend from services where service_id = in_service_id;

    SET days = 0;
    OPEN blocks;
    FETCH blocks INTO l_tf, l_tt;
    WHILE NOT done DO
        
        IF TIMESTAMPDIFF(SECOND, l_tf, l_tt) > 43200 THEN
            
            SET days = days + GREATEST(0, DATEDIFF(date_round(l_tt), date_round(l_tf)));
        END IF;
        SET done = FALSE;
        FETCH blocks INTO l_tf, l_tt;
    END WHILE;
    CLOSE blocks;

    RETURN IFNULL(days, 0);
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of FUNCTION GET_TARIFF
