/*!50003 DROP FUNCTION IF EXISTS `GET_TARIFF` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 FUNCTION `GET_TARIFF`(in_vg_id int, in_date datetime) RETURNS int(11)
    READS SQL DATA
    SQL SECURITY INVOKER
    COMMENT 'Возвращает тариф, назнач. уч.записи на момент времени in_date'
BEGIN
    DECLARE l_tar_id int;
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET l_tar_id = NULL;

    SELECT `tar_id_new` INTO l_tar_id 
    FROM `tarifs_history` 
    WHERE `vg_id` = in_vg_id AND `rasp_time` <= in_date 
    ORDER BY `changed` DESC, `record_id` DESC LIMIT 1;

    IF ( l_tar_id IS NULL ) THEN
        SELECT `tar_id_new` INTO l_tar_id 
        FROM `tarifs_history` 
        WHERE `vg_id` = in_vg_id 
        ORDER BY `rasp_time`, `record_id` LIMIT 1;
        IF ( l_tar_id IS NULL ) THEN
            SELECT `tar_id` INTO l_tar_id FROM `vgroups` WHERE `vg_id` = in_vg_id;
        END IF;
    END IF;

    RETURN l_tar_id;
END */;;

