/*!50003 DROP FUNCTION IF EXISTS `GUESS_DATE` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 FUNCTION `GUESS_DATE`(in_date varchar(64)) RETURNS date
    NO SQL
    DETERMINISTIC
    SQL SECURITY INVOKER
    COMMENT 'Определяет дату по строке различного формата'
BEGIN
    SET in_date = TRIM(in_date);
    IF in_date REGEXP '[0-9]{4}[-\./][0-9]{2}[-\./][0-9]{2}' OR in_date REGEXP '[0-9]{8}' THEN
        RETURN DATE(REPLACE(REPLACE(REPLACE(in_date, '-', ''), '.', ''), '/', ''));
    ELSEIF in_date REGEXP '[0-9]{2}[-\./][0-9]{2}[-\./][0-9]{4}' THEN
        RETURN DATE(CONCAT(RIGHT(in_date, 4), '-', SUBSTR(in_date, 4, 2), '-', LEFT(in_date, 2)));
    ELSEIF in_date REGEXP '[0-9]{2}[-\./][0-9]{2}[-\./][0-9]{2}' THEN
        IF LEFT(in_date, 2) + 0 > 31 OR LEFT(in_date, 2) + 0 = 0 THEN
            RETURN DATE(CONCAT(IF(LEFT(in_date, 2) + 2000 > YEAR(CURDATE()), 1900 + LEFT(in_date, 2), LEFT(in_date, 2) + 2000),
                '-', SUBSTR(in_date, 4, 2), '-', RIGHT(in_date, 2)));
        ELSEIF RIGHT(in_date, 2) + 0 > 31 OR RIGHT(in_date, 2) + 0 = 0 THEN
            RETURN DATE(CONCAT(IF(RIGHT(in_date, 2) + 2000 > YEAR(CURDATE()), 1900 + RIGHT(in_date, 2), RIGHT(in_date, 2) + 2000),
                '-', SUBSTR(in_date, 4, 2), '-', LEFT(in_date, 2)));
        ELSEIF SUBSTR(in_date, 3, 1) = '/' THEN
            RETURN DATE(CONCAT(IF(LEFT(in_date, 2) + 2000 > YEAR(CURDATE()), 1900 + LEFT(in_date, 2), LEFT(in_date, 2) + 2000),
                '-', SUBSTR(in_date, 4, 2), '-', RIGHT(in_date, 2)));
        ELSE
            RETURN DATE(CONCAT(IF(RIGHT(in_date, 2) + 2000 > YEAR(CURDATE()), 1900 + RIGHT(in_date, 2), RIGHT(in_date, 2) + 2000),
                '-', SUBSTR(in_date, 4, 2), '-', LEFT(in_date, 2)));
        END IF;
    END IF;
    RETURN DATE('0000-00-00');
END */;;

