    ELSEIF in_mac REGEXP '[0-9a-fA-F]{1,2}[0-9a-fA-F]{1,2}[0-9a-fA-F]{1,2}[0-9a-fA-F]{1,2}[0-9a-fA-F]{1,2}[0-9a-fA-F]{1,2}' THEN
        IF length(in_mac) = 12 THEN
            RETURN CONCAT(LEFT(in_mac, 2), ':'
                         , SUBSTRING(in_mac, 3, 2), ':'
                         , SUBSTRING(in_mac, 5, 2), ':'
                         , SUBSTRING(in_mac, 7, 2), ':'
                         , SUBSTRING(in_mac, 9, 2), ':'
                         , RIGHT(in_mac, 2)
                         );
         ELSE 
             RETURN in_mac;
         END IF;
    END IF;
END */;;

/*!50003 SET SESSION SQL_MODE=@OLD_SQL_MODE */;;
# Dump of FUNCTION have_wrong_symbols
# ------------------------------------------------------------

/*!50003 DROP FUNCTION IF EXISTS `have_wrong_symbols` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 FUNCTION `have_wrong_symbols`(txt varchar(4000)) RETURNS tinyint(1)
    NO SQL
    DETERMINISTIC
    SQL SECURITY INVOKER
    COMMENT 'Проверяет есть ли символы не совпадающие с кодировкой utf8'
BEGIN
  DECLARE len, i, symbol, v_error int;

  SET len = CHAR_LENGTH(txt);
  SET i = 1;
  SET v_error = 0;
  WHILE i <= len DO
    SET symbol = ORD(SUBSTR(txt,i,1));
    IF ((symbol < 32)
       OR (symbol > 126 AND symbol < 53392)
       OR (symbol > 53439 AND symbol < 53632)
       OR (symbol > 53647)) > 0
    THEN
        SET v_error = v_error + 1;
    END IF;
    SET i = i + 1;
  END WHILE;

IF v_error > 0 THEN
    RETURN TRUE;
ELSE
    RETURN FALSE;
END IF;

END */;;

