    READS SQL DATA
    SQL SECURITY INVOKER
BEGIN
    DECLARE DONE boolean;
    DECLARE t_l_trim, replaced_A INT(11);
    DECLARE t_old_number, t_new_number, n_numfrom VARCHAR(32);
    DECLARE t_replace_what TINYINT(4);
    DECLARE this_replace CURSOR FOR SELECT old_number, new_number, l_trim, replace_what FROM  phone_replaces WHERE id = in_id ORDER BY record_id;
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET DONE = 1;
    SET n_numfrom = in_numfrom;
    SET replaced_A = 0;
    IF (SELECT COUNT(*) FROM phone_replaces WHERE id = in_id) > 0 THEN
