# Dump of FUNCTION rtf_escape
# ------------------------------------------------------------

/*!50003 DROP FUNCTION IF EXISTS `rtf_escape` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 FUNCTION `rtf_escape`(txt varchar(255)) RETURNS varchar(255) CHARSET utf8
    NO SQL
    DETERMINISTIC
    SQL SECURITY INVOKER
    COMMENT 'Заменяет спец. символы в строке для ее использования в RTF'
BEGIN
  DECLARE len int;
  DECLARE i int;
  DECLARE r varchar(255);
  DECLARE c int;
  SET len = LENGTH(txt);
  SET r = '';
  SET i = 1;
  WHILE i <= len DO
    SET c = ORD(SUBSTR(txt,i,1));
    IF c > 127 THEN
      SET r = CONCAT(r, '\\\'', HEX(c));
    ELSE
      SET r = CONCAT(r, CHAR(c));
    END IF;
    SET i = i + 1;
  END WHILE;
  RETURN r;
END */;;

