/*!50003 DROP FUNCTION IF EXISTS `str_number` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 FUNCTION `str_number`(in_amount BIGINT) RETURNS varchar(255) CHARSET utf8
    NO SQL
    DETERMINISTIC
    SQL SECURITY INVOKER
    COMMENT 'Возвращает запись числа прописью'
BEGIN
  DECLARE m INT;
  DECLARE n INT;
  DECLARE s VARCHAR(255);
  DECLARE d VARCHAR(255);
  DECLARE sign VARCHAR(255) default '';
  IF in_amount=0 THEN
    RETURN CASE @LANG WHEN 'en' THEN _utf8'Zero' WHEN 'tk' THEN _utf8'Nol' ELSE _utf8'Ноль' END;
  END IF;

  IF in_amount<0 THEN
    SET sign = CASE @LANG WHEN 'en' THEN _utf8'Minus ' WHEN 'tk' THEN _utf8'Kemçili ' ELSE _utf8'Минус ' END; 
    SET in_amount = abs(in_amount);
  END IF;

  IF (in_amount > 999999999999) THEN
    RETURN 'Out of range';
  END IF;

  SET s = '';
  SET n = 1;
  SET m = in_amount%1000;
  SET in_amount = TRUNCATE(in_amount/1000,0);

  WHILE in_amount OR m DO
    SET d = '';
    SET d = CONCAT(d, CASE TRUNCATE(m/100,0)
      WHEN 1 THEN CASE @LANG WHEN 'en' THEN _utf8'one hundred ' WHEN 'tk' THEN _utf8'bir ýüz ' ELSE _utf8'сто ' END
      WHEN 2 THEN CASE @LANG WHEN 'en' THEN _utf8'two hundred ' WHEN 'tk' THEN _utf8'iki ýüz ' ELSE _utf8'двести ' END
      WHEN 3 THEN CASE @LANG WHEN 'en' THEN _utf8'three hundred ' WHEN 'tk' THEN _utf8'üç ýüz ' ELSE _utf8'триста ' END
      WHEN 4 THEN CASE @LANG WHEN 'en' THEN _utf8'four hundred ' WHEN 'tk' THEN _utf8'dört ýüz ' ELSE _utf8'четыреста ' END
      WHEN 5 THEN CASE @LANG WHEN 'en' THEN _utf8'five hundred ' WHEN 'tk' THEN _utf8'bäş ýüz ' ELSE _utf8'пятьсот ' END
      WHEN 6 THEN CASE @LANG WHEN 'en' THEN _utf8'six hundred ' WHEN 'tk' THEN _utf8'alty ýüz ' ELSE _utf8'шестьсот ' END
      WHEN 7 THEN CASE @LANG WHEN 'en' THEN _utf8'seven hundred ' WHEN 'tk' THEN _utf8'ýedi ýüz ' ELSE _utf8'семьсот ' END
      WHEN 8 THEN CASE @LANG WHEN 'en' THEN _utf8'eight hundred ' WHEN 'tk' THEN _utf8'sekiz ýüz ' ELSE _utf8'восемьсот ' END
      WHEN 9 THEN CASE @LANG WHEN 'en' THEN _utf8'nine hundred ' WHEN 'tk' THEN _utf8'dokuz ýüz ' ELSE _utf8'девятьсот ' END
      ELSE '' END);
    SET m = m%100;
    IF m >= 20 THEN
      SET d = CONCAT(d, CASE TRUNCATE(m/10,0)
        WHEN 2 THEN CASE @LANG WHEN 'en' THEN _utf8'twenty ' WHEN 'tk' THEN _utf8'ýigrimi ' ELSE _utf8'двадцать ' END
        WHEN 3 THEN CASE @LANG WHEN 'en' THEN _utf8'thirty ' WHEN 'tk' THEN _utf8'otuz ' ELSE _utf8'тридцать ' END
        WHEN 4 THEN CASE @LANG WHEN 'en' THEN _utf8'forty ' WHEN 'tk' THEN _utf8'kyrk ' ELSE _utf8'сорок ' END
        WHEN 5 THEN CASE @LANG WHEN 'en' THEN _utf8'fifty ' WHEN 'tk' THEN _utf8'elli ' ELSE _utf8'пятьдесят ' END
        WHEN 6 THEN CASE @LANG WHEN 'en' THEN _utf8'sixty ' WHEN 'tk' THEN _utf8'altmyş ' ELSE _utf8'шестьдесят ' END
        WHEN 7 THEN CASE @LANG WHEN 'en' THEN _utf8'seventy ' WHEN 'tk' THEN _utf8'ýetmiş ' ELSE _utf8'семьдесят ' END
        WHEN 8 THEN CASE @LANG WHEN 'en' THEN _utf8'eighty ' WHEN 'tk' THEN _utf8'segsen ' ELSE _utf8'восемьдесят ' END
        WHEN 9 THEN CASE @LANG WHEN 'en' THEN _utf8'ninety ' WHEN 'tk' THEN _utf8'togsan ' ELSE _utf8'девяносто ' END
        ELSE '' END);
      SET m = m%10;
    END IF;
    SET d = CONCAT(d, CASE m
      WHEN 1 THEN CASE @LANG WHEN 'en' THEN _utf8'one ' WHEN 'tk' THEN _utf8'bir ' ELSE IF(n=2,_utf8'одна ',_utf8'один ') END
      WHEN 2 THEN CASE @LANG WHEN 'en' THEN _utf8'two ' WHEN 'tk' THEN _utf8'iki ' ELSE IF(n=2,_utf8'две ',_utf8'два ') END
      WHEN 3 THEN CASE @LANG WHEN 'en' THEN _utf8'three ' WHEN 'tk' THEN _utf8'üç ' ELSE _utf8'три ' END
      WHEN 4 THEN CASE @LANG WHEN 'en' THEN _utf8'four ' WHEN 'tk' THEN _utf8'dört ' ELSE _utf8'четыре ' END
      WHEN 5 THEN CASE @LANG WHEN 'en' THEN _utf8'five ' WHEN 'tk' THEN _utf8'bäş ' ELSE _utf8'пять ' END
      WHEN 6 THEN CASE @LANG WHEN 'en' THEN _utf8'six ' WHEN 'tk' THEN _utf8'alty ' ELSE _utf8'шесть ' END
      WHEN 7 THEN CASE @LANG WHEN 'en' THEN _utf8'seven ' WHEN 'tk' THEN _utf8'ýedi ' ELSE _utf8'семь ' END
      WHEN 8 THEN CASE @LANG WHEN 'en' THEN _utf8'eight ' WHEN 'tk' THEN _utf8'sekiz ' ELSE _utf8'восемь ' END
      WHEN 9 THEN CASE @LANG WHEN 'en' THEN _utf8'nine ' WHEN 'tk' THEN _utf8'dokuz ' ELSE _utf8'девять ' END
      WHEN 10 THEN CASE @LANG WHEN 'en' THEN _utf8'ten ' WHEN 'tk' THEN _utf8'on ' ELSE _utf8'десять ' END
      WHEN 11 THEN CASE @LANG WHEN 'en' THEN _utf8'eleven ' WHEN 'tk' THEN _utf8'on bir ' ELSE _utf8'одиннадцать ' END
      WHEN 12 THEN CASE @LANG WHEN 'en' THEN _utf8'twelve ' WHEN 'tk' THEN _utf8'on iki ' ELSE _utf8'двенадцать ' END
      WHEN 13 THEN CASE @LANG WHEN 'en' THEN _utf8'thirteen ' WHEN 'tk' THEN _utf8'on üç ' ELSE _utf8'тринадцать ' END
      WHEN 14 THEN CASE @LANG WHEN 'en' THEN _utf8'fourteen ' WHEN 'tk' THEN _utf8'on dört ' ELSE _utf8'четырнадцать ' END
      WHEN 15 THEN CASE @LANG WHEN 'en' THEN _utf8'fifteen ' WHEN 'tk' THEN _utf8'on bäş ' ELSE _utf8'пятнадцать ' END
      WHEN 16 THEN CASE @LANG WHEN 'en' THEN _utf8'sixteen ' WHEN 'tk' THEN _utf8'on alty ' ELSE _utf8'шестнадцать ' END
      WHEN 17 THEN CASE @LANG WHEN 'en' THEN _utf8'seventeen ' WHEN 'tk' THEN _utf8'on ýedi ' ELSE _utf8'семнадцать ' END
      WHEN 18 THEN CASE @LANG WHEN 'en' THEN _utf8'eighteen ' WHEN 'tk' THEN _utf8'on sekiz ' ELSE _utf8'восемнадцать ' END
      WHEN 19 THEN CASE @LANG WHEN 'en' THEN _utf8'nineteen ' WHEN 'tk' THEN _utf8'on dokuz ' ELSE _utf8'девятнадцать ' END
      ELSE '' END);
    IF LENGTH(d)>0 THEN
      SET d = CONCAT(d, CASE n
        WHEN 2 THEN CASE @LANG WHEN 'en' THEN _utf8'thousand ' WHEN 'tk' THEN _utf8'müň ' ELSE IF(m=1,_utf8'тысяча ',IF(m IN(2,3,4),_utf8'тысячи ',_utf8'тысяч ')) END
        WHEN 3 THEN CASE @LANG WHEN 'en' THEN _utf8'million ' WHEN 'tk' THEN _utf8'million' ELSE IF(m=1,_utf8'миллион ',IF(m IN(2,3,4),_utf8'миллиона ', _utf8'миллионов ')) END
        WHEN 4 THEN CASE @LANG WHEN 'en' THEN _utf8'billion ' WHEN 'tk' THEN _utf8'milliard ' ELSE IF(m=1,_utf8'миллиард ',IF(m IN(2,3,4),_utf8'миллиарда ', _utf8'миллиардов ')) END
        ELSE '' END);
    END IF;
    SET s = CONCAT(d, s);
    SET n = n + 1;
    SET m = in_amount%1000;
    SET in_amount = TRUNCATE(in_amount/1000,0);
  END WHILE;
  RETURN CONCAT(sign, UPPER(LEFT(s,1)), SUBSTRING(s,2,CHAR_LENGTH(s)-2));
END */;;

