/*!50003 DROP FUNCTION IF EXISTS `xml_escape` */;;
/*!50003 SET SESSION SQL_MODE="STRICT_TRANS_TABLES,NO_ENGINE_SUBSTITUTION"*/;;
/*!50003 CREATE*/ /*!50020 DEFINER=`root`@`localhost`*/ /*!50003 FUNCTION `xml_escape`(in_str VARCHAR(511)) RETURNS varchar(511) CHARSET utf8
    NO SQL
    DETERMINISTIC
    SQL SECURITY INVOKER
    COMMENT 'Заменяет спец. символы в строке для ее использования в XML'
BEGIN
  DECLARE amp INT default 0;
  DECLARE rep VARCHAR(64);  
  DECLARE out_str VARCHAR(511) default '';
  SET amp = LOCATE('&', in_str);
  WHILE amp DO
    SET out_str = CONCAT(out_str, LEFT(in_str, amp - 1));
    SET in_str = SUBSTR(in_str, amp);
    SET rep = LEFT(in_str, 6);
    IF NOT rep REGEXP '^&(#[0-9]{1,3}|amp|lt|gt|quot|apos|nbsp);' THEN
      SET rep = REPLACE(rep, '&', '&amp;');
    END IF;
    SET out_str = CONCAT(out_str, rep);
    SET in_str = SUBSTR(in_str, 7);
    SET amp = LOCATE('&', in_str);
  END WHILE;
  SET out_str = CONCAT(out_str, in_str);
  SET out_str = REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(out_str, '<', '&lt;'), '>', '&gt;'), '"', '&quot;'), '\'', '&apos;'), '&nbsp;', '&#160;');
  SET out_str = REPLACE(out_str, char(0x00), char(0x20));
  SET out_str = REPLACE(out_str, char(0x0A), char(0x20));
  SET out_str = REPLACE(out_str, char(0x0B), char(0x20));
  SET out_str = REPLACE(out_str, char(0x0D), char(0x20));

  SET out_str = replace(replace(replace(out_str, char(0xD0A0), char(0xFFFF)), char(0xA0), char(0x20)), char(0xFFFF),char(0xD0A0));
  SET out_str = REPLACE(out_str, char(0x16), '');
  SET out_str = REPLACE(out_str, char(0x1B), '');
  RETURN out_str;
END */;;

